function getNativeAgentHookStatusPythonScript(): string {
  return String.raw`
import json
import os
import pathlib
import shutil
import sys
from datetime import datetime, timezone

home = pathlib.Path(sys.argv[1])
notify_hook_path = pathlib.Path(sys.argv[2])
hook_state_dir = pathlib.Path(sys.argv[3])
pi_extension_path = pathlib.Path(sys.argv[4])

agents = [
    {"agentId": "codex", "cli": "codex", "kind": "json", "paths": [home / ".codex" / "hooks.json"], "commandAgent": None},
    {"agentId": "claude", "cli": "claude", "kind": "json", "paths": [home / ".claude" / "settings.json"], "commandAgent": None},
    {"agentId": "cursor", "cli": "cursor-agent", "kind": "json", "paths": [home / ".cursor" / "hooks.json"], "commandAgent": "cursor"},
    {"agentId": "pi", "cli": "pi", "kind": "pi", "paths": [pi_extension_path], "commandAgent": "pi"},
    {"agentId": "gemini", "cli": "gemini", "kind": "json", "paths": [home / ".gemini" / "settings.json"], "commandAgent": "gemini"},
    {"agentId": "copilot", "cli": "copilot", "kind": "json", "paths": [home / ".copilot" / "config.json"], "commandAgent": "copilot"},
    {"agentId": "droid", "cli": "droid", "kind": "json", "paths": [home / ".factory" / "settings.json"], "commandAgent": "droid"},
    {"agentId": "grok", "cli": "grok", "kind": "json", "paths": [home / ".grok" / "hooks" / "ghostex-session.json"], "commandAgent": "grok"},
    {"agentId": "antigravity", "cli": "agy", "kind": "antigravity", "paths": [home / ".gemini" / "config" / "hooks.json"], "commandAgent": "antigravity"},
    {"agentId": "amp", "cli": "amp", "kind": "amp", "paths": [home / ".config" / "amp" / "plugins" / "ghostex-session.ts"], "commandAgent": "amp"},
    {"agentId": "rovodev", "cli": "acli", "kind": "marked-yaml", "paths": [home / ".rovodev" / "config.yml"], "commandAgent": "rovodev", "marker": "ghostex hooks rovodev begin"},
    {"agentId": "hermes-agent", "cli": "hermes", "kind": "marked-yaml", "paths": [home / ".hermes" / "config.yaml"], "commandAgent": "hermes-agent", "marker": "ghostex hooks hermes-agent begin"},
    {"agentId": "codebuddy", "cli": "codebuddy", "kind": "json", "paths": [home / ".codebuddy" / "settings.json"], "commandAgent": "codebuddy"},
    {"agentId": "qoder", "cli": "qodercli", "kind": "json", "paths": [home / ".qoder" / "settings.json"], "commandAgent": "qoder"},
]

profiles_path = home / ".codex-profiles"
if profiles_path.is_dir():
    codex = agents[0]
    for profile_path in sorted(profiles_path.iterdir()):
        if profile_path.is_dir():
            codex["paths"].append(profile_path / "hooks.json")

def load_json(path):
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None
    return data if isinstance(data, dict) else None

def recursive_strings(value):
    if isinstance(value, str):
        yield value
    elif isinstance(value, list):
        for item in value:
            yield from recursive_strings(item)
    elif isinstance(value, dict):
        for item in value.values():
            yield from recursive_strings(item)

def has_notify_command_in_json(path, command_agent):
    data = load_json(path)
    if data is None:
        return False
    notify = str(notify_hook_path)
    expected_agent = f"GHOSTEX_AGENT={command_agent} " if command_agent else ""
    for value in recursive_strings(data):
        if command_agent:
            if notify in value and expected_agent in value:
                return True
        elif value.strip() == notify:
            return True
    return False

def text(path):
    try:
        return path.read_text(encoding="utf-8")
    except Exception:
        return ""

def is_installed(agent):
    paths = agent["paths"]
    kind = agent["kind"]
    if kind == "json":
        existing_paths = [path for path in paths if path.exists()]
        if agent["agentId"] == "codex" and existing_paths:
            return all(has_notify_command_in_json(path, None) for path in existing_paths)
        return any(has_notify_command_in_json(path, agent.get("commandAgent")) for path in paths)
    if kind == "antigravity":
        return any("ghostex" in (load_json(path) or {}) for path in paths)
    if kind == "amp":
        return any("ghostex-amp-session-extension-marker" in text(path) for path in paths)
    if kind == "pi":
        return any("syncSessionState" in text(path) and "agentSessionId" in text(path) for path in paths)
    if kind == "marked-yaml":
        marker = agent.get("marker", "")
        return any(marker in text(path) and str(notify_hook_path) in text(path) for path in paths)
    return False

def display_path(path):
    try:
        return "~/" + str(path.relative_to(home))
    except ValueError:
        return str(path)

rows = []
for agent in agents:
    cli_installed = shutil.which(agent["cli"]) is not None
    hook_installed = is_installed(agent)
    if not cli_installed:
        status = "cliMissing"
        detail = f"{agent['cli']} was not found on PATH."
    elif hook_installed:
        status = "installed"
        installed_paths = [display_path(path) for path in agent["paths"] if path.exists()]
        detail = "Installed in " + (", ".join(installed_paths[:2]) if installed_paths else display_path(agent["paths"][0]))
    else:
        status = "missing"
        detail = "Run Install Hooks to write " + display_path(agent["paths"][0])
    rows.append({
        "agentId": agent["agentId"],
        "cliCommand": agent["cli"],
        "cliInstalled": cli_installed,
        "detail": detail,
        "hookInstalled": hook_installed,
        "paths": [str(path) for path in agent["paths"]],
        "status": status,
    })

print(json.dumps({
    "agents": rows,
    "generatedAt": datetime.now(timezone.utc).isoformat(),
    "hookStateDirectory": str(hook_state_dir),
    "notifyHookPath": str(notify_hook_path),
    "type": "agentHookStatus",
}))
`;
}

function buildEnsureNativeAgentHooksCommand(): string {
  const notifyHookPath = ghostex_AGENT_NOTIFY_HOOK_PATH;
  const piExtensionPath = NATIVE_PI_EXTENSION_PATH;
  const homeDirectory = nativeHomeDirectory();
  const claudeSettingsPath = `${nativeHomeDirectory()}/.claude/settings.json`;
  const hookStateDirectory = GHOSTEX_AGENT_HOOK_STATE_DIR;
  return [
    "set -e",
    `mkdir -p ${quoteNativeShellArg(dirnameNativePath(notifyHookPath))} ${quoteNativeShellArg(dirnameNativePath(claudeSettingsPath))} ${quoteNativeShellArg(dirnameNativePath(piExtensionPath))} ${quoteNativeShellArg(hookStateDirectory)}`,
    `cat > ${quoteNativeShellArg(notifyHookPath)} <<'ghostex_NOTIFY_HOOK'`,
    getNativeCodexNotifyHookScript(),
    "ghostex_NOTIFY_HOOK",
    `chmod 755 ${quoteNativeShellArg(notifyHookPath)}`,
    `cat > ${quoteNativeShellArg(piExtensionPath)} <<'ghostex_PI_EXTENSION'`,
    getNativePiExtensionScript(),
    "ghostex_PI_EXTENSION",
    `/usr/bin/python3 - ${quoteNativeShellArg(notifyHookPath)} ${quoteNativeShellArg(homeDirectory)} <<'ghostex_GENERIC_AGENT_HOOK_MERGE'`,
    getNativeGenericAgentHookMergeScript(),
    "ghostex_GENERIC_AGENT_HOOK_MERGE",
    `/usr/bin/python3 - ${quoteNativeShellArg(notifyHookPath)} ${quoteNativeShellArg(homeDirectory)} <<'ghostex_AMP_PLUGIN_INSTALL'`,
    getNativeAmpPluginInstallScript(),
    "ghostex_AMP_PLUGIN_INSTALL",
    `/usr/bin/python3 - ${quoteNativeShellArg(notifyHookPath)} ${quoteNativeShellArg(homeDirectory)} <<'ghostex_CODEX_HOOK_MERGE_ALL'`,
    getNativeCodexHookMergeAllScript(),
    "ghostex_CODEX_HOOK_MERGE_ALL",
    `/usr/bin/python3 - ${quoteNativeShellArg(claudeSettingsPath)} ${quoteNativeShellArg(notifyHookPath)} claude <<'ghostex_CLAUDE_HOOK_MERGE'`,
    getNativeAgentHookMergeScript(),
    "ghostex_CLAUDE_HOOK_MERGE",
  ].join("\n");
}

function getNativeCodexNotifyHookScript(): string {
  /*
   * CDXC:SessionRestore 2026-05-22-23:33:
   * Ghostex must capture native agent session ids from hook payloads.
   * Resume commands should prefer that exact id, while the existing title-based
   * restore path remains the backup when a hook did not capture an id.
   *
   * CDXC:SessionRestore 2026-06-07-01:57:
   * Ghostex-owned prompt generation is not a user session. The notify hook must
   * ignore internal generation markers so Codex exec jobs for titles or commit
   * messages cannot overwrite the restorable agent identity of the terminal that
   * launched them.
   */
  return `#!/bin/bash
if [ -n "$1" ]; then
  INPUT="$1"
else
  INPUT="$(cat)"
fi

SESSION_STATE_FILE="\${VSMUX_SESSION_STATE_FILE:-\${GHOSTEX_SESSION_STATE_FILE:-$ghostex_SESSION_STATE_FILE}}"
HOOK_STATE_DIR=${quoteNativeShellArg(GHOSTEX_AGENT_HOOK_STATE_DIR)}
GHOSTEX_DIRECT_SESSION_REF="\${GHOSTEX_GLOBAL_SESSION_REF:-}"
GHOSTEX_DIRECT_BASE_URL="\${GHOSTEX_GXSERVER_BASE_URL:-}"
GHOSTEX_DIRECT_TOKEN_FILE="\${GHOSTEX_GXSERVER_AUTH_TOKEN_FILE:-}"
if [ "\${GHOSTEX_INTERNAL_PROMPT_GENERATION:-}" = "1" ] || [ "\${GHOSTEX_INTERNAL_TITLE_GENERATION:-}" = "1" ]; then
  printf '{"continue":true}'
  exit 0
fi
if [ -z "$SESSION_STATE_FILE" ] && { [ -z "$GHOSTEX_DIRECT_SESSION_REF" ] || [ -z "$GHOSTEX_DIRECT_BASE_URL" ] || [ -z "$GHOSTEX_DIRECT_TOKEN_FILE" ]; }; then
  printf '{"continue":true}'
  exit 0
fi

/usr/bin/python3 - "$SESSION_STATE_FILE" "$INPUT" "$HOOK_STATE_DIR" <<'PY'
import datetime
import base64
import json
import os
import pathlib
import time
import sys
import urllib.request

state_path = sys.argv[1]
raw_input = sys.argv[2]
hook_state_dir = pathlib.Path(sys.argv[3]).expanduser()
has_state_path = bool(state_path.strip())
try:
    payload = json.loads(raw_input)
except Exception:
    payload = {}

state = {}
if has_state_path:
    try:
        with open(state_path, "r", encoding="utf-8") as handle:
            for line in handle:
                key, separator, value = line.partition("=")
                if separator:
                    state[key] = value.strip() if key in {"firstUserMessageBase64", "agentSessionPath"} else " ".join(value.strip().split())
    except FileNotFoundError:
        pass

def first_string(*values):
    for value in values:
        if isinstance(value, str) and value.strip():
            return " ".join(value.strip().split())
    return ""

def first_path(*values):
    for value in values:
        if isinstance(value, str) and value.strip():
            return value.strip()
    return ""

def decode_base64_text(value):
    try:
        return base64.b64decode((value or "").encode("ascii")).decode("utf-8").strip()
    except Exception:
        return ""

def normalize_prompt_text(value):
    return " ".join(str(value or "").strip().split())

def normalized_agent_key(value):
    normalized = " ".join(str(value or "").strip().lower().split())
    if normalized in {"claude", "claude code"}:
        return "claude"
    if normalized in {"codex", "openai codex", "codex cli"}:
        return "codex"
    if normalized in {"pi", "π"}:
        return "pi"
    if normalized in {"opencode", "open code"}:
        return "opencode"
    if normalized in {"grok", "grok build"}:
        return "grok"
    if normalized in {"amp", "amp cli"}:
        return "amp"
    if normalized in {"cursor", "cursor agent", "cursor cli", "cursor-agent"}:
        return "cursor"
    if normalized in {"gemini", "gemini cli"}:
        return "gemini"
    if normalized in {"agy", "antigravity", "antigravity cli"}:
        return "antigravity"
    if normalized in {"copilot", "github copilot"}:
        return "copilot"
    if normalized in {"codebuddy", "code buddy"}:
        return "codebuddy"
    if normalized in {"droid", "factory", "factory droid"}:
        return "droid"
    if normalized in {"qoder", "qodercli"}:
        return "qoder"
    if normalized in {"rovo", "rovo dev", "rovodev"}:
        return "rovodev"
    if normalized in {"hermes", "hermes agent", "hermes-agent"}:
        return "hermes-agent"
    return "".join(ch if ch.isalnum() or ch in {"-", "_"} else "-" for ch in normalized).strip("-") or "codex"

def nested_get(source, *path):
    current = source
    for key in path:
        if not isinstance(current, dict):
            return None
        current = current.get(key)
    return current

def write_state():
    if not has_state_path:
        return
    keys = [
        "status",
        "statusUpdatedAt",
        "attentionEventId",
        "attentionAcknowledgedAt",
        "attentionAcknowledgedEventId",
        "agent",
        "agentSessionId",
        "agentSessionPath",
        "firstUserMessageBase64",
        "frozenAt",
        "autoTitleFromFirstPrompt",
        "historyBase64",
        "lastActivityAt",
        "pendingFirstPromptAutoRenamePrompt",
        "title",
    ]
    path = pathlib.Path(state_path)
    path.parent.mkdir(parents=True, exist_ok=True)
    temp_path = path.with_suffix(path.suffix + ".tmp")
    temp_path.write_text("".join(f"{key}={state.get(key, '')}\\n" for key in keys), encoding="utf-8")
    temp_path.replace(path)

def write_hook_store(agent_key, session_id, transcript_path):
    workspace_id = first_string(os.environ.get("GHOSTEX_WORKSPACE_ID"), os.environ.get("VSMUX_WORKSPACE_ID"), os.environ.get("ghostex_WORKSPACE_ID"))
    surface_id = first_string(os.environ.get("GHOSTEX_SESSION_ID"), os.environ.get("VSMUX_SESSION_ID"), os.environ.get("ghostex_SESSION_ID"))
    if not workspace_id or not surface_id:
        direct_project_id, direct_session_id = parse_global_session_ref(os.environ.get("GHOSTEX_GLOBAL_SESSION_REF", ""))
        workspace_id = workspace_id or direct_project_id
        surface_id = surface_id or direct_session_id
    if not session_id or not workspace_id or not surface_id:
        return
    store_path = hook_state_dir / f"{agent_key}-hook-sessions.json"
    try:
        data = json.loads(store_path.read_text(encoding="utf-8"))
    except Exception:
        data = {}
    if not isinstance(data, dict):
        data = {}
    sessions = data.get("sessions")
    if not isinstance(sessions, dict):
        sessions = {}
    sessions[session_id] = {
        "sessionId": session_id,
        "workspaceId": workspace_id,
        "surfaceId": surface_id,
        "cwd": first_path(payload.get("cwd"), os.environ.get("GHOSTEX_WORKSPACE_ROOT"), os.environ.get("VSMUX_WORKSPACE_ROOT"), os.getcwd()),
        "transcriptPath": transcript_path or None,
        "pid": os.getppid(),
        "isRestorable": True,
        "updatedAt": time.time(),
    }
    data["version"] = 1
    data["sessions"] = sessions
    store_path.parent.mkdir(parents=True, exist_ok=True)
    temp_path = store_path.with_suffix(store_path.suffix + ".tmp")
    temp_path.write_text(json.dumps(data, indent=2, sort_keys=True) + "\\n", encoding="utf-8")
    temp_path.replace(store_path)

def parse_global_session_ref(value):
    parts = str(value or "").strip().split(":")
    if len(parts) == 3 and parts[1] and parts[2]:
        return parts[1], parts[2]
    return "", ""

def read_gxserver_auth_token():
    token_file = first_path(os.environ.get("GHOSTEX_GXSERVER_AUTH_TOKEN_FILE"))
    if not token_file:
        return ""
    try:
        return pathlib.Path(token_file).expanduser().read_text(encoding="utf-8").strip()
    except Exception:
        return ""

def post_gxserver_session_state(agent_key, session_id, transcript_path, first_user_message):
    base_url = first_string(os.environ.get("GHOSTEX_GXSERVER_BASE_URL")).rstrip("/")
    project_id, surface_id = parse_global_session_ref(os.environ.get("GHOSTEX_GLOBAL_SESSION_REF", ""))
    token = read_gxserver_auth_token()
    if not base_url or not project_id or not surface_id or not token:
        return
    try:
        protocol_version = int(first_string(os.environ.get("GHOSTEX_GXSERVER_PROTOCOL_VERSION"), "0"))
    except Exception:
        protocol_version = 0
    params = {
        "agentName": agent_key,
        "projectId": project_id,
        "sessionId": surface_id,
    }
    if session_id:
        params["agentSessionId"] = session_id
    if transcript_path:
        params["agentSessionPath"] = transcript_path
    if first_user_message:
        params["firstUserMessage"] = first_user_message
    body = json.dumps({"protocolVersion": protocol_version, "params": params}).encode("utf-8")
    request = urllib.request.Request(
        base_url + "/api/ingestSessionStateEvent",
        data=body,
        headers={
            "Authorization": "Bearer " + token,
            "Content-Type": "application/json",
            "x-gxserver-protocol-version": str(protocol_version),
        },
        method="POST",
    )
    try:
        with urllib.request.urlopen(request, timeout=1.5) as response:
            response.read(128)
    except Exception:
        pass

# CDXC:CursorCLI 2026-05-27-09:06:
# Cursor Agent's global hook command exports GHOSTEX_AGENT=cursor even when a manually-started pane inherited another agent value. Prefer that explicit hook identity so Cursor transcript metadata cannot be persisted as Codex.
payload_agent = payload.get("agent")
explicit_agent_name = first_string(payload_agent, os.environ.get("GHOSTEX_AGENT"), os.environ.get("ghostex_AGENT"))
agent_name = first_string(explicit_agent_name, os.environ.get("VSMUX_AGENT"), state.get("agent"), "codex")
agent_key = normalized_agent_key(agent_name)
event_name = first_string(payload.get("hook_event_name"), payload.get("event"))
session_id = first_string(
    payload.get("session_id"),
    payload.get("sessionId"),
    payload.get("conversation_id"),
    payload.get("conversationId"),
    payload.get("thread_id"),
    payload.get("threadId"),
    nested_get(payload, "session", "id"),
    nested_get(payload, "thread", "id"),
    nested_get(payload, "properties", "sessionID"),
    nested_get(payload, "properties", "sessionId"),
    nested_get(payload, "properties", "session_id"),
    nested_get(payload, "properties", "info", "id"),
)
transcript_path = first_path(payload.get("transcript_path"), payload.get("transcriptPath"), payload.get("log_path"), payload.get("logPath"))
prompt = first_string(
    payload.get("prompt"),
    payload.get("text"),
    payload.get("message"),
    payload.get("input"),
    nested_get(payload, "prompt", "text"),
)

def now_iso():
    return datetime.datetime.now(datetime.timezone.utc).isoformat().replace("+00:00", "Z")

def update_status(status):
    timestamp = now_iso()
    state["status"] = status
    state["statusUpdatedAt"] = timestamp
    state["lastActivityAt"] = timestamp
    if status == "attention":
        state["attentionEventId"] = f"{timestamp}:attention"
        state["attentionAcknowledgedAt"] = ""
        state["attentionAcknowledgedEventId"] = ""
    elif status == "working":
        state["attentionAcknowledgedAt"] = timestamp
        state["attentionAcknowledgedEventId"] = state.get("attentionEventId", "")

state["status"] = state.get("status") or "idle"
state["statusUpdatedAt"] = state.get("statusUpdatedAt") or state.get("lastActivityAt", "")
state["agent"] = agent_key if explicit_agent_name else (state.get("agent") or agent_key)
if session_id:
    state["agentSessionId"] = session_id
if transcript_path:
    state["agentSessionPath"] = transcript_path
if session_id:
    write_hook_store(agent_key, session_id, transcript_path)

if event_name in {"UserPromptSubmit", "BeforeAgent", "PreInvocation", "beforeSubmitPrompt", "pre_llm_call", "pre_tool_call"}:
    update_status("working")
elif event_name in {"Stop", "AfterAgent", "afterAgentResponse", "turn-completion", "Notification", "stop", "on_tool_permission", "PermissionRequest"}:
    update_status("attention")
elif event_name in {"SessionEnd", "session_shutdown", "release"}:
    update_status("idle")

if event_name in {"UserPromptSubmit", "BeforeAgent", "PreInvocation", "beforeSubmitPrompt", "pre_llm_call", "pre_tool_call", "on_tool_permission"} and prompt:
    state["firstUserMessageBase64"] = state.get("firstUserMessageBase64") or base64.b64encode(prompt.encode("utf-8")).decode("ascii")
    state["lastActivityAt"] = state.get("lastActivityAt") or now_iso()
    # CDXC:SessionTitleSync 2026-05-30-05:42:
    # Cursor Agent and Claude Code name their own sessions. Keep recording the
    # first message for session metadata, but do not queue Ghostex auto-rename.
    if agent_key not in {"claude", "cursor"} and state.get("autoTitleFromFirstPrompt") not in {"1", "true", "TRUE", "True"} and not state.get("pendingFirstPromptAutoRenamePrompt", "").strip():
        first_prompt = normalize_prompt_text(decode_base64_text(state.get("firstUserMessageBase64", "")))
        current_prompt = normalize_prompt_text(prompt)
        # CDXC:SessionTitleSync 2026-05-30-05:44:
        # Cancelled first-prompt title generation clears the pending field but
        # preserves the first message. Queue the next prompt with that original
        # message so the retry title reflects both pieces of user intent.
        if first_prompt and first_prompt != current_prompt:
            state["pendingFirstPromptAutoRenamePrompt"] = normalize_prompt_text(first_prompt + "\\n" + current_prompt)
        else:
            state["pendingFirstPromptAutoRenamePrompt"] = current_prompt

first_user_message = first_string(
    state.get("pendingFirstPromptAutoRenamePrompt"),
    decode_base64_text(state.get("firstUserMessageBase64", "")),
    prompt,
)
post_gxserver_session_state(agent_key, session_id, transcript_path, first_user_message)
write_state()
PY

printf '{"continue":true}'
exit 0
`;
}

function getNativeAgentHookMergeScript(): string {
  return `import json
import pathlib
import sys

hooks_path = pathlib.Path(sys.argv[1])
notify_hook_path = sys.argv[2]
agent_name = sys.argv[3]
command = notify_hook_path
try:
    with open(hooks_path, "r", encoding="utf-8") as handle:
        data = json.load(handle)
except FileNotFoundError:
    data = {}

if not isinstance(data, dict):
    data = {}
hooks = data.get("hooks")
if not isinstance(hooks, dict):
    hooks = {}
    data["hooks"] = hooks

def is_ghostex_command(hook):
    return isinstance(hook, dict) and hook.get("command") == command

matcher = "*" if agent_name == "claude" else None

def merge_event(event_name):
    groups = hooks.get(event_name)
    if not isinstance(groups, list):
        groups = []

    for group in groups:
        if not isinstance(group, dict):
            continue
        group_hooks = group.get("hooks")
        if isinstance(group_hooks, list) and any(is_ghostex_command(hook) for hook in group_hooks):
            hooks[event_name] = groups
            return

    next_group = {
        "hooks": [
            {
                "type": "command",
                "command": command,
            }
        ]
    }
    if matcher is not None:
        next_group["matcher"] = matcher
    groups.append(next_group)
    hooks[event_name] = groups

for event_name in ["SessionStart", "UserPromptSubmit"]:
    merge_event(event_name)

hooks_path.parent.mkdir(parents=True, exist_ok=True)
with open(hooks_path, "w", encoding="utf-8") as handle:
    json.dump(data, handle, indent=2)
    handle.write("\\n")
`;
}

function getNativeGenericAgentHookMergeScript(): string {
  return `import json
import pathlib
import shlex
import shutil
import sys

notify_hook_path = pathlib.Path(sys.argv[1])
home_path = pathlib.Path(sys.argv[2])

def p(*parts):
    return home_path.joinpath(*parts)

targets = [
    (p(".grok", "hooks", "ghostex-session.json"), "nested", "grok", "grok", ["SessionStart", "UserPromptSubmit", "Stop", "Notification", "SessionEnd"]),
    (p(".gemini", "settings.json"), "nested", "gemini", "gemini", ["SessionStart", "BeforeAgent", "AfterAgent", "SessionEnd"]),
    (p(".copilot", "config.json"), "nested", "copilot", "copilot", ["SessionStart", "Stop", "Notification", "SessionEnd"]),
    (p(".codebuddy", "settings.json"), "nested", "codebuddy", "codebuddy", ["SessionStart", "Stop", "Notification", "SessionEnd"]),
    (p(".factory", "settings.json"), "nested", "droid", "droid", ["SessionStart", "Stop", "Notification", "SessionEnd"]),
    (p(".qoder", "settings.json"), "nested", "qoder", "qodercli", ["SessionStart", "Stop", "SessionEnd"]),
    (p(".cursor", "hooks.json"), "flat", "cursor", "cursor-agent", ["beforeSubmitPrompt", "beforeShellExecution", "afterAgentResponse", "stop"]),
    (p(".gemini", "config", "hooks.json"), "antigravity", "antigravity", "agy", ["SessionStart", "PreInvocation", "Stop", "turn-completion", "Notification", "SessionEnd"]),
]

def load_json(path):
    try:
        with path.open("r", encoding="utf-8") as handle:
            data = json.load(handle)
    except FileNotFoundError:
        data = {}
    except Exception:
        data = {}
    return data if isinstance(data, dict) else {}

def command_for(agent):
    return f"GHOSTEX_AGENT={shlex.quote(agent)} {shlex.quote(str(notify_hook_path))}"

def is_ghostex_command(hook, command):
    return isinstance(hook, dict) and hook.get("command") == command

def merge_nested(data, events, command):
    hooks = data.get("hooks")
    if not isinstance(hooks, dict):
        hooks = {}
        data["hooks"] = hooks
    for event_name in events:
        groups = hooks.get(event_name)
        if not isinstance(groups, list):
            groups = []
        found = False
        for group in groups:
            if not isinstance(group, dict):
                continue
            group_hooks = group.get("hooks")
            if isinstance(group_hooks, list) and any(is_ghostex_command(hook, command) for hook in group_hooks):
                found = True
                break
        if not found:
            groups.append({"hooks": [{"type": "command", "command": command, "timeout": 5000}]})
        hooks[event_name] = groups

def merge_flat(data, events, command):
    hooks = data.get("hooks")
    if not isinstance(hooks, dict):
        hooks = {}
        data["hooks"] = hooks
    data["version"] = data.get("version") or 1
    for event_name in events:
        entries = hooks.get(event_name)
        if not isinstance(entries, list):
            entries = []
        if not any(is_ghostex_command(entry, command) for entry in entries):
            entries.append({"command": command})
        hooks[event_name] = entries

def merge_antigravity(data, events, command):
    group = {}
    for event_name in events:
        group[event_name] = [{"type": "command", "command": command, "timeout": 5}]
    data["ghostex"] = group

def yaml_double_quote(value):
    return '"' + str(value).replace("\\\\", "\\\\\\\\").replace('"', '\\"').replace("\\n", "\\\\n") + '"'

def without_marked_block(lines, begin_marker, end_marker):
    result = []
    index = 0
    while index < len(lines):
        if lines[index].strip() != begin_marker:
            result.append(lines[index])
            index += 1
            continue
        index += 1
        while index < len(lines) and lines[index].strip() != end_marker:
            index += 1
        if index < len(lines):
            index += 1
    while result and not result[-1].strip():
        result.pop()
    return result

def install_rovo_hooks(path, command):
    begin_marker = "# ghostex hooks rovodev begin"
    end_marker = "# ghostex hooks rovodev end"
    try:
        lines = path.read_text(encoding="utf-8").splitlines()
    except FileNotFoundError:
        lines = []
    lines = without_marked_block(lines, begin_marker, end_marker)
    if lines and lines[-1].strip():
        lines.append("")
    lines.extend([
        begin_marker,
        "eventHooks:",
        "  events:",
        "    - name: on_complete",
        "      commands:",
        f"        - command: {yaml_double_quote(command)}",
        "    - name: on_error",
        "      commands:",
        f"        - command: {yaml_double_quote(command)}",
        "    - name: on_tool_permission",
        "      commands:",
        f"        - command: {yaml_double_quote(command)}",
        end_marker,
    ])
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text("\\n".join(lines) + "\\n", encoding="utf-8")

def install_hermes_hooks(path, command):
    begin_marker = "# ghostex hooks hermes-agent begin"
    end_marker = "# ghostex hooks hermes-agent end"
    shell_command = f"sh -c {shlex.quote(command)}"
    try:
        lines = path.read_text(encoding="utf-8").splitlines()
    except FileNotFoundError:
        lines = []
    lines = without_marked_block(lines, begin_marker, end_marker)
    if lines and lines[-1].strip():
        lines.append("")
    lines.extend([
        begin_marker,
        "hooks:",
        "  on_session_start:",
        f"    - command: {yaml_double_quote(shell_command)}",
        "      timeout: 5",
        "  pre_llm_call:",
        f"    - command: {yaml_double_quote(shell_command)}",
        "      timeout: 5",
        "  post_llm_call:",
        f"    - command: {yaml_double_quote(shell_command)}",
        "      timeout: 5",
        "  on_session_end:",
        f"    - command: {yaml_double_quote(shell_command)}",
        "      timeout: 5",
        "  on_session_finalize:",
        f"    - command: {yaml_double_quote(shell_command)}",
        "      timeout: 5",
        "  on_session_reset:",
        f"    - command: {yaml_double_quote(shell_command)}",
        "      timeout: 5",
        end_marker,
    ])
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text("\\n".join(lines) + "\\n", encoding="utf-8")

for path, format_name, agent, binary_name, events in targets:
    if shutil.which(binary_name) is None:
        continue
    command = command_for(agent)
    data = load_json(path)
    if format_name == "flat":
        merge_flat(data, events, command)
    elif format_name == "antigravity":
        merge_antigravity(data, events, command)
    else:
        merge_nested(data, events, command)
    path.parent.mkdir(parents=True, exist_ok=True)
    temp_path = path.with_suffix(path.suffix + ".tmp")
    temp_path.write_text(json.dumps(data, indent=2, sort_keys=True) + "\\n", encoding="utf-8")
    temp_path.replace(path)
    print(f"agentHooksPath={path}")

if shutil.which("acli") is not None:
    rovo_path = p(".rovodev", "config.yml")
    install_rovo_hooks(rovo_path, command_for("rovodev"))
    print(f"agentHooksPath={rovo_path}")

hermes_dir = p(".hermes")
if shutil.which("hermes") is not None and hermes_dir.exists():
    hermes_path = hermes_dir / "config.yaml"
    install_hermes_hooks(hermes_path, command_for("hermes-agent"))
    print(f"agentHooksPath={hermes_path}")
`;
}

function getNativeAmpPluginInstallScript(): string {
  return `import pathlib
import shutil
import sys

notify_hook_path = pathlib.Path(sys.argv[1])
home_path = pathlib.Path(sys.argv[2])
if shutil.which("amp") is None:
    sys.exit(0)
plugin_path = home_path / ".config" / "amp" / "plugins" / "ghostex-session.ts"
plugin_source = r'''// ghostex-amp-session-extension-marker v1
import { spawn } from "node:child_process";
import type { PluginAPI } from "@ampcode/plugin";

function firstString(...values: unknown[]): string | null {
  for (const value of values) {
    if (typeof value === "string" && value.trim().length > 0) return value.trim();
  }
  return null;
}

function sendHook(eventName: string, event: any, ctx: any): void {
  if (process.env.GHOSTEX_AMP_HOOKS_DISABLED === "1") return;
  const sessionId = firstString(event?.thread?.id, ctx?.thread?.id);
  if (!sessionId) return;
  const payload = {
    agent: "amp",
    cwd: firstString(process.env.PWD, process.cwd()) || process.cwd(),
    event: eventName,
    hook_event_name: eventName,
    session_id: sessionId,
  };
  try {
    const child = spawn("__GHOSTEX_NOTIFY_HOOK__", [], { stdio: ["pipe", "ignore", "ignore"], env: { ...process.env, GHOSTEX_AGENT: "amp" }, detached: true });
    child.on("error", () => {});
    child.stdin.on("error", () => {});
    child.stdin.end(JSON.stringify(payload));
    child.unref();
  } catch (_) {}
}

export default function (amp: PluginAPI) {
  amp.on("session.start", async (event: any, ctx: any) => sendHook("SessionStart", event, ctx));
  amp.on("agent.start", async (event: any, ctx: any) => sendHook("UserPromptSubmit", event, ctx));
  amp.on("agent.end", async (event: any, ctx: any) => sendHook("Stop", event, ctx));
}
'''.replace("__GHOSTEX_NOTIFY_HOOK__", str(notify_hook_path))

plugin_path.parent.mkdir(parents=True, exist_ok=True)
plugin_path.write_text(plugin_source, encoding="utf-8")
print(f"ampPluginPath={plugin_path}")
`;
}

function getNativePiExtensionScript(): string {
  return `import fs from "node:fs";
import path from "node:path";
import type { ExtensionAPI, ExtensionContext, InputEvent } from "@earendil-works/pi-coding-agent";

const BRAILLE_FRAMES = ["⠸", "⠴", "⠼", "⠧", "⠦", "⠏", "⠋", "⠇", "⠙", "⠹"] as const;
const STATE_KEYS = [
  "status",
  "statusUpdatedAt",
  "attentionEventId",
  "attentionAcknowledgedAt",
  "attentionAcknowledgedEventId",
  "agent",
  "agentSessionId",
  "agentSessionPath",
  "firstUserMessageBase64",
  "frozenAt",
  "autoTitleFromFirstPrompt",
  "historyBase64",
  "lastActivityAt",
  "pendingFirstPromptAutoRenamePrompt",
  "title",
] as const;

function getStateFile(): string | undefined {
  return (
    process.env.VSMUX_SESSION_STATE_FILE ||
    process.env.GHOSTEX_SESSION_STATE_FILE ||
    process.env.ghostex_SESSION_STATE_FILE
  );
}

function readState(filePath: string): Record<string, string> {
  const state: Record<string, string> = {};
  try {
    const raw = fs.readFileSync(filePath, "utf8");
    for (const line of raw.split(/\\r?\\n/g)) {
      const separatorIndex = line.indexOf("=");
      if (separatorIndex <= 0) {
        continue;
      }
      const key = line.slice(0, separatorIndex);
      const value = line.slice(separatorIndex + 1);
      state[key] = key === "firstUserMessageBase64" || key === "agentSessionPath"
        ? value.trim()
        : value.trim().replace(/\\s+/g, " ");
    }
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code !== "ENOENT") {
      throw error;
    }
  }
  return state;
}

function writeState(filePath: string, state: Record<string, string>): void {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  const tempPath = filePath + ".tmp";
  fs.writeFileSync(
    tempPath,
    STATE_KEYS.map((key) => key + "=" + (state[key] || "")).join("\\n") + "\\n",
    "utf8",
  );
  fs.renameSync(tempPath, filePath);
}

function updateStatus(state: Record<string, string>, status: "attention" | "idle" | "working"): string {
  const timestamp = new Date().toISOString();
  state.status = status;
  state.statusUpdatedAt = timestamp;
  state.lastActivityAt = timestamp;
  if (status === "attention") {
    state.attentionEventId = timestamp + ":attention";
    state.attentionAcknowledgedAt = "";
    state.attentionAcknowledgedEventId = "";
  } else if (status === "working") {
    state.attentionAcknowledgedAt = timestamp;
    state.attentionAcknowledgedEventId = state.attentionEventId || "";
  }
  return timestamp;
}

function baseTitle(pi: ExtensionAPI, ctx: ExtensionContext): string {
  const cwd = path.basename(ctx.cwd || process.cwd());
  const session = pi.getSessionName();
  return session ? "π - " + session + " - " + cwd : "π - " + cwd;
}

function syncSessionState(pi: ExtensionAPI, ctx: ExtensionContext, updates: Record<string, string> = {}): void {
  const filePath = getStateFile();
  if (!filePath) {
    return;
  }
  const state = readState(filePath);
  const nextStatus = updates.status as "attention" | "idle" | "working" | undefined;
  if (nextStatus === "attention" || nextStatus === "idle" || nextStatus === "working") {
    updateStatus(state, nextStatus);
  } else {
    state.status = state.status || "idle";
    state.statusUpdatedAt = state.statusUpdatedAt || state.lastActivityAt || "";
  }
  state.agent = "pi";
  state.agentSessionId = ctx.sessionManager.getSessionId() || state.agentSessionId || "";
  state.agentSessionPath = ctx.sessionManager.getSessionFile() || state.agentSessionPath || "";
  state.title = pi.getSessionName() || state.title || "";
  for (const [key, value] of Object.entries(updates)) {
    if (key === "status" || key === "lastActivityAt") {
      continue;
    }
    state[key] = value;
  }
  writeState(filePath, state);
}

function captureInput(pi: ExtensionAPI, event: InputEvent, ctx: ExtensionContext): void {
  const prompt = event.text.trim();
  if (!prompt) {
    return;
  }
  const filePath = getStateFile();
  if (!filePath) {
    return;
  }
  const state = readState(filePath);
  state.status = state.status || "idle";
  state.agent = "pi";
  state.agentSessionId = ctx.sessionManager.getSessionId() || state.agentSessionId || "";
  state.agentSessionPath = ctx.sessionManager.getSessionFile() || state.agentSessionPath || "";
  state.title = pi.getSessionName() || state.title || "";
  state.firstUserMessageBase64 =
    state.firstUserMessageBase64 || Buffer.from(prompt, "utf8").toString("base64");
  state.lastActivityAt = new Date().toISOString();
  if (!state.pendingFirstPromptAutoRenamePrompt && !/^(1|true)$/iu.test(state.autoTitleFromFirstPrompt || "")) {
    /*
     * CDXC:SessionTitleSync 2026-05-30-05:44:
     * Cancelled first-prompt title generation keeps the first message stored
     * but clears the pending prompt. Retry with the next prompt plus the
     * original first message so generated titles use both user requests.
     */
    const firstPrompt = Buffer.from(state.firstUserMessageBase64 || "", "base64")
      .toString("utf8")
      .replace(/\\s+/g, " ")
      .trim();
    const currentPrompt = prompt.replace(/\\s+/g, " ").trim();
    state.pendingFirstPromptAutoRenamePrompt =
      firstPrompt && firstPrompt !== currentPrompt
        ? (firstPrompt + " " + currentPrompt).replace(/\\s+/g, " ")
        : currentPrompt;
  }
  writeState(filePath, state);
}

export default function (pi: ExtensionAPI) {
  let timer: ReturnType<typeof setInterval> | undefined;
  let frameIndex = 0;

  function stopAnimation(ctx: ExtensionContext): void {
    if (timer) {
      clearInterval(timer);
      timer = undefined;
    }
    frameIndex = 0;
    ctx.ui.setTitle(baseTitle(pi, ctx));
  }

  function startAnimation(ctx: ExtensionContext): void {
    stopAnimation(ctx);
    timer = setInterval(() => {
      const frame = BRAILLE_FRAMES[frameIndex % BRAILLE_FRAMES.length];
      ctx.ui.setTitle(frame + " " + baseTitle(pi, ctx));
      frameIndex += 1;
    }, 120);
  }

  pi.on("session_start", async (_event, ctx) => {
    syncSessionState(pi, ctx);
    ctx.ui.setTitle(baseTitle(pi, ctx));
  });

  pi.on("input", async (event, ctx) => {
    captureInput(pi, event, ctx);
    return { action: "continue" };
  });

  pi.on("agent_start", async (_event, ctx) => {
    syncSessionState(pi, ctx, { status: "working" });
    startAnimation(ctx);
  });

  pi.on("agent_end", async (_event, ctx) => {
    syncSessionState(pi, ctx, { status: "attention" });
    stopAnimation(ctx);
  });

  pi.on("session_shutdown", async (_event, ctx) => {
    syncSessionState(pi, ctx, { status: "idle" });
    stopAnimation(ctx);
  });
}
`;
}

function getNativeCodexHookMergeAllScript(): string {
  return `import json
import pathlib
import sys

notify_hook_path = pathlib.Path(sys.argv[1])
home_path = pathlib.Path(sys.argv[2])
command = str(notify_hook_path)

def load_hooks_data(hooks_path):
    try:
        with open(hooks_path, "r", encoding="utf-8") as handle:
            data = json.load(handle)
    except FileNotFoundError:
        data = {}

    if not isinstance(data, dict):
        data = {}
    hooks = data.get("hooks")
    if not isinstance(hooks, dict):
        hooks = {}
        data["hooks"] = hooks
    return data, hooks

def is_ghostex_command(hook):
    return isinstance(hook, dict) and hook.get("command") == command

def merge_hook(hooks_path):
    data, hooks = load_hooks_data(hooks_path)
    def merge_event(event_name):
        groups = hooks.get(event_name)
        if not isinstance(groups, list):
            groups = []

        for group in groups:
            if not isinstance(group, dict):
                continue
            group_hooks = group.get("hooks")
            if isinstance(group_hooks, list) and any(is_ghostex_command(hook) for hook in group_hooks):
                hooks[event_name] = groups
                return

        groups.append({
            "hooks": [
                {
                    "type": "command",
                    "command": command,
                }
            ]
        })
        hooks[event_name] = groups

    for event_name in ["SessionStart", "UserPromptSubmit", "Stop", "Notification", "SessionEnd"]:
        merge_event(event_name)

    hooks_path.parent.mkdir(parents=True, exist_ok=True)
    with open(hooks_path, "w", encoding="utf-8") as handle:
        json.dump(data, handle, indent=2)
        handle.write("\\n")

hook_paths = [home_path / ".codex" / "hooks.json"]
profiles_path = home_path / ".codex-profiles"
if profiles_path.is_dir():
    for profile_path in sorted(profiles_path.iterdir()):
        if profile_path.is_dir():
            hook_paths.append(profile_path / "hooks.json")

seen = set()
for hooks_path in hook_paths:
    resolved = str(hooks_path)
    if resolved in seen:
        continue
    seen.add(resolved)
    merge_hook(hooks_path)
    print(f"codexHooksPath={resolved}")
`;
}

function dirnameNativePath(path: string): string {
  const index = path.lastIndexOf("/");
  return index > 0 ? path.slice(0, index) : ".";
}

function quoteNativeShellArg(value: string): string {
  return `'${value.replace(/'/g, "'\\''")}'`;
}

function suppressNativeSessionActivityIndicators(
  sessionId: string,
  reason: "agent-detected" | "agent-launch" | "restore-resume-command",
): void {
  const suppressedUntil = Date.now() + NATIVE_INITIAL_ACTIVITY_SUPPRESSION_MS;
  nativeActivitySuppressedUntilBySessionId.set(sessionId, suppressedUntil);
  nativeWorkingStartedAtBySessionId.delete(sessionId);
  const terminalState = terminalStateById.get(sessionId);
  if (terminalState?.activity === "attention" || terminalState?.activity === "working") {
    terminalState.activity = "idle";
    persistTerminalSessionRestoreActivity(sessionId, undefined);
    clearNativeSessionAttentionTracking(sessionId);
  }
  /**
   * CDXC:SessionRestore 2026-04-27-08:20
   * Native Ghostty title events can briefly report agent working/done markers
   * while a new or resumed agent is still booting. Mirror agent-tiler's startup
   * activity suppression so launch/resume noise does not flash Working or Done
   * before the agent has had a real chance to work.
   */
  appendAgentDetectionDebugLog("nativeSidebar.activitySuppression.started", {
    reason,
    sessionId,
    suppressedUntil: new Date(suppressedUntil).toISOString(),
  });
}

function getNativeActivitySuppressedUntil(sessionId: string): number | undefined {
  const suppressedUntil = nativeActivitySuppressedUntilBySessionId.get(sessionId);
  if (
    suppressedUntil !== undefined &&
    Number.isFinite(suppressedUntil) &&
    suppressedUntil <= Date.now()
  ) {
    nativeActivitySuppressedUntilBySessionId.delete(sessionId);
    appendAgentDetectionDebugLog("nativeSidebar.activitySuppression.expired", {
      sessionId,
      suppressedUntil: new Date(suppressedUntil).toISOString(),
    });
    return undefined;
  }

  return suppressedUntil;
}

function buildNativeRestoredTerminalInitialInput(session: TerminalSessionRecord): string {
  return readGxserverAgentResumePlanSync(session)?.startupText ?? "";
}

function readGxserverAgentResumePlanSync(session: TerminalSessionRecord) {
  const reference = resolveSidebarSessionReference(session.sessionId);
  try {
    return gxserverClient.fetchAgentResumePlanSync({
      projectId: reference.project.projectId as never,
      sessionId: reference.sessionId as never,
    });
  } catch (error) {
    appendRestoreDebugLog("nativeSidebar.gxserverAgentResumePlan.failed", {
      message: error instanceof Error ? error.message : String(error),
      projectId: reference.project.projectId,
      sessionId: reference.sessionId,
    });
    return undefined;
  }
}

async function fetchGxserverAgentResumePlanForSession(
  project: NativeProject,
  sessionId: string,
) {
  try {
    return await gxserverClient.fetchAgentResumePlan({
      projectId: project.projectId as never,
      sessionId: sessionId as never,
    });
  } catch (error) {
    appendRestoreDebugLog("nativeSidebar.gxserverAgentResumePlan.fetchFailed", {
      message: error instanceof Error ? error.message : String(error),
      projectId: project.projectId,
      sessionId,
    });
    showNativeMessage("error", error instanceof Error ? error.message : String(error));
    return undefined;
  }
}

function canRestoreNativeTerminalSession(session: TerminalSessionRecord): boolean {
  const agentId = resolveNativeResumeAgentIdForSession(session);
  if (agentId === "pi") {
    return Boolean(resolveNativeAgentCommand(agentId) && getNativePiSessionReference(session));
  }
  if (agentId === "codex") {
    return Boolean(
      resolveNativeAgentCommand(agentId) &&
        (getNativeCodexSessionReference(session) !== undefined ||
          getNativeStoredTrustedResumeTitle(session).title !== undefined),
    );
  }
  if (agentId === "cursor") {
    return Boolean(
      resolveNativeAgentCommand(agentId) &&
        (getNativeCursorSessionReference(session) !== undefined ||
          getNativeStoredTrustedResumeTitle(session).title !== undefined),
    );
  }
  if (agentId === "claude") {
    return Boolean(
      resolveNativeAgentCommand(agentId) &&
        (getNativeClaudeSessionReference(session) !== undefined ||
          getNativeStoredTrustedResumeTitle(session).title !== undefined),
    );
  }
  if (agentId === "opencode") {
    return Boolean(
      resolveNativeAgentCommand(agentId) &&
        (getNativeOpenCodeSessionReference(session) !== undefined ||
          getNativeStoredTrustedResumeTitle(session).title !== undefined),
    );
  }
  return Boolean(resolveNativeAgentCommand(agentId) && getNativeExactAgentSessionReference(agentId, session));
}

function getNativePaneTitleBarActions(session: SessionRecord): NativeTerminalTitleBarAction[] {
  /**
   * CDXC:PaneTitleBarUX 2026-05-11-11:05
   * Terminal title bars expose hover-only reload/fork/rename, Delayed Send,
   * split, browser, and terminal creation controls. Close and Sleep moved into
   * each hovered tab on 2026-05-11-02:02 so the tab controls target the
   * represented session even when the selected pane owns a different titlebar
   * view.
   *
   * Browser and T3 Code panes expose pane creation, split controls, and the
   * project-scoped Merge All Tabs command in title-bar chrome. Their
   * page/runtime tooling stays in the dedicated browser/T3 surfaces.
   *
   * CDXC:PaneTabs 2026-05-15-13:35
   * Merge All Tabs belongs directly below Split Sideways and Split Downwards
   * in normal workspace pane menus. It merges the clicked workspace group's
   * split/tab tree into one pane while command terminals remain in the separate
   * Commands panel action set.
   */
  const popOutAction = session.isPoppedOut === true ? "restorePopOut" : "popOut";
  /**
   * CDXC:PanePopOut 2026-05-19-10:15:
   * Browser pane tab-bar overflow menus must expose Pop Out Pane for the active
   * browser tab, matching terminal and agent panes. Keep T3 panes on the
   * creation/split/merge action set only.
   */
  if (session.kind === "browser") {
    return [
      "newTerminal",
      "openBrowser",
      "splitHorizontal",
      "splitVertical",
      "rotatePanesClockwise",
      "mergeAllTabs",
      popOutAction,
    ];
  }
  if (session.kind === "t3") {
    return [
      "newTerminal",
      "openBrowser",
      "splitHorizontal",
      "splitVertical",
      "rotatePanesClockwise",
      "mergeAllTabs",
    ];
  }
  return [
    "newTerminal",
    "openBrowser",
    "splitHorizontal",
    "splitVertical",
    "rotatePanesClockwise",
    "mergeAllTabs",
    "rename",
    "delayedSend",
    "fork",
    "reload",
    popOutAction,
  ];
}

type NativeResumeAgentId =
  | "amp"
  | "antigravity"
  | "claude"
  | "codebuddy"
  | "codex"
  | "copilot"
  | "cursor"
  | "droid"
  | "gemini"
  | "grok"
  | "hermes-agent"
  | "opencode"
  | "pi"
  | "qoder"
  | "rovodev";

function resolveNativeResumeAgentIdForSession(
  session: Pick<TerminalSessionRecord, "agentName" | "agentSessionPath">,
): NativeResumeAgentId | undefined {
  /**
   * CDXC:SessionRestore 2026-05-27-09:06:
   * Manual `cursor-agent` starts inside an existing terminal can inherit a stale
   * terminal agent env value from the pane. When Cursor's hook has captured a
   * Cursor transcript path, resume must treat that path as the authoritative
   * agent identity instead of using the older stored `agentName`.
   */
  if (isCursorAgentTranscriptPath(session.agentSessionPath)) {
    return "cursor";
  }
  return resolveNativeResumeAgentId(session.agentName);
}

function getNativeCodexSessionReference(session: TerminalSessionRecord): string | undefined {
  const sessionIdentity = session.agentSessionId?.trim();
  return sessionIdentity ? (getCodexSessionIdFromTitle(sessionIdentity) ?? sessionIdentity) : undefined;
}

function getNativeClaudeSessionReference(session: TerminalSessionRecord): string | undefined {
  return session.agentSessionId?.trim() || undefined;
}

function getNativeOpenCodeSessionReference(session: TerminalSessionRecord): string | undefined {
  return session.agentSessionId?.trim() || undefined;
}

function getNativePiSessionReference(session: TerminalSessionRecord): string | undefined {
  return session.agentSessionPath?.trim() || session.agentSessionId?.trim() || undefined;
}

function getNativeCursorSessionReference(session: TerminalSessionRecord): string | undefined {
  return (
    getCursorChatSessionIdFromIdentity(session.agentSessionId) ??
    getCursorChatSessionIdFromIdentity(session.agentSessionPath)
  );
}

function getNativeExactAgentSessionReference(
  agentId: NativeResumeAgentId | undefined,
  session: TerminalSessionRecord,
): string | undefined {
  if (!agentId) {
    return undefined;
  }
  if (agentId === "codex") {
    return getNativeCodexSessionReference(session);
  }
  if (agentId === "cursor") {
    return getNativeCursorSessionReference(session);
  }
  if (agentId === "pi") {
    return getNativePiSessionReference(session);
  }
  return session.agentSessionId?.trim() || undefined;
}

async function createCursorCliChatId(
  projectPath: string,
  agentCommand: string,
): Promise<string | undefined> {
  const executable = getNativeCommandExecutableName(agentCommand) ?? "cursor-agent";
  try {
    const result = await runNativeProcess(executable, ["create-chat"], {
      cwd: projectPath,
      timeoutMs: 15_000,
    });
    const chatId = getCursorChatSessionIdFromIdentity(result.stdout);
    appendAgentDetectionDebugLog("nativeSidebar.cursorCreateChat", {
      chatId,
      executable,
      exitCode: result.exitCode,
      projectPath,
      stderrPreview: result.stderr.trim().slice(0, 120),
      stdoutPreview: result.stdout.trim().slice(0, 120),
    });
    return result.exitCode === 0 ? chatId : undefined;
  } catch (error) {
    appendAgentDetectionDebugLog("nativeSidebar.cursorCreateChat.error", {
      executable,
      message: error instanceof Error ? error.message : String(error),
      projectPath,
    });
    return undefined;
  }
}

type LaunchAgentTerminalOptions = {
  agentSessionId?: string;
  commandId?: string;
  commandTitle?: string;
  diagnosticSource?: "fork-session" | "previousSessionRestore";
  focusAfterCreate?: boolean;
  forceSessionPersistenceOff?: boolean;
  initialPresentation?: "background" | "focused";
  queueProviderStartupText?: boolean;
  restoredFromSessionId?: GxserverSessionId;
  sessionTag?: SidebarSessionTag;
  sidebarOrder?: number;
  shellCommand?: string;
  sessionPersistenceName?: string;
  sessionPersistenceProvider?: TerminalSessionPersistenceProvider;
  splitDirection?: "horizontal" | "vertical";
  startupText?: string;
  surface?: TerminalSessionRecord["surface"];
  titleSource?: TerminalSessionRecord["titleSource"];
  visiblePlacement?: VisibleSessionPlacement;
};

async function launchAgentTerminal(
  agent: SidebarAgentButton,
  groupId?: string,
  options?: LaunchAgentTerminalOptions,
): Promise<SessionRecord | undefined> {
  const canonicalProject = ensureNativeProjectRegisteredWithGxserver(activeProject(), "launchAgentTerminal");
  if (!canonicalProject) {
    return undefined;
  }
  const project = canonicalProject;
  let agentSessionId = options?.agentSessionId;
  if (agent.agentId === "cursor") {
    const projectPath = project.path;
    agentSessionId =
      agentSessionId ?? (await createCursorCliChatId(projectPath, agent.command ?? "cursor-agent"));
  }
  const launchPlan = gxserverClient.fetchAgentLaunchPlanSync({
    agentId: agent.agentId,
    agentSessionId,
    projectId: project.projectId as never,
  });
  return createTerminal(
    createAgentSessionDefaultTitle(agent.name),
    launchPlan.startupText,
    groupId,
    agent.agentId,
    {
      ...options,
      agentSessionId,
    },
  );
}

async function writeNativeTerminalTextInLineChunks(
  nativeSessionId: string,
  text: string,
): Promise<void> {
  const chunks = splitAgentPromptTextIntoLineChunks(text);
  for (let index = 0; index < chunks.length; index++) {
    if (index > 0) {
      await delayNativeAgentPromptStep(AGENT_PROMPT_CHUNK_DELAY_MS);
    }
    const chunkText = index === 0 ? chunks[index]! : `\n${chunks[index]!}`;
    postNative({ sessionId: nativeSessionId, text: chunkText, type: "writeTerminalText" });
  }
}

async function stageNativeAgentPrompt(input: {
  agent: SidebarAgentButton;
  prompt: string;
  projectId: string;
  renameTitle?: string;
  session: Pick<SessionRecord, "sessionId">;
  submitPrompt?: boolean;
}): Promise<void> {
  const prompt = input.prompt.trim();
  if (!prompt) {
    return;
  }
  const nativeSessionId = nativeSessionIdForProjectSidebarSession(
    input.projectId,
    input.session.sessionId,
  );
  /**
   * CDXC:PromptAgents 2026-05-29-20:21:
   * Agent prompt automation must not paste into a terminal while the CLI is
   * still mounting its TUI. Wait for native terminalReady, then give the agent
   * prompt editor time to appear. When a helper session needs a title, submit
   * `/rename` first and only write the real prompt after that command has
   * settled, so Multi-commit, Find Session, project-board Start Work, merge
   * conflicts, and worktree first prompts all use the same ordered path.
   *
   * CDXC:PromptAgents 2026-05-31-07:35:
   * Long bead prompts must be written in fifteen-line chunks so Cursor Agent does
   * not collapse the staged text into a "[Pasted text #1 +N lines]" chip before submit.
   */
  await waitForNativeTerminalReady(input.session.sessionId);
  await delayNativeAgentPromptStep(AGENT_PROMPT_READY_DELAY_MS);
  const renameTitle = input.renameTitle?.trim();
  if (renameTitle) {
    const agentId = input.agent.agentId.trim().toLowerCase();
    const renameCommand = agentId === "pi" ? `/name ${renameTitle}` : `/rename ${renameTitle}`;
    postNative({ sessionId: nativeSessionId, text: renameCommand, type: "writeTerminalText" });
    await delayNativeAgentPromptStep(AGENT_PROMPT_SUBMIT_DELAY_MS);
    postNative({ sessionId: nativeSessionId, type: "sendTerminalEnter" });
    await delayNativeAgentPromptStep(AGENT_PROMPT_STEP_DELAY_MS);
  }
  await writeNativeTerminalTextInLineChunks(nativeSessionId, prompt);
  if (input.submitPrompt === true) {
    await delayNativeAgentPromptStep(AGENT_PROMPT_SUBMIT_DELAY_MS);
    postNative({ sessionId: nativeSessionId, type: "sendTerminalEnter" });
  }
}

function getNativeTrustedResumeTitle(session: TerminalSessionRecord): string | undefined {
  const result = getNativeStoredTrustedResumeTitle(session);
  /**
   * CDXC:SessionRestore 2026-04-28-06:06
   * Restore trust is based on persisted title provenance plus title filtering,
   * not the sidebar `∗` marker. Generated, terminal-auto, and native user
   * titles are resumable because native user renames are submitted to the agent
   * with `/rename <title>`. Legacy records without a title source can also
   * resume when the title itself passes filtering. Explicit placeholders,
   * paths, bare agent names, and command noise remain rejected.
   */
  appendRestoreDebugLog("nativeSidebar.resumeTitleTrust", {
    reason: result.reason,
    sessionId: session.sessionId,
    title: session.title,
    titleSource: session.titleSource,
    trusted: result.title !== undefined,
  });
  return result.title;
}

function getNativeStoredTrustedResumeTitle(
  session: TerminalSessionRecord,
): { reason: string; title?: string } {
  if (!isNativeTrustedResumeTitleSource(session.titleSource)) {
    return { reason: `untrusted-title-source:${session.titleSource ?? "missing"}` };
  }
  const resumeTitle = getVisibleTerminalTitle(session.title)?.trim();
  if (!resumeTitle) {
    return { reason: "title-empty-or-filtered" };
  }
  if (isRejectedNativeResumeTitle(resumeTitle)) {
    return { reason: "title-rejected-as-command-or-noise" };
  }
  return { reason: "trusted-stored-title", title: resumeTitle };
}

function isNativeTrustedResumeTitleSource(
  titleSource: TerminalSessionRecord["titleSource"],
): boolean {
  return titleSource !== "placeholder";
}

function isRejectedNativeResumeTitle(title: string): boolean {
  const normalizedTitle = title.trim();
  const normalizedLowerTitle = normalizedTitle.toLowerCase();
  /**
   * CDXC:SessionRestore 2026-04-27-17:45
   * Resume must never target transient terminal command titles. Ghostty can
   * briefly publish the launched agent command (`x`, `codex`, etc.) or mojibake
   * status bytes as the title; those values are display noise, not persisted
   * agent session names.
   *
   * CDXC:SessionTitleSync 2026-05-07-17:27
   * zmx reconnect can also publish the Ghostty ghost placeholder before the
   * persisted pane title is available. Reject it here even though shared
   * visibility filtering also handles it, so native resume/title-sync callers
   * cannot persist the placeholder if they bypass that visibility step.
   *
   * CDXC:PreviousSessions 2026-05-31-15:00:
   * Search by Text is the launch label for the prompt-history search terminal,
   * not a resumable session title. Reject it even on legacy records that were
   * saved before the placeholder title source was written to gxserver.
   */
  return (
    normalizedTitle === "ð^ß^Ñ»" ||
    isTemporaryNativeSessionTitle(normalizedTitle) ||
    isGhostPlaceholderSessionTitle(normalizedTitle) ||
    /[\u0000-\u001f\u007f]/u.test(normalizedTitle) ||
    (normalizedTitle.startsWith("ð") && normalizedTitle.endsWith("»")) ||
    getNativeAgentCommandExecutableNames().has(normalizedLowerTitle) ||
    getNativeAgentCommandExecutableNames().has(getNativeCommandExecutableName(normalizedLowerTitle) ?? "")
  );
}

function isTemporaryNativeSessionTitle(title: string): boolean {
  return title.trim().replace(/\s+/g, " ").toLowerCase() === "search by text";
}

function getNativeAgentCommandExecutableNames(): Set<string> {
  return new Set(
    [...DEFAULT_SIDEBAR_AGENTS.map((agent) => agent.command), ...storedAgents.map((agent) => agent.command)]
      .map(getNativeCommandExecutableName)
      .filter((commandName): commandName is string => Boolean(commandName)),
  );
}

function getNativeCommandExecutableName(command: string | undefined): string | undefined {
  const firstPart = command?.trim().split(/\s+/u)[0]?.trim();
  return firstPart ? firstPart.replace(/^['"]|['"]$/gu, "").toLowerCase() : undefined;
}

function resolveNativeResumeAgentId(
  agentName: string | undefined,
): NativeResumeAgentId | undefined {
  const normalizedAgentName = agentName?.trim().toLowerCase();
  if (!normalizedAgentName) {
    return undefined;
  }

  if (isNativeResumeAgentId(normalizedAgentName)) {
    return normalizedAgentName;
  }
  if (normalizedAgentName === "π") {
    return "pi";
  }
  if (normalizedAgentName === "agy" || normalizedAgentName === "antigravity cli") {
    return "antigravity";
  }
  if (normalizedAgentName === "amp cli") {
    return "amp";
  }
  if (normalizedAgentName === "code buddy") {
    return "codebuddy";
  }
  if (
    normalizedAgentName === "cursor agent" ||
    normalizedAgentName === "cursor cli" ||
    normalizedAgentName === "cursor-agent"
  ) {
    return "cursor";
  }
  if (normalizedAgentName === "droid" || normalizedAgentName === "factory droid") {
    return "droid";
  }
  if (normalizedAgentName === "hermes" || normalizedAgentName === "hermes agent") {
    return "hermes-agent";
  }
  if (normalizedAgentName === "qodercli") {
    return "qoder";
  }
  if (normalizedAgentName === "rovo" || normalizedAgentName === "rovo dev") {
    return "rovodev";
  }

  const defaultAgent = getDefaultSidebarAgentById(normalizedAgentName);
  if (isNativeResumeAgentId(defaultAgent?.agentId)) {
    return defaultAgent.agentId;
  }

  const matchingAgent = agents.find(
    (agent) =>
      agent.agentId.trim().toLowerCase() === normalizedAgentName ||
      agent.name.trim().toLowerCase() === normalizedAgentName,
  );
  return isNativeResumeAgentId(matchingAgent?.agentId) ? matchingAgent.agentId : undefined;
}

function isNativeResumeAgentId(agentId: string | undefined): agentId is NativeResumeAgentId {
  return (
    agentId === "amp" ||
    agentId === "antigravity" ||
    agentId === "claude" ||
    agentId === "codebuddy" ||
    agentId === "codex" ||
    agentId === "copilot" ||
    agentId === "cursor" ||
    agentId === "droid" ||
    agentId === "gemini" ||
    agentId === "grok" ||
    agentId === "hermes-agent" ||
    agentId === "opencode" ||
    agentId === "pi" ||
    agentId === "qoder" ||
    agentId === "rovodev"
  );
}

function resolveNativeAgentCommand(agentId: NativeResumeAgentId | undefined): string | undefined {
  if (!agentId) {
    return undefined;
  }

  return (
    agents.find((agent) => agent.agentId === agentId)?.command?.trim() ??
    getDefaultSidebarAgentById(agentId)?.command
  );
}

function readGxserverAgentRuntimeCommandForSession(
  agentId: NativeResumeAgentId,
  session: TerminalSessionRecord,
): string | undefined {
  const reference = resolveSidebarSessionReference(session.sessionId);
  try {
    /*
    CDXC:GxserverAgentCommands 2026-06-02-22:23:
    Native fork UI still composes provider-specific fork subcommands, but the executable plus runtime Accept All flags come from gxserver's launch plan. Do not use macOS-local settings or shared/sidebar Accept All helpers here, because gxserver owns agent command shaping for all clients.
    */
    return gxserverClient.fetchAgentLaunchPlanSync({
      agentId,
      projectId: reference.project.projectId as never,
    }).command;
  } catch (error) {
    appendRestoreDebugLog("nativeSidebar.gxserverAgentLaunchPlanForFork.failed", {
      agentId,
      errorType: error instanceof Error ? error.name : typeof error,
      hasMessage: (error instanceof Error ? error.message : String(error)).length > 0,
      projectId: reference.project.projectId,
      sessionId: reference.sessionId,
    });
    return undefined;
  }
}

const GXSERVER_CANONICAL_PROJECT_ID_PATTERN = /^P[0-9][a-z0-9]{3}$/u;
const GXSERVER_CANONICAL_SESSION_ID_PATTERN = /^G[0-9][a-z0-9]{3}$/u;

function ensureNativeProjectRegisteredWithGxserver(
  project: NativeProject,
  reason: string,
): NativeProject | undefined {
  try {
    const gxserverProject = gxserverClient.addProjectPathSync({
      name: project.name,
      path: project.path,
    });
    applyGxserverProjectDomainStateToPresentationCache(gxserverProject, reason);
    return reconcileNativeProjectWithGxserverProject(project, gxserverProject, reason);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    appendTerminalLaunchDebugLog("nativeSidebar.gxserverProject.registerFailed", {
      errorType: error instanceof Error ? error.name : typeof error,
      hasMessage: message.length > 0,
      projectIdIsCanonical: GXSERVER_CANONICAL_PROJECT_ID_PATTERN.test(project.projectId),
      projectPathDepth: project.path.split("/").filter(Boolean).length,
      reason,
    });
    showNativeMessage("error", message);
    return undefined;
  }
}

function reconcileNativeProjectWithGxserverProject(
  project: NativeProject,
  gxserverProject: GxserverProjectDomainState,
  reason: string,
): NativeProject {
  if (project.projectId === gxserverProject.projectId) {
    return project;
  }
  /*
  CDXC:GxserverProjectIdentity 2026-05-31-17:47:
  macOS may have stale pre-daemon sidebar rows whose ids start with `project-*`. Before creating a zmx-backed terminal, rekey the row to the gxserver P-id returned for the same filesystem path so createSession, attach metadata, sleep/wake, and remote inventory all address one shared project identity.
  */
  const nextProject: NativeProject = {
    ...project,
    name: gxserverProject.name || project.name,
    projectId: gxserverProject.projectId,
  };
  const oldProjectId = project.projectId;
  projects = projects.map((candidate) =>
    candidate.projectId === oldProjectId ? nextProject : candidate,
  );
  if (activeProjectId === oldProjectId) {
    activeProjectId = gxserverProject.projectId;
  }
  ensureProjectCommandsState(resolveNativeProjectCommandsOwnerId(gxserverProject.projectId));
  writeProjectCommandsStore();
  writeStoredProjects(reason);
  appendTerminalLaunchDebugLog("nativeSidebar.gxserverProject.rekeyed", {
    oldProjectId,
    projectId: gxserverProject.projectId,
    projectPath: project.path,
    reason,
    wasCanonical: GXSERVER_CANONICAL_PROJECT_ID_PATTERN.test(oldProjectId),
  });
  return nextProject;
}

function createGxserverTerminalRecordForNativeCreate(
  project: NativeProject,
  title: string,
  agentName: string | undefined,
  sessionPersistenceProvider: TerminalSessionPersistenceProvider | undefined,
  options: LaunchAgentTerminalOptions | undefined,
): GxserverSessionDomainState | undefined {
  /*
  CDXC:GxserverSessionIdentity 2026-05-30-18:20:
  New terminal/agent sessions must be born in gxserver before the macOS sidebar writes local pane layout. This preserves the hard-cutover requirement that G IDs and canonical session identity come from gxserver, while the React sidebar continues to own grouping, tab, split, and focus placement exactly as before.

  CDXC:ProjectSidebarOwnership 2026-06-02-08:24:
  tmux, zellij, and off-provider terminal panes still run through native/AppKit, but their shared session identity belongs to gxserver like zmx sessions. Store provider metadata in the domain row so native provider behavior stays local while project/session inventory is no longer macOS-owned.
  */
  try {
    const session = gxserverClient.createTerminalSessionSync({
      agentId: agentName,
      commandId: options?.surface === "commands" ? options.commandId : undefined,
      cwd: project.path,
      kind: agentName ? "agent" : "terminal",
      launchSettings: {
        commandTitle: options?.commandTitle,
        startupText: options?.startupText,
        surface: options?.surface ?? "workspace",
      },
      lifecycleState: "running",
      providerState: {
        lifecycleState: sessionPersistenceProvider === "zmx" ? "exists" : "unknown",
        provider: sessionPersistenceProvider ?? "off",
        ...(options?.sessionPersistenceName ? { providerName: options.sessionPersistenceName } : {}),
      },
      projectId: project.projectId as never,
      restoredFromSessionId: options?.restoredFromSessionId,
      runtimeSettings: {
        agentName,
        agentSessionId: options?.agentSessionId,
        sessionPersistenceProvider: sessionPersistenceProvider ?? "off",
        titleSource: options?.titleSource,
      },
      surface: options?.surface ?? "workspace",
      sessionTag: options?.sessionTag,
      sidebarOrder: options?.sidebarOrder,
      title,
    });
    return session;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    appendTerminalLaunchDebugLog("nativeSidebar.gxserverCreateSession.failed", {
      agentName,
      message,
      projectId: project.projectId,
      title,
    });
    showNativeMessage("error", message);
    return undefined;
  }
}

function createTerminal(
  title = DEFAULT_TERMINAL_SESSION_TITLE,
  initialInput = "",
  groupId?: string,
  agentName?: string,
  options?: LaunchAgentTerminalOptions,
): TerminalSessionRecord | undefined {
  let project = activeProject();
  if (!shouldKeepProjectEditorOpenForNewSession(project.projectId)) {
    activateWorkspaceSurfaceForProject(project.projectId);
  }
  if (quickKindForProject(project) === "terminal") {
    const existingChatSession = findFirstTerminalSessionInProject(project);
    if (existingChatSession) {
      /**
       * CDXC:Chats 2026-05-04-09:41
       * Each chat folder is a single-terminal conversation container. Requests
       * to create another terminal while a chat is active should select the
       * existing chat terminal instead of adding a second session to that chat.
       */
      updateActiveProjectWorkspace(
        (workspace) =>
          focusSessionInSimpleWorkspace(workspace, existingChatSession.sessionId).snapshot,
      );
      publish();
      if (options?.focusAfterCreate !== false) {
        postNative({
          sessionId: nativeSessionIdForProjectSidebarSession(
            project.projectId,
            existingChatSession.sessionId,
          ),
          type: "focusTerminal",
        });
      }
      return existingChatSession;
    }
  }
  /*
  CDXC:RemoteAttach 2026-06-08-19:35:
  Remote session clicks open a local Ghostty pane whose process command SSH-attaches to the owning machine. That pane must not inherit the local tmux/zmx/zellij setting, because remote attach is already a provider attach on another host and should not be replayed as typed startup text through a second local provider shell.
  */
  const sessionPersistenceProvider =
    options?.forceSessionPersistenceOff === true
      ? undefined
      : options?.sessionPersistenceProvider ?? activeSessionPersistenceProviderFromSettings();
  const canonicalProject = ensureNativeProjectRegisteredWithGxserver(project, "createTerminal");
  if (!canonicalProject) {
    return undefined;
  }
  project = canonicalProject;
  const targetWorkspace = groupId
    ? focusGroupInSimpleWorkspace(project.workspace, groupId).snapshot
    : project.workspace;
  const beforeSnapshot = targetWorkspace.groups.find(
    (group) => group.groupId === targetWorkspace.activeGroupId,
  )?.snapshot;
  appendSidebarRefreshDebugLog("nativeSidebar.createTerminal.before", {
    agentName,
    groupId,
    project: summarizeSidebarRefreshProject(project),
    title,
    visiblePlacement: summarizeVisiblePlacement(options?.visiblePlacement),
  });
  appendTerminalLaunchDebugLog("nativeSidebar.createTerminal.request", {
    activeProjectId,
    agentName,
    diagnosticSource: options?.diagnosticSource,
    focusedSessionIdBefore: beforeSnapshot?.focusedSessionId,
    groupId,
    hasShellCommand: Boolean(options?.shellCommand?.trim()),
    initialInputPreview: initialInput.trim().slice(0, 80),
    initialPresentation: options?.initialPresentation ?? "focused",
    projectId: project.projectId,
    sessionCountBefore: beforeSnapshot?.sessions.length,
    title,
    visibleSessionIdsBefore: beforeSnapshot?.visibleSessionIds,
  });
  appendPaneLayoutTraceDebugLog("createTerminal.request", {
    activeProjectId,
    groupId,
    projectId: project.projectId,
    targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(targetWorkspace),
    title,
    visiblePlacement: summarizeVisiblePlacement(options?.visiblePlacement),
  });
  /**
   * CDXC:SessionPersistence 2026-05-10-03:35
   * New, reloaded, restored, and previous-session terminals use the current
   * Settings provider as the source of truth. Recreate callers pass that
   * resolved provider through options so archived records cannot keep an old
   * tmux/zmx/zellij backend alive after the user switches provider or turns
   * persistence off.
   */
  const gxserverSession = createGxserverTerminalRecordForNativeCreate(
    project,
    title,
    agentName,
    sessionPersistenceProvider,
    {
      ...options,
      startupText: initialInput,
      surface: options?.surface ?? "workspace",
    },
  );
  if (!gxserverSession) {
    return undefined;
  }
  const sessionPersistenceName = sessionPersistenceProvider
    ? sessionPersistenceProvider === "zmx"
      ? gxserverSession?.zmxName
      : options?.sessionPersistenceName
    : undefined;
  const result = createSessionInSimpleWorkspace(
    targetWorkspace,
    {
      agentName,
      agentSessionId: options?.agentSessionId,
      initialPresentation: options?.initialPresentation,
      sessionId: gxserverSession?.sessionId,
      sessionTag: options?.sessionTag,
      sessionPersistenceName,
      sessionPersistenceProvider,
      terminalEngine: "ghostty-native",
      title,
      titleSource: options?.titleSource,
    },
    options?.visiblePlacement
      ? {
          visiblePlacement:
            options.visiblePlacement.kind === "insertAfter" && options.splitDirection
              ? { ...options.visiblePlacement, splitDirection: options.splitDirection }
              : options.visiblePlacement,
        }
      : undefined,
  );
  const generatedSession = result.session?.kind === "terminal" ? result.session : undefined;
  if (!generatedSession) {
    appendTerminalLaunchDebugLog("nativeSidebar.createTerminal.noSession", {
      agentName,
      groupId,
      projectId: project.projectId,
      title,
    });
    return undefined;
  }
  const nativeSessionId = rememberNativeSessionMapping(project.projectId, generatedSession.sessionId);
  if (
    options?.splitDirection &&
    options.visiblePlacement?.kind === "insertAfter" &&
    options.visiblePlacement.targetSessionId
  ) {
    /**
     * CDXC:NativeSplits 2026-05-10-18:30
     * Split direction is a layout hint for the newly created target/new pair.
     * The sidebar still owns visibleSessionIds, while native layout uses this
     * hint to split the targeted pane sideways or downward immediately.
     */
    nativeSplitLayoutHint = {
      direction: options.splitDirection,
      nextSessionId: generatedSession.sessionId,
      projectId: project.projectId,
      targetSessionId: options.visiblePlacement.targetSessionId,
    };
  }
  const sessionStateFilePath = createNativeSessionStateFilePath(
    project.projectId,
    generatedSession.sessionId,
  );
  updateActiveProjectWorkspace(() => result.snapshot);
  const session = generatedSession;
  if (!session) {
    return undefined;
  }
  const hasStartupCommand = Boolean(initialInput.trim() || options?.shellCommand?.trim());
  if (hasStartupCommand && agentName) {
    suppressNativeSessionActivityIndicators(session.sessionId, "agent-launch");
  }

  terminalStateById.set(session.sessionId, {
    activity: hasStartupCommand && !agentName ? "working" : "idle",
    agentName,
    agentSessionId: session.agentSessionId,
    agentSessionPath: session.agentSessionPath,
    lifecycleState: "running",
    sessionPersistenceName,
    sessionPersistenceProvider,
    sessionStateFilePath,
    terminalTitle: title,
  });
  scheduleSettledTerminalTitleSync(session.sessionId, "create-terminal-created");
  appendTerminalLaunchDebugLog("nativeSidebar.createTerminal.created", {
    activateOnCreate: false,
    agentName,
    diagnosticSource: options?.diagnosticSource,
    focusedSessionIdAfter: result.snapshot.groups.find(
      (group) => group.groupId === result.snapshot.activeGroupId,
    )?.snapshot.focusedSessionId,
    focusAfterCreate: options?.focusAfterCreate !== false,
    hasShellCommand: Boolean(options?.shellCommand?.trim()),
    initialInputPreview: initialInput.trim().slice(0, 80),
    nativeSessionId,
    projectId: project.projectId,
    sessionId: session.sessionId,
    visibleSessionIdsAfter: result.snapshot.groups.find(
      (group) => group.groupId === result.snapshot.activeGroupId,
    )?.snapshot.visibleSessionIds,
  });
  appendPaneLayoutTraceDebugLog("createTerminal.created", {
    activeProjectId,
    agentName,
    nativeSessionId,
    projectId: project.projectId,
    sessionId: session.sessionId,
    targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(
      result.snapshot,
      result.snapshot.activeGroupId,
    ),
    title,
    visiblePlacement: summarizeVisiblePlacement(options?.visiblePlacement),
  });
  appendAgentDetectionDebugLog("nativeSidebar.terminalState.created", {
    agentName,
    initialActivity: hasStartupCommand && !agentName ? "working" : "idle",
    initialInputPreview: initialInput.trim().slice(0, 120),
    nativeSessionId,
    sessionId: session.sessionId,
    sessionStateFilePath,
    terminalTitle: title,
  });
  const nativeEnvironment = createNativeAgentSessionEnvironment({
    agentName,
    project,
    sessionId: session.sessionId,
    sessionStateFilePath,
  });
  appendTerminalLaunchDebugLog("nativeSidebar.createTerminal.colorEnv", {
    agentName,
    colorEnv: readAgentColorEnvironmentSnapshot(nativeEnvironment),
    nativeSessionId,
    projectId: project.projectId,
    sessionPersistenceName,
    sessionPersistenceProvider,
    sessionId: session.sessionId,
  });
  if (
    sessionPersistenceProvider &&
    sessionPersistenceProvider !== "zmx" &&
    initialInput.trim() &&
    (options?.queueProviderStartupText === true ||
      sessionPersistenceName === undefined ||
      options?.diagnosticSource === "previousSessionRestore")
  ) {
    /**
     * CDXC:AgentTerminalLifecycle 2026-05-27-10:24:
     * tmux/zellij reload/restart replacements can still create a new provider
     * shell even when they reuse a known persistence name. Explicit reload
     * callers must be able to queue restore text; terminalReady remains the
     * guard for those providers, while zmx startup replay decisions now come
     * from gxserver attach metadata.
     */
    queueNativeTerminalStartupText(session.sessionId, initialInput);
  }
  markNativeTerminalSurfaceCreationPending(
    project.projectId,
    session.sessionId,
    nativeSessionId,
    options?.diagnosticSource ?? "create-terminal",
  );
  void postNativeCreateTerminalWithGxserverAttach({
    /**
     * CDXC:CrashRootCause 2026-05-04-09:19
     * Rapid agent launches must not let native createTerminal briefly activate
     * and focus a new Ghostty surface before the sidebar publishes the current
     * visible terminal set. The sidebar workspace snapshot is the source of
     * truth for visibility, and focus is sent only after that layout command.
     */
    activateOnCreate: false,
    cwd: project.path,
    diagnosticSource: options?.diagnosticSource,
    env: nativeEnvironment,
    /**
     * CDXC:AgentTerminalLifecycle 2026-05-25-16:26:
     * Provider-backed terminals must not embed agent or restore commands into
     * tmux/zmx/zellij provider creation commands. Create the provider session
     * as a normal shell, then let terminalReady send the queued startup text
     * once so exiting the agent returns to that shell instead of ending the
     * native pane process.
     */
    initialInput: sessionPersistenceProvider || options?.shellCommand ? "" : initialInput,
    sessionId: nativeSessionId,
    sessionPersistenceName,
    sessionPersistenceProvider,
    shellCommand: sessionPersistenceProvider ? undefined : options?.shellCommand,
    title,
    type: "createTerminal",
  }, project, session.sessionId, initialInput, {
    /*
    CDXC:LocalFirstSidebar 2026-06-01-19:34:
    zmx-backed creates should not publish the new focused layout until gxserver attach metadata has been resolved and Swift has received the createTerminal command. Publishing earlier makes the native workarea briefly show an empty focused slot before the terminal surface exists.
    */
    focusAfterCreate:
      sessionPersistenceProvider === "zmx" && options?.focusAfterCreate !== false,
  });
  if (sessionPersistenceProvider !== "zmx") {
    publish();
  }
  appendSidebarRefreshDebugLog("nativeSidebar.createTerminal.afterPublish", {
    agentName,
    nativeSessionId,
    project: summarizeSidebarRefreshProject(),
    sessionId: session.sessionId,
    title,
  });
  if (sessionPersistenceProvider !== "zmx" && options?.focusAfterCreate !== false) {
    postNative({ sessionId: nativeSessionId, type: "focusTerminal" });
  }
  return session;
}

function createFocusedTabGroupPlacement(groupId?: string): VisibleSessionPlacement | undefined {
  const project = activeProject();
  const targetWorkspace = groupId
    ? focusGroupInSimpleWorkspace(project.workspace, groupId).snapshot
    : project.workspace;
  const targetGroup =
    targetWorkspace.groups.find((group) => group.groupId === targetWorkspace.activeGroupId) ??
    targetWorkspace.groups[0];
  const targetSessionId = targetGroup?.snapshot.focusedSessionId;
  if (!targetGroup || !targetSessionId) {
    appendPaneLayoutTraceDebugLog("focusedTabPlacement.unresolved", {
      activeProjectId,
      groupId,
      projectId: project.projectId,
      reason: !targetGroup ? "group-missing" : "focused-session-missing",
      targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(targetWorkspace, groupId),
    });
    return undefined;
  }

  const targetSession = targetGroup.snapshot.sessions.find(
    (session) => session.sessionId === targetSessionId,
  );
  if (!targetSession || targetSession.isSleeping === true) {
    appendPaneLayoutTraceDebugLog("focusedTabPlacement.unresolved", {
      activeProjectId,
      groupId,
      projectId: project.projectId,
      reason: !targetSession ? "focused-session-record-missing" : "focused-session-sleeping",
      targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(targetWorkspace, targetGroup.groupId),
      targetSessionId,
    });
    return undefined;
  }

  /**
   * CDXC:PaneTabs 2026-05-11-11:51
   * Empty-sidebar double-click, top New Session, and project-header pane
   * buttons must add the new pane as the active tab in the currently focused
   * tab group. Require the focused session to already be surfaced so creation
   * preserves the user's split tree, tab groups, and pane ratios instead of
   * rebuilding layout from a hidden or sleeping anchor.
   *
   * CDXC:Hotkeys 2026-06-06-04:36:
   * Cmd+T and Cmd+N create terminal/browser tabs immediately after the focused tab in the current split pane. The shared placement helper uses explicit after-positioning so keyboard-created tabs stay adjacent to the user's current context.
   */
  if (!targetGroup.snapshot.visibleSessionIds.includes(targetSessionId)) {
    appendPaneLayoutTraceDebugLog("focusedTabPlacement.unresolved", {
      activeProjectId,
      groupId,
      projectId: project.projectId,
      reason: "focused-session-not-visible",
      targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(targetWorkspace, targetGroup.groupId),
      targetSessionId,
    });
    return undefined;
  }

  appendPaneLayoutTraceDebugLog("focusedTabPlacement.resolved", {
    activeProjectId,
    groupId,
    projectId: project.projectId,
    targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(targetWorkspace, targetGroup.groupId),
    targetSessionId,
  });
  return { kind: "appendToTabGroup", position: "after", targetSessionId };
}

function createNativeSessionInCurrentContext(): void {
  /**
   * CDXC:SessionCreation 2026-05-11-11:51
   * The top "New Session" action and matching hotkey create in the currently
   * live project. When the selected context is the Combined Chats group, starting
   * a session means creating a new projectless chat folder instead of adding a
   * second terminal to an existing one-session chat container. In normal projects,
   * add the terminal as a selected tab in the focused pane's existing tab group
   * so double-click creation never opens a new split group or resizes panes.
   */
  if (quickKindForProject(activeProject()) === "terminal") {
    void createNativeChat();
    return;
  }

  createTerminal(DEFAULT_TERMINAL_SESSION_TITLE, "", undefined, undefined, {
    visiblePlacement: createFocusedTabGroupPlacement(),
  });
}

function openCommandsPanelForActiveProject(): void {
  rememberActiveProjectWorkspaceTerminalBeforeCommandsPanel("openCommandsPanel");
  updateActiveProjectCommandsPanel((panel) => ({
    ...panel,
    ...createCommandsPanelOpenStatePatch(panel, {
      defaultHeightPx: settings.commandsPanelDefaultHeightPx,
    }),
  }));
  const activeCommandSessionId = activeProject().commandsPanel.activeSessionId;
  if (!activeCommandSessionId) {
    createCommandTerminal("Command Terminal", "", { focusAfterCreate: true });
    return;
  }
  queueNativeLayoutFocusRequest(activeCommandSessionId, "openCommandsPanel");
  publish();
  postNative({
    sessionId: nativeSessionIdForProjectSidebarSession(activeProjectId, activeCommandSessionId),
    type: "focusTerminal",
  });
}

function toggleFocusedCommandsPanelForActiveProject(): void {
  const project = activeProject();
  const focusedSessionId = lastNativeFocusedSidebarSessionId;
  /**
   * CDXC:CommandsPanel 2026-05-14-14:37:
   * F12 is the command-panel shortcut. When keyboard focus is already inside
   * the visible command panel, pressing F12 should collapse that panel instead
   * of re-focusing the same command terminal.
   */
  if (
    project.commandsPanel.isVisible &&
    focusedSessionId &&
    commandPanelContainsSession(project, focusedSessionId)
  ) {
    hideCommandsPanelForActiveProject();
    return;
  }
  openCommandsPanelForActiveProject();
}

function hideCommandsPanelForActiveProject(): void {
  const restoreSessionId = rememberedWorkspaceTerminalForCommandsPanel(activeProject());
  updateActiveProjectCommandsPanel((panel) => ({
    ...panel,
    isVisible: false,
  }));
  if (restoreSessionId) {
    focusTerminal(restoreSessionId);
    return;
  }
  publish();
}

function toggleCommandsPanelForActiveProject(): void {
  if (activeProject().commandsPanel.isVisible) {
    hideCommandsPanelForActiveProject();
    return;
  }
  openCommandsPanelForActiveProject();
}

function setCommandsPanelModeForActiveProject(mode: CommandsPanelMode): void {
  updateActiveProjectCommandsPanel((panel) => ({
    ...panel,
    isVisible: true,
    mode,
  }));
  publish();
}

function createFullWidthTerminalPaneInCurrentProject(): void {
  /**
   * CDXC:CommandsPanel 2026-05-13-17:02
   * Legacy sidebar messages still route to the Commands panel shortcut: click
   * once to reveal/focus the project command surface,
   * click again to hide it without killing command terminals.
   */
  toggleCommandsPanelForActiveProject();
}

function splitFocusedNativePane(direction: "horizontal" | "vertical"): void {
  const targetSessionId = activeSnapshot().focusedSessionId;
  /**
   * CDXC:NativeSplits 2026-05-10-18:30
   * Split hotkeys create a new terminal and insert it next to the pane that was
   * focused before the shortcut. Direction is kept explicit for the command
   * surface even while the native layout still renders the exact visible set
   * with the current automatic split tree.
   */
  appendTerminalLaunchDebugLog("nativeSidebar.splitFocusedPane.request", {
    direction,
    targetSessionId,
    visibleSessionIdsBefore: activeSnapshot().visibleSessionIds,
  });
  createTerminal(DEFAULT_TERMINAL_SESSION_TITLE, "", undefined, undefined, {
    splitDirection: direction,
    visiblePlacement: {
      kind: "insertAfter",
      targetSessionId,
    },
  });
}

function createNativeT3Session(
  groupId?: string,
  options?: {
    visiblePlacement?: VisibleSessionPlacement;
  },
): T3SessionRecord | undefined {
  const project = activeProject();
  if (!shouldKeepProjectEditorOpenForNewSession(project.projectId)) {
    activateWorkspaceSurfaceForProject(project.projectId);
  }
  const targetWorkspace = groupId
    ? focusGroupInSimpleWorkspace(project.workspace, groupId).snapshot
    : project.workspace;
  const pendingThreadId = `pending-${Date.now().toString(36)}`;
  appendPaneLayoutTraceDebugLog("createT3.request", {
    activeProjectId,
    groupId,
    pendingThreadId,
    projectId: project.projectId,
    targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(targetWorkspace, groupId),
    visiblePlacement: summarizeVisiblePlacement(options?.visiblePlacement),
  });
  /**
   * CDXC:T3Code 2026-04-30-02:24
   * Native T3 Code buttons must create T3 pane records, matching the reference
   * app's special T3 path. Do not launch `npx --yes t3` in a terminal because
   * the CLI opens its own browser instead of becoming an embedded ghostex pane.
   */
  const result = createSessionInSimpleWorkspace(
    targetWorkspace,
    {
      kind: "t3",
      t3: {
        boundThreadId: pendingThreadId,
        projectId: `native-${project.projectId}`,
        serverOrigin: "http://127.0.0.1:0",
        threadId: pendingThreadId,
        workspaceRoot: project.path,
      },
      title: "T3 Code",
    },
    options?.visiblePlacement ? { visiblePlacement: options.visiblePlacement } : undefined,
  );
  const session = result.session?.kind === "t3" ? result.session : undefined;
  if (!session) {
    appendPaneLayoutTraceDebugLog("createT3.noSession", {
      activeProjectId,
      groupId,
      pendingThreadId,
      projectId: project.projectId,
      visiblePlacement: summarizeVisiblePlacement(options?.visiblePlacement),
    });
    return undefined;
  }

  const nativeSessionId = rememberNativeSessionMapping(project.projectId, session.sessionId);
  updateActiveProjectWorkspace(() => result.snapshot);
  appendPaneLayoutTraceDebugLog("createT3.created", {
    activeProjectId,
    nativeSessionId,
    projectId: project.projectId,
    sessionId: session.sessionId,
    targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(
      result.snapshot,
      result.snapshot.activeGroupId,
    ),
    threadId: session.t3.threadId,
    visiblePlacement: summarizeVisiblePlacement(options?.visiblePlacement),
  });
  postNative({ cwd: project.path, type: "startT3CodeRuntime" });
  postNative({
    cwd: project.path,
    projectId: session.t3.projectId,
    sessionId: nativeSessionId,
    threadId: session.t3.threadId,
    title: "T3 Code",
    type: "createWebPane",
    url: "http://127.0.0.1:3774",
  });
  postNative({ sessionId: nativeSessionId, type: "focusWebPane" });
  publish();
  return session;
}

function restoreNativeT3Session(
  project: NativeProject,
  session: T3SessionRecord,
  reason: string,
  options: { focusAfterRestore?: boolean } = {},
): void {
  /**
   * CDXC:T3Code 2026-04-30-09:33
   * Persisted native T3 cards outlive their WKWebView surfaces across app
   * restarts. Focusing a restored T3 card must recreate the embedded web pane
   * and managed runtime instead of only sending focus to a missing native id.
   */
  const nativeSessionId = rememberNativeSessionMapping(project.projectId, session.sessionId);
  const workspaceRoot = session.t3?.workspaceRoot ?? project.path;
  const serverOrigin =
    session.t3?.serverOrigin?.startsWith("http") && !session.t3.serverOrigin.endsWith(":0")
      ? session.t3.serverOrigin
      : "http://127.0.0.1:3774";
  postNative({ cwd: workspaceRoot, type: "startT3CodeRuntime" });
  postNative({
    cwd: workspaceRoot,
    projectId: session.t3.projectId,
    sessionId: nativeSessionId,
    threadId: session.t3.threadId,
    title: session.title || "T3 Code",
    type: "createWebPane",
    url: serverOrigin,
  });
  if (options.focusAfterRestore !== false) {
    postNative({ sessionId: nativeSessionId, type: "focusWebPane" });
  }
  appendAgentDetectionDebugLog("nativeSidebar.t3Session.restored", {
    nativeSessionId,
    reason,
    sessionId: session.sessionId,
    workspaceRoot,
  });
}

function findNativeT3SessionBoundToThread(
  project: NativeProject,
  threadId: string,
  options: { excludeSessionId?: string } = {},
): T3SessionRecord | undefined {
  activateWorkspaceSurfaceForProject(project.projectId);
  /**
   * CDXC:T3Code 2026-05-04-03:06
   * Native T3 sidebar cards are durable bindings to one T3 thread. When the
   * embedded T3 UI navigates to a different thread, ghostex must first look for an
   * existing card bound to that thread instead of replacing the current card's
   * stored thread metadata.
   */
  const normalizedThreadId = normalizeNativeT3ThreadId(threadId);
  if (!normalizedThreadId) {
    return undefined;
  }

  for (const group of project.workspace.groups) {
    for (const session of group.snapshot.sessions) {
      if (session.kind !== "t3" || session.sessionId === options.excludeSessionId) {
        continue;
      }
      const sessionThreadId = normalizeNativeT3ThreadId(
        session.t3.boundThreadId || session.t3.threadId,
      );
      if (sessionThreadId === normalizedThreadId) {
        return session;
      }
    }
  }

  return undefined;
}

function createNativeT3SessionForBoundThread(
  project: NativeProject,
  sourceSession: T3SessionRecord,
  threadId: string,
  title?: string,
): T3SessionRecord | undefined {
  /**
   * CDXC:T3Code 2026-05-04-03:06
   * Opening a different T3 thread from inside an embedded pane should create a
   * sibling T3 pane/card linked to the new thread. This preserves the original
   * sidebar card as a stable shortcut to its bound thread while keeping multiple
   * T3 threads visible in ghostex at the same time.
   */
  const groupId = project.workspace.groups.find((group) =>
    group.snapshot.sessions.some((session) => session.sessionId === sourceSession.sessionId),
  )?.groupId;
  const targetWorkspace = groupId
    ? focusGroupInSimpleWorkspace(project.workspace, groupId).snapshot
    : project.workspace;
  const resolvedTitle = normalizeNativeT3ThreadTitle(title) ?? "T3 Code";
  const result = createSessionInSimpleWorkspace(targetWorkspace, {
    kind: "t3",
    t3: {
      ...sourceSession.t3,
      boundThreadId: threadId,
      threadId,
    },
    title: resolvedTitle,
  });
  const session = result.session?.kind === "t3" ? result.session : undefined;
  if (!session) {
    return undefined;
  }

  const nativeSessionId = rememberNativeSessionMapping(project.projectId, session.sessionId);
  updateProjectWorkspace(project.projectId, () => result.snapshot);
  postNative({ cwd: session.t3.workspaceRoot || project.path, type: "startT3CodeRuntime" });
  postNative({
    cwd: session.t3.workspaceRoot || project.path,
    projectId: session.t3.projectId,
    sessionId: nativeSessionId,
    threadId: session.t3.threadId,
    title: resolvedTitle,
    type: "createWebPane",
    url: session.t3.serverOrigin || NATIVE_T3_REMOTE_ACCESS_ORIGIN,
  });
  postNative({ sessionId: nativeSessionId, type: "focusWebPane" });
  return session;
}

function normalizeNativeT3ThreadId(threadId: string | undefined): string | undefined {
  const normalized = threadId?.trim();
  if (!normalized || normalized.startsWith("pending-")) {
    return undefined;
  }
  return normalized.toLowerCase();
}

function normalizeNativeT3ThreadTitle(title: string | undefined): string | undefined {
  const normalized = title?.replace(/\s+/g, " ").trim();
  const lower = normalized?.toLowerCase();
  if (
    !normalized ||
    lower === "t3 code" ||
    lower === "t3 code (alpha)" ||
    lower === "no active thread" ||
    lower === "pick a thread to continue"
  ) {
    return undefined;
  }
  return normalized;
}

function persistNativeT3SessionTitle(
  projectId: string,
  sessionId: string,
  title: string | undefined,
): boolean {
  const normalizedTitle = normalizeNativeT3ThreadTitle(title);
  if (!normalizedTitle) {
    return false;
  }

  updateProjectWorkspace(
    projectId,
    (workspace) =>
      setSessionTitleInSimpleWorkspace(workspace, sessionId, normalizedTitle, {
        titleSource: "generated",
      }).snapshot,
  );
  return true;
}

async function resolveNativeT3ThreadTitle(
  threadId: string,
  fallbackTitle?: string,
): Promise<string | undefined> {
  const normalizedFallback = normalizeNativeT3ThreadTitle(fallbackTitle);
  if (normalizedFallback) {
    return normalizedFallback;
  }

  try {
    return await fetchNativeT3ThreadTitle(threadId);
  } catch (error) {
    appendAgentDetectionDebugLog("nativeSidebar.t3ThreadTitle.fetch.failed", {
      error: error instanceof Error ? error.message : String(error),
      threadId,
    });
    return undefined;
  }
}

function findNativeT3ProjectSession(projectId: string, sessionId: string): T3SessionRecord | undefined {
  const project = findProject(projectId);
  const session = project ? findSessionRecordInProject(project, sessionId) : undefined;
  return session?.kind === "t3" ? session : undefined;
}

async function syncNativeT3ProjectSessionTitleFromRuntime(
  projectId: string,
  sessionId: string,
  threadId: string,
  fallbackTitle?: string,
): Promise<boolean> {
  const title = await resolveNativeT3ThreadTitle(threadId, fallbackTitle);
  if (!persistNativeT3SessionTitle(projectId, sessionId, title)) {
    return false;
  }
  publish();
  return true;
}

function scheduleNativeT3SessionTitleSync(
  projectId: string,
  sessionId: string,
  threadId: string,
  fallbackTitle?: string,
): void {
  /**
   * CDXC:T3Code 2026-05-04-04:41
   * Binding a newly opened T3 thread and naming its ghostex sidebar card are
   * separate concerns. If T3 has not projected the thread title yet, retry the
   * snapshot lookup for the bound session without changing its thread binding.
   */
  const fallback = normalizeNativeT3ThreadTitle(fallbackTitle);
  void (async () => {
    for (const delayMs of NATIVE_T3_TITLE_SYNC_RETRY_DELAYS_MS) {
      await delay(delayMs);
      const session = findNativeT3ProjectSession(projectId, sessionId);
      if (!session) {
        return;
      }
      const boundThreadId = normalizeNativeT3ThreadId(session.t3.boundThreadId || session.t3.threadId);
      if (boundThreadId !== normalizeNativeT3ThreadId(threadId)) {
        return;
      }
      const synced = await syncNativeT3ProjectSessionTitleFromRuntime(
        projectId,
        sessionId,
        threadId,
        fallback,
      );
      if (synced) {
        return;
      }
    }
  })().catch((error) => {
    appendAgentDetectionDebugLog("nativeSidebar.t3ThreadTitle.retry.failed", {
      error: error instanceof Error ? error.message : String(error),
      projectId,
      sessionId,
      threadId,
    });
  });
}

async function fetchNativeT3ThreadTitle(threadId: string): Promise<string | undefined> {
  const normalizedThreadId = normalizeNativeT3ThreadId(threadId);
  if (!normalizedThreadId) {
    return undefined;
  }

  const ownerBearerToken = await waitForNativeT3OwnerBearerToken();
  const result = await runNativeProcess(
    "/bin/sh",
    [
      "-lc",
      [
        "/usr/bin/curl",
        "--fail",
        "--silent",
        "--show-error",
        "--max-time",
        "5",
        "-H",
        '"authorization: Bearer $T3_OWNER_BEARER"',
        '"$T3_ORIGIN/api/orchestration/snapshot"',
      ].join(" "),
    ],
    {
      env: {
        T3_ORIGIN: NATIVE_T3_REMOTE_ACCESS_ORIGIN,
        T3_OWNER_BEARER: ownerBearerToken,
      },
    },
  );
  if (result.exitCode !== 0) {
    throw new Error(result.stderr || result.stdout || "T3 snapshot request failed.");
  }

  const snapshot = JSON.parse(result.stdout) as {
    threads?: Array<{ deletedAt?: unknown; id?: unknown; title?: unknown }>;
  };
  const thread = snapshot.threads?.find((candidate) => {
    if (typeof candidate.id !== "string" || candidate.deletedAt != null) {
      return false;
    }
    return normalizeNativeT3ThreadId(candidate.id) === normalizedThreadId;
  });
  return typeof thread?.title === "string" ? normalizeNativeT3ThreadTitle(thread.title) : undefined;
}

function handleNativeT3ThreadReady(
  sidebarSessionId: string,
  hostEvent: Extract<NativeHostEvent, { type: "t3ThreadReady" }>,
): void {
  const reference = resolveSidebarSessionReference(sidebarSessionId);
  updateProjectWorkspace(
    reference.project.projectId,
    (workspace) =>
      setT3SessionMetadataInSimpleWorkspace(workspace, reference.sessionId, {
        boundThreadId: hostEvent.threadId,
        projectId: hostEvent.projectId,
        serverOrigin: hostEvent.serverOrigin,
        threadId: hostEvent.threadId,
        workspaceRoot: hostEvent.workspaceRoot,
      }).snapshot,
  );
  publish();
  void syncNativeT3SessionTitleFromRuntime(sidebarSessionId, hostEvent.threadId);
}

async function syncNativeT3SessionTitleFromRuntime(
  sidebarSessionId: string,
  threadId: string,
  fallbackTitle?: string,
): Promise<void> {
  const reference = resolveSidebarSessionReference(sidebarSessionId);
  const synced = await syncNativeT3ProjectSessionTitleFromRuntime(
    reference.project.projectId,
    reference.sessionId,
    threadId,
    fallbackTitle,
  );
  if (!synced) {
    scheduleNativeT3SessionTitleSync(
      reference.project.projectId,
      reference.sessionId,
      threadId,
      fallbackTitle,
    );
  }
}

async function relinkNativeT3SessionThread(
  sidebarSessionId: string,
  threadId: string,
): Promise<void> {
  const normalizedThreadId = normalizeNativeT3ThreadId(threadId);
  if (!normalizedThreadId) {
    return;
  }

  const reference = resolveSidebarSessionReference(sidebarSessionId);
  const session = findSessionRecordInProject(reference.project, reference.sessionId);
  if (session?.kind !== "t3") {
    return;
  }

  const title = await resolveNativeT3ThreadTitle(threadId);
  updateProjectWorkspace(
    reference.project.projectId,
    (workspace) =>
      setT3SessionMetadataInSimpleWorkspace(workspace, reference.sessionId, {
        ...session.t3,
        boundThreadId: threadId.trim(),
        threadId: threadId.trim(),
      }).snapshot,
  );
  persistNativeT3SessionTitle(reference.project.projectId, reference.sessionId, title);
  const refreshedProject = findProject(reference.project.projectId) ?? reference.project;
  const refreshedSession = findSessionRecordInProject(refreshedProject, reference.sessionId);
  if (refreshedSession?.kind === "t3") {
    restoreNativeT3Session(refreshedProject, refreshedSession, "manual-thread-link");
  }
  publish();
}

async function handleNativeT3ThreadChanged(
  sidebarSessionId: string,
  threadId: string,
  title?: string,
): Promise<void> {
  /**
   * CDXC:T3Code 2026-05-04-03:06
   * T3's in-app navigation changes the web route inside one WKWebView. ghostex keeps
   * card identity stable by focusing/creating the card for the navigated thread,
   * then re-routing the source WKWebView back to its bound thread without taking
   * focus back from the user's selected target thread.
   */
  const normalizedThreadId = normalizeNativeT3ThreadId(threadId);
  if (!normalizedThreadId || nativeT3ThreadChangeInFlightBySessionId.has(sidebarSessionId)) {
    return;
  }

  const reference = resolveSidebarSessionReference(sidebarSessionId);
  const session = findSessionRecordInProject(reference.project, reference.sessionId);
  if (session?.kind !== "t3") {
    return;
  }

  const currentBoundThreadId = session.t3.boundThreadId || session.t3.threadId;
  if (normalizeNativeT3ThreadId(currentBoundThreadId) === normalizedThreadId) {
    await syncNativeT3SessionTitleFromRuntime(sidebarSessionId, threadId, title);
    return;
  }

  nativeT3ThreadChangeInFlightBySessionId.add(sidebarSessionId);
  try {
    const resolvedTitle = await resolveNativeT3ThreadTitle(threadId, title);
    let targetSession = findNativeT3SessionBoundToThread(reference.project, threadId, {
      excludeSessionId: reference.sessionId,
    });

    appendAgentDetectionDebugLog("nativeSidebar.t3ThreadChanged.bindingPreservationStart", {
      currentSessionId: reference.sessionId,
      currentThreadId: currentBoundThreadId,
      nextThreadId: threadId,
      reusedSessionId: targetSession?.sessionId,
      title: resolvedTitle,
    });

    if (targetSession) {
      if (
        !persistNativeT3SessionTitle(reference.project.projectId, targetSession.sessionId, resolvedTitle)
      ) {
        scheduleNativeT3SessionTitleSync(
          reference.project.projectId,
          targetSession.sessionId,
          threadId,
          title,
        );
      }
    } else {
      targetSession = createNativeT3SessionForBoundThread(
        reference.project,
        session,
        threadId.trim(),
        resolvedTitle,
      );
      if (targetSession && !normalizeNativeT3ThreadTitle(resolvedTitle)) {
        scheduleNativeT3SessionTitleSync(
          reference.project.projectId,
          targetSession.sessionId,
          threadId,
          title,
        );
      }
    }

    const refreshedSource = findSessionRecordInProject(reference.project, reference.sessionId);
    if (refreshedSource?.kind === "t3") {
      restoreNativeT3Session(reference.project, refreshedSource, "thread-switch-restored-binding", {
        focusAfterRestore: false,
      });
    }

    if (targetSession) {
      if (activeProjectId !== reference.project.projectId) {
        focusProject(reference.project.projectId);
      }
      focusTerminal(targetSession.sessionId);
    } else {
      publish();
    }
  } finally {
    nativeT3ThreadChangeInFlightBySessionId.delete(sidebarSessionId);
  }
}

function restoreNativeBrowserSession(
  project: NativeProject,
  session: BrowserSessionRecord,
  reason: string,
): void {
  /**
   * CDXC:BrowserPanes 2026-05-02-06:35
   * Persisted browser-pane cards restore through the same native web-pane host
   * as newly opened browser actions. This keeps app restarts from turning
   * browser session cards into inert sidebar entries.
   */
  const startedAt = new Date().toISOString();
  persistNativeSessionLifecycleTimestamps(project.projectId, session.sessionId, {
    lastAccessedAt: startedAt,
    lastStartedAt: startedAt,
  });
  const nativeSessionId = rememberNativeSessionMapping(project.projectId, session.sessionId);
  postNative({
    browserFeedbackTool: settings.browserFeedbackTool,
    cwd: project.path,
    sessionId: nativeSessionId,
    title: session.title || browserPaneTitleFromUrl(session.browser.url),
    type: "createWebPane",
    url: session.browser.url,
  });
  postNative({ sessionId: nativeSessionId, type: "focusWebPane" });
  appendAgentDetectionDebugLog("nativeSidebar.browserSession.restored", {
    nativeSessionId,
    reason,
    sessionId: session.sessionId,
    url: session.browser.url,
  });
}

function syncSessionTitleFromNativeTerminalTitle(
  sessionId: string,
  rawTitle: string,
  previousTerminalTitle: string | undefined,
): boolean {
  const terminalState = terminalStateById.get(sessionId);
  const session = findSessionRecord(sessionId);
  if (!terminalState || !session) {
    appendSessionTitleDebugLog("nativeSidebar.sessionRenameSkipped", {
      agentName: terminalState?.agentName,
      hasSessionRecord: Boolean(session),
      hasTerminalState: Boolean(terminalState),
      rawTitle,
      reason: !terminalState
        ? "terminal-state-missing"
        : "session-record-not-found",
      sessionId,
    });
    return false;
  }
  /*
  CDXC:SessionTitleSync 2026-05-31-15:00:
  macOS is a title-event client. It forwards raw terminal title observations to
  gxserver and applies the canonical title, provenance, and status response
  instead of deciding whether a terminal title should rename, work, or need
  attention locally.
  */
  void syncSessionTitleFromGxserverTerminalTitle(sessionId, rawTitle, previousTerminalTitle);
  return true;
}

function shouldForwardNativeTerminalTitleImmediatelyToGxserver(
  session: SessionRecord,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
): boolean {
  /*
  CDXC:SidebarPerformance 2026-06-06-23:07:
  zmx-backed sessions already publish terminal titles through gxserver's coalesced zmx watcher. Do not also forward every native Ghostty title frame from the sidebar WKWebView, because spinner frames can arrive many times per second and turn into full hydrate publishes, gxserver writes, and WebKit memory growth.
  */
  if (
    session.kind === "terminal" &&
    terminalState.sessionPersistenceProvider === "zmx" &&
    terminalState.sessionPersistenceName
  ) {
    return false;
  }
  return session.kind === "terminal";
}

function scheduleSettledTerminalTitleSync(sessionId: string, reason: string): void {
  const terminalState = terminalStateById.get(sessionId);
  const session = findSessionRecord(sessionId);
  if (!terminalState || session?.kind !== "terminal" || !shouldSyncSettledTerminalTitle(session, terminalState.terminalTitle)) {
    return;
  }
  const existingTimeout = settledTerminalTitleSyncTimeoutBySessionId.get(sessionId);
  if (existingTimeout !== undefined) {
    window.clearTimeout(existingTimeout);
  }
  /*
  CDXC:GxserverTitleObservations 2026-06-01-09:35:
  A restored or newly attached native Ghostty surface can report a transient shell/window title before the Agent CLI redraws the real conversation title. Keep macOS a dumb observation client by sending the current terminal title to gxserver only after a short settled delay on restore, ready, focus, and title-change paths.
  */
  const timeout = window.setTimeout(() => {
    settledTerminalTitleSyncTimeoutBySessionId.delete(sessionId);
    flushSettledTerminalTitleSync(sessionId, reason);
  }, NATIVE_SETTLED_TERMINAL_TITLE_SYNC_DELAY_MS);
  settledTerminalTitleSyncTimeoutBySessionId.set(sessionId, timeout);
  appendSessionTitleDebugLog("nativeSidebar.settledTerminalTitleSync.scheduled", {
    reason,
    sessionId,
    titlePreview: summarizeTerminalText(terminalState.terminalTitle ?? ""),
  });
}

function flushSettledTerminalTitleSync(sessionId: string, reason: string): void {
  const terminalState = terminalStateById.get(sessionId);
  const session = findSessionRecord(sessionId);
  const rawTitle = terminalState?.terminalTitle;
  if (!terminalState || session?.kind !== "terminal" || !shouldSyncSettledTerminalTitle(session, rawTitle)) {
    appendSessionTitleDebugLog("nativeSidebar.settledTerminalTitleSync.skipped", {
      hasSessionRecord: Boolean(session),
      hasTerminalState: Boolean(terminalState),
      reason,
      sessionId,
      titlePreview: summarizeTerminalText(rawTitle ?? ""),
    });
    return;
  }
  appendSessionTitleDebugLog("nativeSidebar.settledTerminalTitleSync.flushed", {
    agentName: terminalState.agentName,
    reason,
    sessionId,
    titlePreview: summarizeTerminalText(rawTitle ?? ""),
  });
  syncSessionTitleFromNativeTerminalTitle(sessionId, rawTitle, undefined);
}

function shouldSyncSettledTerminalTitle(
  session: TerminalSessionRecord,
  rawTitle: string | undefined,
): rawTitle is string {
  const visibleTerminalTitle = getVisibleTerminalTitle(rawTitle)?.trim();
  if (!visibleTerminalTitle) {
    return false;
  }
  const visibleStoredTitle = getVisibleTerminalTitle(session.title)?.trim();
  return !visibleStoredTitle || normalizeComparableTitle(visibleStoredTitle) !== normalizeComparableTitle(visibleTerminalTitle);
}

function clearSettledTerminalTitleSync(sessionId: string): void {
  const timeout = settledTerminalTitleSyncTimeoutBySessionId.get(sessionId);
  if (timeout !== undefined) {
    window.clearTimeout(timeout);
    settledTerminalTitleSyncTimeoutBySessionId.delete(sessionId);
  }
}

function normalizeComparableTitle(value: string): string {
  return value.trim().replace(/\s+/gu, " ");
}

async function syncSessionTitleFromGxserverTerminalTitle(
  sessionId: string,
  rawTitle: string,
  previousTerminalTitle: string | undefined,
): Promise<void> {
  const terminalState = terminalStateById.get(sessionId);
  if (!terminalState) {
    return;
  }
  const reference = resolveSidebarSessionReference(sessionId);
  try {
    const result = await gxserverClient.rpc<GxserverTerminalTitleEventResult>(
      "/api/ingestTerminalTitleEvent",
      {
        agentName: terminalState.agentName,
        previousTerminalTitle,
        projectId: reference.project.projectId,
        protectStoredTitleFromAutomation: terminalState.protectStoredTitleFromAutomation === true,
        rawTitle,
        sessionId: reference.sessionId,
        sessionPersistenceProvider: terminalState.sessionPersistenceProvider,
      },
    );
    applyGxserverTerminalTitleResult(reference.project.projectId, reference.sessionId, rawTitle, result);
  } catch (error) {
    appendSessionTitleDebugLog("nativeSidebar.gxserver.sessionTitleEventFailed", {
      message: error instanceof Error ? error.message : String(error),
      projectId: reference.project.projectId,
      rawTitle,
      sessionId,
    });
  }
}

function applyGxserverTerminalTitleResult(
  projectId: string,
  sessionId: string,
  rawTitle: string,
  result: GxserverTerminalTitleEventResult,
): void {
  const terminalState = terminalStateById.get(sessionId);
  const session = findSessionRecord(sessionId);
  if (!terminalState || !session) {
    return;
  }
  gxserverTitleProjectionBySessionKey.set(
    gxserverTitleProjectionKey(projectId, sessionId),
    result.projection,
  );
  let didChangeLocalState = false;
  if (result.agentSessionId && terminalState.agentSessionId !== result.agentSessionId) {
    terminalState.agentSessionId = result.agentSessionId;
    setTerminalSessionAgentSessionMetadata(sessionId, {
      agentSessionId: result.agentSessionId,
      agentSessionPath: terminalState.agentSessionPath ?? (session.kind === "terminal" ? session.agentSessionPath : undefined),
    });
    didChangeLocalState = true;
  }

  const titleSource = result.projection.titleSource;
  if (result.changed && (session.title !== result.session.title || session.titleSource !== titleSource)) {
    if (session.kind === "terminal" && session.surface === "commands") {
      updateProjectCommandsPanel(projectId, (panel) => ({
        ...panel,
        sessions: panel.sessions.map((candidate) =>
          candidate.sessionId === sessionId
            ? { ...candidate, title: result.session.title, titleSource }
            : candidate,
        ),
      }));
    } else {
      updateProjectWorkspace(
        projectId,
        (workspace) =>
          setSessionTitleInSimpleWorkspace(workspace, sessionId, result.session.title, {
            titleSource,
          }).snapshot,
      );
    }
    didChangeLocalState = true;
  }
  if (applyGxserverSessionActivityResult(sessionId, result, "terminal-title")) {
    didChangeLocalState = true;
  }
  if (didChangeLocalState) {
    publish();
  }
  appendSessionTitleDebugLog(result.changed ? "nativeSidebar.sessionRenameApplied" : "nativeSidebar.sessionRenameSkipped", {
    agentName: terminalState.agentName,
    currentSessionTitle: session.title,
    rawTitle,
    reason: result.reason,
    sessionId,
    visibleTitle: result.visibleTitle,
  });
}

async function syncGxserverSessionStateEvent(
  sessionId: string,
  params: {
    agentName?: string;
    agentSessionId?: string;
    agentSessionPath?: string;
    firstPromptTitleGenerationAgent?: GxserverSessionStateEventParams["firstPromptTitleGenerationAgent"];
    firstPromptTitleGenerationCommand?: string;
    firstUserMessage?: string;
    title?: string;
    titleSource?: TerminalSessionRecord["titleSource"];
  },
): Promise<void> {
  const reference = resolveSidebarSessionReference(sessionId);
  try {
    const result = await gxserverClient.rpc<GxserverSessionStateEventResult>(
      "/api/ingestSessionStateEvent",
      {
        ...params,
        projectId: reference.project.projectId,
        sessionId: reference.sessionId,
      },
    );
    applyGxserverSessionStateEventResult(reference.project.projectId, reference.sessionId, result);
  } catch (error) {
    appendSessionTitleDebugLog("nativeSidebar.gxserver.sessionStateEventFailed", {
      message: error instanceof Error ? error.message : String(error),
      projectId: reference.project.projectId,
      sessionId,
    });
  }
}

async function syncGxserverAgentHookEvent(
  sessionId: string,
  params: {
    agentName?: string;
    agentSessionId?: string;
    agentSessionPath?: string;
    firstUserMessage?: string;
    status?: "attention" | "idle" | "working";
    statusUpdatedAt?: string;
    title?: string;
  },
): Promise<void> {
  const reference = resolveSidebarSessionReference(sessionId);
  try {
    const result = await gxserverClient.rpc<GxserverIngestAgentHookEventResult>(
      "/api/ingestAgentHookEvent",
      {
        ...params,
        eventName: "legacy-session-state",
        projectId: reference.project.projectId,
        sessionId: reference.sessionId,
      },
    );
    applyGxserverAgentHookEventResult(reference.project.projectId, reference.sessionId, result);
  } catch (error) {
    appendAgentDetectionDebugLog("nativeSidebar.gxserver.agentHookEventFailed", {
      message: error instanceof Error ? error.message : String(error),
      sessionId,
    });
  }
}

function applyGxserverAgentHookEventResult(
  projectId: string,
  sessionId: string,
  result: GxserverIngestAgentHookEventResult,
): void {
  applyGxserverSessionStateEventResult(
    projectId,
    sessionId,
    result as unknown as GxserverSessionStateEventResult,
  );
  if (result.activity && applyGxserverSessionActivityResult(sessionId, {
    activity: result.activity,
    enteredAttention: result.enteredAttention,
    session: result.session,
  }, "agent-hook-event")) {
    publish();
  }
}

function applyGxserverSessionStateEventResult(
  projectId: string,
  sessionId: string,
  result: GxserverSessionStateEventResult,
): void {
  const terminalState = terminalStateById.get(sessionId);
  const session = findSessionRecord(sessionId);
  if (!terminalState || session?.kind !== "terminal") {
    return;
  }
  gxserverTitleProjectionBySessionKey.set(
    gxserverTitleProjectionKey(projectId, sessionId),
    result.projection,
  );

  let didChange = false;
  const nextAgentName = textValue(result.session.agentId) ?? textValue(result.session.runtimeSettings.agentName);
  const nextAgentSessionId = textValue(result.session.runtimeSettings.agentSessionId);
  const nextAgentSessionPath = textValue(result.session.runtimeSettings.agentSessionPath);
  const nextFirstPromptTitleGenerationInProgress = readGxserverFirstPromptTitleGenerationRunning(
    result.session.runtimeSettings,
  );
  if (
    nextFirstPromptTitleGenerationInProgress !== undefined &&
    terminalState.firstPromptAutoRenameInProgress !== nextFirstPromptTitleGenerationInProgress
  ) {
    /*
    CDXC:GxserverSessionTitle 2026-06-04-07:11:
    gxserver now owns first-prompt title generation. Mirror its running status into the legacy native flag immediately after ingest so the existing sidebar card animation and AppKit terminal overlay appear as soon as gxserver claims the job, then clear when later gxserver responses report a terminal status.
    */
    terminalState.firstPromptAutoRenameInProgress = nextFirstPromptTitleGenerationInProgress;
    didChange = true;
  }
  if (nextAgentName && terminalState.agentName !== nextAgentName) {
    terminalState.agentName = nextAgentName;
    setTerminalSessionAgentName(sessionId, nextAgentName);
    didChange = true;
  }
  if (
    terminalState.agentSessionId !== nextAgentSessionId ||
    terminalState.agentSessionPath !== nextAgentSessionPath
  ) {
    terminalState.agentSessionId = nextAgentSessionId;
    terminalState.agentSessionPath = nextAgentSessionPath;
    setTerminalSessionAgentSessionMetadata(sessionId, {
      agentSessionId: nextAgentSessionId,
      agentSessionPath: nextAgentSessionPath,
    });
    didChange = true;
  }
  if (
    result.changed &&
    (session.title !== result.session.title || session.titleSource !== result.projection.titleSource)
  ) {
    const titleSource = result.projection.titleSource;
    if (session.surface === "commands") {
      updateProjectCommandsPanel(projectId, (panel) => ({
        ...panel,
        sessions: panel.sessions.map((candidate) =>
          candidate.sessionId === sessionId
            ? { ...candidate, title: result.session.title, titleSource }
            : candidate,
        ),
      }));
    } else {
      updateProjectWorkspace(
        projectId,
        (workspace) =>
          setSessionTitleInSimpleWorkspace(workspace, sessionId, result.session.title, {
            titleSource,
          }).snapshot,
      );
    }
    terminalState.protectStoredTitleFromAutomation = result.projection.trustedResumeTitle !== undefined;
    didChange = true;
  }
  if (didChange) {
    publish();
  }
}

function applyGxserverSessionRenameRequestResult(
  projectId: string,
  sessionId: string,
  result: GxserverSessionRenameRequestResult,
): void {
  const session = findSessionRecord(sessionId);
  if (session?.kind !== "terminal") {
    return;
  }
  gxserverTitleProjectionBySessionKey.set(
    gxserverTitleProjectionKey(projectId, sessionId),
    result.projection,
  );
  if (
    !result.changed ||
    (session.title === result.session.title && session.titleSource === result.projection.titleSource)
  ) {
    return;
  }
  const titleSource = result.projection.titleSource;
  if (session.surface === "commands") {
    updateProjectCommandsPanel(projectId, (panel) => ({
      ...panel,
      sessions: panel.sessions.map((candidate) =>
        candidate.sessionId === sessionId
          ? { ...candidate, title: result.session.title, titleSource }
          : candidate,
      ),
    }));
  } else {
    updateProjectWorkspace(
      projectId,
      (workspace) =>
        setSessionTitleInSimpleWorkspace(workspace, sessionId, result.session.title, {
          titleSource,
        }).snapshot,
    );
  }
  publish();
}

function applyGxserverSessionActivityResult(
  sessionId: string,
  result: Pick<GxserverTerminalTitleEventResult | GxserverUpdateAgentActivityResult, "activity" | "enteredAttention" | "session">,
  source: string,
): boolean {
  const terminalState = terminalStateById.get(sessionId);
  if (!terminalState) {
    return false;
  }
  let didChange = false;
  const reportedActivity = result.activity.activity;
  const attentionEventId = getNativeGxserverAttentionEventId(result.activity);
  /*
  CDXC:SessionAttention 2026-06-07-03:40:
  gxserver and hook files can briefly re-publish an attention event after the
  native user already acknowledged it. Keep the local cleared state for the
  same attentionEventId instead of letting a stale server/file replay restore
  attention UI and completion side effects.
  */
  const nextActivity =
    reportedActivity === "attention" &&
    isNativeAttentionEventLocallyAcknowledged(sessionId, attentionEventId)
      ? "idle"
      : reportedActivity;
  const previousActivity = terminalState.activity;
  if (result.activity.agentName && terminalState.agentName !== result.activity.agentName) {
    terminalState.agentName = result.activity.agentName;
    setTerminalSessionAgentName(sessionId, result.activity.agentName);
    didChange = true;
  }
  if (previousActivity !== nextActivity) {
    terminalState.activity = nextActivity;
    didChange = true;
  }
  if (result.session.lastActiveAt && isNativeTimestampNewer(result.session.lastActiveAt, terminalState.lastActivityAt)) {
    terminalState.lastActivityAt = result.session.lastActiveAt;
    persistTerminalSessionLastActivityAt(sessionId, result.session.lastActiveAt);
    didChange = true;
  }
  if (nextActivity === "working") {
    if (previousActivity !== "working") {
      clearNativeSessionAttentionTracking(sessionId);
      persistTerminalSessionRestoreActivity(sessionId, "working");
    }
  } else if (nextActivity === "attention") {
    if (result.enteredAttention) {
      handleNativeSessionEnteredAttention(sessionId, source, attentionEventId);
    } else if (previousActivity !== "attention") {
      persistTerminalSessionRestoreActivity(sessionId, "attention");
    }
  } else if (previousActivity !== "idle") {
    clearNativeSessionAttentionTracking(sessionId);
    persistTerminalSessionRestoreActivity(sessionId, undefined);
  }
  return didChange;
}

async function syncNativeSessionActivityWithGxserver(
  sessionId: string,
  params: Record<string, unknown>,
  source: string,
): Promise<void> {
  const terminalState = terminalStateById.get(sessionId);
  if (!terminalState) {
    return;
  }
  const reference = resolveSidebarSessionReference(sessionId);
  try {
    const result = await gxserverClient.rpc<GxserverUpdateAgentActivityResult>(
      "/api/updateAgentActivity",
      {
        agentName: terminalState.agentName,
        projectId: reference.project.projectId,
        sessionId: reference.sessionId,
        ...params,
      },
    );
    if (applyGxserverSessionActivityResult(sessionId, result, source)) {
      publish();
    }
  } catch (error) {
    appendAgentDetectionDebugLog("nativeSidebar.gxserver.sessionActivityEventFailed", {
      message: error instanceof Error ? error.message : String(error),
      sessionId,
      source,
    });
  }
}

function isValidNativeAgentTerminalTitle(title: string, agentName: string | undefined): boolean {
  return (
    supportsTerminalTitleSessionSync(agentName) &&
    title.trim().length > 1 &&
    /[\p{L}\p{N}]/u.test(title) &&
    getVisibleTerminalTitle(title) !== undefined &&
    !isRejectedNativeResumeTitle(title)
  );
}

type NativePersistedSessionState = {
  agentName?: string;
  agentSessionId?: string;
  agentSessionPath?: string;
  attentionAcknowledgedAt?: string;
  attentionAcknowledgedEventId?: string;
  attentionEventId?: string;
  commandExitCode?: number;
  commandRunId?: string;
  firstUserMessage?: string;
  hasAutoTitleFromFirstPrompt?: boolean;
  lastActivityAt?: string;
  pendingFirstPromptAutoRenamePrompt?: string;
  status?: "attention" | "idle" | "working";
  statusUpdatedAt?: string;
  title?: string;
};

function getNativeGxserverAttentionEventId(
  activity: Pick<GxserverAgentActivityState, "activity" | "attentionEventId" | "lastChangedAt">,
): string | undefined {
  /*
  CDXC:SessionAttention 2026-06-07-03:40:
  Some attention projections, especially stale title-derived working, may not
  carry an explicit attentionEventId. Use the attention transition timestamp as
  the stable event key so those replays are still deduped and locally
  acknowledged without muting future attention events.
  */
  if (activity.activity !== "attention") {
    return undefined;
  }
  return normalizeNativeAttentionEventId(activity.attentionEventId) ??
    normalizeNativeAttentionEventId(activity.lastChangedAt);
}

function getNativePersistedAttentionEventId(
  persistedState: NativePersistedSessionState,
): string | undefined {
  if (persistedState.status !== "attention") {
    return undefined;
  }
  return normalizeNativeAttentionEventId(persistedState.attentionEventId) ??
    normalizeNativeAttentionEventId(persistedState.statusUpdatedAt) ??
    normalizeNativeAttentionEventId(persistedState.lastActivityAt);
}

function getNativeGxserverPresentationAttentionEventId(
  presentation: Pick<GxserverPresentationSession, "activity" | "attention">,
): string | undefined {
  /*
  CDXC:SessionAttention 2026-06-08-13:19:
  Presentation attention rows carry eventId for sound/notification dedupe. Keep enteredAt as a compatibility key for older daemon payloads so macOS can still avoid replaying the same attention transition within one process.
  */
  if (presentation.activity !== "attention") {
    return undefined;
  }
  return normalizeNativeAttentionEventId(presentation.attention?.eventId) ??
    normalizeNativeAttentionEventId(presentation.attention?.enteredAt);
}

function shouldRunNativeGxserverPresentationAttentionSideEffects(reason: string): boolean {
  /*
  CDXC:SessionAttention 2026-06-08-13:19:
  Startup and stream-recovery snapshots can contain sessions that were already green before this client observed them. Only presentation change deltas represent the live edge where macOS should play completion sound and optionally show the attention banner.
  */
  return reason === "delta:sessionPresentationChanged";
}

function readGxserverFirstPromptTitleGenerationRunning(
  runtimeSettings: Record<string, unknown> | undefined,
): boolean | undefined {
  /*
  CDXC:GxserverSessionTitle 2026-06-04-07:11:
  Direct gxserver state-event responses should mutate the legacy native overlay flag only when gxserver includes an explicit first-prompt title status. `running` starts the overlay, terminal statuses clear it, and unrelated missing statuses leave any separate local loading flow alone.
  */
  const status = textValue(runtimeSettings?.gxserverFirstPromptAutoTitleStatus);
  if (!status) {
    return undefined;
  }
  return status === "running";
}

function setNativeManualGeneratedRenameInProgress(sessionId: string, inProgress: boolean): void {
  const terminalState = terminalStateById.get(sessionId);
  if (!terminalState) {
    return;
  }
  const nextValue = inProgress ? true : undefined;
  if (terminalState.manualGeneratedRenameInProgress === nextValue) {
    return;
  }
  /*
  CDXC:SessionRename 2026-06-06-06:51:
  The Cmd+R Generate Name flow should keep the visible title overlay up for the whole rename transaction, not only for the prompt summarization call. Clear this local flag only when the generated title has either failed, applied without an agent command, or the staged agent rename command has been submitted.
  */
  terminalState.manualGeneratedRenameInProgress = nextValue;
  publish();
}

async function pollNativeFirstPromptAutoRenameSessions(): Promise<void> {
  for (const [sessionId, terminalState] of terminalStateById.entries()) {
    if (
      terminalState.lifecycleState !== "running" ||
      isNativeSessionTitleGenerationOverlayActive(terminalState)
    ) {
      continue;
    }
    await processNativeFirstPromptAutoRename(sessionId, terminalState);
  }
}

async function processNativeFirstPromptAutoRename(
  sessionId: string,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
): Promise<void> {
  const session = findSessionRecord(sessionId);
  if (session?.kind !== "terminal" || !terminalState.sessionStateFilePath) {
    logNativeFirstPromptAutoRenameSkipOnce(
      sessionId,
      terminalState,
      "missing-terminal-session-state",
      {
        hasSessionRecord: Boolean(session),
        sessionStateFilePath: terminalState.sessionStateFilePath,
      },
    );
    return;
  }

  const persistedState = await readNativePersistedSessionState(terminalState.sessionStateFilePath);
  const didUpdateCommandPaneActivity = syncNativePersistedCommandPaneActivity(
    sessionId,
    terminalState,
    session,
    persistedState,
  );
  const didUpdatePersistedAgentActivity = syncNativePersistedAgentActivity(
    sessionId,
    terminalState,
    session,
    persistedState,
  );
  const didUpdateAgentSessionState = syncNativePersistedAgentSessionState(
    sessionId,
    terminalState,
    persistedState,
  );
  const didUpdateFirstUserMessage =
    persistedState.firstUserMessage !== undefined &&
    terminalState.firstUserMessage !== persistedState.firstUserMessage;
  if (didUpdateFirstUserMessage) {
    terminalState.firstUserMessage = persistedState.firstUserMessage;
    publish();
  }
  const didUpdateLastActivity =
    persistedState.lastActivityAt !== undefined &&
    terminalState.lastActivityAt !== persistedState.lastActivityAt &&
    isNativeTimestampNewer(persistedState.lastActivityAt, terminalState.lastActivityAt);
  if (didUpdateLastActivity && persistedState.lastActivityAt) {
    /**
     * CDXC:NativeSidebar 2026-04-28-05:14
     * Native terminal hooks write the same lastActivityAt state used by the
     * reference extension. Promote it into live sidebar state so hover
     * timestamps and last-active ordering advance after user prompts.
     *
     * CDXC:SessionLastActive 2026-05-15-14:10
     * Semantic activity transitions can stamp Last Active before the hook file
     * is flushed. Only accept newer persisted values so an older prompt-only
     * hook timestamp cannot move the card backwards after work starts or
     * finishes.
     */
    terminalState.lastActivityAt = persistedState.lastActivityAt;
    persistTerminalSessionLastActivityAt(sessionId, persistedState.lastActivityAt);
    publish();
  }
  if (
    didUpdateCommandPaneActivity ||
    didUpdatePersistedAgentActivity ||
    didUpdateAgentSessionState
  ) {
    publish();
  }
  const firstPromptForGxserver =
    persistedState.pendingFirstPromptAutoRenamePrompt?.trim() ||
    persistedState.firstUserMessage?.trim();
  if (!firstPromptForGxserver) {
    logNativeFirstPromptAutoRenameSkipOnce(sessionId, terminalState, "emptyPrompt", {
      agentName: persistedState.agentName || terminalState.agentName,
      hasPendingPrompt: false,
      sessionStateFilePath: terminalState.sessionStateFilePath,
    });
    return;
  }
  if (terminalState.firstPromptAutoRenameProcessedPrompt === firstPromptForGxserver) {
    logNativeFirstPromptAutoRenameSkipOnce(sessionId, terminalState, "alreadyForwardedToGxserver", {
      agentName: persistedState.agentName || terminalState.agentName,
      hasPendingPrompt: Boolean(persistedState.pendingFirstPromptAutoRenamePrompt),
      sessionStateFilePath: terminalState.sessionStateFilePath,
    });
    return;
  }
  /*
  CDXC:GxserverSessionTitle 2026-06-04-04:05:
  macOS no longer generates first-prompt titles or submits `/rename` from the sidebar poller. Legacy state-file hooks are only an observation bridge; gxserver receives the agent identity and first prompt, then owns eligibility, generation, persistence, and command submission for every client surface.

  CDXC:GxserverSessionTitle 2026-06-04-08:24:
  Settings owns the user's title-generation agent choice, while gxserver owns the title job. Forward the selected built-in/custom command with the observed first prompt so the server can generate names through Cursor, Claude, Codex, Grok Build, or a user command without moving generation back into the sidebar.
  */
  await syncGxserverSessionStateEvent(sessionId, {
    agentName: persistedState.agentName || terminalState.agentName,
    agentSessionId: persistedState.agentSessionId || terminalState.agentSessionId,
    agentSessionPath: persistedState.agentSessionPath || terminalState.agentSessionPath,
    firstPromptTitleGenerationAgent: settings.sessionTitleGenerationAgent,
    firstPromptTitleGenerationCommand: resolveSessionTitleGenerationCommandForGxserver(
      settings.sessionTitleGenerationAgent,
    ),
    firstUserMessage: firstPromptForGxserver,
    title: persistedState.title,
    titleSource: persistedState.title ? "terminal-auto" : undefined,
  });
  terminalState.firstPromptAutoRenameProcessedPrompt = firstPromptForGxserver;
  logNativeFirstPromptAutoRenameSkipOnce(sessionId, terminalState, "forwardedToGxserver", {
    agentName: persistedState.agentName || terminalState.agentName,
    hasPendingPrompt: Boolean(persistedState.pendingFirstPromptAutoRenamePrompt),
    sessionStateFilePath: terminalState.sessionStateFilePath,
  });
}

function resolveSessionTitleGenerationCommandForGxserver(
  agent: SessionTitleGenerationAgent,
): string | undefined {
  if (agent === "custom") {
    return settings.customSessionTitleGenerationCommand.trim();
  }
  return resolveSidebarAgentButtonById(agent)?.command?.trim() || undefined;
}

async function cancelNativeFirstPromptAutoRename(sessionId: string): Promise<void> {
  const terminalState = terminalStateById.get(sessionId);
  if (!terminalState?.firstPromptAutoRenameInProgress) {
    return;
  }
  const reference = resolveSidebarSessionReference(sessionId);
  terminalState.firstPromptAutoRenameActivePrompt = undefined;
  terminalState.firstPromptAutoRenameGenerationId = undefined;
  terminalState.firstPromptAutoRenameInProgress = false;
  terminalState.firstPromptAutoRenameLastLogKey = undefined;
  publish();
  try {
    const result = await gxserverClient.rpc<GxserverCancelFirstPromptAutoTitleResult>(
      "/api/cancelFirstPromptAutoTitle",
      {
        projectId: reference.project.projectId,
        reason: "escape",
        sessionId: reference.sessionId,
      },
    );
    let pendingPromptCleared = false;
    if (result.session.runtimeSettings.gxserverFirstPromptAutoTitleStatus === "cancelled") {
      if (terminalState.sessionStateFilePath) {
        pendingPromptCleared = await clearNativeFirstPromptAutoRenamePendingPrompt(
          terminalState.sessionStateFilePath,
        );
      }
      terminalState.firstPromptAutoRenameInProgress = false;
      publish();
    }
    appendSessionTitleDebugLog("nativeSidebar.firstPromptAutoRename.cancelled", {
      pendingPromptCleared,
      reason: "gxserver-owned",
      sessionId,
    });
  } catch (error) {
    appendSessionTitleGenerationErrorLog("nativeSidebar.firstPromptAutoRename.cancelFailed", {
      error: error instanceof Error ? error.message : String(error),
      sessionId,
    });
  }
}

async function clearNativeFirstPromptAutoRenamePendingPrompt(
  sessionStateFilePath: string,
): Promise<boolean> {
  /*
  CDXC:GxserverSessionTitle 2026-06-07-01:19:
  Escape cancellation should suppress only the currently pending title prompt. Clear the hook-state pending prompt while preserving the first-user-message field so the next UserPromptSubmit hook can queue a retry that includes the original request plus the new user message.
  */
  const command = [
    `/usr/bin/python3 - ${quoteNativeShellArg(sessionStateFilePath)} <<'GHOSTEX_CLEAR_PENDING_FIRST_PROMPT'`,
    "import pathlib",
    "import sys",
    "",
    "keys = [",
    '    "status",',
    '    "statusUpdatedAt",',
    '    "attentionEventId",',
    '    "attentionAcknowledgedAt",',
    '    "attentionAcknowledgedEventId",',
    '    "agent",',
    '    "agentSessionId",',
    '    "agentSessionPath",',
    '    "firstUserMessageBase64",',
    '    "frozenAt",',
    '    "autoTitleFromFirstPrompt",',
    '    "historyBase64",',
    '    "lastActivityAt",',
    '    "pendingFirstPromptAutoRenamePrompt",',
    '    "title",',
    "]",
    "state_path = pathlib.Path(sys.argv[1])",
    "state = {}",
    "try:",
    "    lines = state_path.read_text(encoding='utf-8').splitlines()",
    "except FileNotFoundError:",
    "    print('unchanged')",
    "    sys.exit(0)",
    "for line in lines:",
    "    key, separator, value = line.partition('=')",
    "    if separator:",
    "        state[key] = value",
    "changed = bool(state.get('pendingFirstPromptAutoRenamePrompt', '').strip())",
    "state['pendingFirstPromptAutoRenamePrompt'] = ''",
    "state_path.parent.mkdir(parents=True, exist_ok=True)",
    "temp_path = state_path.with_suffix(state_path.suffix + '.tmp')",
    "temp_path.write_text(''.join(f'{key}={state.get(key, \"\")}\\n' for key in keys), encoding='utf-8')",
    "temp_path.replace(state_path)",
    "print('changed' if changed else 'unchanged')",
    "GHOSTEX_CLEAR_PENDING_FIRST_PROMPT",
  ].join("\n");
  const result = await runNativeProcess("/bin/zsh", ["-lc", command], { timeoutMs: 5_000 });
  if (result.exitCode !== 0) {
    appendSessionTitleGenerationErrorLog("nativeSidebar.firstPromptAutoRename.clearPendingFailed", {
      exitCode: result.exitCode,
      stderrLength: result.stderr.length,
      stdoutLength: result.stdout.length,
    });
    return false;
  }
  return result.stdout.trim() === "changed";
}

async function readNativePersistedSessionState(
  sessionStateFilePath: string,
): Promise<NativePersistedSessionState> {
  const result = await runNativeProcess("/bin/cat", [sessionStateFilePath]);
  if (result.exitCode !== 0 || !result.stdout.trim()) {
    return {};
  }
  return parseNativePersistedSessionState(result.stdout);
}

function syncNativePersistedCommandPaneActivity(
  sessionId: string,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
  session: TerminalSessionRecord,
  persistedState: NativePersistedSessionState,
): boolean {
  if (session.surface !== "commands" || persistedState.status === undefined) {
    return false;
  }

  const commandId = sidebarCommandCommandIdBySessionId.get(sessionId);
  const storedSession = commandId
    ? getNativeSidebarCommandSession(activeProjectId, commandId)
    : undefined;
  if (
    storedSession?.runId &&
    persistedState.commandRunId !== undefined &&
    persistedState.commandRunId !== storedSession.runId
  ) {
    return false;
  }
  if (storedSession?.runId && persistedState.commandRunId === undefined) {
    return false;
  }

  let didChange = false;
  const nextActivity = persistedState.status === "working" ? "working" : "idle";
  if (terminalState.activity !== nextActivity) {
    terminalState.activity = nextActivity;
    persistTerminalSessionRestoreActivity(
      sessionId,
      nextActivity === "working" ? "working" : undefined,
    );
    didChange = true;
  }

  if (persistedState.status !== "idle" || !persistedState.commandRunId) {
    return didChange;
  }

  if (!commandId || !storedSession || storedSession.runId !== persistedState.commandRunId) {
    return didChange;
  }
  if (storedSession.closeOnExit) {
    return didChange;
  }

  const didFail = (persistedState.commandExitCode ?? 0) !== 0;
  postNativeSidebarCommandRunState(commandId, storedSession.runId, didFail ? "error" : "success");
  if (didFail || storedSession.playCompletionSound) {
    playNativeSidebarActionCompletionSound(sessionId);
  }
  sidebarCommandSessionByCommandId.set(createProjectCommandSessionKey(activeProjectId, commandId), {
    ...storedSession,
    runId: undefined,
  });
  return true;
}

function syncNativePersistedAgentActivity(
  sessionId: string,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
  session: TerminalSessionRecord,
  persistedState: NativePersistedSessionState,
): boolean {
  if (session.surface === "commands" || persistedState.status === undefined) {
    return false;
  }

  /*
  CDXC:SharedSessionStatus 2026-06-07-10:06:
  The legacy session-state file is now only a compatibility observation bridge.
  macOS must not locally decide working/attention/idle from `.env`; forward each
  new persisted hook status to gxserver and apply the daemon response so every
  client shares the same status state machine.
  */
  const syncKey = [
    persistedState.status,
    persistedState.statusUpdatedAt ?? persistedState.lastActivityAt ?? "",
    persistedState.agentName ?? terminalState.agentName ?? "",
    persistedState.agentSessionId ?? "",
    persistedState.agentSessionPath ?? "",
    persistedState.title ?? "",
  ].join("\u001f");
  if (nativePersistedAgentHookEventSyncKeyBySessionId.get(sessionId) === syncKey) {
    return false;
  }
  nativePersistedAgentHookEventSyncKeyBySessionId.set(sessionId, syncKey);
  void syncGxserverAgentHookEvent(sessionId, {
    agentName: persistedState.agentName || terminalState.agentName,
    agentSessionId: persistedState.agentSessionId || terminalState.agentSessionId,
    agentSessionPath: persistedState.agentSessionPath || terminalState.agentSessionPath,
    firstUserMessage: persistedState.firstUserMessage,
    status: persistedState.status,
    statusUpdatedAt: persistedState.statusUpdatedAt ?? persistedState.lastActivityAt,
    title: persistedState.title,
  });
  return false;
}

function isNativePersistedWorkingFresh(persistedState: NativePersistedSessionState): boolean {
  const timestamp = getNativeTimestampValue(
    persistedState.statusUpdatedAt ?? persistedState.lastActivityAt,
  );
  return timestamp > 0 && Date.now() - timestamp <= NATIVE_PERSISTED_WORKING_STALE_MS;
}

function isNativePersistedAttentionAcknowledged(
  persistedState: NativePersistedSessionState,
): boolean {
  if (persistedState.status !== "attention") {
    return false;
  }
  if (
    persistedState.attentionEventId &&
    persistedState.attentionAcknowledgedEventId === persistedState.attentionEventId
  ) {
    return true;
  }
  const acknowledgedAt = getNativeTimestampValue(persistedState.attentionAcknowledgedAt);
  const updatedAt = getNativeTimestampValue(
    persistedState.statusUpdatedAt ?? persistedState.lastActivityAt,
  );
  return acknowledgedAt > 0 && updatedAt > 0 && acknowledgedAt >= updatedAt;
}

function isNativePersistedAttentionAcknowledgedForSession(
  sessionId: string,
  persistedState: NativePersistedSessionState,
  attentionEventId: string | undefined,
): boolean {
  return (
    isNativePersistedAttentionAcknowledged(persistedState) ||
    isNativeAttentionEventLocallyAcknowledged(sessionId, attentionEventId)
  );
}

function syncNativePersistedAgentSessionState(
  sessionId: string,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
  persistedState: NativePersistedSessionState,
): boolean {
  const nextAgentSessionId = persistedState.agentSessionId?.trim() || undefined;
  const nextAgentSessionPath = persistedState.agentSessionPath?.trim() || undefined;
  /**
   * CDXC:CursorCLI 2026-05-27-09:06:
   * Cursor transcript paths are stronger evidence than an inherited terminal
   * agent name. Promote them while syncing hook state so sidebar icons and
   * future restore commands converge on Cursor after manual `cursor-agent`
   * starts.
   */
  const nextAgentName =
    (isCursorAgentTranscriptPath(nextAgentSessionPath) ? "cursor" : undefined) ??
    persistedState.agentName?.trim() ??
    undefined;
  let didChange = false;

  if (nextAgentName && terminalState.agentName !== nextAgentName) {
    terminalState.agentName = nextAgentName;
    setTerminalSessionAgentName(sessionId, nextAgentName);
    didChange = true;
  }

  if (
    (nextAgentSessionId !== undefined || nextAgentSessionPath !== undefined) &&
    (terminalState.agentSessionId !== nextAgentSessionId ||
      terminalState.agentSessionPath !== nextAgentSessionPath)
  ) {
    terminalState.agentSessionId = nextAgentSessionId;
    terminalState.agentSessionPath = nextAgentSessionPath;
    setTerminalSessionAgentSessionMetadata(sessionId, {
      agentSessionId: nextAgentSessionId,
      agentSessionPath: nextAgentSessionPath,
    });
    didChange = true;
  }

  if (didChange) {
    /*
    CDXC:GxserverSessionPresentation 2026-05-31-21:10:
    Agent hook state is an observation stream, not a macOS-owned title reducer. Forward captured agent identity/title data to gxserver so restored Codex sessions are named by the shared presentation rules instead of remaining local-only `Terminal Session` rows.
    */
    void syncGxserverSessionStateEvent(sessionId, {
      agentName: nextAgentName,
      agentSessionId: nextAgentSessionId,
      agentSessionPath: nextAgentSessionPath,
      firstUserMessage: persistedState.firstUserMessage,
      title: persistedState.title,
      titleSource: persistedState.title ? "terminal-auto" : undefined,
    });
  }

  return didChange;
}

function getStampNativeSessionSemanticActivityScript(): string {
  return `import os
import pathlib
import sys
from datetime import datetime

state_path = pathlib.Path(sys.argv[1])
timestamp = sys.argv[2]
activity = sys.argv[3]

keys = [
    "status",
    "statusUpdatedAt",
    "attentionEventId",
    "attentionAcknowledgedAt",
    "attentionAcknowledgedEventId",
    "agent",
    "agentSessionId",
    "agentSessionPath",
    "firstUserMessageBase64",
    "frozenAt",
    "autoTitleFromFirstPrompt",
    "historyBase64",
    "lastActivityAt",
    "pendingFirstPromptAutoRenamePrompt",
    "title",
]

state = {}
try:
    lines = state_path.read_text(encoding="utf-8").splitlines()
except FileNotFoundError:
    lines = []

for line in lines:
    key, separator, value = line.partition("=")
    if separator:
        state[key] = value

def parse_timestamp(value):
    if not value:
        return None
    try:
        return datetime.fromisoformat(value.replace("Z", "+00:00"))
    except ValueError:
        return None

existing_timestamp = parse_timestamp(state.get("lastActivityAt", ""))
next_timestamp = parse_timestamp(timestamp)
if next_timestamp is None:
    sys.exit(0)
if existing_timestamp is not None and existing_timestamp > next_timestamp:
    sys.exit(0)

state["status"] = activity
state["statusUpdatedAt"] = timestamp
state["lastActivityAt"] = timestamp
if activity == "attention":
    state["attentionEventId"] = f"{timestamp}:attention"
    state["attentionAcknowledgedAt"] = ""
    state["attentionAcknowledgedEventId"] = ""
elif activity == "working":
    state["attentionAcknowledgedAt"] = timestamp
    state["attentionAcknowledgedEventId"] = state.get("attentionEventId", "")
elif activity == "idle":
    state["attentionAcknowledgedAt"] = timestamp
    state["attentionAcknowledgedEventId"] = state.get("attentionEventId", "")
state_path.parent.mkdir(parents=True, exist_ok=True)
# CDXC:SessionAttention 2026-06-07-03:40:
# Concurrent hook/ack writes for the same session-state file must not share one
# temp path; use a per-process temp file so atomic replace stays race-safe.
temp_path = state_path.with_name(f"{state_path.name}.{os.getpid()}.tmp")
temp_path.write_text("".join(f"{key}={state.get(key, '')}\\n" for key in keys), encoding="utf-8")
temp_path.replace(state_path)
`;
}

function getAcknowledgeNativeSessionAttentionScript(): string {
  return `import os
import pathlib
import sys

state_path = pathlib.Path(sys.argv[1])
timestamp = sys.argv[2]

keys = [
    "status",
    "statusUpdatedAt",
    "attentionEventId",
    "attentionAcknowledgedAt",
    "attentionAcknowledgedEventId",
    "agent",
    "agentSessionId",
    "agentSessionPath",
    "firstUserMessageBase64",
    "frozenAt",
    "autoTitleFromFirstPrompt",
    "historyBase64",
    "lastActivityAt",
    "pendingFirstPromptAutoRenamePrompt",
    "title",
]

state = {}
try:
    lines = state_path.read_text(encoding="utf-8").splitlines()
except FileNotFoundError:
    sys.exit(0)

for line in lines:
    key, separator, value = line.partition("=")
    if separator:
        state[key] = value

if state.get("status") != "attention":
    sys.exit(0)

state["attentionAcknowledgedAt"] = timestamp
state["attentionAcknowledgedEventId"] = state.get("attentionEventId", "")
state_path.parent.mkdir(parents=True, exist_ok=True)
# CDXC:SessionAttention 2026-06-07-03:40:
# Acknowledgement can be requested from focus, restore, and sidebar paths at the
# same time. Use a unique temp path per process so one ack cannot remove another
# ack's pending replace source.
temp_path = state_path.with_name(f"{state_path.name}.{os.getpid()}.tmp")
temp_path.write_text("".join(f"{key}={state.get(key, '')}\\n" for key in keys), encoding="utf-8")
temp_path.replace(state_path)
`;
}

function parseNativePersistedSessionState(rawState: string): NativePersistedSessionState {
  const state: NativePersistedSessionState = {};
  for (const line of rawState.split(/\r?\n/g)) {
    const [key, ...valueParts] = line.split("=");
    const rawValue = valueParts.join("=").trim();
    const value =
      key === "firstUserMessageBase64" || key === "agentSessionPath"
        ? rawValue
        : rawValue.replace(/\s+/g, " ");
    if (!value) {
      continue;
    }
    if (key === "agent") {
      state.agentName = value;
    } else if (key === "attentionAcknowledgedAt") {
      state.attentionAcknowledgedAt = normalizeNativeIsoTimestamp(value);
    } else if (key === "attentionAcknowledgedEventId") {
      state.attentionAcknowledgedEventId = value;
    } else if (key === "attentionEventId") {
      state.attentionEventId = value;
    } else if (key === "agentSessionId") {
      state.agentSessionId = value;
    } else if (key === "agentSessionPath") {
      state.agentSessionPath = value;
    } else if (key === "commandExitCode") {
      const exitCode = Number.parseInt(value, 10);
      if (Number.isFinite(exitCode)) {
        state.commandExitCode = exitCode;
      }
    } else if (key === "commandRunId") {
      state.commandRunId = value;
    } else if (key === "firstUserMessageBase64") {
      state.firstUserMessage = normalizeNativePersistedTextBase64(value);
    } else if (key === "autoTitleFromFirstPrompt") {
      state.hasAutoTitleFromFirstPrompt = value === "1" || /^true$/iu.test(value);
    } else if (key === "lastActivityAt") {
      state.lastActivityAt = normalizeNativeIsoTimestamp(value);
    } else if (key === "pendingFirstPromptAutoRenamePrompt") {
      state.pendingFirstPromptAutoRenamePrompt = value;
    } else if (
      key === "status" &&
      (value === "attention" || value === "idle" || value === "working")
    ) {
      state.status = value;
    } else if (key === "statusUpdatedAt") {
      state.statusUpdatedAt = normalizeNativeIsoTimestamp(value);
    } else if (key === "title") {
      state.title = getVisibleTerminalTitle(value);
    }
  }
  /**
   * CDXC:FirstMessage 2026-04-28-05:48
   * Existing agent sessions may only have the first prompt in the legacy
   * pending auto-title field. Treat that saved prompt as the first message
   * until a newer hook writes the dedicated base64 field.
   */
  state.firstUserMessage = state.firstUserMessage ?? state.pendingFirstPromptAutoRenamePrompt;
  return state;
}

function normalizeNativePersistedTextBase64(value: string): string | undefined {
  try {
    const decodedBytes = Uint8Array.from(atob(value), (char) => char.charCodeAt(0));
    const decodedValue = new TextDecoder().decode(decodedBytes).trim();
    return decodedValue || undefined;
  } catch {
    return undefined;
  }
}

function normalizeNativeIsoTimestamp(value: string): string | undefined {
  const timestamp = Date.parse(value);
  if (!Number.isFinite(timestamp)) {
    return undefined;
  }
  return new Date(timestamp).toISOString();
}

function getNativeTimestampValue(value: string | undefined): number {
  if (!value) {
    return 0;
  }
  const timestamp = Date.parse(value);
  return Number.isFinite(timestamp) ? timestamp : 0;
}

function isNativeTimestampNewer(candidate: string, current: string | undefined): boolean {
  const candidateTimestamp = getNativeTimestampValue(candidate);
  if (candidateTimestamp <= 0) {
    return false;
  }
  return candidateTimestamp > getNativeTimestampValue(current);
}

async function generateNativeSessionTitleFromPrompt(
  cwd: string,
  prompt: string,
  agentId?: string,
): Promise<string> {
  const sourceText = prompt.slice(0, GENERATED_SESSION_TITLE_SOURCE_MAX_LENGTH);
  const generationPrompt = buildNativeSessionTitlePrompt(sourceText);
  const agent = resolveDefaultPromptAgent(agentId);
  if (!agent) {
    throw new Error("Choose a configured prompt agent before generating a session title.");
  }
  const delimiter = `ghostex_SESSION_TITLE_${Date.now().toString(36)}`;
  /**
   * CDXC:SessionTitleSync 2026-04-26-20:27
   * Internal first-prompt title generation summarizes user text only. It must
   * not require the terminal cwd to be a trusted Git repository, because new
   * empty sessions can start at `/` or another non-repo path.
   *
   * CDXC:PromptAgents 2026-05-29-10:53:
   * Generated session titles should use the selected/default prompt agent, not a
   * hardcoded Codex shell command. Manual Rename Generate Name passes its modal
   * choice, while automatic first-prompt titles use Settings' default.
   */
  const command = buildNativePromptGenerationShellCommand({
    agent,
    delimiter,
    prompt: generationPrompt,
    purpose: "session title",
  });
  const result = await runNativePromptGenerationShellCommand(command, { cwd });
  if (result.exitCode !== 0) {
    throw new Error(
      result.stderr.trim() || result.stdout.trim() || `${agent.name} title generation failed.`,
    );
  }
  return parseNativeGeneratedSessionTitleText(result.stdout, agent.name);
}

async function generateNativeWorktreeNameFromPrompt(cwd: string, prompt: string): Promise<string> {
  try {
    return normalizeNativeWorktreeSlug(await generateNativeSessionTitleFromPrompt(cwd, prompt));
  } catch (error) {
    appendSessionTitleGenerationErrorLog("nativeSidebar.worktree.generateName.failed", {
      error: error instanceof Error ? error.message : String(error),
      promptLength: prompt.length,
    });
    return normalizeNativeWorktreeSlug(prompt);
  }
}

function buildNativeSessionTitlePrompt(sourceText: string): string {
  return [
    "Write a concise session title that summarizes the user's text.",
    "Return plain text only.",
    "Rules:",
    "- keep it specific and scannable",
    "- prefer 2 to 4 words when possible",
    `- must be fewer than ${GENERATED_SESSION_TITLE_MAX_LENGTH + 1} characters`,
    "- do not abbreviate with ellipses",
    "- do not use quotes, markdown, or commentary",
    "- do not end with punctuation",
    "- focus on the task, bug, feature, or topic",
    "",
    "User text:",
    sourceText,
    "",
    "Output handling:",
    "- Produce only the final session title.",
    "- Do not wrap the result in backticks.",
    "- Print only the final result to stdout.",
  ].join("\n");
}

function parseNativeGeneratedSessionTitleText(value: string, agentName = "Agent"): string {
  const normalized = normalizeNativeGeneratedText(value);
  const titleLine = normalized.split(/\r?\n/g).find((line) => line.trim().length > 0);
  if (!titleLine) {
    throw new Error(`${agentName} title generation returned an empty session title.`);
  }
  const sanitized = titleLine
    .replace(/^["'`]+|["'`]+$/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/[.…]+$/gu, "");
  if (!sanitized) {
    throw new Error(`${agentName} title generation returned an empty session title.`);
  }
  return clampNativeGeneratedSessionTitleLength(sanitized);
}

function normalizeNativeGeneratedText(value: string): string {
  const trimmed = value.trim();
  const fencedMatch = /^```(?:[a-z0-9_-]+)?\n([\s\S]*?)\n```$/iu.exec(trimmed);
  return fencedMatch ? fencedMatch[1].trim() : trimmed;
}

function clampNativeGeneratedSessionTitleLength(value: string): string {
  if (value.length <= GENERATED_SESSION_TITLE_MAX_LENGTH) {
    return value;
  }
  const words = value.split(" ").filter(Boolean);
  let candidate = "";
  for (const word of words) {
    const nextCandidate = candidate ? `${candidate} ${word}` : word;
    if (nextCandidate.length > GENERATED_SESSION_TITLE_MAX_LENGTH) {
      break;
    }
    candidate = nextCandidate;
  }
  return candidate || value.slice(0, GENERATED_SESSION_TITLE_MAX_LENGTH).trim();
}

function normalizeNativeWorktreeSlug(value: string): string {
  const slug = value
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9._/-]+/g, "-")
    .replace(/[/.]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 48)
    .replace(/^-+|-+$/g, "");
  return slug || `worktree-${Date.now().toString(36)}`;
}

function logNativeFirstPromptAutoRenameSkipOnce(
  sessionId: string,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
  reason: string,
  details?: Record<string, unknown>,
): void {
  const key = `${reason}:${details?.hasPendingPrompt ?? ""}:${details?.currentTitle ?? ""}`;
  if (terminalState.firstPromptAutoRenameLastLogKey === key) {
    return;
  }
  terminalState.firstPromptAutoRenameLastLogKey = key;
  appendSessionTitleDebugLog("nativeSidebar.firstPromptAutoRename.skipped", {
    ...details,
    reason,
    sessionId,
  });
}

function getNativePromptPreview(prompt: string | undefined): string | undefined {
  const normalizedPrompt = prompt?.replace(/\s+/g, " ").trim();
  if (!normalizedPrompt) {
    return undefined;
  }
  return normalizedPrompt.length > 160
    ? `${normalizedPrompt.slice(0, 157).trimEnd()}...`
    : normalizedPrompt;
}

function createProjectSessionListTransitionOrigin(
  project: NativeProject,
): NativeGxserverSessionTransitionOrigin {
  const presentationGroups = createPresentationSidebarGroups(gxserverStartupSnapshot?.presentation)
    ?.filter((group) => group.projectContext?.editor.projectId === project.projectId);
  if (presentationGroups && presentationGroups.length > 0) {
    /*
    CDXC:ProjectSidebarOwnership 2026-06-02-18:48:
    Close/sleep focus remains a macOS current-window decision, but the project-session order must come from the same gxserver presentation groups the sidebar renders. Do not compute the next visible shared session from the old native workspace tree after presentation cutover.
    */
    const sessionIdsByGroup = Object.fromEntries(
      presentationGroups.map((group) => [group.groupId, group.sessions.map((session) => session.sessionId)]),
    );
    const sessionsById = Object.fromEntries(
      presentationGroups.flatMap((group) => group.sessions.map((session) => [session.sessionId, session])),
    );
    const displayLayout = createDisplaySessionLayout({
      sessionIdsByGroup,
      sessionsById,
      sortMode: activeSessionsSortMode,
      workspaceGroupIds: presentationGroups.map((group) => group.groupId),
    });
    return {
      kind: "projectSessionList",
      orderedSessions: displayLayout.groupIds.flatMap((groupId) =>
        (displayLayout.sessionIdsByGroup[groupId] ?? []).flatMap((sidebarSessionId) => {
          const session = sessionsById[sidebarSessionId];
          return session ? [createSessionTransitionOriginEntryFromSidebarSession(session)] : [];
        }),
      ),
    };
  }

  const groups = createProjectedSidebarGroupsForProject(project).filter(
    (group) => group.groupId !== COMMANDS_PANEL_SESSION_GROUP_ID,
  );
  const sessionIdsByGroup = Object.fromEntries(
    groups.map((group) => [group.groupId, group.sessions.map((session) => session.sessionId)]),
  );
  const sessionsById = Object.fromEntries(
    groups.flatMap((group) => group.sessions.map((session) => [session.sessionId, session])),
  );
  const displayLayout = createDisplaySessionLayout({
    sessionIdsByGroup,
    sessionsById,
    sortMode: activeSessionsSortMode,
    workspaceGroupIds: groups.map((group) => group.groupId),
  });
  return {
    kind: "projectSessionList",
    orderedSessions: displayLayout.groupIds.flatMap(
      (groupId) => (displayLayout.sessionIdsByGroup[groupId] ?? []).map(createSessionTransitionOriginEntry),
    ),
  };
}

function createCommandPaneTransitionOrigin(
  project: NativeProject,
  sessionId: string,
): NativeGxserverSessionTransitionOrigin {
  const paneSessionIds =
    findPaneTabGroupSessionIds(project.commandsPanel.paneLayout, sessionId) ??
    project.commandsPanel.sessions.map((session) => session.sessionId);
  return {
    kind: "paneTabGroup",
    orderedSessions: paneSessionIds.map(createSessionTransitionOriginEntry),
  };
}

function createSessionTransitionOriginEntry(sessionId: string): NativeSessionTransitionOriginSession {
  const session = findSessionRecord(sessionId);
  return session?.isSleeping === true
    ? { lifecycleState: "sleeping", sessionId }
    : { sessionId };
}

function createSessionTransitionOriginEntryFromSidebarSession(
  session: SidebarSessionItem,
): NativeSessionTransitionOriginSession {
  const reference = parseCombinedProjectSessionId(session.sessionId);
  const sessionId = reference?.sessionId ?? session.sessionId;
  return session.lifecycleState === "sleeping" || session.isSleeping === true
    ? { lifecycleState: "sleeping", sessionId }
    : { sessionId };
}

function isNativeLiveProjectTransitionCandidate(
  reference: ReturnType<typeof resolveSidebarSessionReference>,
  sessionId: string,
): boolean {
  const session = findSessionRecordInProject(reference.project, sessionId);
  if (session?.isSleeping === true) {
    return false;
  }
  const presentation = findGxserverPresentationSession(reference.project.projectId, sessionId);
  if (presentation) {
    return presentation.lifecycleState === "running";
  }
  if (!session) {
    return false;
  }
  if (session.kind === "terminal") {
    return isSessionLiveFromResourceStates(
      getNativePaneStateForSession(session.sessionId),
      getProviderSessionStateForSession(reference.project.projectId, session),
    );
  }
  return true;
}

function isNativeTransitionCandidateSleeping(
  project: NativeProject,
  candidate: NativeSessionTransitionOriginSession,
): boolean {
  if (candidate.lifecycleState === "sleeping") {
    return true;
  }
  const session = findSessionRecordInProject(project, candidate.sessionId);
  if (session?.isSleeping === true) {
    return true;
  }
  const presentation = findGxserverPresentationSession(project.projectId, candidate.sessionId);
  return presentation?.lifecycleState === "sleeping";
}

function updateGxserverSessionLifecycleOnly(
  projectId: string,
  sessionId: string,
  lifecycleState: "sleeping" | "stopped",
  reason: string,
): void {
  /*
  CDXC:ProjectSidebarOwnership 2026-06-02-10:46:
  tmux, zellij, and off-provider terminal runtime remains native-owned, but the visible project/session inventory is gxserver-owned. When native closes or sleeps those panes, update gxserver lifecycle through /api/updateSession so presentation deltas reconcile without forcing a zmx provider-kill path.
  */
  void gxserverClient
    .rpc("/api/updateSession", {
      lifecycleState,
      projectId,
      sessionId,
    })
    .catch((error) => {
      appendTerminalFocusDebugLog("nativeSidebar.gxserverLifecycleOnly.failed", {
        lifecycleState,
        message: error instanceof Error ? error.message : String(error),
        projectId,
        reason,
        sessionId,
      });
      showNativeMessage("error", error instanceof Error ? error.message : String(error));
    });
}

function applyGxserverSessionTransition(
  reference: ReturnType<typeof resolveSidebarSessionReference>,
  session: SessionRecord | undefined,
  action: "close" | "sleep",
  origin: NativeGxserverSessionTransitionOrigin,
): { focusTarget?: NativeSessionTransitionFocusTarget; handled: boolean } {
  const presentationSession = findGxserverPresentationSession(
    reference.project.projectId,
    reference.sessionId,
  );
  const localProvider = session?.kind === "terminal"
    ? getTerminalProviderSessionInfo(session)?.provider ?? session.sessionPersistenceProvider
    : undefined;
  const canTransitionLocalTerminal = session?.kind === "terminal";
  const canTransitionPresentationSession =
    session === undefined && hasGxserverPresentationZmxRuntime(presentationSession);
  if (
    (!canTransitionLocalTerminal && !canTransitionPresentationSession) ||
    !isCanonicalGxserverProjectSession(reference.project.projectId, reference.sessionId)
  ) {
    return { handled: false };
  }
  const orderedSessions =
    origin.kind === "projectSessionList"
      ? origin.orderedSessions.filter((entry) =>
          isCanonicalGxserverProjectSession(reference.project.projectId, entry.sessionId),
        )
      : origin.orderedSessions.slice();
  if (!orderedSessions.some((entry) => entry.sessionId === reference.sessionId)) {
    orderedSessions.push(createSessionTransitionOriginEntry(reference.sessionId));
  }
  const focusTarget = resolveNativeSessionTransitionFocusTarget({
    action,
    isLiveProjectCandidate: (sessionId) =>
      isNativeLiveProjectTransitionCandidate(reference, sessionId),
    isRemovedSessionFocused: isFocusedSidebarSession(reference.project, reference.sessionId),
    isSleepingCandidate: (candidate) =>
      isNativeTransitionCandidateSleeping(reference.project, candidate),
    origin: { kind: origin.kind, orderedSessions } as NativeGxserverSessionTransitionOrigin,
    projectId: reference.project.projectId,
    removedSessionId: reference.sessionId,
  });

  const useProviderTransition = shouldUseGxserverProviderTransition({
    localProvider,
    presentation: presentationSession,
  });
  if (!useProviderTransition) {
    updateGxserverSessionLifecycleOnly(
      reference.project.projectId,
      reference.sessionId,
      action === "sleep" ? "sleeping" : "stopped",
      action === "sleep" ? "sleepSession" : "closeTerminal",
    );
    appendTerminalFocusDebugLog("nativeSidebar.gxserverLifecycleOnly.applied", {
      action,
      focusTarget,
      originKind: origin.kind,
      projectId: reference.project.projectId,
      sessionId: reference.sessionId,
    });
    return { focusTarget, handled: true };
  }

  try {
    const result = gxserverClient.transitionSessionSync({
      action,
      projectId: reference.project.projectId as never,
      reason: action === "sleep" ? "sleepSession" : "closeTerminal",
      sessionId: reference.sessionId as never,
    });
    rememberGxserverProviderSessionState(result.session);
    appendTerminalFocusDebugLog("nativeSidebar.gxserverTransition.applied", {
      action,
      focusTarget,
      originKind: origin.kind,
      projectId: reference.project.projectId,
      sessionId: reference.sessionId,
    });
    return { focusTarget, handled: true };
  } catch (error) {
    appendTerminalFocusDebugLog("nativeSidebar.gxserverTransition.failed", {
      action,
      message: error instanceof Error ? error.message : String(error),
      originKind: origin.kind,
      projectId: reference.project.projectId,
      sessionId: reference.sessionId,
    });
    return { handled: false };
  }
}

function focusGxserverSessionTransitionTarget(
  target: NativeSessionTransitionFocusTarget | undefined,
  originKind: NativeGxserverSessionTransitionOrigin["kind"],
): void {
  if (!target) {
    return;
  }
  if (originKind === "paneTabGroup" && target.projectId === activeProjectId) {
    handleNativePaneTabSelected(target.sessionId);
    return;
  }
  focusSidebarSession(createCombinedProjectSessionId(target.projectId, target.sessionId));
}

function isCanonicalGxserverProjectSession(projectId: string, sessionId: string): boolean {
  return GXSERVER_CANONICAL_PROJECT_ID_PATTERN.test(projectId) && GXSERVER_CANONICAL_SESSION_ID_PATTERN.test(sessionId);
}

function shouldParkLastProjectSidebarSessionOnClose(
  reference: ReturnType<typeof resolveSidebarSessionReference>,
  presentationSession: GxserverPresentationSession | undefined,
): boolean {
  if (
    !presentationSession ||
    presentationSession.surface !== "workspace" ||
    presentationSession.visibleInSidebarByDefault !== true ||
    isQuickProject(reference.project) ||
    reference.project.isChat === true
  ) {
    return false;
  }
  const visibleWorkspaceSessions = gxserverStartupSnapshot?.presentation?.sessions.filter(
    (session) =>
      session.projectId === reference.project.projectId &&
      session.surface === "workspace" &&
      session.visibleInSidebarByDefault === true &&
      !isGxserverPresentationSessionLocallyHidden(session.projectId, session.sessionId),
  ) ?? [];
  return (
    visibleWorkspaceSessions.length === 1 &&
    visibleWorkspaceSessions[0]?.sessionId === reference.sessionId
  );
}

function closeTerminal(
  sessionId: string,
  options: {
    preservePersistenceSession?: boolean;
    transitionOrigin?: NativeGxserverSessionTransitionOrigin;
  } = {},
): void {
  const reference = resolveSidebarSessionReference(sessionId);
  if (isQuickFileEditorSidebarReference(reference)) {
    removeProject(reference.project.projectId);
    return;
  }
  const sessionRecord = findSessionRecordInProject(reference.project, reference.sessionId);
  const presentationSession = findGxserverPresentationSession(
    reference.project.projectId,
    reference.sessionId,
  );
  const shouldParkLastProjectSession = shouldParkLastProjectSidebarSessionOnClose(
    reference,
    presentationSession,
  );
  /*
  CDXC:LocalFirstSidebar 2026-06-01-20:52:
  Closing the last visible session in a normal project must not remove the project from the sidebar. Park that final session as sleeping through gxserver and keep its presentation row visible, while non-final closes still disappear immediately.
  */
  if (!shouldParkLastProjectSession) {
    hideGxserverPresentationSessionLocally(
      reference.project.projectId,
      reference.sessionId,
      "closeTerminal",
    );
  }
  const terminalState = terminalStateById.get(reference.sessionId);
  const sessionPersistenceProvider =
    terminalState?.sessionPersistenceProvider ??
    (sessionRecord?.kind === "terminal"
      ? sessionRecord.sessionPersistenceProvider
      : presentationSession
        ? "zmx"
        : undefined);
  let shouldStopZmxThroughGxserver =
    options.preservePersistenceSession !== true &&
    (sessionRecord?.kind === "terminal" ||
      (sessionRecord === undefined && presentationSession !== undefined)) &&
    sessionPersistenceProvider === "zmx";
  /*
   * CDXC:GitActionToasts 2026-05-30-06:39:
   * Closing a sidebar session is the user's implicit cancel signal for Git
   * agent workflows. Resolve the persistent running toast here because a
   * manually closed terminal can disappear before the normal done event updates
   * the toast.
   */
  finishGitWorkflowToastForSession(reference.sessionId, "warning", "Session closed");
  if (sessionRecord?.kind === "terminal" && sessionRecord.surface === "commands") {
    const commandTransitionOrigin =
      options.transitionOrigin ?? createCommandPaneTransitionOrigin(reference.project, reference.sessionId);
    const commandTransitionResult = applyGxserverSessionTransition(
      reference,
      sessionRecord,
      "close",
      commandTransitionOrigin,
    );
    if (commandTransitionResult.handled) {
      shouldStopZmxThroughGxserver = false;
    }
    const nativeSessionId = forgetNativeSessionMappingForProject(
      reference.project.projectId,
      reference.sessionId,
    );
    clearNativeSidebarCommandSessionBySessionId(reference.sessionId);
    updateProjectCommandsPanel(reference.project.projectId, (panel) => {
      const sessions = panel.sessions.filter((session) => session.sessionId !== reference.sessionId);
      const paneLayout = removeCommandSessionFromPaneLayout(panel.paneLayout, reference.sessionId);
      return {
        ...panel,
        activeSessionId:
          panel.activeSessionId === reference.sessionId
            ? sessions[0]?.sessionId
            : panel.activeSessionId,
        paneLayout,
        sessions,
      };
    });
    terminalStateById.delete(reference.sessionId);
    forgetRemoteAttachLocalSessionForSidebarSession(
      createCombinedProjectSessionId(reference.project.projectId, reference.sessionId),
    );
    clearSettledTerminalTitleSync(reference.sessionId);
    forgetProviderSessionState(reference.project.projectId, reference.sessionId);
    pendingNativeTerminalStartupTextBySessionId.delete(reference.sessionId);
    nativeActivitySuppressedUntilBySessionId.delete(reference.sessionId);
    nativeWorkingStartedAtBySessionId.delete(reference.sessionId);
    clearNativeSessionAttentionTracking(reference.sessionId);
    nativeAttentionNotificationLastSentAtBySessionId.delete(reference.sessionId);
    clearDelayedSendTimer(reference.sessionId, reference.project.projectId);
    if (shouldStopZmxThroughGxserver) {
      stopGxserverZmxSessionRuntime(reference.project.projectId, reference.sessionId, "closeTerminal");
    }
    postNative({
      preservePersistenceSession: options.preservePersistenceSession || shouldStopZmxThroughGxserver,
      sessionId: nativeSessionId,
      type: "closeTerminal",
    });
    publish();
    focusGxserverSessionTransitionTarget(commandTransitionResult.focusTarget, commandTransitionOrigin.kind);
    return;
  }
  const transitionOrigin = options.transitionOrigin ?? createProjectSessionListTransitionOrigin(reference.project);
  const transitionResult = applyGxserverSessionTransition(
    reference,
    sessionRecord,
    shouldParkLastProjectSession ? "sleep" : "close",
    transitionOrigin,
  );
  if (shouldParkLastProjectSession && !transitionResult.handled) {
    appendSidebarRefreshDebugLog("nativeSidebar.closeSession.lastProjectSessionParkSkipped", {
      projectId: reference.project.projectId,
      requestedSessionId: sessionId,
      resolvedSessionId: reference.sessionId,
    });
    publish();
    return;
  }
  if (transitionResult.handled) {
    shouldStopZmxThroughGxserver = false;
  }
  appendSidebarRefreshDebugLog("nativeSidebar.closeSession.before", {
    project: summarizeSidebarRefreshProject(reference.project),
    requestedSessionId: sessionId,
    resolvedSessionId: reference.sessionId,
    sessionKind: sessionRecord?.kind,
  });
  const shouldRemoveQuickTerminalContainer =
    quickKindForProject(reference.project) === "terminal" && sessionRecord?.kind === "terminal";
  const nativeSessionId = forgetNativeSessionMappingForProject(
    reference.project.projectId,
    reference.sessionId,
  );
  clearNativeSidebarCommandSessionBySessionId(reference.sessionId);
  if (!shouldRemoveQuickTerminalContainer && !shouldParkLastProjectSession) {
    rememberPreviousSession(reference.sessionId, reference.project);
  }
  let shouldRemoveProjectAfterClose = false;
  updateProjectWorkspace(
    reference.project.projectId,
    (workspace) => {
      const nextWorkspace = removeSessionInSimpleWorkspace(workspace, reference.sessionId).snapshot;
      shouldRemoveProjectAfterClose =
        shouldRemoveQuickTerminalContainer && !workspaceHasOpenSessions(nextWorkspace);
      return nextWorkspace;
    },
  );
  terminalStateById.delete(reference.sessionId);
  forgetRemoteAttachLocalSessionForSidebarSession(
    createCombinedProjectSessionId(reference.project.projectId, reference.sessionId),
  );
  clearSettledTerminalTitleSync(reference.sessionId);
  forgetProviderSessionState(reference.project.projectId, reference.sessionId);
  pendingNativeTerminalStartupTextBySessionId.delete(reference.sessionId);
  nativeActivitySuppressedUntilBySessionId.delete(reference.sessionId);
  nativeWorkingStartedAtBySessionId.delete(reference.sessionId);
  clearNativeSessionAttentionTracking(reference.sessionId);
  nativeAttentionNotificationLastSentAtBySessionId.delete(reference.sessionId);
  clearDelayedSendTimer(reference.sessionId, reference.project.projectId);
  if (shouldStopZmxThroughGxserver) {
    stopGxserverZmxSessionRuntime(reference.project.projectId, reference.sessionId, "closeTerminal");
  }
  postNative({
    preservePersistenceSession: options.preservePersistenceSession || shouldStopZmxThroughGxserver,
    sessionId: nativeSessionId,
    type:
      sessionRecord?.kind === "t3" || sessionRecord?.kind === "browser"
        ? "closeWebPane"
        : "closeTerminal",
  });
  if (shouldRemoveProjectAfterClose) {
    /*
     * CDXC:OSIntegration 2026-05-27-11:26:
     * Default-terminal launches create projectless Quick terminal containers for
     * one-off shells. When the last terminal in that container closes, remove
     * the Quick project itself so the sidebar does not keep an empty one-off
     * entry or a closed-session history row.
     */
    removeProject(reference.project.projectId);
    return;
  }
  publish();
  focusGxserverSessionTransitionTarget(transitionResult.focusTarget, transitionOrigin.kind);
  appendSidebarRefreshDebugLog("nativeSidebar.closeSession.afterPublish", {
    nativeSessionId,
    project: summarizeSidebarRefreshProject(),
    requestedSessionId: sessionId,
    resolvedSessionId: reference.sessionId,
    sessionKind: sessionRecord?.kind,
  });
}

function focusTerminal(sessionId: string): void {
  const reference = resolveSidebarSessionReference(sessionId);
  if (isQuickFileEditorSidebarReference(reference)) {
    focusQuickFileEditorProject(reference.project);
    return;
  }
  const focusIntent = beginNativeSidebarFocusIntent(reference, "focusTerminal");
  const sidebarCardFocusTrace = getRecentSidebarCardFocusTrace(reference.sessionId);
  const forceSidebarCardFocusTrace = sidebarCardFocusTrace !== undefined;
  const focusTargetBefore = summarizeSidebarSessionFocusTarget(
    reference.project,
    reference.sessionId,
  );
  const shouldKeepProjectEditorOpen = shouldKeepProjectEditorOpenForSessionFocus(
    reference.project.projectId,
  );
  let sessionRecord = findSessionRecordInProject(reference.project, reference.sessionId);
  if (!sessionRecord) {
    sessionRecord = materializeGxserverPresentationSessionForFocus(
      reference,
      "sidebar-presentation-focus",
      focusIntent,
      shouldKeepProjectEditorOpen ? "projectEditorCompanion" : "workspaceTerminal",
    );
  }
  const terminalState = terminalStateById.get(reference.sessionId);
  if (sessionRecord?.kind === "terminal" || sessionRecord?.kind === "browser") {
    persistNativeSessionLifecycleTimestamps(reference.project.projectId, reference.sessionId, {
      lastAccessedAt: new Date().toISOString(),
    });
  }
  const wasSleepingTerminal = sessionRecord?.kind === "terminal" && sessionRecord.isSleeping === true;
  const sessionPersistenceProvider =
    terminalState?.sessionPersistenceProvider ??
    (sessionRecord?.kind === "terminal" ? sessionRecord.sessionPersistenceProvider : undefined);
  const sessionPersistenceName =
    terminalState?.sessionPersistenceName ??
    (sessionRecord?.kind === "terminal" ? sessionRecord.sessionPersistenceName : undefined);
  if (sessionPersistenceProvider === "zmx") {
    /*
     * CDXC:ZmxPersistenceRecovery 2026-05-21-07:37:
     * Clicking an old zmx-backed sidebar card can focus a Ghostty surface whose
     * provider attach exits immediately because the named zmx session is gone.
     * Record the focus attempt here so the terminalExited handler can turn that
     * fast attach failure into one full reload that recreates zmx and resumes
     * the agent session.
     */
    recentZmxFocusAttachAttemptsBySessionId.set(reference.sessionId, {
      nativeSessionId: nativeSessionIdForProjectSidebarSession(
        reference.project.projectId,
        reference.sessionId,
      ),
      sessionPersistenceName,
      startedAt: Date.now(),
    });
    appendZmxPersistenceFocusReproLog("nativeSidebar.zmxPersistenceFocus.requested", {
      activeProjectId,
      activeSnapshotFocusedSessionId: activeSnapshot().focusedSessionId,
      commandPanelContainsSession: commandPanelContainsSession(reference.project, reference.sessionId),
      focusTargetBefore,
      hasNativeTerminalState: terminalState !== undefined,
      nativeSessionId: nativeSessionIdForProjectSidebarSession(
        reference.project.projectId,
        reference.sessionId,
      ),
      requestedSessionId: sessionId,
      resolvedProjectId: reference.project.projectId,
      resolvedSessionId: reference.sessionId,
      sessionKind: sessionRecord?.kind,
      sessionPersistenceName,
      sessionPersistenceProvider,
      terminalStateSessionPersistenceName: terminalState?.sessionPersistenceName,
      terminalStateSessionPersistenceProvider: terminalState?.sessionPersistenceProvider,
      visibleSessionIdsBefore: activeSnapshot().visibleSessionIds,
    });
  }
  appendTerminalFocusDebugLog("nativeFocusTrace.sidebarFocusTerminalStart", {
    activeProjectId,
    activeSnapshotFocusedSessionId: activeSnapshot().focusedSessionId,
    commandPanelContainsSession: commandPanelContainsSession(reference.project, reference.sessionId),
    focusTargetBefore,
    projectEditorIsOpen:
      projectEditorSurfaceByProjectId.get(reference.project.projectId)?.isOpen === true,
    requestedSessionId: sessionId,
    resolvedProjectId: reference.project.projectId,
    resolvedSessionId: reference.sessionId,
    sidebarCardFocusTrace: summarizeSidebarCardFocusTrace(sidebarCardFocusTrace),
  }, { force: forceSidebarCardFocusTrace });
  if (activeProjectId !== reference.project.projectId) {
    focusProject(reference.project.projectId);
  }
  if (commandPanelContainsSession(reference.project, reference.sessionId)) {
    updateProjectCommandsPanel(reference.project.projectId, (panel) => ({
      ...panel,
      activeSessionId: reference.sessionId,
      isVisible: true,
      paneLayout: setActiveCommandSessionInPaneLayout(panel.paneLayout, reference.sessionId),
    }));
    queueNativeLayoutFocusRequest(reference.sessionId, "focusCommandTerminal");
    if (!terminalStateById.has(reference.sessionId)) {
      const session = findTerminalSessionInProject(reference.project, reference.sessionId);
      if (session) {
        restoreNativeTerminalSession(reference.project, session, "focus-command-session");
      }
    }
    publishSidebarFocusUpdate();
    postNativeFocusTerminalForCurrentIntent(
      nativeSessionIdForProjectSidebarSession(
        reference.project.projectId,
        reference.sessionId,
      ),
      focusIntent,
      "focus-command-terminal",
    );
    return;
  }
  /**
   * CDXC:ProjectEditorCompanion 2026-05-14-09:19:
   * Session-card clicks inside an active embedded VS Code project should select
   * the left native companion pane, not close the editor surface. Keep the
   * project-editor state open and always send the native focus command, even if
   * the clicked session is already the focused sidebar session, so a locally
   * closed companion pane can be restored.
   * CDXC:ProjectEditorCompanion 2026-05-23-13:50:
   * When the companion pane is hidden in Code, Git, or Project view, sidebar
   * session clicks must return to the Agents workarea and focus the clicked
   * session tab instead of retargeting an invisible companion pane.
   * CDXC:ProjectEditorCompanion 2026-05-14-09:40:
   * While VS Code is open, the direct native focus command is the companion
   * retargeting path. Do not enqueue the layout focus request too, because that
   * adds a second native focus/layout pass and can visibly refresh the editor
   * embed even though only the left companion session changed.
   */
  if (!shouldKeepProjectEditorOpen) {
    activateWorkspaceSurfaceForProject(reference.project.projectId);
  }
  const shouldRestoreProjectModeAfterFocus = shouldSessionFocusExitFocusedTabGroup(
    activeProject().workspace,
    reference.sessionId,
  );
  updateActiveProjectWorkspace((workspace) =>
    /*
    CDXC:ProjectEditorCompanion 2026-06-02-19:06:
    Source view session-card clicks retarget the native companion pane through a dedicated host command. Keep the sidebar selection/focus state current, but do not run the Agents-view pane-tab selection helper while the project editor companion is visible because that changes the native workspace layout command and can flicker the VS Code embed.
    */
    shouldKeepProjectEditorOpen
      ? focusSessionInSimpleWorkspace(workspace, reference.sessionId).snapshot
      : focusSidebarSessionInSimpleWorkspace(workspace, reference.sessionId).snapshot,
  );
  const focusTargetAfter = summarizeSidebarSessionFocusTarget(activeProject(), reference.sessionId);
  if (!shouldKeepProjectEditorOpen) {
    queueNativeLayoutFocusRequest(reference.sessionId, "focusTerminal");
  }
  if (shouldRestoreProjectModeAfterFocus) {
    restoreProjectModeAfterSessionFocus(reference.project.projectId);
  }
  /**
   * CDXC:SidebarSessionFocus 2026-05-15-20:01:
   * A session card must activate the existing paneLayout owner for that
   * session. Log the target group, paneLayout membership, tab sibling list,
   * focus request, and before/after visible ids so an unexpected new split can
   * be traced to either stale sidebar state, missing paneLayout membership, or
   * native layout synthesis.
   */
  appendTerminalFocusDebugLog("nativeFocusTrace.sidebarFocusTerminalPostState", {
    activeProjectId,
    focusTargetAfter,
    focusedSessionId: activeSnapshot().focusedSessionId,
    isProjectEditorCompanionPath: shouldKeepProjectEditorOpen,
    nativeSessionId: nativeSessionIdForProjectSidebarSession(
      reference.project.projectId,
      reference.sessionId,
    ),
    requestedSessionId: sessionId,
    resolvedSessionId: reference.sessionId,
    sidebarCardFocusTrace: summarizeSidebarCardFocusTrace(sidebarCardFocusTrace),
    sessionKind: sessionRecord?.kind,
    visibleSessionIds: activeSnapshot().visibleSessionIds,
  }, { force: forceSidebarCardFocusTrace });
  if (sessionRecord?.kind === "t3" || sessionRecord?.kind === "browser") {
    if (!nativeSessionIdBySidebarSessionId.has(reference.sessionId)) {
      if (sessionRecord.kind === "t3") {
        restoreNativeT3Session(activeProject(), sessionRecord, "focus-restored-session");
      } else {
        restoreNativeBrowserSession(activeProject(), sessionRecord, "focus-restored-session");
      }
    }
    if (shouldKeepProjectEditorOpen) {
      publishSidebarFocusUpdate();
      postNativeFocusProjectEditorCompanionForCurrentIntent(
        nativeSessionIdForProjectSidebarSession(
          reference.project.projectId,
          reference.sessionId,
        ),
        focusIntent,
        "focus-project-editor-companion-web-pane",
      );
      return;
    }
    postNative({
      sessionId: nativeSessionIdForProjectSidebarSession(
        reference.project.projectId,
        reference.sessionId,
      ),
      type: "focusWebPane",
    });
    publishSidebarFocusUpdate();
    return;
  }
  const session = findTerminalSession(reference.sessionId);
  /**
   * CDXC:SessionSleep 2026-04-27-09:09
   * Sleeping a native Ghostty session destroys its terminal surface. Activating
   * that card must first recreate the terminal and run the agent resume command
   * before sending native focus, matching agent-tiler's detached-session wake.
   * CDXC:CrashRootCause 2026-05-04-11:53
   * Restored sleeping terminals mount inactive, so the focused sidebar snapshot
   * must be published to native before the explicit focus command. This keeps
   * restore ordering aligned with new terminal launches and prevents a
   * previous+restored active-surface window during rapid card clicks.
   */
  let restoredSleepingTerminal = false;
  if (session && (wasSleepingTerminal || !terminalStateById.has(reference.sessionId))) {
    if (wasSleepingTerminal) {
      clearStaleTerminalRuntimeStateBeforeWake(
        reference.project.projectId,
        reference.sessionId,
        "focus-sleeping-session",
      );
    }
    const providerSessionState = getProviderSessionStateForSession(
      reference.project.projectId,
      session,
    );
    restoreNativeTerminalSession(
      activeProject(),
      session,
      providerSessionState === "exists"
        ? "focus-live-provider-session"
        : "focus-sleeping-session",
      shouldKeepProjectEditorOpen
        ? {
            focusAfterReady: {
              focusIntent,
              reason: "focus-project-editor-companion-restored-terminal-ready",
              surface: "projectEditorCompanion",
            },
          }
        : undefined,
    );
    restoredSleepingTerminal = true;
  }
  if (sessionPersistenceProvider === "zmx") {
    appendZmxPersistenceFocusReproLog("nativeSidebar.zmxPersistenceFocus.preNativeFocus", {
      activeProjectId,
      focusedSessionId: activeSnapshot().focusedSessionId,
      focusTargetAfter,
      isProjectEditorCompanionPath: shouldKeepProjectEditorOpen,
      nativeSessionId: nativeSessionIdForProjectSidebarSession(
        reference.project.projectId,
        reference.sessionId,
      ),
      restoredSleepingTerminal,
      resolvedProjectId: reference.project.projectId,
      resolvedSessionId: reference.sessionId,
      sessionPersistenceName,
      sessionPersistenceProvider,
      visibleSessionIdsAfterState: activeSnapshot().visibleSessionIds,
    });
  }
  acknowledgeNativeTerminalAttention(reference.sessionId, "sidebar-focus");
  if (restoredSleepingTerminal) {
    publishSidebarFocusUpdate();
    if (shouldKeepProjectEditorOpen) {
      /*
       * CDXC:ProjectEditorCompanion 2026-06-05-03:59:
       * Restored Project/Kanban companion terminals focus from terminalReady,
       * not from this click turn. Sending focus here can race AppKit surface
       * registration and be skipped because the terminal is not yet eligible
       * for the companion pane.
       */
      return;
    }
    postNativeFocusTerminalForCurrentIntent(
      nativeSessionIdForProjectSidebarSession(
        reference.project.projectId,
        reference.sessionId,
      ),
      focusIntent,
      "focus-restored-sleeping-terminal",
    );
    return;
  }
  if (shouldKeepProjectEditorOpen) {
    publishSidebarFocusUpdate();
    postNativeFocusProjectEditorCompanionForCurrentIntent(
      nativeSessionIdForProjectSidebarSession(
        reference.project.projectId,
        reference.sessionId,
      ),
      focusIntent,
      "focus-project-editor-companion-direct",
    );
    return;
  }
  postNativeFocusTerminalForCurrentIntent(
    nativeSessionIdForProjectSidebarSession(
      reference.project.projectId,
      reference.sessionId,
    ),
    focusIntent,
    "focus-terminal-direct",
  );
  publishSidebarFocusUpdate();
}

function recoveredZmxAttachExitKey(
  nativeSessionId: string,
  sessionId: string,
  sessionPersistenceName: string | undefined,
): string {
  return `${nativeSessionId}::${sessionId}::${sessionPersistenceName ?? ""}`;
}

function handleRecentZmxAttachExitWithFullReload(
  sidebarSessionId: string,
  nativeSessionId: string,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
  exitCode: number | undefined,
): boolean {
  if (terminalState.sessionPersistenceProvider !== "zmx") {
    return false;
  }
  const attempt = recentZmxFocusAttachAttemptsBySessionId.get(sidebarSessionId);
  if (!attempt) {
    return false;
  }
  const now = Date.now();
  const elapsedMs = now - attempt.startedAt;
  if (
    attempt.nativeSessionId !== nativeSessionId ||
    elapsedMs < 0 ||
    elapsedMs > zmxFocusAttachExitRecoveryWindowMs
  ) {
    return false;
  }
  recentZmxFocusAttachAttemptsBySessionId.delete(sidebarSessionId);
  const reference = resolveSidebarSessionReference(sidebarSessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  const recoveryKey = recoveredZmxAttachExitKey(
    nativeSessionId,
    reference.sessionId,
    terminalState.sessionPersistenceName ?? attempt.sessionPersistenceName,
  );
  if (!session || !canRestoreNativeTerminalSession(session)) {
    appendZmxPersistenceFocusReproLog("nativeSidebar.zmxPersistenceFocus.fastExitRecoverySkipped", {
      canRestore: session ? canRestoreNativeTerminalSession(session) : false,
      elapsedMs,
      exitCode,
      hasSession: Boolean(session),
      nativeSessionId,
      recoveryKey,
      sessionId: reference.sessionId,
      sessionPersistenceName: terminalState.sessionPersistenceName ?? attempt.sessionPersistenceName,
    });
    return false;
  }
  if (recoveredZmxAttachExitKeys.has(recoveryKey)) {
    appendZmxPersistenceFocusReproLog("nativeSidebar.zmxPersistenceFocus.fastExitRecoverySkipped", {
      elapsedMs,
      exitCode,
      nativeSessionId,
      reason: "already-recovered",
      recoveryKey,
      sessionId: reference.sessionId,
      sessionPersistenceName: terminalState.sessionPersistenceName ?? attempt.sessionPersistenceName,
    });
    return false;
  }
  recoveredZmxAttachExitKeys.add(recoveryKey);
  appendZmxPersistenceFocusReproLog("nativeSidebar.zmxPersistenceFocus.fastExitFullReload", {
    elapsedMs,
    exitCode,
    nativeSessionId,
    recoveryKey,
    sessionId: reference.sessionId,
    sessionPersistenceName: terminalState.sessionPersistenceName ?? attempt.sessionPersistenceName,
  });
  restartNativeSession(createCombinedProjectSessionId(reference.project.projectId, reference.sessionId));
  return true;
}

function focusSidebarSession(sessionId: string): void {
  focusTerminal(sessionId);
}

function focusSidebarSessionMode(sessionId: string): void {
  const reference = resolveSidebarSessionReference(sessionId);
  if (commandPanelContainsSession(reference.project, reference.sessionId)) {
    focusTerminal(sessionId);
    return;
  }
  const activeGroup =
    reference.project.workspace.groups.find(
      (group) => group.groupId === reference.project.workspace.activeGroupId,
    ) ?? reference.project.workspace.groups[0];
  const snapshot = activeGroup?.snapshot;
  /**
   * CDXC:SessionFocusMode 2026-05-23-14:35:
   * Double-clicking a native pane tab while Focus mode is already active for that tab group must exit Focus and restore the prior Code/Git/Project surface instead of re-entering Focus.
   *
   * CDXC:SessionFocusMode 2026-05-28-09:41:
   * Focus mode is a split-pane zoom. When the zoom is already active, a second Focus request for the focused pane group is an automatic exit rather than another focus transition.
   */
  if (
    snapshot &&
    snapshot.visibleCount === 1 &&
    snapshot.fullscreenRestoreVisibleCount !== undefined
  ) {
    const focusedTabSessionIds = getFocusedWorkspaceTabSessionIds(snapshot);
    if (focusedTabSessionIds.includes(reference.sessionId)) {
      updateProjectWorkspace(
        reference.project.projectId,
        (workspace) => toggleFullscreenSessionInSimpleWorkspace(workspace),
      );
      restoreProjectModeAfterSessionFocus(reference.project.projectId);
      publish();
      focusTerminal(sessionId);
      return;
    }
  }
  if (activeProjectId !== reference.project.projectId) {
    focusProject(reference.project.projectId);
  }
  rememberProjectModeBeforeSessionFocus(reference.project.projectId);
  activateWorkspaceSurfaceForProject(reference.project.projectId);
  updateProjectWorkspace(
    reference.project.projectId,
    (workspace) =>
      focusSessionExclusivelyInSimpleWorkspace(workspace, reference.sessionId).snapshot,
  );
  appendTerminalFocusDebugLog("nativeSidebar.sessionFocusMode.applied", {
    activeProjectId,
    projectId: reference.project.projectId,
    sessionId: reference.sessionId,
    targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(
      activeProject().workspace,
      activeProject().workspace.activeGroupId,
    ),
  });
  focusTerminal(sessionId);
}

function runNativeHotkeyAction(actionId: ghostexHotkeyActionId, source: "dom" | "native"): void {
  const action = getghostexHotkeyActionById(actionId);
  if (!action) {
    logNativeHotkeyDebug("nativeHotkeys.actionMissing", { actionId });
    return;
  }
  logNativeHotkeyDebug("nativeHotkeys.actionStart", {
    actionId,
    kind: action.kind,
  });

  /**
   * CDXC:Hotkeys 2026-04-28-05:20
   * App-level hotkeys execute against the same native sidebar state mutations
   * as clicks and CLI commands. Do the real command directly here so terminal
   * focus shortcuts do not depend on a hidden fallback UI path.
   */
  switch (action.kind) {
    case "createSession":
      createNativeSessionInCurrentContext();
      return;
    case "focusAdjacentGroup":
      focusAdjacentNativeHotkeyGroup(action.direction);
      return;
    case "focusDirection":
      focusNativeHotkeyDirection(action.direction);
      return;
    case "focusGroup":
      focusNativeHotkeyGroupByIndex(action.groupIndex);
      return;
    case "focusSessionSlot":
      if (action.slotNumber === -1) {
        focusAdjacentNativeHotkeySession(-1);
        return;
      }
      if (action.slotNumber === 0) {
        focusAdjacentNativeHotkeySession(1);
        return;
      }
      focusNativeHotkeySessionSlot(action.slotNumber);
      return;
    case "focusedPaneAction":
      /**
       * CDXC:CommandPalette 2026-05-17-01:32:
       * Command-palette pane actions and their hotkeys should execute through
       * the same focused-session titlebar handler as the native pane menu, so
       * browser, split, merge, fork, reload, delay, and pop-out behavior stays
       * scoped to the user's current pane.
       */
      runFocusedPaneHotkeyAction(action.focusedPaneAction);
      return;
    case "moveSidebar":
      moveSidebarToOtherSide();
      return;
    case "openCommandPalette":
      /**
       * CDXC:CommandPalette 2026-05-15-20:38:
       * Native Cmd+K should reveal the full-window app-modal command palette
       * from terminal focus without opening the Commands panel or depending on
       * a sidebar-local DOM render path.
       */
      openAppModal({ modal: "commandPalette", type: "open" });
      return;
    case "openCommandsPanel":
      if (source === "native") {
        toggleFocusedCommandsPanelForActiveProject();
        return;
      }
      openCommandsPanelForActiveProject();
      return;
    case "openSettings":
      openAppModal({ modal: "settings", type: "open" });
      return;
    case "renameActiveSession":
      promptRenameFocusedNativeHotkeySession();
      return;
    case "runActionSlot":
      /**
       * CDXC:ActionsHotkeys 2026-05-17-01:18:
       * Action hotkeys are positional launchers for the current Actions list.
       * Resolve the command at dispatch time so reordering actions changes
       * Ctrl+Shift+N behavior without rewriting saved hotkey settings.
       */
      runNativeSidebarCommandSlot(action.slotNumber);
      return;
    case "setViewMode":
      updateActiveProjectWorkspace((workspace) =>
        setViewModeInSimpleWorkspace(workspace, action.viewMode),
      );
      publish();
      return;
    case "switchWorkareaView":
      switchNativeWorkareaView(action.view);
      return;
    case "splitFocusedPane":
      splitFocusedNativePane(action.direction);
      return;
  }
}

function switchNativeWorkareaView(view: "agents" | "github" | "kanban" | "source"): void {
  /**
   * CDXC:Hotkeys 2026-06-06-04:36:
   * Option+1..4 must switch the active project workarea using the same route as the titlebar segmented control: Agents, Source, GitHub, Kanban. Reuse those handlers so hotkeys preserve project-editor sleep, focus, and validation behavior.
   */
  switch (view) {
    case "agents":
      openAgentsModeFromTitlebar();
      return;
    case "source":
      openActiveProjectEditorFromTitlebar();
      return;
    case "github":
      void openGitHubProjectFromTitlebar();
      return;
    case "kanban":
      openTasksPlaceholderFromTitlebar();
      return;
  }
}

function runFocusedPaneHotkeyAction(action: ghostexFocusedPaneAction): void {
  const focusedSessionId = activeSnapshot().focusedSessionId;
  if (!focusedSessionId) {
    logNativeHotkeyDebug("nativeHotkeys.focusedPaneActionNoFocusedSession", { action });
    return;
  }
  if (action === "popOutPane") {
    const session = findSessionRecord(focusedSessionId);
    handleNativeTerminalTitleBarAction(
      focusedSessionId,
      session?.isPoppedOut === true ? "restorePopOut" : "popOut",
    );
    return;
  }
  handleNativeTerminalTitleBarAction(focusedSessionId, focusedPaneHotkeyActionToTitlebarAction(action));
}

function focusedPaneHotkeyActionToTitlebarAction(
  action: Exclude<ghostexFocusedPaneAction, "popOutPane">,
): NativeTerminalTitleBarAction {
  switch (action) {
    case "openBrowserPane":
      return "openBrowser";
    case "rotatePanesClockwise":
      return "rotatePanesClockwise";
    case "mergeAllTabs":
      return "mergeAllTabs";
    case "delayedSend":
      return "delayedSend";
    case "forkSession":
      return "fork";
    case "reloadSession":
      return "reload";
  }
}

function runNativeSidebarCommandSlot(slotNumber: number): void {
  const command = commands[slotNumber - 1];
  if (!command) {
    logNativeHotkeyDebug("nativeHotkeys.actionSlotMissing", {
      slotNumber: String(slotNumber),
      totalCommands: String(commands.length),
    });
    return;
  }
  runNativeSidebarCommand(command);
}

function getMatchingNativeHotkeyActionId(
  hotkeyText: string | undefined,
  now: number,
  source: "dom" | "native",
): ghostexHotkeyActionId | undefined {
  if (!hotkeyText) {
    pendingHotkeyPrefix = undefined;
    return undefined;
  }
  const normalizedHotkeys = settings.hotkeys;
  const sequence = pendingHotkeyPrefix ? `${pendingHotkeyPrefix} ${hotkeyText}` : hotkeyText;
  const matchedActionId = getghostexHotkeyActionIdForKey(normalizedHotkeys, sequence);
  if (matchedActionId) {
    logNativeHotkeyDebug("nativeHotkeys.match", {
      actionId: matchedActionId,
      hotkeyText,
      sequence,
      source,
    });
    pendingHotkeyPrefix = undefined;
    return matchedActionId;
  }

  const hasPrefix = Object.values(normalizedHotkeys).some((value) =>
    value?.startsWith(`${hotkeyText} `),
  );
  if (hasPrefix) {
    logNativeHotkeyDebug("nativeHotkeys.prefixStarted", {
      hotkeyText,
      source,
    });
  } else if (hotkeyText.includes("+")) {
    logNativeHotkeyDebug("nativeHotkeys.noMatch", {
      configuredCount: Object.keys(normalizedHotkeys).length,
      hotkeyText,
      pendingHotkeyPrefix,
      sequence,
      source,
    });
  }
  pendingHotkeyPrefix = hasPrefix ? hotkeyText : undefined;
  window.setTimeout(() => {
    if (pendingHotkeyPrefix === hotkeyText && Date.now() - now >= 1_000) {
      logNativeHotkeyDebug("nativeHotkeys.prefixExpired", {
        hotkeyText,
        source,
      });
      pendingHotkeyPrefix = undefined;
    }
  }, 1_000);
  return undefined;
}

function keyboardEventToNativeHotkeyText(event: KeyboardEvent): string | undefined {
  const key = normalizeNativeHotkeyKey(event.key);
  if (!key) {
    return undefined;
  }
  const parts = [
    event.metaKey ? "cmd" : "",
    event.ctrlKey ? "ctrl" : "",
    event.altKey ? "alt" : "",
    event.shiftKey ? "shift" : "",
    key,
  ].filter(Boolean);
  return normalizeHotkeyText(parts.length > 1 ? parts.join("+") : key);
}

function normalizeNativeHotkeyKey(key: string): string | undefined {
  if (key.length === 1) {
    return key.toLowerCase();
  }
  switch (key) {
    case "ArrowUp":
      return "up";
    case "ArrowRight":
      return "right";
    case "ArrowDown":
      return "down";
    case "ArrowLeft":
      return "left";
    case "Escape":
    case "Meta":
    case "Control":
    case "Alt":
    case "Shift":
      return undefined;
    default:
      return key.toLowerCase();
  }
}

function isNativeHotkeyEditableTarget(target: EventTarget | null): boolean {
  if (target instanceof Element && target.closest("[data-hotkey-recorder='true']")) {
    /**
     * CDXC:Hotkeys 2026-05-10-12:06
     * Rebinding must let the recorder own Command/Option chords that are already
     * assigned globally. Do not dispatch app actions from inside recorder chrome.
     */
    return true;
  }
  return (
    target instanceof HTMLInputElement ||
    target instanceof HTMLTextAreaElement ||
    target instanceof HTMLSelectElement ||
    (target instanceof HTMLElement && target.isContentEditable)
  );
}

function isNativeHotkeyCandidate(event: KeyboardEvent, hotkeyText: string | undefined): boolean {
  return Boolean(hotkeyText && (event.metaKey || event.ctrlKey || event.altKey || event.shiftKey));
}

function isNativeSessionNavigationHotkeyActionId(
  actionId: ghostexHotkeyActionId,
): boolean {
  return actionId === "focusNextSession" || actionId === "focusPreviousSession";
}

function isNativeSessionNavigationHotkeyText(hotkeyText: string | undefined): boolean {
  return (
    hotkeyText === "cmd+tab" ||
    hotkeyText === "cmd+shift+tab" ||
    hotkeyText === "cmd+shift+[" ||
    hotkeyText === "cmd+shift+]"
  );
}

function isNativeCommandArrowHotkey(
  event: KeyboardEvent,
  hotkeyText: string | undefined,
): boolean {
  return (
    event.metaKey &&
    !event.ctrlKey &&
    !event.altKey &&
    (hotkeyText === "cmd+left" || hotkeyText === "cmd+right")
  );
}

function describeNativeHotkeyTarget(target: EventTarget | null): string {
  if (!(target instanceof Element)) {
    return target === null ? "null" : typeof target;
  }
  const tagName = target.tagName.toLowerCase();
  const role = target.getAttribute("role");
  const dataSlot = target.getAttribute("data-slot");
  return [tagName, role ? `role=${role}` : "", dataSlot ? `slot=${dataSlot}` : ""]
    .filter(Boolean)
    .join(" ");
}

function focusNativeHotkeyDirection(direction: SessionGridDirection): void {
  const snapshotBefore = activeSnapshot();
  const groupBefore = activeWorkspaceGroup();
  const shouldTraceCommandArrow = direction === "left" || direction === "right";
  if (shouldTraceCommandArrow) {
    logNativeHotkeyDebug("nativeHotkeys.commandArrowFocusDirectionStart", {
      activeGroupId: groupBefore.groupId,
      direction,
      focusedSessionId: snapshotBefore.focusedSessionId,
      paneLayout: summarizeSessionPaneLayout(snapshotBefore.paneLayout),
      sessionIds: snapshotBefore.sessions.map((session) => session.sessionId),
      visibleSessionIds: snapshotBefore.visibleSessionIds,
    });
  }
  if (focusProjectEditorCompanionHotkeyDirection(direction, snapshotBefore)) {
    return;
  }
  const result = focusVisibleDirectionInSimpleWorkspace(activeProject().workspace, direction);
  const resultGroup = result.snapshot.groups.find((group) => group.groupId === groupBefore.groupId);
  const resultSnapshot = resultGroup?.snapshot ?? snapshotBefore;
  if (!result.changed) {
    logNativeHotkeyDebug(
      shouldTraceCommandArrow
        ? "nativeHotkeys.commandArrowFocusDirectionUnchanged"
        : "nativeHotkeys.focusDirectionUnchanged",
      {
        direction,
        focusedSessionId: snapshotBefore.focusedSessionId,
        paneLayout: summarizeSessionPaneLayout(snapshotBefore.paneLayout),
        visibleSessionIds: snapshotBefore.visibleSessionIds,
      },
    );
    return;
  }
  if (shouldTraceCommandArrow) {
    logNativeHotkeyDebug("nativeHotkeys.commandArrowFocusDirectionResolved", {
      activeGroupId: groupBefore.groupId,
      direction,
      focusedSessionIdAfter: resultSnapshot.focusedSessionId,
      focusedSessionIdBefore: snapshotBefore.focusedSessionId,
      paneLayoutAfter: summarizeSessionPaneLayout(resultSnapshot.paneLayout),
      paneLayoutBefore: summarizeSessionPaneLayout(snapshotBefore.paneLayout),
      sessionIdsAfter: resultSnapshot.sessions.map((session) => session.sessionId),
      sessionIdsBefore: snapshotBefore.sessions.map((session) => session.sessionId),
      visibleSessionIdsAfter: resultSnapshot.visibleSessionIds,
      visibleSessionIdsBefore: snapshotBefore.visibleSessionIds,
    });
  }
  /**
   * CDXC:PaneFocus 2026-05-28-14:29:
   * Directional focus hotkeys should move focus only among currently visible macOS pane sessions.
   * Apply the visible-only workspace mutation directly so Cmd+Alt+Arrow cannot reveal hidden sessions or change visibleSessionIds.
   */
  updateActiveProjectWorkspace(() => result.snapshot);
  publish();
  const focusedSessionId = activeSnapshot().focusedSessionId;
  if (focusedSessionId) {
    if (shouldTraceCommandArrow) {
      logNativeHotkeyDebug("nativeHotkeys.commandArrowFocusSidebarSession", {
        direction,
        focusedSessionId,
      });
    }
    focusSidebarSession(focusedSessionId);
  }
}

function focusProjectEditorCompanionHotkeyDirection(
  direction: SessionGridDirection,
  snapshot: SessionGridSnapshot,
): boolean {
  const project = activeProject();
  const surfaceState = projectEditorSurfaceByProjectId.get(project.projectId);
  if (surfaceState?.isOpen !== true || surfaceState.isSleeping === true) {
    return false;
  }

  if (direction === "up" || direction === "down") {
    logNativeHotkeyDebug("nativeHotkeys.projectEditorCompanionDirectionIgnored", {
      activeProjectEditorId: surfaceState.nativeEditorId,
      direction,
      mode: surfaceState.mode,
      projectId: project.projectId,
    });
    return true;
  }

  /**
   * CDXC:PaneFocus 2026-05-29-05:25:
   * In Code, Git, and Project modes, directional focus treats the companion agent pane as the left target and the project-editor workarea as the right target.
   * Left/right should move keyboard focus between those two native regions without changing visibleSessionIds; up/down are consumed because the editor companion layout is horizontal only.
   */
  if (direction === "right") {
    postNative({
      projectId: surfaceState.nativeEditorId,
      type: "focusProjectEditorPane",
    });
    logNativeHotkeyDebug("nativeHotkeys.projectEditorCompanionFocusEditor", {
      activeProjectEditorId: surfaceState.nativeEditorId,
      mode: surfaceState.mode,
      projectId: project.projectId,
    });
    return true;
  }

  const focusedSessionId = snapshot.focusedSessionId;
  const focusedSession =
    focusedSessionId && snapshot.visibleSessionIds.includes(focusedSessionId)
      ? snapshot.sessions.find((session) => session.sessionId === focusedSessionId)
      : undefined;
  if (
    !focusedSession ||
    focusedSession.isSleeping === true ||
    project.projectEditorCompanionPaneHidden === true
  ) {
    logNativeHotkeyDebug("nativeHotkeys.projectEditorCompanionFocusAgentMissing", {
      activeProjectEditorId: surfaceState.nativeEditorId,
      companionHidden: project.projectEditorCompanionPaneHidden === true,
      focusedSessionId: focusedSessionId ?? "",
      hasFocusedVisibleSession: focusedSession !== undefined,
      mode: surfaceState.mode,
      projectId: project.projectId,
    });
    return true;
  }

  postNative({
    sessionId: nativeSessionIdForProjectSidebarSession(
      project.projectId,
      focusedSession.sessionId,
    ),
    type: focusedSession.kind === "terminal" ? "focusTerminal" : "focusWebPane",
  });
  logNativeHotkeyDebug("nativeHotkeys.projectEditorCompanionFocusAgent", {
    activeProjectEditorId: surfaceState.nativeEditorId,
    focusedSessionId: focusedSession.sessionId,
    mode: surfaceState.mode,
    projectId: project.projectId,
    sessionKind: focusedSession.kind,
  });
  return true;
}

function focusNativeHotkeyGroupByIndex(groupIndex: number): void {
  const targetGroup = activeProject().workspace.groups[groupIndex - 1];
  if (!targetGroup) {
    logNativeHotkeyDebug("nativeHotkeys.groupIndexMissing", {
      groupCount: activeProject().workspace.groups.length,
      groupIndex,
    });
    return;
  }
  focusNativeHotkeyGroup(targetGroup.groupId, "index");
}

function focusAdjacentNativeHotkeyGroup(direction: -1 | 1): void {
  const groups = activeProject().workspace.groups;
  if (groups.length === 0) {
    logNativeHotkeyDebug("nativeHotkeys.adjacentGroupMissing", { direction });
    return;
  }
  const activeGroupIndex = Math.max(
    0,
    groups.findIndex((group) => group.groupId === activeProject().workspace.activeGroupId),
  );
  const nextIndex = (activeGroupIndex + direction + groups.length) % groups.length;
  focusNativeHotkeyGroup(groups[nextIndex]!.groupId, direction > 0 ? "next" : "previous");
}

function focusNativeHotkeyGroup(groupId: string, source: "index" | "next" | "previous"): void {
  updateActiveProjectWorkspace(
    (workspace) => focusGroupInSimpleWorkspace(workspace, groupId).snapshot,
  );
  publish();
  const focusedSessionId = activeSnapshot().focusedSessionId;
  if (focusedSessionId) {
    focusSidebarSession(focusedSessionId);
  }
  logNativeHotkeyDebug("nativeHotkeys.groupFocused", { groupId, source });
}

function focusNativeHotkeySessionSlot(slotNumber: number): void {
  const sessionIds = getRenderedNativeHotkeySidebarSessionSlotIds();
  const sessionId = sessionIds[slotNumber - 1];
  if (sessionId) {
    focusSidebarSession(sessionId);
    return;
  }
  logNativeHotkeyDebug("nativeHotkeys.sessionSlotMissing", {
    activeSessionsSortMode,
    sessionCount: sessionIds.length,
    slotNumber,
  });
}

function focusAdjacentNativeHotkeySession(direction: -1 | 1): void {
  const slots = getRenderedNativeHotkeySidebarSessionSlots();
  if (slots.length === 0) {
    logNativeHotkeyDebug("nativeHotkeys.adjacentSessionMissing", { direction });
    return;
  }
  const focusedIndex = slots.findIndex((slot) =>
    isNativeHotkeyFocusedSessionId(slot.sessionId),
  );
  /**
   * CDXC:Hotkeys 2026-05-11-09:26
   * Cmd+[ and Cmd+] navigate the visible sidebar session list, not only the
   * active workspace group. In Combined mode this crosses into the next
   * expanded project group and skips collapsed project sections because users
   * expect hidden sessions to stay out of keyboard traversal.
   *
   * CDXC:Hotkeys 2026-06-07-14:05:
   * Cmd+Shift+[ and Cmd+Shift+] are supported in addition to Cmd+Shift+Tab and Cmd+Tab. Previous/next session traversal must follow rendered sidebar row order across expanded groups and skip sleeping rows instead of waking hidden or parked sessions.
   */
  const fallbackSlots = slots.filter((slot) => !slot.isSleeping);
  const nextSessionId =
    focusedIndex === -1
      ? direction > 0
        ? fallbackSlots[0]?.sessionId
        : fallbackSlots.at(-1)?.sessionId
      : getAdjacentAwakeRenderedNativeHotkeySessionId(slots, focusedIndex, direction);
  if (!nextSessionId) {
    logNativeHotkeyDebug("nativeHotkeys.adjacentSessionMissing", { direction });
    return;
  }
  focusSidebarSession(nextSessionId);
}

function getAdjacentAwakeRenderedNativeHotkeySessionId(
  slots: readonly NativeRenderedHotkeySidebarSessionSlot[],
  focusedIndex: number,
  direction: -1 | 1,
): string | undefined {
  for (let step = 1; step <= slots.length; step += 1) {
    const candidate = slots[(focusedIndex + direction * step + slots.length) % slots.length];
    if (candidate && !candidate.isSleeping) {
      return candidate.sessionId;
    }
  }
  return undefined;
}

function getVisibleNativeHotkeySidebarSessionsForNavigation(): SidebarSessionItem[] {
  /*
  CDXC:GxserverPresentation 2026-06-01-15:42:
  Keyboard traversal must use the same gxserver presentation groups rendered in the sidebar. Do not rebuild hotkey order from the retired native combined project tree, because hidden command/local sessions would reintroduce a second presentation source.
  */
  const groups = (createPresentationSidebarGroups(gxserverStartupSnapshot?.presentation) ?? [])
    .filter((group) => isNativeHotkeySidebarGroupExpanded(group.groupId));
  const sessionIdsByGroup = Object.fromEntries(
    groups.map((group) => [group.groupId, group.sessions.map((session) => session.sessionId)]),
  );
  const sessionsById = Object.fromEntries(
    groups.flatMap((group) => group.sessions.map((session) => [session.sessionId, session])),
  );
  const displayLayout = createDisplaySessionLayout({
    sessionIdsByGroup,
    sessionsById,
    sortMode: activeSessionsSortMode,
    workspaceGroupIds: groups.map((group) => group.groupId),
  });

  /**
   * CDXC:Hotkeys 2026-05-15-10:15:
   * Next Tab and Previous Tab must follow the same visible sidebar order the
   * user sees, including the active sessions sort mode and collapsed Combined
   * sections. Build the traversal list from the display layout instead of the
   * underlying workspace session arrays so keyboard navigation does not jump
   * by an invisible storage order.
   */
  return displayLayout.groupIds.flatMap((groupId) =>
    (displayLayout.sessionIdsByGroup[groupId] ?? [])
      .map((sessionId) => sessionsById[sessionId])
      .filter((session): session is SidebarSessionItem => session !== undefined),
  );
}

function isNativeHotkeyFocusedSession(session: SidebarSessionItem): boolean {
  return isNativeHotkeyFocusedSessionId(session.sessionId);
}

function isNativeHotkeyFocusedSessionId(sessionId: string): boolean {
  const reference = resolveSidebarSessionReference(sessionId);
  return (
    reference.project.projectId === activeProjectId &&
    reference.sessionId === activeSnapshot().focusedSessionId
  );
}

function isNativeHotkeySidebarGroupExpanded(groupId: string): boolean {
  const element = document.querySelector(
    `[data-sidebar-group-id="${escapeNativeHotkeySelectorValue(groupId)}"]`,
  );
  if (!element) {
    return true;
  }
  return (
    element.getAttribute("data-collapsed") !== "true" &&
    !element.closest(".reference-sidebar-collapsible-body[data-collapsed='true']")
  );
}

function escapeNativeHotkeySelectorValue(value: string): string {
  return typeof CSS !== "undefined" && typeof CSS.escape === "function"
    ? CSS.escape(value)
    : value.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

type NativeRenderedHotkeySidebarSessionSlot = {
  isSleeping: boolean;
  sessionId: string;
};

function getRenderedNativeHotkeySidebarSessionSlotIds(): string[] {
  return getRenderedNativeHotkeySidebarSessionSlots().map((slot) => slot.sessionId);
}

function getRenderedNativeHotkeySidebarSessionSlots(): NativeRenderedHotkeySidebarSessionSlot[] {
  const root = document.querySelector(".native-sidebar-main") ?? document;
  const seenSessionIds = new Set<string>();
  const slots: NativeRenderedHotkeySidebarSessionSlot[] = [];
  /**
   * CDXC:Hotkeys 2026-06-05-21:17:
   * Cmd+1..9 must follow the exact session rows currently painted in the native sidebar. A repro showed state/group-derived slot order could reserve hidden rows, so read mounted session cards in DOM order and skip collapsed or non-rendered ancestors instead of selecting from active-group inventory.
   *
   * CDXC:Hotkeys 2026-06-07-14:05:
   * Previous/next session hotkeys use the same rendered rows but also read each row's sleeping state so traversal can skip sleeping sessions while still honoring expanded-group sidebar order.
   */
  for (const element of Array.from(
    root.querySelectorAll<HTMLElement>("[data-sidebar-session-id]"),
  )) {
    const sessionId = element.getAttribute("data-sidebar-session-id");
    if (
      !sessionId ||
      seenSessionIds.has(sessionId) ||
      element.getAttribute("data-visible") === "false" ||
      element.closest('[aria-hidden="true"], [data-collapsed="true"]') ||
      element.getClientRects().length === 0
    ) {
      continue;
    }
    seenSessionIds.add(sessionId);
    slots.push({
      isSleeping: element.getAttribute("data-sleeping") === "true",
      sessionId,
    });
  }
  return slots;
}

function promptRenameFocusedNativeHotkeySession(): void {
  const focusedSessionId = activeSnapshot().focusedSessionId;
  if (!focusedSessionId) {
    logNativeHotkeyDebug("nativeHotkeys.renameNoFocusedSession", {});
    return;
  }
  const session = findTerminalSession(focusedSessionId);
  if (!session) {
    logNativeHotkeyDebug("nativeHotkeys.renameFocusedSessionNotTerminal", { focusedSessionId });
    return;
  }
  /**
   * CDXC:AppModals 2026-04-28-16:18
   * Native hotkey rename must use the shared React modal host instead of
   * browser prompt UI, matching the no VS Code/native prompt requirement.
   */
  openAppModal({
    initialTitle: session.title || DEFAULT_TERMINAL_SESSION_TITLE,
    modal: "renameSession",
    sessionId: focusedSessionId,
    type: "open",
  });
}

function acknowledgeNativeTerminalAttention(
  sessionId: string,
  reason: "native-focus" | "sidebar-focus" | "tui-attach",
): boolean {
  const terminalState = terminalStateById.get(sessionId);
  if (
    terminalState?.activity !== "attention" &&
    getGxserverPresentationActivityForSidebarSession(sessionId) !== "attention"
  ) {
    return false;
  }

  const attentionEnteredAt = nativeAttentionEnteredAtBySessionId.get(sessionId);
  const remainingVisibleMs =
    attentionEnteredAt === undefined
      ? 0
      : NATIVE_MIN_ATTENTION_VISIBLE_MS - Math.max(0, Date.now() - attentionEnteredAt);
  if (attentionEnteredAt !== undefined && remainingVisibleMs > 0) {
    if (!nativeAttentionAcknowledgementTimeoutBySessionId.has(sessionId)) {
      const timeout = window.setTimeout(() => {
        nativeAttentionAcknowledgementTimeoutBySessionId.delete(sessionId);
        const latestAttentionEnteredAt = nativeAttentionEnteredAtBySessionId.get(sessionId);
        if (
          latestAttentionEnteredAt !== attentionEnteredAt ||
          !completeNativeTerminalAttentionAcknowledgement(sessionId, reason, attentionEnteredAt)
        ) {
          return;
        }
        publish();
      }, remainingVisibleMs);
      nativeAttentionAcknowledgementTimeoutBySessionId.set(sessionId, timeout);
    }
    appendAgentDetectionDebugLog("nativeSidebar.sessionAttentionAcknowledgementDeferred", {
      attentionEnteredAt: new Date(attentionEnteredAt).toISOString(),
      reason,
      remainingVisibleMs,
      sessionId,
    });
    return true;
  }

  return completeNativeTerminalAttentionAcknowledgement(sessionId, reason, attentionEnteredAt);
}

function completeNativeTerminalAttentionAcknowledgement(
  sessionId: string,
  reason: "native-focus" | "sidebar-focus" | "tui-attach",
  attentionEnteredAt?: number,
): boolean {
  const terminalState = terminalStateById.get(sessionId);
  if (
    !terminalState ||
    (terminalState.activity !== "attention" &&
      getGxserverPresentationActivityForSidebarSession(sessionId) !== "attention")
  ) {
    return false;
  }
  const latestAttentionEnteredAt = nativeAttentionEnteredAtBySessionId.get(sessionId);
  if (
    attentionEnteredAt !== undefined &&
    latestAttentionEnteredAt !== undefined &&
    latestAttentionEnteredAt !== attentionEnteredAt
  ) {
    return false;
  }

  /**
   * CDXC:NativeSessionStatus 2026-04-27-07:39
   * Done/green is an attention state, not just an exited lifecycle. Clicking a
   * green session card acknowledges that completion and clears both the card
   * dot and workspace-bar done count until the next working-to-done transition.
   *
   * CDXC:SessionAttention 2026-05-16-23:35:
   * Pane/tab clicks should always acknowledge the current green attention state. If the click arrives before the 1.5-second visibility floor, acknowledgement is completed by the deferred timer above so the border and dot disappear only after the user has had enough time to perceive them.
   *
   * CDXC:SessionAttention 2026-06-02-18:31:
   * Native pane chrome can now render attention from gxserver presentation even when local terminalState still contains stale title-derived working. Treat presentation attention as the same acknowledgeable event so clicking the green terminal border or tab routes through the existing gxserver acknowledgement path.
   */
  terminalState.activity = "idle";
  setGxserverPresentationSessionActivityLocally(
    sessionId,
    "idle",
    "attention-acknowledge",
  );
  persistTerminalSessionRestoreActivity(sessionId, undefined);
  markNativeAttentionEventLocallyAcknowledged(
    sessionId,
    nativeAttentionEventIdBySessionId.get(sessionId),
  );
  void syncNativeSessionActivityWithGxserver(sessionId, { event: "acknowledge" }, "attention-acknowledge");
  if (terminalState.sessionStateFilePath) {
    void persistNativeSessionAttentionAcknowledged(
      terminalState.sessionStateFilePath,
      new Date().toISOString(),
      sessionId,
      reason,
    );
  }
  nativeAttentionEnteredAtBySessionId.delete(sessionId);
  clearNativeSessionAttentionAcknowledgementTimer(sessionId);
  appendAgentDetectionDebugLog("nativeSidebar.sessionAttentionAcknowledged", {
    attentionEnteredAt:
      attentionEnteredAt === undefined ? undefined : new Date(attentionEnteredAt).toISOString(),
    reason,
    sessionId,
  });
  return true;
}

function getGxserverPresentationActivityForSidebarSession(
  sessionId: string,
): "attention" | "idle" | "working" | undefined {
  const reference = resolveSidebarSessionReference(sessionId);
  return findGxserverPresentationSession(reference.project.projectId, reference.sessionId)?.activity;
}

async function persistNativeSessionAttentionAcknowledged(
  sessionStateFilePath: string,
  timestamp: string,
  sessionId: string,
  source: string,
): Promise<void> {
  const command = [
    `/usr/bin/python3 - ${quoteNativeShellArg(sessionStateFilePath)} ${quoteNativeShellArg(timestamp)} <<'GHOSTEX_ACK_ATTENTION'`,
    getAcknowledgeNativeSessionAttentionScript(),
    "GHOSTEX_ACK_ATTENTION",
  ].join("\n");
  try {
    const result = await runNativeProcess("/bin/zsh", ["-lc", command]);
    if (result.exitCode !== 0) {
      appendAgentDetectionDebugLog("nativeSidebar.attentionAcknowledgePersistFailed", {
        error: result.stderr.trim() || result.stdout.trim() || "persist attention acknowledgement failed",
        sessionId,
        sessionStateFilePath,
        source,
        timestamp,
      });
    }
  } catch (error) {
    appendAgentDetectionDebugLog("nativeSidebar.attentionAcknowledgePersistFailed", {
      error: error instanceof Error ? error.message : String(error),
      sessionId,
      sessionStateFilePath,
      source,
      timestamp,
    });
  }
}

function findSessionGroupId(sessionId: string): string | undefined {
  const reference = resolveSidebarSessionReference(sessionId);
  return reference.project.workspace.groups.find((group) =>
    group.snapshot.sessions.some((session) => session.sessionId === reference.sessionId),
  )?.groupId;
}

function findTerminalSession(sessionId: string): TerminalSessionRecord | undefined {
  const reference = resolveSidebarSessionReference(sessionId);
  return findTerminalSessionInProject(reference.project, reference.sessionId);
}

function findTerminalSessionInProject(
  project: NativeProject,
  sessionId: string,
): TerminalSessionRecord | undefined {
  const commandSession = project.commandsPanel.sessions.find(
    (candidate) => candidate.sessionId === sessionId,
  );
  if (commandSession) {
    return commandSession;
  }
  for (const group of project.workspace.groups) {
    const session = group.snapshot.sessions.find(
      (candidate) => candidate.sessionId === sessionId,
    );
    if (session?.kind === "terminal") {
      return session;
    }
  }
  return undefined;
}

function findFirstTerminalSessionInProject(
  project: NativeProject,
): TerminalSessionRecord | undefined {
  for (const group of project.workspace.groups) {
    const session = group.snapshot.sessions.find(
      (candidate): candidate is TerminalSessionRecord => candidate.kind === "terminal",
    );
    if (session) {
      return session;
    }
  }
  return undefined;
}

async function renameNativeSidebarTerminalSession(
  sessionId: string,
  title: string,
  source: string,
  options?: { agentId?: string; shouldGenerateTitle?: boolean },
): Promise<void> {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  if (!session) {
    appendSessionTitleRenameTraceDebugLog("nativeSidebar.renameSession.resolveFailed", {
      activeProjectId,
      projectId: reference.project.projectId,
      projectPath: reference.project.path,
      requestedSessionId: sessionId,
      resolvedSessionId: reference.sessionId,
      source,
      titleLength: title.length,
      titlePreview: summarizeTerminalText(title),
      workspaceSessionIds: reference.project.workspace.groups.flatMap((group) =>
        group.snapshot.sessions.map((candidate) => candidate.sessionId),
      ),
    });
    return;
  }

  const shouldGenerateTitle = options?.shouldGenerateTitle === true;
  const requestedTitleInput = shouldGenerateTitle
    ? title.trim()
    : normalizeSessionRenameTitle(title);
  if (!requestedTitleInput) {
    appendSessionTitleRenameTraceDebugLog("nativeSidebar.renameSession.emptyTitleSkipped", {
      projectId: reference.project.projectId,
      requestedSessionId: sessionId,
      resolvedSessionId: reference.sessionId,
      shouldGenerateTitle,
      source,
      titleLength: title.length,
      titlePreview: summarizeTerminalText(title),
    });
    return;
  }

  const terminalState = terminalStateById.get(reference.sessionId);
  appendSessionTitleRenameTraceDebugLog("nativeSidebar.renameSession.started", {
    agentNameFromSession: session.agentName,
    agentNameFromTerminalState: terminalState?.agentName,
    existingMappedNativeSessionId: nativeSessionIdBySidebarSessionId.get(reference.sessionId),
    focusedSessionId: activeSnapshot().focusedSessionId,
    isSleeping: session.isSleeping === true,
    projectId: reference.project.projectId,
    projectPath: reference.project.path,
    requestedSessionId: sessionId,
    requestedTitleLength: requestedTitleInput.length,
    requestedTitlePreview: summarizeTerminalText(requestedTitleInput),
    resolvedSessionId: reference.sessionId,
    sessionPersistenceName: session.sessionPersistenceName,
    sessionPersistenceProvider: session.sessionPersistenceProvider,
    shouldGenerateTitle,
    source,
    storedTitle: session.title,
    terminalTitle: terminalState?.terminalTitle,
    visibleSessionIds: activeSnapshot().visibleSessionIds,
  });

  /**
   * CDXC:SessionNaming 2026-05-09-17:25
   * Long pasted text in the rename modal must remain editable until the user
   * submits. The modal owns the 70-character threshold UI and marks Generate
   * Name submits explicitly, while the controller only generates for that
   * explicit request or the saved first-message Generate Title action.
   */
  let requestedTitle = requestedTitleInput;
  if (shouldGenerateTitle) {
    setNativeManualGeneratedRenameInProgress(reference.sessionId, true);
    appendSessionTitleDebugLog("nativeSidebar.renameSession.generateTitle.started", {
      pastedTextLength: requestedTitleInput.length,
      sessionId: reference.sessionId,
      source,
    });
    try {
      requestedTitle = await generateNativeSessionTitleFromPrompt(
        reference.project.path,
        requestedTitleInput,
        options?.agentId,
      );
      appendSessionTitleDebugLog("nativeSidebar.renameSession.generateTitle.completed", {
        pastedTextLength: requestedTitleInput.length,
        sessionId: reference.sessionId,
        source,
        title: requestedTitle,
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      appendSessionTitleGenerationErrorLog("nativeSidebar.renameSession.generateTitle.failed", {
        error: message,
        pastedTextLength: requestedTitleInput.length,
        sessionId: reference.sessionId,
        source,
      });
      setNativeManualGeneratedRenameInProgress(reference.sessionId, false);
      return;
    }
  }

  const nativeSessionId = nativeSessionIdForProjectSidebarSession(
    reference.project.projectId,
    reference.sessionId,
  );
  const normalizedRenameTitle = normalizeTerminalTitle(requestedTitle) ?? requestedTitle;
  const agentName = terminalState?.agentName ?? session.agentName;
  const shouldUseGxserverRenameRequest = isCanonicalGxserverProjectSession(
    reference.project.projectId,
    reference.sessionId,
  );
  if (shouldUseGxserverRenameRequest) {
    /*
    CDXC:GxserverAgentTitles 2026-06-01-09:03:
    For gxserver-backed panes, native rename is a request, not local title persistence. gxserver may apply it immediately for plain terminals, but agent sessions keep it pending until structured agent metadata proves the CLI accepted the rename.

    CDXC:ProjectSidebarOwnership 2026-06-02-10:52:
    Rename ownership follows canonical session identity, not the zmx provider. tmux, zellij, and off-provider sessions still use native pane runtime, but P/G session title provenance belongs to gxserver so CLI/UI renames cannot leave local-only titles behind.
    */
    try {
      const result = await gxserverClient.rpc<GxserverSessionRenameRequestResult>(
        "/api/requestSessionRename",
        {
          agentName,
          agentSessionId: terminalState?.agentSessionId ?? (session.kind === "terminal" ? session.agentSessionId : undefined),
          agentSessionPath: terminalState?.agentSessionPath ?? (session.kind === "terminal" ? session.agentSessionPath : undefined),
          projectId: reference.project.projectId,
          sessionId: reference.sessionId,
          title: requestedTitle,
          titleSource: shouldGenerateTitle ? "generated" : "user",
        },
      );
      applyGxserverSessionRenameRequestResult(reference.project.projectId, reference.sessionId, result);
      appendSessionTitleRenameTraceDebugLog("nativeSidebar.renameSession.gxserverRequestApplied", {
        agentName,
        pendingAgentMetadata: result.pendingAgentMetadata,
        projectId: reference.project.projectId,
        reason: result.reason,
        requestedSessionId: sessionId,
        requestedTitleLength: requestedTitle.length,
        requestedTitlePreview: summarizeTerminalText(requestedTitle),
        resolvedSessionId: reference.sessionId,
        shouldSendAgentRenameCommand: result.shouldSendAgentRenameCommand,
        source,
      });
      if (!result.shouldSendAgentRenameCommand) {
        setNativeManualGeneratedRenameInProgress(reference.sessionId, false);
        publish();
        return;
      }
    } catch (error) {
      appendSessionTitleRenameTraceDebugLog("nativeSidebar.renameSession.gxserverRequestFailed", {
        agentName,
        error: error instanceof Error ? error.message : String(error),
        projectId: reference.project.projectId,
        requestedSessionId: sessionId,
        resolvedSessionId: reference.sessionId,
        source,
      });
      if (!agentName?.trim()) {
        setNativeManualGeneratedRenameInProgress(reference.sessionId, false);
        return;
      }
    }
  } else {
    updateProjectWorkspace(
      reference.project.projectId,
      (workspace) =>
        setSessionTitleInSimpleWorkspace(workspace, reference.sessionId, requestedTitle, {
          titleSource: shouldGenerateTitle ? "generated" : "user",
        }).snapshot,
    );
  }
  appendSessionTitleRenameTraceDebugLog(
    shouldUseGxserverRenameRequest
      ? "nativeSidebar.renameSession.agentTitleRequested"
      : "nativeSidebar.renameSession.titleStored",
    {
      agentName,
      nativeSessionId,
      normalizedRenameTitleLength: normalizedRenameTitle.length,
      normalizedRenameTitlePreview: summarizeTerminalText(normalizedRenameTitle),
      projectId: reference.project.projectId,
      requestedSessionId: sessionId,
      requestedTitleLength: requestedTitle.length,
      requestedTitlePreview: summarizeTerminalText(requestedTitle),
      resolvedSessionId: reference.sessionId,
      source,
      titleSource: shouldGenerateTitle ? "generated" : "user",
    },
  );
  if (!agentName?.trim()) {
    /**
     * CDXC:SidebarRename 2026-05-11-12:37
     * Plain terminal sessions can be renamed in ghostex without an Agent CLI.
     * Do not stage `/rename <title>` into those shells; only agent-backed
     * terminals should receive an in-terminal rename command.
     */
    appendSessionTitleRenameTraceDebugLog("terminalRenameCommand.skipped", {
      nativeSessionId,
      reason: "no-agent-associated",
      requestedSessionId: sessionId,
      requestedTitleLength: requestedTitle.length,
      requestedTitlePreview: summarizeTerminalText(requestedTitle),
      resolvedSessionId: reference.sessionId,
      sessionAgentName: session.agentName,
      source,
      terminalStateAgentName: terminalState?.agentName,
    });
    appendSessionTitleDebugLog("terminalRenameCommand.skipped", {
      nativeSessionId,
      reason: "no-agent-associated",
      requestedTitle,
      sessionId: reference.sessionId,
      source,
    });
    setNativeManualGeneratedRenameInProgress(reference.sessionId, false);
    publish();
    return;
  }
  const isPiSession = resolveNativeResumeAgentId(agentName) === "pi";
  const commandText = isPiSession
    ? `/name ${normalizedRenameTitle}`
    : `/rename ${normalizedRenameTitle}`;
  appendSessionTitleRenameTraceDebugLog("terminalRenameCommand.writeSubmitting", {
    agentName,
    commandPreview: summarizeTerminalText(commandText),
    commandTextLength: commandText.length,
    isPiSession,
    nativeSessionId,
    projectId: reference.project.projectId,
    requestedSessionId: sessionId,
    resolvedSessionId: reference.sessionId,
    source,
  });
  /**
   * CDXC:SidebarRename 2026-04-28-15:49
   * Manual sidebar renames for agent-backed terminals in the native app must
   * match the reference controller flow: persist the card title, stage
   * `/rename <title>` in the targeted terminal, then submit through the native
   * Enter path so the Agent CLI thread name changes instead of only the
   * sidebar label changing.
   *
   * CDXC:PiAgent 2026-05-08-09:42
   * Pi uses `/name <title>` for session naming. Native manual renames must
   * stage that command for Pi panes while keeping Codex/Claude on `/rename`.
   */
  postNative({ sessionId: nativeSessionId, text: commandText, type: "writeTerminalText" });
  appendSessionTitleRenameTraceDebugLog("terminalRenameCommand.writeSubmitted", {
    agentName,
    commandPreview: summarizeTerminalText(commandText),
    commandTextLength: commandText.length,
    nativeSessionId,
    requestedSessionId: sessionId,
    resolvedSessionId: reference.sessionId,
    source,
  });
  window.setTimeout(() => {
    appendSessionTitleRenameTraceDebugLog("terminalRenameCommand.enterSubmitting", {
      nativeSessionId,
      requestedSessionId: sessionId,
      resolvedSessionId: reference.sessionId,
      source,
    });
    postNative({ sessionId: nativeSessionId, type: "sendTerminalEnter" });
    appendSessionTitleRenameTraceDebugLog("terminalRenameCommand.enterSubmitted", {
      nativeSessionId,
      requestedSessionId: sessionId,
      resolvedSessionId: reference.sessionId,
      source,
    });
    appendSessionTitleDebugLog("terminalRenameCommand.sent", {
      commandText,
      nativeSessionId,
      requestedTitle,
      sessionId: reference.sessionId,
      source,
    });
    setNativeManualGeneratedRenameInProgress(reference.sessionId, false);
  }, AUTO_SUBMIT_STAGED_RENAME_DELAY_MS);
  publish();
}

function stopNativeSleepingSessionRuntime(
  sessionId: string,
  project = activeProject(),
  options: { gxserverTransitionHandled?: boolean } = {},
): void {
  const nativeSessionId = forgetNativeSessionMappingForProject(project.projectId, sessionId);
  const session = findTerminalSessionInProject(project, sessionId);
  const terminalState = terminalStateById.get(sessionId);
  const presentationSession = findGxserverPresentationSession(project.projectId, sessionId);
  const shouldStopZmxThroughGxserver =
    options.gxserverTransitionHandled !== true &&
    shouldUseGxserverProviderTransition({
      localProvider: terminalState?.sessionPersistenceProvider ?? session?.sessionPersistenceProvider,
      presentation: presentationSession,
    });
  clearNativeSidebarCommandSessionBySessionId(sessionId);
  terminalStateById.delete(sessionId);
  clearSettledTerminalTitleSync(sessionId);
  pendingNativeTerminalStartupTextBySessionId.delete(sessionId);
  nativeActivitySuppressedUntilBySessionId.delete(sessionId);
  nativeWorkingStartedAtBySessionId.delete(sessionId);
  clearNativeSessionAttentionTracking(sessionId);
  /**
   * CDXC:SessionSleep 2026-05-17-01:33:
   * Sleeping must release the actual agent CLI, not only detach the Ghostty view.
   * Close the tmux/zmx/zellij provider session too; wake recreates the provider
   * session and runs the stored agent resume command when the sidebar has a
   * restorable identity.
   *
   * CDXC:GxserverTerminalAttach 2026-05-30-15:50:
   * zmx provider shutdown is server-owned after the gxserver cutover. Keep the
   * native close as a Ghostty surface detach while gxserver handles kill/cache
   * semantics for sleep.
   */
  if (shouldStopZmxThroughGxserver) {
    stopGxserverZmxSessionRuntime(project.projectId, sessionId, "sleepSession");
  }
  postNative({
    preservePersistenceSession: shouldStopZmxThroughGxserver,
    sessionId: nativeSessionId,
    type: "closeTerminal",
  });
}

function setNativeSessionSleeping(
  sessionId: string,
  sleeping: boolean,
  options: {
    focusTransition?: boolean;
    publish?: boolean;
    transitionOrigin?: NativeGxserverSessionTransitionOrigin;
  } = {},
): void {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  const presentationSession = findGxserverPresentationSession(
    reference.project.projectId,
    reference.sessionId,
  );
  if (!session) {
    if (!presentationSession || presentationSession.surface !== "workspace") {
      return;
    }
    if (!sleeping) {
      focusSidebarSession(sessionId);
      return;
    }
    if (presentationSession.lifecycleState === "sleeping") {
      return;
    }
    const transitionOrigin = options.transitionOrigin ?? createProjectSessionListTransitionOrigin(reference.project);
    const transitionResult = applyGxserverSessionTransition(
      reference,
      undefined,
      "sleep",
      transitionOrigin,
    );
    if (transitionResult.handled) {
      setGxserverPresentationSessionLifecycleLocally(
        reference.project.projectId,
        reference.sessionId,
        "sleeping",
        "sleep-presentation-session",
      );
      if (options.publish !== false) {
        publish();
      }
      if (options.focusTransition !== false) {
        focusGxserverSessionTransitionTarget(transitionResult.focusTarget, transitionOrigin.kind);
      }
    }
    return;
  }
  const wasSleeping = session.isSleeping === true;
  /*
   * CDXC:NativeSidebarBulkActions 2026-06-07-13:34:
   * Bulk sleep commands can arrive from stale sidebar data while rows are
   * already parked. Treat those as no-ops before provider/runtime cleanup so
   * Sleep below, group sleep, and titlebar sleep never re-close sleeping agents.
   */
  if (sleeping && (wasSleeping || presentationSession?.lifecycleState === "sleeping")) {
    return;
  }
  const transitionOrigin =
    options.transitionOrigin ??
    (session.surface === "commands"
      ? createCommandPaneTransitionOrigin(reference.project, reference.sessionId)
      : createProjectSessionListTransitionOrigin(reference.project));
  const transitionResult: { focusTarget?: NativeSessionTransitionFocusTarget; handled: boolean } =
    sleeping
      ? applyGxserverSessionTransition(reference, session, "sleep", transitionOrigin)
      : { handled: false };
  if (session.surface === "commands") {
    updateProjectCommandsPanel(reference.project.projectId, (panel) => ({
      ...panel,
      sessions: panel.sessions.map((candidate) =>
        candidate.sessionId === reference.sessionId
          ? {
              ...candidate,
              isPoppedOut: sleeping ? undefined : candidate.isPoppedOut,
              isSleeping: sleeping,
            }
          : candidate,
      ),
    }));
  } else {
    updateProjectWorkspace(
      reference.project.projectId,
      (workspace) =>
        setSessionSleepingInSimpleWorkspace(workspace, reference.sessionId, sleeping).snapshot,
    );
  }
  if (sleeping) {
    const providerInfo = getTerminalProviderSessionInfo(session);
    if (providerInfo) {
      rememberProviderSessionState(
        reference.project.projectId,
        reference.sessionId,
        providerInfo.provider,
        providerInfo.sessionName,
        "missing",
      );
    } else {
      forgetProviderSessionState(reference.project.projectId, reference.sessionId);
    }
    stopNativeSleepingSessionRuntime(reference.sessionId, reference.project, {
      gxserverTransitionHandled: transitionResult.handled,
    });
  } else if (wasSleeping || !terminalStateById.has(reference.sessionId)) {
    if (wasSleeping) {
      clearStaleTerminalRuntimeStateBeforeWake(
        reference.project.projectId,
        reference.sessionId,
        session.surface === "commands" ? "wake-command-session" : "wake-session",
      );
    }
    forgetProviderSessionState(reference.project.projectId, reference.sessionId);
    const nextProject = findProject(reference.project.projectId) ?? reference.project;
    const nextSession = findTerminalSessionInProject(nextProject, reference.sessionId);
    if (nextSession) {
      restoreNativeTerminalSession(
        nextProject,
        nextSession,
        nextSession.surface === "commands" ? "wake-command-session" : "wake-session",
      );
    }
  }
  if (options.publish !== false) {
    publish();
  }
  if (sleeping && options.focusTransition !== false) {
    focusGxserverSessionTransitionTarget(transitionResult.focusTarget, transitionOrigin.kind);
  }
}

function isNativeSidebarSessionAlreadySleeping(sessionId: string): boolean {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  const presentationSession = findGxserverPresentationSession(
    reference.project.projectId,
    reference.sessionId,
  );
  return session?.isSleeping === true || presentationSession?.lifecycleState === "sleeping";
}

function setNativeSessionsSleepingInBackground(
  sessionIds: readonly string[],
  sleeping: boolean,
): void {
  /*
   * CDXC:NativeSidebarBulkActions 2026-06-07-13:34:
   * Sidebar bulk sleep/wake messages should return control to the webview after
   * one native message. Deduplicate and skip already-sleeping targets, then run
   * lifecycle work in macrotasks with one final publish so the sidebar does not
   * repaint after every individual session shutdown.
   */
  const targetSessionIds = Array.from(new Set(sessionIds)).filter((sessionId) =>
    sleeping ? !isNativeSidebarSessionAlreadySleeping(sessionId) : true,
  );
  if (targetSessionIds.length === 0) {
    return;
  }

  runNativeSidebarBulkActionInBackground([
    ...targetSessionIds.map((sessionId) => () =>
      setNativeSessionSleeping(sessionId, sleeping, {
        focusTransition: false,
        publish: false,
      }),
    ),
    () => publish(),
  ]);
}

function closeNativeSessionsInBackground(sessionIds: readonly string[]): void {
  const targetSessionIds = Array.from(new Set(sessionIds));
  if (targetSessionIds.length === 0) {
    return;
  }
  runNativeSidebarBulkActionInBackground(
    targetSessionIds.map((sessionId) => () => closeTerminal(sessionId)),
  );
}

function setNativeBrowserSessionSleeping(
  projectId: string,
  sessionId: string,
  sleeping: boolean,
): void {
  const project = findProject(projectId);
  const session = project ? findSessionRecordInProject(project, sessionId) : undefined;
  if (!project || session?.kind !== "browser") {
    return;
  }
  const wasSleeping = session.isSleeping === true;
  updateProjectWorkspace(
    project.projectId,
    (workspace) => setSessionSleepingInSimpleWorkspace(workspace, session.sessionId, sleeping).snapshot,
  );
  /**
   * CDXC:AutoSleep 2026-05-28-08:32:
   * Browser sessions are sleepable web panes, not terminal runtimes. Closing the
   * native web pane is enough for sleep; waking routes through the existing
   * browser restore path and stamps start/access timestamps for the next policy
   * decision.
   */
  if (sleeping) {
    const nativeSessionId = forgetNativeSessionMappingForProject(project.projectId, session.sessionId);
    postNative({ sessionId: nativeSessionId, type: "closeWebPane" });
  } else if (wasSleeping || !nativeSessionIdBySidebarSessionId.has(session.sessionId)) {
    const nextProject = findProject(project.projectId) ?? project;
    const nextSession = findSessionRecordInProject(nextProject, session.sessionId);
    if (nextSession?.kind === "browser") {
      restoreNativeBrowserSession(nextProject, nextSession, "wake-browser-session");
    }
  }
  publish();
}

function sleepInactiveSessionsFromTitlebar(sessionIds: string[]): void {
  /**
   * CDXC:TitlebarResources 2026-05-16-19:53:
   * The titlebar sleep shortcut may be clicked from stale dropdown data, so the
   * sidebar revalidates each target against current project/session state.
   * Sleep only idle, awake agent terminals older than seven minutes and never
   * sleep sessions that are currently working or requesting attention.
   *
   * CDXC:TitlebarResources 2026-05-26-17:16:
   * Revalidation must match the Resources button: sleep every awake idle
   * terminal id the titlebar sends, including terminals without detected agent
   * metadata or old Last Active timestamps. Keep working and attention sessions
   * awake because those states indicate active output or user review.
   *
   * CDXC:TitlebarResources 2026-06-02-19:02:
   * The Resources list can contain gxserver presentation rows that are not materialized in native workspace storage yet. Revalidate from the current hydrate groups before sleeping so the titlebar action matches visible presentation, then delegate to setNativeSessionSleeping for gxserver-owned lifecycle mutation.
   *
   * CDXC:TitlebarResources 2026-06-06-06:09:
   * Delayed Send is an awake-terminal contract: the scheduled Enter must fire
   * in the existing pane. Revalidation must keep delayed-send sessions awake
   * even if stale titlebar data still sends their ids.
   */
  const sidebarSessionsById = new Map(
    buildSidebarMessage().groups.flatMap((group) =>
      group.sessions.map((session) => [session.sessionId, session] as const),
    ),
  );
  const sessionIdsToSleep: string[] = [];
  for (const sessionId of Array.from(new Set(sessionIds))) {
    const reference = resolveSidebarSessionReference(sessionId);
    const session = findTerminalSessionInProject(reference.project, reference.sessionId);
    const presentationSession = findGxserverPresentationSession(
      reference.project.projectId,
      reference.sessionId,
    );
    if ((!session || session.kind !== "terminal") && !presentationSession) {
      continue;
    }
    const projectedSession = sidebarSessionsById.get(sessionId);
    if (
      !projectedSession ||
      projectedSession.sessionKind !== "terminal" ||
      projectedSession.isSleeping === true ||
      projectedSession.lifecycleState === "sleeping" ||
      hasProjectedDelayedSend(projectedSession)
    ) {
      continue;
    }
    const terminalState = terminalStateById.get(reference.sessionId);
    const activity = projectedSession?.activity ?? terminalState?.activity ?? "idle";
    if (activity === "working" || activity === "attention") {
      continue;
    }
    sessionIdsToSleep.push(sessionId);
  }
  runNativeSidebarBulkActionInBackground(
    sessionIdsToSleep.map((sessionId) => () => setNativeSessionSleeping(sessionId, true)),
  );
}

function focusResourceSessionFromTitlebar(sessionId: string): void {
  /**
   * CDXC:TitlebarResources 2026-05-28-10:39:
   * The Resources panel can focus an individual session from its process row.
   * Reuse sidebar-card focus behavior so combined cross-project ids, sleeping
   * terminal wake, command-panel panes, browser panes, and project switching all
   * stay owned by the existing session focus pipeline.
   */
  if (!sessionId.trim()) {
    return;
  }
  focusSidebarSession(sessionId);
}

function sleepInactiveProjectSessions(projectId: string): void {
  /**
   * CDXC:ProjectSleep 2026-05-27-06:28:
   * A combined sidebar project row is a projection over all workspace groups,
   * not a native group id. Sleep Inactive must therefore enumerate the project's
   * current project sessions, including command-panel zmx terminals. Live/idle
   * zmx sessions are eligible; only working and attention sessions remain awake
   * because they represent active output or user review.
   *
   * CDXC:ProjectSleep 2026-05-29-09:20:
   * Sleep Inactive must use projected resource state, not raw `isSleeping`,
   * because durable session records can say sleeping while their zmx provider
   * session still exists and is shown as live. Sleep the idle live projection so
   * provider runtimes are actually released.
   *
   * CDXC:ProjectSleep 2026-06-02-19:02:
   * With gxserver presentation active, project-level Sleep Inactive must operate on the rendered presentation-backed project rows, not the old native workspace storage. Command-panel sessions remain macOS layout state, so include them from the native command panel after the visible project rows.
   *
   * CDXC:ProjectSleep 2026-06-06-06:09:
   * Sleep Inactive must not sleep terminal sessions with active Delayed Send
   * timers because the pending Enter depends on the live terminal surface.
   */
  const project = findProject(projectId);
  if (!project) {
    return;
  }
  const presentationGroups = createPresentationSidebarGroups(gxserverStartupSnapshot?.presentation)
    ?.filter((group) => group.projectContext?.editor.projectId === project.projectId);
  if (presentationGroups && presentationGroups.length > 0) {
    const backgroundOperations: NativeSidebarBackgroundOperation[] = [];
    for (const group of presentationGroups) {
      for (const projectedSession of group.sessions) {
        if (
          projectedSession.sessionKind !== "terminal" ||
          projectedSession.isSleeping === true ||
          projectedSession.lifecycleState === "sleeping" ||
          projectedSession.activity === "working" ||
          projectedSession.activity === "attention" ||
          hasProjectedDelayedSend(projectedSession)
        ) {
          continue;
        }
        backgroundOperations.push(() => setNativeSessionSleeping(projectedSession.sessionId, true));
      }
    }
    const commandGroup = createProjectedSidebarGroupsForProject(project).find(
      (group) => group.groupId === COMMANDS_PANEL_SESSION_GROUP_ID,
    );
    for (const projectedSession of commandGroup?.sessions ?? []) {
      if (
        projectedSession.sessionKind !== "terminal" ||
        projectedSession.isSleeping === true ||
        projectedSession.lifecycleState === "sleeping" ||
        projectedSession.activity === "working" ||
        projectedSession.activity === "attention" ||
        hasProjectedDelayedSend(projectedSession)
      ) {
        continue;
      }
      const combinedSessionId = createCombinedProjectSessionId(
        project.projectId,
        projectedSession.sessionId,
      );
      backgroundOperations.push(() => setNativeSessionSleeping(combinedSessionId, true));
    }
    runNativeSidebarBulkActionInBackground(backgroundOperations);
    return;
  }
  const projectedSessionsById = new Map(
    createProjectedSidebarGroupsForProject(project)
      .flatMap((group) => group.sessions)
      .map((session) => [session.sessionId, session]),
  );
  const backgroundOperations: NativeSidebarBackgroundOperation[] = [];

  for (const group of createProjectSessionGroupsForProjection(project)) {
    for (const session of group.snapshot.sessions) {
      const projectedSession = projectedSessionsById.get(session.sessionId);
      if (projectedSession?.isSleeping === true) {
        continue;
      }
      const terminalState = terminalStateById.get(session.sessionId);
      const activity = projectedSession?.activity ?? terminalState?.activity ?? "idle";
      if (activity === "working" || activity === "attention") {
        continue;
      }
      if (
        hasProjectedDelayedSend(projectedSession) ||
        (session.kind === "terminal" &&
          getDelayedSendProjectionForProjectSession(project.projectId, session.sessionId))
      ) {
        continue;
      }
      const combinedSessionId = createCombinedProjectSessionId(project.projectId, session.sessionId);
      if (session.kind === "terminal") {
        backgroundOperations.push(() => setNativeSessionSleeping(combinedSessionId, true));
      } else if (session.kind === "browser") {
        backgroundOperations.push(() =>
          setNativeBrowserSessionSleeping(project.projectId, session.sessionId, true),
        );
      }
    }
  }
  runNativeSidebarBulkActionInBackground(backgroundOperations);
}

function hasProjectedDelayedSend(
  session:
    | Pick<
        SidebarSessionItem,
        "delayedSendDeadlineAt" | "delayedSendRemainingLabel" | "delayedSendRemainingMs"
      >
    | undefined,
): boolean {
  return Boolean(
    session?.delayedSendRemainingLabel ||
      session?.delayedSendDeadlineAt ||
      typeof session?.delayedSendRemainingMs === "number",
  );
}

function closeInactiveProjectSessions(projectId: string): void {
  /*
   * CDXC:ProjectClose 2026-06-04-23:40:
   * Project-level Close inactive shares Sleep Inactive's project-wide terminal
   * eligibility but applies the normal close path. Working and attention
   * sessions stay alive, and the project itself is not moved to Recent Projects.
   */
  const project = findProject(projectId);
  if (!project) {
    return;
  }
  const presentationGroups = createPresentationSidebarGroups(gxserverStartupSnapshot?.presentation)
    ?.filter((group) => group.projectContext?.editor.projectId === project.projectId);
  if (presentationGroups && presentationGroups.length > 0) {
    const backgroundOperations: NativeSidebarBackgroundOperation[] = [];
    for (const group of presentationGroups) {
      for (const projectedSession of group.sessions) {
        if (
          projectedSession.sessionKind !== "terminal" ||
          projectedSession.isSleeping === true ||
          projectedSession.lifecycleState === "sleeping" ||
          projectedSession.activity === "working" ||
          projectedSession.activity === "attention"
        ) {
          continue;
        }
        backgroundOperations.push(() => closeTerminal(projectedSession.sessionId));
      }
    }
    const commandGroup = createProjectedSidebarGroupsForProject(project).find(
      (group) => group.groupId === COMMANDS_PANEL_SESSION_GROUP_ID,
    );
    for (const projectedSession of commandGroup?.sessions ?? []) {
      if (
        projectedSession.sessionKind !== "terminal" ||
        projectedSession.isSleeping === true ||
        projectedSession.lifecycleState === "sleeping" ||
        projectedSession.activity === "working" ||
        projectedSession.activity === "attention"
      ) {
        continue;
      }
      const combinedSessionId = createCombinedProjectSessionId(
        project.projectId,
        projectedSession.sessionId,
      );
      backgroundOperations.push(() => closeTerminal(combinedSessionId));
    }
    runNativeSidebarBulkActionInBackground(backgroundOperations);
    return;
  }

  const projectedSessionsById = new Map(
    createProjectedSidebarGroupsForProject(project)
      .flatMap((group) => group.sessions)
      .map((session) => [session.sessionId, session]),
  );
  const backgroundOperations: NativeSidebarBackgroundOperation[] = [];

  for (const group of createProjectSessionGroupsForProjection(project)) {
    for (const session of group.snapshot.sessions) {
      if (session.kind !== "terminal") {
        continue;
      }
      const projectedSession = projectedSessionsById.get(session.sessionId);
      if (projectedSession?.isSleeping === true) {
        continue;
      }
      const terminalState = terminalStateById.get(session.sessionId);
      const activity = projectedSession?.activity ?? terminalState?.activity ?? "idle";
      if (activity === "working" || activity === "attention") {
        continue;
      }
      const combinedSessionId = createCombinedProjectSessionId(project.projectId, session.sessionId);
      backgroundOperations.push(() => closeTerminal(combinedSessionId));
    }
  }
  runNativeSidebarBulkActionInBackground(backgroundOperations);
}

function startNativeAutoSleepMonitor(): void {
  if (nativeAutoSleepMonitorIntervalId !== undefined) {
    return;
  }
  /**
   * CDXC:AutoSleep 2026-06-02-15:27:
   * Auto Sleep is a macOS policy loop because it observes current-window activity and local browser/editor surfaces. Shared terminal candidates must still come from gxserver presentation, and sleep mutations must route through gxserver-owned lifecycle paths.
   */
  nativeAutoSleepMonitorIntervalId = window.setInterval(
    () => runNativeAutoSleepMonitor("interval"),
    AUTO_SLEEP_MONITOR_INTERVAL_MS,
  );
}

function runNativeAutoSleepMonitor(source: "interval" | "settings-change" | "startup"): void {
  if (!settings.autoSleepAgentSessionsEnabled && !settings.autoSleepBrowserSessionsEnabled) {
    return;
  }
  const nowMs = Date.now();
  const terminalSessionIdsToSleep: string[] = [];
  const browserSessionsToSleep: Array<{ projectId: string; sessionId: string }> = [];
  if (gxserverStartupSnapshot?.presentation) {
    /*
    CDXC:AutoSleep 2026-06-02-19:10:
    Auto Sleep is a macOS policy decision, but terminal candidates must come from the rendered gxserver presentation when it is active. Do not scan the old native workspace tree for shared terminal rows, because stale local rows could sleep sessions the sidebar no longer presents. Browser panes remain macOS-local and are evaluated from native pane storage below.
    */
    for (const group of buildSidebarMessage().groups) {
      for (const projectedSession of group.sessions) {
        if (projectedSession.sessionKind !== "terminal") {
          continue;
        }
        const reference = resolveSidebarSessionReference(projectedSession.sessionId);
        const session = findTerminalSessionInProject(reference.project, reference.sessionId);
        if (
          session &&
          shouldAutoSleepAgentSession({
            nowMs,
            project: reference.project,
            projectedSession,
            session,
          })
        ) {
          terminalSessionIdsToSleep.push(projectedSession.sessionId);
        }
      }
    }
    for (const project of projects) {
      if (project.isRecentProject === true || !isQuickProject(project)) {
        continue;
      }
      for (const group of project.workspace.groups) {
        for (const session of group.snapshot.sessions) {
          if (
            session.kind === "browser" &&
            shouldAutoSleepBrowserSession({ nowMs, project, session })
          ) {
            browserSessionsToSleep.push({
              projectId: project.projectId,
              sessionId: session.sessionId,
            });
          }
        }
      }
    }
    if (terminalSessionIdsToSleep.length === 0 && browserSessionsToSleep.length === 0) {
      return;
    }
    if (isNativeSidebarDebugLoggingEnabled()) {
      console.info("[ghostex-native-sidebar] auto-sleep sessions", {
        browserCount: browserSessionsToSleep.length,
        source,
        terminalCount: terminalSessionIdsToSleep.length,
      });
    }
    for (const sessionId of terminalSessionIdsToSleep) {
      setNativeSessionSleeping(sessionId, true);
    }
    for (const session of browserSessionsToSleep) {
      setNativeBrowserSessionSleeping(session.projectId, session.sessionId, true);
    }
    return;
  }
  for (const project of projects) {
    if (project.isRecentProject === true) {
      continue;
    }
    const projectedSessionsById = new Map(
      createProjectedSidebarGroupsForProject(project)
        .flatMap((group) => group.sessions)
        .map((session) => [session.sessionId, session]),
    );
    for (const group of createProjectSessionGroupsForProjection(project)) {
      for (const session of group.snapshot.sessions) {
        if (session.kind === "browser") {
          if (
            shouldAutoSleepBrowserSession({
              nowMs,
              project,
              session,
            })
          ) {
            browserSessionsToSleep.push({
              projectId: project.projectId,
              sessionId: session.sessionId,
            });
          }
          continue;
        }
        if (session.kind !== "terminal") {
          continue;
        }
        if (
          shouldAutoSleepAgentSession({
            nowMs,
            project,
            projectedSession: projectedSessionsById.get(session.sessionId),
            session,
          })
        ) {
          terminalSessionIdsToSleep.push(createCombinedProjectSessionId(project.projectId, session.sessionId));
        }
      }
    }
  }
  if (terminalSessionIdsToSleep.length === 0 && browserSessionsToSleep.length === 0) {
    return;
  }
  if (isNativeSidebarDebugLoggingEnabled()) {
    console.info("[ghostex-native-sidebar] auto-sleep sessions", {
      browserCount: browserSessionsToSleep.length,
      source,
      terminalCount: terminalSessionIdsToSleep.length,
    });
  }
  for (const sessionId of terminalSessionIdsToSleep) {
    setNativeSessionSleeping(sessionId, true);
  }
  for (const session of browserSessionsToSleep) {
    setNativeBrowserSessionSleeping(session.projectId, session.sessionId, true);
  }
}

function shouldAutoSleepAgentSession({
  nowMs,
  project,
  projectedSession,
  session,
}: {
  nowMs: number;
  project: NativeProject;
  projectedSession?: SidebarSessionItem;
  session: TerminalSessionRecord;
}): boolean {
  if (session.isSleeping === true) {
    return false;
  }
  if (!settings.autoSleepAgentSessionsEnabled) {
    return false;
  }
  const terminalState = terminalStateById.get(session.sessionId);
  if (!terminalState || terminalState.lifecycleState !== "running") {
    return false;
  }
  /**
   * CDXC:AutoSleep 2026-06-06-06:09:
   * Agent Auto Sleep must not sleep terminals with active Delayed Send timers.
   * The delayed Enter is intentionally bound to the live pane, so sleeping the
   * agent before the timer fires would cancel the user-visible scheduled send.
   */
  if (
    hasProjectedDelayedSend(projectedSession) ||
    getDelayedSendProjectionForProjectSession(project.projectId, session.sessionId)
  ) {
    return false;
  }
  const sessionForRestore = mergeNativeTerminalRuntimeMetadata(session, terminalState);
  if (!resolveNativeResumeAgentIdForSession(sessionForRestore)) {
    return false;
  }
  const activity = projectedSession?.activity ?? terminalState.activity ?? "idle";
  if (activity !== "idle") {
    return false;
  }
  if (isTitleObservationUnsafeForAutoSleep(projectedSession)) {
    return false;
  }
  if (session.isFavorite === true && !settings.autoSleepFavoriteAgentSessions) {
    return false;
  }
  /*
  CDXC:AutoSleep 2026-06-07-00:56:
  The focused agent session is always user-active from the sidebar's point of view. Do not expose or honor an override that allows Auto Sleep to retire the active conversation.
  */
  if (isFocusedAgentAutoSleepSession(project, session)) {
    return false;
  }
  if (
    settings.autoSleepRequireAgentResumeCommand &&
    !canRestoreNativeTerminalSession(sessionForRestore)
  ) {
    return false;
  }
  const lastActivityMs = nativeAutoSleepLastActivityMs(session, terminalState);
  if (lastActivityMs === undefined) {
    return false;
  }
  return nowMs - lastActivityMs >= settings.autoSleepAgentIdleMinutes * AUTO_SLEEP_MINUTE_MS;
}

function isTitleObservationUnsafeForAutoSleep(session: SidebarSessionItem | undefined): boolean {
  /*
  CDXC:AutoSleep 2026-06-07-00:30:
  Working-status detection for gxserver terminals depends on the zmx title observer. When the observer is starting, retrying, or failed, Auto Sleep must treat an idle projection as unknown rather than idle; once the observer is active, normal idle-time sleeping applies.
  */
  const status = session?.titleObservation?.status;
  return status === "starting" || status === "retrying" || status === "failed";
}

function shouldAutoSleepBrowserSession({
  nowMs,
  project,
  session,
}: {
  nowMs: number;
  project: NativeProject;
  session: BrowserSessionRecord;
}): boolean {
  if (!settings.autoSleepBrowserSessionsEnabled || session.isSleeping === true) {
    return false;
  }
  if (isFocusedSidebarSession(project, session.sessionId)) {
    return false;
  }
  const lastAccessedMs = nativeSessionTimestampMs(session.lastAccessedAt ?? session.createdAt);
  if (lastAccessedMs === undefined) {
    return false;
  }
  return nowMs - lastAccessedMs >= settings.autoSleepBrowserIdleMinutes * AUTO_SLEEP_MINUTE_MS;
}

function mergeNativeTerminalRuntimeMetadata(
  session: TerminalSessionRecord,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
): TerminalSessionRecord {
  return {
    ...session,
    agentName: terminalState.agentName ?? session.agentName,
    agentSessionId: terminalState.agentSessionId ?? session.agentSessionId,
    agentSessionPath: terminalState.agentSessionPath ?? session.agentSessionPath,
    lastStartedAt: terminalState.lastStartedAt ?? session.lastStartedAt,
    lastActivityAt: terminalState.lastActivityAt ?? session.lastActivityAt,
  };
}

function nativeAutoSleepLastActivityMs(
  session: TerminalSessionRecord,
  terminalState: NonNullable<ReturnType<typeof terminalStateById.get>>,
): number | undefined {
  /**
   * CDXC:AutoSleep 2026-05-28-08:32:
   * Agent terminals are often woken or started for inspection without producing
   * new agent output. Use the newer of semantic Last Active and start/wake time
   * so a legitimately old idle conversation does not immediately re-sleep after
   * the user brings it back.
   */
  return maxNativeTimestampMs([
    terminalState.lastActivityAt,
    session.lastActivityAt,
    terminalState.lastStartedAt,
    session.lastStartedAt,
    session.createdAt,
  ]);
}

function maxNativeTimestampMs(values: Array<string | undefined>): number | undefined {
  let result: number | undefined;
  for (const value of values) {
    const timestampMs = nativeSessionTimestampMs(value);
    if (timestampMs === undefined) {
      continue;
    }
    result = result === undefined ? timestampMs : Math.max(result, timestampMs);
  }
  return result;
}

function nativeSessionTimestampMs(value: string | undefined): number | undefined {
  if (!value) {
    return undefined;
  }
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : undefined;
}

function isFocusedAgentAutoSleepSession(
  project: NativeProject,
  session: TerminalSessionRecord,
): boolean {
  return isFocusedSidebarSession(project, session.sessionId);
}

function isFocusedSidebarSession(project: NativeProject, sessionId: string): boolean {
  if (activeProjectId !== project.projectId) {
    return false;
  }
  const activeGroup = project.workspace.groups.find(
    (group) => group.groupId === project.workspace.activeGroupId,
  );
  return (
    activeGroup?.snapshot.focusedSessionId === sessionId ||
    (project.commandsPanel.isVisible === true &&
      project.commandsPanel.activeSessionId === sessionId)
  );
}

function wakeProjectSleepingSessions(projectId: string): void {
  /**
   * CDXC:ProjectSleep 2026-05-27-02:18:
   * Combined project-row Wake must operate on the whole project because the
   * sidebar row does not resolve to a concrete workspace group. Wake each
   * sleeping workspace terminal through the session sleep path so stale native
   * runtime state is cleared and zmx restore logic stays centralized.
   *
   * CDXC:ProjectSleep 2026-05-27-06:28:
   * Commands-panel terminals are now part of the project session projection, so
   * project Wake includes sleeping command zmx sessions instead of leaving them
   * stranded outside the sidebar batch action.
   *
   * CDXC:ProjectSleep 2026-06-02-19:10:
   * With gxserver presentation active, project Wake must enumerate rendered presentation rows for workspace sessions instead of the old native workspace tree. Command-panel sessions remain current-window macOS state and are appended separately.
   */
  const project = findProject(projectId);
  if (!project) {
    return;
  }
  const presentationGroups = createPresentationSidebarGroups(gxserverStartupSnapshot?.presentation)
    ?.filter((group) => group.projectContext?.editor.projectId === project.projectId);
  const sessionIds = presentationGroups && presentationGroups.length > 0
    ? presentationGroups.flatMap((group) =>
        group.sessions
          .filter(
            (session) =>
              session.sessionKind === "terminal" &&
              (session.isSleeping === true || session.lifecycleState === "sleeping"),
          )
          .map((session) => session.sessionId),
      )
    : project.workspace.groups.flatMap((group) =>
        group.snapshot.sessions
          .filter(
            (session): session is TerminalSessionRecord =>
              session.kind === "terminal" && session.isSleeping === true,
          )
          .map((session) => createCombinedProjectSessionId(project.projectId, session.sessionId)),
      );
  sessionIds.push(
    ...project.commandsPanel.sessions
      .filter((session) => session.isSleeping === true)
      .map((session) => createCombinedProjectSessionId(project.projectId, session.sessionId)),
  );
  if (sessionIds.length === 0) {
    return;
  }
  if (activeProjectId !== project.projectId) {
    focusProject(project.projectId);
  }
  runNativeSidebarBulkActionInBackground(
    sessionIds.map((sessionId) => () => setNativeSessionSleeping(sessionId, false)),
  );
}

function fullReloadProjectZmxSessions(projectId: string): void {
  /**
   * CDXC:ProjectReload 2026-05-27-02:18:
   * Project-row Full reload is a batch action for live zmx-backed terminals,
   * not a history restore. Reload only workspace terminals that are awake,
   * attached to a native zmx terminal, and idle; skip working and attention
   * statuses so active agent work is not interrupted.
   *
   * CDXC:ProjectReload 2026-05-27-06:28:
   * Commands-panel zmx terminals are project sessions too. Include them in the
   * same attached/idle reload pass so titlebar action panes cannot drift out of
   * project-level tracking.
   *
   * CDXC:ProjectReload 2026-06-02-19:10:
   * Full Reload is a native runtime action, but its workspace candidate set must come from gxserver presentation when active so stale native session rows cannot be reloaded outside the rendered sidebar.
   */
  const project = findProject(projectId);
  if (!project) {
    return;
  }
  const presentationGroups = createPresentationSidebarGroups(gxserverStartupSnapshot?.presentation)
    ?.filter((group) => group.projectContext?.editor.projectId === project.projectId);
  if (presentationGroups && presentationGroups.length > 0) {
    const sessionIdsToReload: string[] = [];
    for (const group of presentationGroups) {
      for (const projectedSession of group.sessions) {
        if (shouldFullReloadNativeZmxSession(project, projectedSession.sessionId, projectedSession)) {
          sessionIdsToReload.push(projectedSession.sessionId);
        }
      }
    }
    const commandGroup = createProjectedSidebarGroupsForProject(project).find(
      (group) => group.groupId === COMMANDS_PANEL_SESSION_GROUP_ID,
    );
    for (const projectedSession of commandGroup?.sessions ?? []) {
      const combinedSessionId = createCombinedProjectSessionId(project.projectId, projectedSession.sessionId);
      if (shouldFullReloadNativeZmxSession(project, combinedSessionId, projectedSession)) {
        sessionIdsToReload.push(combinedSessionId);
      }
    }
    runNativeSidebarBulkActionInBackground(
      sessionIdsToReload.map((sessionId) => () => restartNativeSession(sessionId)),
    );
    return;
  }
  const projectedSessionsById = new Map(
    createProjectedSidebarGroupsForProject(project)
      .flatMap((group) => group.sessions)
      .map((session) => [session.sessionId, session]),
  );
  const sessionIdsToReload: string[] = [];

  for (const group of createProjectSessionGroupsForProjection(project)) {
    for (const session of group.snapshot.sessions) {
      if (session.kind !== "terminal") {
        continue;
      }
      const terminalState = terminalStateById.get(session.sessionId);
      const provider =
        terminalState?.sessionPersistenceProvider ??
        session.sessionPersistenceProvider ??
        (session.tmuxSessionName ? "tmux" : undefined);
      if (provider !== "zmx" || terminalState?.lifecycleState !== "running") {
        continue;
      }
      const projectedSession = projectedSessionsById.get(session.sessionId);
      if (projectedSession?.isSleeping === true) {
        continue;
      }
      const activity = projectedSession?.activity ?? terminalState.activity ?? "idle";
      if (activity === "working" || activity === "attention") {
        continue;
      }
      if (!buildNativeRestoredTerminalInitialInput(session).trim()) {
        continue;
      }
      sessionIdsToReload.push(createCombinedProjectSessionId(project.projectId, session.sessionId));
    }
  }

  runNativeSidebarBulkActionInBackground(
    sessionIdsToReload.map((sessionId) => () => restartNativeSession(sessionId)),
  );
}

function shouldFullReloadNativeZmxSession(
  project: NativeProject,
  sidebarSessionId: string,
  projectedSession: SidebarSessionItem | undefined,
): boolean {
  const reference = resolveSidebarSessionReference(sidebarSessionId);
  const session = findTerminalSessionInProject(project, reference.sessionId);
  if (!session) {
    return false;
  }
  const terminalState = terminalStateById.get(reference.sessionId);
  const provider =
    terminalState?.sessionPersistenceProvider ??
    session.sessionPersistenceProvider ??
    (session.tmuxSessionName ? "tmux" : undefined);
  if (provider !== "zmx" || terminalState?.lifecycleState !== "running") {
    return false;
  }
  if (projectedSession?.isSleeping === true || projectedSession?.lifecycleState === "sleeping") {
    return false;
  }
  const activity = projectedSession?.activity ?? terminalState.activity ?? "idle";
  if (activity === "working" || activity === "attention") {
    return false;
  }
  return Boolean(buildNativeRestoredTerminalInitialInput(session).trim());
}

function quitResourcesFromTitlebar(sessionIds: string[], projectIds: string[]): void {
  /**
   * CDXC:TitlebarResources 2026-05-21-16:38:
   * Resource-manager Quit controls must route through the native sidebar adapter so terminal lifecycle changes, Browser panes, and VS Code project-editor state update from one current-window coordinator. Shared terminal mutations still go through gxserver-owned sleep paths.
   *
   * CDXC:TitlebarResources 2026-05-22-23:12:
   * Quitting an agent from the resource manager should free the terminal
   * runtime like the session-tab Sleep action while keeping the sidebar card
   * available for wake/resume. Only non-terminal resources still use the close
   * path because they do not have terminal sleep state.
   *
   * CDXC:TitlebarResources 2026-05-23-10:46:
   * Resource-manager Quit must never remove actual terminal sessions from the
   * sidebar. The titlebar owns process termination from its resource list; the
   * sidebar only records terminal resources as sleeping so users can wake or
   * resume them after RAM is released.
   *
   * CDXC:TitlebarResources 2026-06-02-19:10:
   * Resource rows can be gxserver presentation-only. Terminal quits must still route through setNativeSessionSleeping so gxserver owns lifecycle mutation and macOS only records local-first presentation.
   */
  const backgroundOperations: NativeSidebarBackgroundOperation[] = [];
  for (const projectId of Array.from(new Set(projectIds))) {
    if (findProject(projectId)) {
      backgroundOperations.push(() => disposeProjectEditorSurface(projectId));
    }
  }
  for (const sessionId of Array.from(new Set(sessionIds))) {
    const reference = resolveSidebarSessionReference(sessionId);
    const session = findSessionRecordInProject(reference.project, reference.sessionId);
    const presentationSession = findGxserverPresentationSession(
      reference.project.projectId,
      reference.sessionId,
    );
    if (!session && !presentationSession) {
      continue;
    }
    if (session?.kind === "terminal" || presentationSession?.kind === "terminal") {
      backgroundOperations.push(() => setNativeSessionSleeping(sessionId, true));
    } else {
      backgroundOperations.push(() => closeTerminal(sessionId));
    }
  }
  backgroundOperations.push(() => publish());
  runNativeSidebarBulkActionInBackground(backgroundOperations);
}

function setNativeSessionPoppedOut(sessionId: string, poppedOut: boolean): void {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findSessionRecordInProject(reference.project, reference.sessionId);
  if (!session || session.isSleeping === true) {
    return;
  }
  updateProjectWorkspace(
    reference.project.projectId,
    (workspace) =>
      setSessionPoppedOutInSimpleWorkspace(workspace, reference.sessionId, poppedOut).snapshot,
  );
  /**
   * CDXC:PanePopOut 2026-06-02-15:27:
   * Pop-out placement is macOS current-window layout, not gxserver shared session state. The sidebar adapter owns the local flag while Swift owns native window reparenting; publish immediately so close/reattach sends one layout sync.
   */
  publish();
}

function setNativeGroupSleeping(groupId: string, sleeping: boolean): void {
  const project = activeProject();
  const group = project.workspace.groups.find((candidate) => candidate.groupId === groupId);
  if (!group) {
    return;
  }
  const sessionsToSleep = sleeping
    ? group.snapshot.sessions.filter(
        (session): session is TerminalSessionRecord =>
          session.kind === "terminal" && session.isSleeping !== true,
      )
    : [];
  const sessionsToWake = sleeping
    ? []
    : group.snapshot.sessions.filter(
        (session): session is TerminalSessionRecord =>
          session.kind === "terminal" && session.isSleeping === true,
      );
  const sessionIdsToForceWake = new Set(sessionsToWake.map((session) => session.sessionId));
  const updateGroupSleeping = () => {
    updateProjectWorkspace(
      project.projectId,
      (workspace) =>
        setGroupSleepingInSimpleWorkspace(
          workspace,
          groupId,
          sleeping,
          sleeping ? sessionsToSleep.map((session) => session.sessionId) : undefined,
        ).snapshot,
    );
  };
  if (sleeping) {
    const backgroundOperations: NativeSidebarBackgroundOperation[] = [updateGroupSleeping];
    for (const session of sessionsToSleep) {
      backgroundOperations.push(() => stopNativeSleepingSessionRuntime(session.sessionId, project));
    }
    backgroundOperations.push(() => publish());
    runNativeSidebarBulkActionInBackground(backgroundOperations);
    return;
  }

  runNativeSidebarBulkActionInBackground([
    updateGroupSleeping,
    () => {
      const nextProject = findProject(project.projectId) ?? project;
      const nextGroup = nextProject.workspace.groups.find(
        (candidate) => candidate.groupId === groupId,
      );
      const restoreOperations: NativeSidebarBackgroundOperation[] = [];
      for (const session of nextGroup?.snapshot.sessions ?? []) {
        if (session.kind !== "terminal") {
          continue;
        }
        if (sessionIdsToForceWake.has(session.sessionId)) {
          restoreOperations.push(() =>
            clearStaleTerminalRuntimeStateBeforeWake(
              nextProject.projectId,
              session.sessionId,
              "wake-group",
            ),
          );
        }
        if (sessionIdsToForceWake.has(session.sessionId) || !terminalStateById.has(session.sessionId)) {
          restoreOperations.push(() => restoreNativeTerminalSession(nextProject, session, "wake-group"));
        }
      }
      restoreOperations.push(() => publish());
      runNativeSidebarBulkActionInBackground(restoreOperations);
    },
  ]);
}

function replaceNativeTerminalWithFreshSession(
  reference: ReturnType<typeof resolveSidebarSessionReference>,
  session: TerminalSessionRecord,
  reason: string,
): boolean {
  /**
   * CDXC:SessionSurfaceRecovery 2026-05-23-09:05:
   * A selected awake terminal can lose its native Ghostty surface while the
   * sidebar still has a running terminalState. When the original agent
   * conversation is not restorable, replace the stale record with a fresh shell
   * in the same pane slot so the user always gets a usable terminal instead of
   * an unselectable tab.
   */
  if (activeProjectId !== reference.project.projectId) {
    focusProject(reference.project.projectId);
  }
  const combinedSessionId = createCombinedProjectSessionId(
    reference.project.projectId,
    reference.sessionId,
  );
  const groupId = findSessionGroupId(combinedSessionId) ?? findSessionGroupId(reference.sessionId);
  appendTerminalFocusDebugLog("nativeSidebar.missingSurfaceFreshTerminal.start", {
    activeProjectId,
    agentName: session.agentName,
    groupId,
    reason,
    sessionId: reference.sessionId,
    sessionPersistenceName: session.sessionPersistenceName,
    sessionPersistenceProvider: session.sessionPersistenceProvider,
    title: session.title,
  });
  const replacementSession = createTerminal(
    session.title || DEFAULT_TERMINAL_SESSION_TITLE,
    "",
    groupId,
    undefined,
    {
      visiblePlacement: { kind: "replace", targetSessionId: reference.sessionId },
    },
  );
  if (!replacementSession) {
    appendTerminalFocusDebugLog("nativeSidebar.missingSurfaceFreshTerminal.failed", {
      groupId,
      reason,
      sessionId: reference.sessionId,
    });
    return false;
  }

  const nativeSessionId = forgetNativeSessionMappingForProject(
    reference.project.projectId,
    reference.sessionId,
  );
  clearNativeSidebarCommandSessionBySessionId(reference.sessionId);
  terminalStateById.delete(reference.sessionId);
  pendingNativeTerminalStartupTextBySessionId.delete(reference.sessionId);
  nativeActivitySuppressedUntilBySessionId.delete(reference.sessionId);
  nativeWorkingStartedAtBySessionId.delete(reference.sessionId);
  clearNativeSessionAttentionTracking(reference.sessionId);
  nativeAttentionNotificationLastSentAtBySessionId.delete(reference.sessionId);
  clearDelayedSendTimer(reference.sessionId, reference.project.projectId);
  updateProjectWorkspace(
    reference.project.projectId,
    (workspace) => removeSessionInSimpleWorkspace(workspace, reference.sessionId).snapshot,
  );
  postNative({ sessionId: nativeSessionId, type: "closeTerminal" });
  queueNativeLayoutFocusRequest(replacementSession.sessionId, "missingSurfaceFreshTerminal");
  appendTerminalFocusDebugLog("nativeSidebar.missingSurfaceFreshTerminal.completed", {
    nativeSessionId,
    reason,
    replacementSessionId: replacementSession.sessionId,
    sessionId: reference.sessionId,
  });
  publish();
  return true;
}

function recoverMissingNativeSessionSurface(nativeSessionId: string): void {
  const durableReference = parseDurableNativeSessionId(nativeSessionId);
  const reference =
    durableReference ?? resolveSidebarSessionReference(sidebarSessionIdForNativeSession(nativeSessionId));
  const session = findSessionRecordInProject(reference.project, reference.sessionId);
  appendTerminalFocusDebugLog("nativeSidebar.missingSurfaceRecovery.received", {
    activeProjectId,
    hasSession: Boolean(session),
    nativeSessionId,
    projectId: reference.project.projectId,
    sessionId: reference.sessionId,
    sessionKind: session?.kind,
  });
  if (!session) {
    return;
  }
  if (session.kind === "terminal") {
    const pendingSurfaceCreate = noteNativeTerminalSurfaceMissingDuringPendingCreate(
      reference.project.projectId,
      reference.sessionId,
      nativeSessionId,
    );
    if (pendingSurfaceCreate) {
      appendTerminalFocusDebugLog("nativeSidebar.missingSurfaceRecovery.pendingCreateIgnored", {
        elapsedMs: Date.now() - pendingSurfaceCreate.startedAt,
        nativeSessionId,
        pendingReason: pendingSurfaceCreate.reason,
        projectId: reference.project.projectId,
        sessionId: reference.sessionId,
      });
      return;
    }
    if (canRestoreNativeTerminalSession(session)) {
      restartNativeSession(createCombinedProjectSessionId(reference.project.projectId, reference.sessionId));
      return;
    }
    replaceNativeTerminalWithFreshSession(reference, session, "missingNativeSurface");
    return;
  }
  if (activeProjectId !== reference.project.projectId) {
    focusProject(reference.project.projectId);
  }
  restoreNativeSessionSurfaceForWake(reference.project, session, "missing-native-surface");
  queueNativeLayoutFocusRequest(reference.sessionId, "missingNativeSurface");
  publish();
}

function handleNativeTerminalRestoreBlocked(
  event: Extract<NativeHostEvent, { type: "terminalRestoreBlocked" }>,
): void {
  const durableReference = parseDurableNativeSessionId(event.sessionId);
  const reference =
    durableReference ?? resolveSidebarSessionReference(sidebarSessionIdForNativeSession(event.sessionId));
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  appendTerminalFocusDebugLog("nativeSidebar.restoreBlocked.received", {
    cwd: event.cwd,
    hasSession: Boolean(session),
    nativeSessionId: event.sessionId,
    projectId: reference.project.projectId,
    reason: event.reason,
    sessionId: reference.sessionId,
  });
  if (!session) {
    return;
  }
  /**
   * CDXC:SessionRestore 2026-05-28-16:13:
   * A deleted saved cwd is rare and not worth a custom recovery flow. Keep the
   * UX to one confirmation: cancel leaves the dead row sleeping for later, and
   * Remove Session deletes the sidebar record because restoring it would only
   * recreate the same missing-folder error.
   */
  clearStaleTerminalRuntimeStateBeforeWake(
    reference.project.projectId,
    reference.sessionId,
    "restore-blocked-missing-cwd",
  );
  clearNativeTerminalSurfaceCreationPending(reference.sessionId);
  const shouldRemove = window.confirm(
    [
      "Session can't be restored.",
      "",
      "It points to a folder that no longer exists:",
      event.cwd,
      "",
      "Remove this session from the sidebar?",
    ].join("\n"),
  );
  if (shouldRemove) {
    closeTerminal(createCombinedProjectSessionId(reference.project.projectId, reference.sessionId), {
      preservePersistenceSession: true,
    });
    return;
  }
  setNativeSessionSleeping(createCombinedProjectSessionId(reference.project.projectId, reference.sessionId), true);
}

function prepareGxserverZmxSessionForInPlaceReload(
  reference: ReturnType<typeof resolveSidebarSessionReference>,
): boolean {
  /*
  CDXC:SessionRestore 2026-06-07-06:50:
  zmx Full reload must stop the existing provider before reattaching the same
  G-session. If the provider remains live, gxserver correctly discards startup
  text to protect the running shell, which would turn Full reload into a focus
  operation instead of a real resume.
  */
  try {
    const result = gxserverClient.transitionSessionSync({
      action: "sleep",
      projectId: reference.project.projectId as never,
      reason: "fullReloadSession",
      sessionId: reference.sessionId as never,
    });
    rememberGxserverProviderSessionState(result.session);
    if (result.session.providerState.lifecycleState !== "missing") {
      appendTerminalLaunchDebugLog("nativeSidebar.fullReloadSession.zmxStopIncomplete", {
        lifecycleState: result.session.lifecycleState,
        projectId: reference.project.projectId,
        providerLifecycleState: result.session.providerState.lifecycleState,
        sessionId: reference.sessionId,
      });
      showNativeMessage("error", "Full reload could not stop the existing zmx session.");
      return false;
    }
    return true;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    appendTerminalLaunchDebugLog("nativeSidebar.fullReloadSession.zmxStopFailed", {
      messageLength: message.length,
      projectId: reference.project.projectId,
      sessionId: reference.sessionId,
    });
    showNativeMessage("error", message);
    return false;
  }
}

function restartNativeSession(sessionId: string): void {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  if (!session) {
    return;
  }
  /**
   * CDXC:SessionRestore 2026-04-27-08:04
   * Right-click Full reload follows agent-tiler semantics in native ghostex:
   * recreate the terminal as the same agent type, then immediately send the
   * agent-specific resume command instead of opening a fresh shell.
   *
   * CDXC:SessionRestore 2026-06-07-06:50:
   * Sidebar Full reload must reload the clicked session in place. Preserve the
   * existing sidebar/G-session id and native durable session id instead of
   * allocating a new gxserver terminal record, because the presentation sidebar
   * would otherwise render the old row plus the replacement row as duplicates.
   */
  if (activeProjectId !== reference.project.projectId) {
    focusProject(reference.project.projectId);
  }
  const sessionPersistenceProvider = resolveTerminalSessionPersistenceProvider();
  const nativeSessionId = rememberNativeSessionMapping(
    reference.project.projectId,
    reference.sessionId,
  );
  markNativeInPlaceReloadClosePending(reference.sessionId, nativeSessionId);
  if (
    sessionPersistenceProvider === "zmx" &&
    !prepareGxserverZmxSessionForInPlaceReload(reference)
  ) {
    nativeInPlaceReloadCloseBySessionId.delete(reference.sessionId);
    return;
  }
  pendingNativeTerminalStartupTextBySessionId.delete(reference.sessionId);
  nativeActivitySuppressedUntilBySessionId.delete(reference.sessionId);
  nativeWorkingStartedAtBySessionId.delete(reference.sessionId);
  clearNativeSessionAttentionTracking(reference.sessionId);
  nativeAttentionNotificationLastSentAtBySessionId.delete(reference.sessionId);
  clearDelayedSendTimer(reference.sessionId, reference.project.projectId);
  postNative({
    preservePersistenceSession: sessionPersistenceProvider === "zmx",
    sessionId: nativeSessionId,
    type: "closeTerminal",
  });
  restoreNativeTerminalSession(
    reference.project,
    session,
    sessionPersistenceProvider === "zmx" ? "full-reload-wake" : "full-reload",
    {
      focusAfterReady: {
        reason: "fullReloadSession",
        surface: "workspaceTerminal",
      },
    },
  );
  publish();
}

async function forkNativeSession(sessionId: string): Promise<void> {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  const groupId = findSessionGroupId(sessionId);
  if (!session && !findGxserverPresentationSession(reference.project.projectId, reference.sessionId)) {
    return;
  }
  if (activeProjectId !== reference.project.projectId) {
    focusProject(reference.project.projectId);
  }
  const targetGroup = reference.project.workspace.groups.find((group) => group.groupId === groupId);
  const visiblePlacement: VisibleSessionPlacement | undefined =
    targetGroup?.snapshot.visibleSessionIds.includes(reference.sessionId) === true
      ? { kind: "appendToTabGroup", targetSessionId: reference.sessionId }
      : createFocusedTabGroupPlacement(groupId);
  /**
   * CDXC:PaneTabs 2026-05-11-18:13
   * Forking from a title-bar or sidebar session is a tab creation action, not a
   * layout rebuild. Attach the fork to the clicked session's existing tab group
   * so fork cannot flatten grouped tabs into one-tab split panes.
   */
  appendPaneLayoutTraceDebugLog("forkSession.placementResolved", {
    activeProjectId,
    groupId,
    projectId: reference.project.projectId,
    targetGroup: summarizeWorkspaceGroupForPaneLayoutTrace(reference.project.workspace, groupId),
    targetSessionId: reference.sessionId,
    visiblePlacement: summarizeVisiblePlacement(visiblePlacement),
  });
  try {
    const fork = await gxserverClient.forkSession({
      projectId: reference.project.projectId as never,
      sessionId: reference.sessionId as never,
    });
    materializeNativeForkedGxserverSession(reference.project, fork.session, groupId, visiblePlacement);
  } catch (error) {
    showAppToast(
      "error",
      "Could not fork session",
      error instanceof Error ? error.message : String(error),
    );
  }
}

function materializeNativeForkedGxserverSession(
  project: NativeProject,
  gxserverSession: GxserverSessionDomainState,
  groupId: string | undefined,
  visiblePlacement: VisibleSessionPlacement | undefined,
): TerminalSessionRecord | undefined {
  /*
  CDXC:GxserverForkSession 2026-06-04-07:42:
  gxserver owns fork session creation and provider startup. Native only materializes the returned G-session into the clicked tab group, preserving macOS pane placement without reconstructing Codex/Claude/Pi fork commands locally.
  */
  const targetWorkspace = groupId
    ? focusGroupInSimpleWorkspace(project.workspace, groupId).snapshot
    : project.workspace;
  const agentName = textValue(gxserverSession.agentId) ?? textValue(gxserverSession.runtimeSettings.agentName);
  const result = createSessionInSimpleWorkspace(
    targetWorkspace,
    {
      agentName,
      agentSessionId: textValue(gxserverSession.runtimeSettings.agentSessionId),
      agentSessionPath: textValue(gxserverSession.runtimeSettings.agentSessionPath),
      initialPresentation: "focused",
      sessionId: gxserverSession.sessionId,
      sessionPersistenceName: gxserverSession.zmxName,
      sessionPersistenceProvider: "zmx",
      terminalEngine: "ghostty-native",
      title: gxserverSession.title || DEFAULT_TERMINAL_SESSION_TITLE,
      titleSource: readGxserverRuntimeTitleSource(gxserverSession.runtimeSettings.titleSource),
    },
    visiblePlacement ? { visiblePlacement } : undefined,
  );
  const session = result.session?.kind === "terminal" ? result.session : undefined;
  if (!session) {
    return undefined;
  }
  updateProjectWorkspace(project.projectId, () => result.snapshot);
  const nativeSessionId = rememberNativeSessionMapping(project.projectId, session.sessionId);
  const sessionStateFilePath = createNativeSessionStateFilePath(project.projectId, session.sessionId);
  terminalStateById.set(session.sessionId, {
    activity: "working",
    agentName,
    agentSessionId: session.agentSessionId,
    agentSessionPath: session.agentSessionPath,
    lifecycleState: "running",
    sessionPersistenceName: gxserverSession.zmxName,
    sessionPersistenceProvider: "zmx",
    sessionStateFilePath,
    terminalTitle: session.title,
  });
  scheduleSettledTerminalTitleSync(session.sessionId, "fork-session-created");
  markNativeTerminalSurfaceCreationPending(project.projectId, session.sessionId, nativeSessionId, "fork-session");
  const nativeEnvironment = createNativeAgentSessionEnvironment({
    agentName,
    project,
    sessionId: session.sessionId,
    sessionStateFilePath,
  });
  void postNativeCreateTerminalWithGxserverAttach({
    activateOnCreate: false,
    cwd: gxserverSession.cwd ?? project.path,
    diagnosticSource: "fork-session",
    env: nativeEnvironment,
    initialInput: "",
    sessionId: nativeSessionId,
    sessionPersistenceName: gxserverSession.zmxName,
    sessionPersistenceProvider: "zmx",
    title: session.title,
    type: "createTerminal",
  }, project, session.sessionId, "", {
    focusAfterCreate: true,
  });
  return session;
}

function promptDelayedSend(sessionId: string): void {
  const session = findSessionRecord(sessionId);
  if (!session || session.kind !== "terminal") {
    return;
  }
  const delayedSend = getDelayedSendProjectionForSidebarSession(sessionId);
  openAppModal({
    delayedSendDeadlineAt: delayedSend?.deadlineAt,
    delayedSendRemainingLabel: delayedSend?.remainingLabel,
    modal: "delayedSend",
    sessionId,
    title: session.title || DEFAULT_TERMINAL_SESSION_TITLE,
    type: "open",
  });
}

function normalizeDelayedSendDeadlineAt(value: string | undefined): string | undefined {
  const normalized = value?.trim();
  return normalized && !Number.isNaN(Date.parse(normalized)) ? normalized : undefined;
}

function isTerminalDelayedSendPersistenceEligible(session: TerminalSessionRecord): boolean {
  const provider = session.sessionPersistenceProvider ?? (session.tmuxSessionName ? "tmux" : undefined);
  return provider === "zmx" || provider === "tmux" || provider === "zellij";
}

function hasRestorableDelayedSendDeadline(session: TerminalSessionRecord): boolean {
  return (
    isTerminalDelayedSendPersistenceEligible(session) &&
    normalizeDelayedSendDeadlineAt(session.delayedSendDeadlineAt) !== undefined
  );
}

function hasStartupRestoreActivityWake(session: TerminalSessionRecord): boolean {
  return session.restoreActivity === "attention" || session.restoreActivity === "working";
}

function restoreDelayedSendTimersFromStoredProjects(): void {
  /**
   * CDXC:DelayedSend 2026-05-21-12:21:
   * Restart must remember active Delayed Send timers for persisted terminal
   * sessions and wake those sessions so the pending Enter key still fires. Use
   * the stored terminal deadline as the single source of truth and give expired
   * deadlines a short grace window so native restore can attach before sending.
   */
  for (const project of projects) {
    for (const session of project.commandsPanel.sessions) {
      restoreDelayedSendTimerForStoredSession(project, session);
    }
    for (const group of project.workspace.groups) {
      for (const session of group.snapshot.sessions) {
        if (session.kind === "terminal") {
          restoreDelayedSendTimerForStoredSession(project, session);
        }
      }
    }
  }
}

function restoreDelayedSendTimerForStoredSession(
  project: NativeProject,
  session: TerminalSessionRecord,
): void {
  if (!hasRestorableDelayedSendDeadline(session)) {
    return;
  }
  const deadlineAt = normalizeDelayedSendDeadlineAt(session.delayedSendDeadlineAt);
  if (!deadlineAt) {
    return;
  }
  const nativeSessionId = nativeSessionIdForProjectSidebarSession(project.projectId, session.sessionId);
  if (delayedSendTimerByNativeSessionId.has(nativeSessionId)) {
    return;
  }
  const deadlineAtMs = Date.parse(deadlineAt);
  const restoreDelayMs = Math.max(
    DELAYED_SEND_RESTORE_FIRE_GRACE_MS,
    deadlineAtMs - Date.now(),
  );
  installDelayedSendTimer(project.projectId, session.sessionId, deadlineAtMs, restoreDelayMs);
}

function setStoredDelayedSendDeadline(
  projectId: string,
  sessionId: string,
  deadlineAt: string | undefined,
  reason: string,
): boolean {
  const normalizedDeadlineAt = normalizeDelayedSendDeadlineAt(deadlineAt);
  let didChange = false;
  projects = projects.map((project) => {
    if (project.projectId !== projectId) {
      return project;
    }

    let projectDidChange = false;
    const nextCommandSessions = project.commandsPanel.sessions.map((session) => {
      const nextSession = updateTerminalSessionDelayedSendDeadline(
        session,
        sessionId,
        normalizedDeadlineAt,
      );
      projectDidChange ||= nextSession !== session;
      return nextSession;
    });
    const nextGroups = project.workspace.groups.map((group) => {
      let groupDidChange = false;
      const nextSessions = group.snapshot.sessions.map((session) => {
        if (session.kind !== "terminal") {
          return session;
        }
        const nextSession = updateTerminalSessionDelayedSendDeadline(
          session,
          sessionId,
          normalizedDeadlineAt,
        );
        groupDidChange ||= nextSession !== session;
        return nextSession;
      });
      projectDidChange ||= groupDidChange;
      return groupDidChange
        ? {
            ...group,
            snapshot: {
              ...group.snapshot,
              sessions: nextSessions,
            },
          }
        : group;
    });

    if (!projectDidChange) {
      return project;
    }

    didChange = true;
    return {
      ...project,
      commandsPanel: {
        ...project.commandsPanel,
        sessions: nextCommandSessions,
      },
      workspace: {
        ...project.workspace,
        groups: nextGroups,
      },
    };
  });

  if (didChange) {
    writeStoredProjects(reason);
  }
  return didChange;
}

function updateTerminalSessionDelayedSendDeadline(
  session: TerminalSessionRecord,
  sessionId: string,
  deadlineAt: string | undefined,
): TerminalSessionRecord {
  if (session.sessionId !== sessionId) {
    return session;
  }
  if (normalizeDelayedSendDeadlineAt(session.delayedSendDeadlineAt) === deadlineAt) {
    return session;
  }
  if (deadlineAt) {
    return {
      ...session,
      delayedSendDeadlineAt: deadlineAt,
    };
  }
  const { delayedSendDeadlineAt: _removedDelayedSendDeadlineAt, ...sessionWithoutDeadline } = session;
  return sessionWithoutDeadline;
}

function installDelayedSendTimer(
  projectId: string,
  sessionId: string,
  deadlineAtMs: number,
  delayMs: number,
): void {
  const nativeSessionId = nativeSessionIdForProjectSidebarSession(projectId, sessionId);
  const existingTimer = delayedSendTimerByNativeSessionId.get(nativeSessionId);
  if (existingTimer !== undefined) {
    window.clearTimeout(existingTimer.timeoutId);
  }

  const timeout = window.setTimeout(() => {
    delayedSendTimerByNativeSessionId.delete(nativeSessionId);
    setStoredDelayedSendDeadline(projectId, sessionId, undefined, "delayedSendFired");
    stopDelayedSendCountdownTickerIfIdle();
    publish();
    const currentProject = findProject(projectId);
    const currentSession = currentProject
      ? findSessionRecordInProject(currentProject, sessionId)
      : undefined;
    if (!currentSession || currentSession.kind !== "terminal" || currentSession.isSleeping === true) {
      return;
    }
    postNative({
      sessionId: nativeSessionId,
      type: "sendTerminalEnter",
    });
  }, delayMs);

  delayedSendTimerByNativeSessionId.set(nativeSessionId, {
    deadlineAtMs,
    projectId,
    sessionId,
    timeoutId: timeout,
  });
  ensureDelayedSendCountdownTicker();
}

function scheduleDelayedSend(sessionId: string, delayMs: number): void {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findSessionRecordInProject(reference.project, reference.sessionId);
  if (!session || session.kind !== "terminal") {
    showNativeMessage("info", "Delayed Send is only available for terminal sessions.");
    return;
  }
  if (!Number.isFinite(delayMs) || delayMs <= 0 || delayMs > DELAYED_SEND_MAX_DELAY_MS) {
    showNativeMessage("warning", "Choose a Delayed Send timer between 1 second and 24 days.");
    return;
  }

  /**
   * CDXC:DelayedSend 2026-05-11-11:56
   * Delayed Send must press Enter in the existing terminal after the requested
   * wait, so use the native sendTerminalEnter command instead of writing a
   * carriage return as terminal text.
   *
   * CDXC:DelayedSend 2026-05-17-03:14
   * The pending Enter needs to remain inspectable and cancellable until it
   * fires, so record the exact deadline and refresh published UI countdowns
   * once per second while any Delayed Send timer exists.
   */
  const deadlineAtMs = Date.now() + delayMs;
  installDelayedSendTimer(reference.project.projectId, reference.sessionId, deadlineAtMs, delayMs);
  setStoredDelayedSendDeadline(
    reference.project.projectId,
    reference.sessionId,
    isTerminalDelayedSendPersistenceEligible(session) ? new Date(deadlineAtMs).toISOString() : undefined,
    "scheduleDelayedSend",
  );
  publish();
  /**
   * CDXC:DelayedSend 2026-05-21-12:21:
   * Scheduling a Delayed Send should acknowledge with the bottom-center
   * app-modal toast layer, matching worktree progress feedback, instead of a
   * blocking macOS alert that forces users to press OK before returning to the
   * terminal prompt they just staged.
   */
  showAppToast(
    "info",
    "Delayed Send scheduled",
    `Presses Enter in ${formatDelayedSendDelay(delayMs)}.`,
  );
}

function cancelDelayedSend(sessionId: string): void {
  if (!clearDelayedSendTimer(sessionId)) {
    /*
     * CDXC:DelayedSend 2026-05-21-12:21:
     * Canceling Delayed Send is status feedback, not a blocking decision. Use
     * the app toast layer so the terminal keeps focus and users do not have to
     * dismiss a macOS alert after canceling or finding no active timer.
     */
    showAppToast("info", "No Delayed Send timer is active");
    return;
  }
  publish();
  showAppToast("info", "Delayed Send canceled");
}

function clearDelayedSendTimer(sessionId: string, projectId?: string): boolean {
  const nativeSessionId = projectId
    ? nativeSessionIdForProjectSidebarSession(projectId, sessionId)
    : nativeSessionIdForSidebarSession(sessionId);
  const timer = delayedSendTimerByNativeSessionId.get(nativeSessionId);
  if (timer === undefined) {
    return false;
  }
  window.clearTimeout(timer.timeoutId);
  delayedSendTimerByNativeSessionId.delete(nativeSessionId);
  setStoredDelayedSendDeadline(timer.projectId, timer.sessionId, undefined, "cancelDelayedSend");
  stopDelayedSendCountdownTickerIfIdle();
  return true;
}

function getDelayedSendProjectionForSidebarSession(
  sessionId: string,
): { deadlineAt: string; remainingLabel: string; remainingMs: number } | undefined {
  const reference = resolveSidebarSessionReference(sessionId);
  return getDelayedSendProjectionForProjectSession(reference.project.projectId, reference.sessionId);
}

function getDelayedSendProjectionForProjectSession(
  projectId: string,
  sessionId: string,
): { deadlineAt: string; remainingLabel: string; remainingMs: number } | undefined {
  const nativeSessionId = nativeSessionIdForProjectSidebarSession(projectId, sessionId);
  const timer = delayedSendTimerByNativeSessionId.get(nativeSessionId);
  if (!timer) {
    return undefined;
  }
  const remainingMs = timer.deadlineAtMs - Date.now();
  if (remainingMs <= 0) {
    return {
      deadlineAt: new Date(timer.deadlineAtMs).toISOString(),
      remainingLabel: formatDelayedSendCountdown(0),
      remainingMs: 0,
    };
  }
  return {
    deadlineAt: new Date(timer.deadlineAtMs).toISOString(),
    remainingLabel: formatDelayedSendCountdown(remainingMs),
    remainingMs,
  };
}

function ensureDelayedSendCountdownTicker(): void {
  if (delayedSendCountdownTicker !== undefined) {
    return;
  }
  delayedSendCountdownTicker = window.setInterval(() => {
    if (delayedSendTimerByNativeSessionId.size === 0) {
      stopDelayedSendCountdownTickerIfIdle();
      return;
    }
    publish();
  }, 1_000);
}

function stopDelayedSendCountdownTickerIfIdle(): void {
  if (delayedSendTimerByNativeSessionId.size > 0 || delayedSendCountdownTicker === undefined) {
    return;
  }
  window.clearInterval(delayedSendCountdownTicker);
  delayedSendCountdownTicker = undefined;
}

function formatDelayedSendDelay(delayMs: number): string {
  const totalSeconds = Math.max(1, Math.round(delayMs / 1_000));
  const hours = Math.floor(totalSeconds / 3_600);
  const minutes = Math.floor((totalSeconds % 3_600) / 60);
  const seconds = totalSeconds % 60;
  const parts = [
    hours > 0 ? `${hours}h` : undefined,
    minutes > 0 ? `${minutes}m` : undefined,
    seconds > 0 ? `${seconds}s` : undefined,
  ].filter((part): part is string => part !== undefined);
  return parts.join(" ") || "1s";
}

function formatDelayedSendCountdown(delayMs: number): string {
  const totalSeconds = Math.max(0, Math.ceil(delayMs / 1_000));
  const hours = Math.floor(totalSeconds / 3_600);
  const minutes = Math.floor((totalSeconds % 3_600) / 60);
  const seconds = totalSeconds % 60;
  const paddedMinutes = String(minutes).padStart(2, "0");
  const paddedSeconds = String(seconds).padStart(2, "0");
  if (hours > 0) {
    return `${String(hours).padStart(2, "0")}:${paddedMinutes}:${paddedSeconds}`;
  }
  return `${paddedMinutes}:${paddedSeconds}`;
}

function findSidebarSessionForCli(
  selector: NativeCliSessionSelector,
): SidebarSessionItem | undefined {
  const sidebarMessage = buildSidebarMessage();
  const sessions = sidebarMessage.groups.flatMap((group) => group.sessions);
  if (selector.sessionId) {
    return sessions.find((session) => session.sessionId === selector.sessionId);
  }
  if (typeof selector.sessionNumber === "number") {
    return sessions.find((session) => session.sessionNumber === selector.sessionNumber);
  }
  if (typeof selector.index === "number") {
    return sessions[selector.index];
  }
  const titleSelector = selector.selectorTitle?.trim().toLowerCase();
  if (titleSelector) {
    const projectSelector = selector.project?.trim().toLowerCase();
    const scopedSessions = projectSelector
      ? sidebarMessage.groups
          .filter((group) => {
            return group.title?.toLowerCase() === projectSelector;
          })
          .flatMap((group) => group.sessions)
      : sessions;
    /**
     * CDXC:CliSessionSelectors 2026-05-23-13:18:
     * Agent orchestration commands should target another sidebar session by
     * either stable id or quoted title. Match titles exact first and substring
     * second so human-readable thread names work without hiding sessions.
     */
    const sessionTitle = (session: SidebarSessionItem | undefined) =>
      (session?.primaryTitle ?? session?.terminalTitle ?? session?.alias ?? "").toLowerCase();
    return (
      scopedSessions.find((session) => sessionTitle(session) === titleSelector) ??
      scopedSessions.find((session) => sessionTitle(session).includes(titleSelector))
    );
  }
  const focusedSessionId = activeSnapshot().focusedSessionId;
  return focusedSessionId
    ? sessions.find((session) => session.sessionId === focusedSessionId)
    : sessions[0];
}

function listNativeCliSessions(): NativeCliSessionListItem[] {
  const sidebarMessage = buildSidebarMessage();
  if (gxserverStartupSnapshot?.presentation) {
    return listNativeCliSessionsFromSidebarMessage(sidebarMessage);
  }
  return listNativeCliSessionsFromNativeProjects();
}

function listNativeCliSessionsFromSidebarMessage(
  sidebarMessage: SidebarHydrateMessage,
): NativeCliSessionListItem[] {
  const items: NativeCliSessionListItem[] = [];
  /*
  CDXC:CliSessions 2026-06-02-18:23:
  The CLI session inventory is a user-facing view of the same sessions as the macOS sidebar. After gxserver presentation is available, build it from the hydrate groups instead of walking the old native project tree so stale pre-cutover sessions cannot remain visible through `gx listSessions`.
  */
  for (const group of sidebarMessage.groups) {
    const projectContext = group.projectContext;
    for (const sidebarSession of group.sessions) {
      if (sidebarSession.sessionKind !== "terminal" && sidebarSession.sessionKind !== "t3") {
        continue;
      }
      const combinedReference = parseCombinedProjectSessionId(sidebarSession.sessionId);
      const projectId =
        projectContext?.editor.projectId ??
        combinedReference?.projectId ??
        group.groupId;
      const localSession = findLocalTerminalSessionForSidebarSession(sidebarSession.sessionId);
      const agentResumePlan = localSession ? readGxserverAgentResumePlanSync(localSession) : undefined;
      const provider = sidebarSession.sessionPersistenceProvider;
      const providerSessionName = sidebarSession.sessionPersistenceName;
      const status = getNativeCliSessionStatusFromSidebarSession(sidebarSession);
      const ownership = resolveNativeSessionInventoryOwnership({
        hasGxserverProjectContext:
          sidebarSession.sessionKind === "terminal" && Boolean(projectContext),
        hasGxserverSessionReference:
          sidebarSession.sessionKind === "terminal" && Boolean(combinedReference),
      });
      items.push({
        activity: sidebarSession.activity,
        agent: sidebarSession.agentIcon,
        alias: items.length + 1,
        attachCommand:
          provider && providerSessionName && status !== "sleep"
            ? buildNativeCliAttachCommand(provider, providerSessionName)
            : undefined,
        groupId: group.groupId,
        groupTitle: group.title,
        isFavorite: sidebarSession.isFavorite,
        isFocused: sidebarSession.isFocused,
        isLocalOnly: ownership.isLocalOnly,
        isLive: sidebarSession.isLive,
        isVisible: sidebarSession.isVisible,
        lastInteractionAt: sidebarSession.lastInteractionAt ?? new Date().toISOString(),
        nativePaneState: sidebarSession.nativePaneState,
        ownership: ownership.ownership,
        projectId,
        projectName: group.title,
        projectPath: projectContext?.path ?? "",
        provider,
        providerSessionName,
        providerSessionState: sidebarSession.providerSessionState,
        resumeFallbackCommand: agentResumePlan?.fallbackCommand,
        resumeCommand: agentResumePlan?.copyCommand,
        sessionId: sidebarSession.sessionId,
        status,
        title:
          sidebarSession.displayTitle ??
          sidebarSession.primaryTitle ??
          sidebarSession.terminalTitle ??
          sidebarSession.alias ??
          DEFAULT_TERMINAL_SESSION_TITLE,
      });
    }
  }
  return items;
}

function findLocalTerminalSessionForSidebarSession(
  sidebarSessionId: string,
): TerminalSessionRecord | undefined {
  return findLocalTerminalSessionReferenceForSidebarSession(sidebarSessionId)?.session;
}

function findLocalTerminalSessionReferenceForSidebarSession(
  sidebarSessionId: string,
): { project: NativeProject; session: TerminalSessionRecord } | undefined {
  const combinedReference = parseCombinedProjectSessionId(sidebarSessionId);
  if (combinedReference) {
    const project = findProject(combinedReference.projectId);
    const session = project ? findTerminalSessionInProject(project, combinedReference.sessionId) : undefined;
    return project && session ? { project, session } : undefined;
  }
  for (const project of projects) {
    const session = findTerminalSessionInProject(project, sidebarSessionId);
    if (session) {
      return { project, session };
    }
  }
  return undefined;
}

function getNativeCliSessionStatusFromSidebarSession(
  session: SidebarSessionItem,
): NativeCliSessionListItem["status"] {
  if (session.lifecycleState === "error") {
    return "error";
  }
  if (session.lifecycleState === "done") {
    return "done";
  }
  if (session.lifecycleState === "sleeping" || session.isSleeping === true) {
    return "sleep";
  }
  return session.activity;
}

function listNativeCliSessionsFromNativeProjects(): NativeCliSessionListItem[] {
  const items: NativeCliSessionListItem[] = [];
  const orderedProjects = orderNativeProjectsForSidebar(projects).filter(
    (project) => project.isRecentProject !== true,
  );
  for (const project of orderedProjects) {
    for (const group of createProjectSessionGroupsForProjection(project)) {
      const projectedSessions = createProjectedSidebarSessionsForGroup(group, project.projectId);
      const terminalProjectedSessions = projectedSessions.filter((projectedSession) => {
        const sessionRecord = group.snapshot.sessions.find(
          (candidate) => candidate.sessionId === projectedSession.sessionId,
        );
        return sessionRecord?.kind === "terminal";
      });
      const sessionsById = Object.fromEntries(
        terminalProjectedSessions.map((projectedSession) => [projectedSession.sessionId, projectedSession]),
      );
      const manualSessionIds = terminalProjectedSessions.map((projectedSession) => projectedSession.sessionId);
      /**
       * CDXC:CliSessions 2026-05-20-12:20:
       * The human `ghostex` / `gx` session list must follow the same project,
       * group, and per-group session order the macOS sidebar renders, including
       * the active Last Active sort mode. Build the CLI inventory from the
       * display layout instead of raw workspace storage order.
       */
      const displayLayout = createDisplaySessionLayout({
        sessionIdsByGroup: { [group.groupId]: manualSessionIds },
        sessionsById,
        sortMode: activeSessionsSortMode,
        workspaceGroupIds: [group.groupId],
      });
      const visualSessionIds = displayLayout.sessionIdsByGroup[group.groupId] ?? manualSessionIds;
      for (const sessionId of visualSessionIds) {
        const session = group.snapshot.sessions.find(
          (candidate): candidate is TerminalSessionRecord =>
            candidate.sessionId === sessionId && candidate.kind === "terminal",
        );
        if (!session) {
          continue;
        }
        const projectedSession = sessionsById[sessionId];
        const terminalState = terminalStateById.get(session.sessionId);
        const provider =
          terminalState?.sessionPersistenceProvider ??
          session.sessionPersistenceProvider ??
          (session.tmuxSessionName ? "tmux" : undefined);
        const providerSessionName =
          terminalState?.sessionPersistenceName ??
          session.sessionPersistenceName ??
          session.tmuxSessionName;
        const providerSessionState = getProviderSessionStateForSession(project.projectId, session);
        const nativePaneState = getNativePaneStateForSession(session.sessionId);
        const isLive = isSessionLiveFromResourceStates(nativePaneState, providerSessionState);
        const status = getNativeCliSessionStatus(
          session,
          projectedSession,
          terminalState,
          providerSessionState,
        );
        /**
         * CDXC:CliSessions 2026-05-07-21:22
         * The human CLI session area needs one stable live-session inventory
         * from the sidebar runtime. It includes global aliases, project context,
         * activity, provider attach commands, and agent resume commands so the
         * Node CLI can render tables and exec the correct local command without
         * scraping debug state.
         */
        const effectiveAgentName =
          resolveNativeResumeAgentIdForSession(session) ?? terminalState?.agentName ?? session.agentName;
        const agentResumePlan = readGxserverAgentResumePlanSync(session);
        items.push({
          /**
           * CDXC:GhostexTui 2026-05-25-16:22:
           * Bare `gx` TUI polls the CLI inventory for sidebar activity so it
           * can render working/attention dots, attached-view counts, and bell
           * notifications using the same state as the macOS sidebar.
           */
          activity: projectedSession?.activity ?? terminalState?.activity ?? "idle",
          agent: effectiveAgentName,
          alias: items.length + 1,
          attachCommand:
            provider && providerSessionName && status !== "sleep"
              ? buildNativeCliAttachCommand(provider, providerSessionName)
              : undefined,
          groupId: group.groupId,
          groupTitle: group.title,
          /**
           * CDXC:GhostexTui 2026-05-25-18:08:
           * The `gx` TUI context menu mirrors the sidebar session menu and
           * needs the favorite state to render Favorite/Unfavorite correctly
           * before invoking the existing CLI favorite-session bridge action.
           */
          isFavorite: session.isFavorite,
          isFocused: group.snapshot.focusedSessionId === session.sessionId,
          isLocalOnly: true,
          isLive,
          isVisible: Boolean(projectedSession?.isVisible),
          lastInteractionAt:
            projectedSession?.lastInteractionAt ?? terminalState?.lastActivityAt ?? session.createdAt,
          nativePaneState,
          ownership: "local",
          projectId: project.projectId,
          projectName: project.name,
          projectPath: project.path,
          provider,
          providerSessionState,
          providerSessionName,
          resumeFallbackCommand: agentResumePlan?.fallbackCommand,
          resumeCommand: agentResumePlan?.copyCommand,
          sessionId: createCombinedProjectSessionId(project.projectId, session.sessionId),
          status,
          title:
            projectedSession?.displayTitle ??
            projectedSession?.primaryTitle ??
            getSessionCardPrimaryTitle(session) ??
            session.title ??
            DEFAULT_TERMINAL_SESSION_TITLE,
        });
      }
    }
  }
  return items;
}

function getNativeCliSessionStatus(
  session: TerminalSessionRecord,
  projectedSession: SidebarSessionItem | undefined,
  terminalState:
    | {
        activity: "attention" | "idle" | "working";
        lifecycleState: "done" | "error" | "running" | "sleeping";
      }
    | undefined,
  providerSessionState: ProviderSessionState = "unknown",
): NativeCliSessionListItem["status"] {
  if (providerSessionState === "exists") {
    return projectedSession?.activity ?? terminalState?.activity ?? "idle";
  }
  if (session.isSleeping === true || terminalState?.lifecycleState === "sleeping") {
    return "sleep";
  }
  if (terminalState?.lifecycleState === "error") {
    return "error";
  }
  if (terminalState?.lifecycleState === "done") {
    return "done";
  }
  return projectedSession?.activity ?? terminalState?.activity ?? "idle";
}

function buildNativeCliAttachCommand(
  provider: TerminalSessionPersistenceProvider,
  sessionName: string,
): string {
  const quotedName = quoteNativeShellArg(sessionName);
  switch (provider) {
    case "tmux":
      return `tmux attach-session -t ${quotedName}`;
    case "zmx":
      return `zmx attach ${quotedName}`;
    case "zellij":
      return `zellij attach ${quotedName}`;
  }
}

function summarizeCreatedCliSession(session: TerminalSessionRecord | undefined) {
  if (!session) {
    return undefined;
  }
  const project = activeProject();
  const group = project.workspace.groups.find((candidate) =>
    candidate.snapshot.sessions.some((candidateSession) => candidateSession.sessionId === session.sessionId),
  );
  return {
    ghostexId: createCombinedProjectSessionId(project.projectId, session.sessionId),
    groupId: group?.groupId,
    projectId: project.projectId,
    sessionId: session.sessionId,
    title: session.title ?? DEFAULT_TERMINAL_SESSION_TITLE,
  };
}

function summarizeCliSessionRecord(session: SessionRecord | undefined) {
  if (!session) {
    return undefined;
  }
  const project = activeProject();
  return {
    ghostexId: createCombinedProjectSessionId(project.projectId, session.sessionId),
    projectId: project.projectId,
    sessionId: session.sessionId,
    title: "title" in session ? session.title : DEFAULT_TERMINAL_SESSION_TITLE,
  };
}

function requireCliSession(payload: Record<string, unknown>): SidebarSessionItem {
  const session = findSidebarSessionForCli({
    index: typeof payload.index === "number" ? payload.index : undefined,
    project: typeof payload.project === "string" ? payload.project : undefined,
    selectorTitle: typeof payload.selectorTitle === "string" ? payload.selectorTitle : undefined,
    sessionId: typeof payload.sessionId === "string" ? payload.sessionId : undefined,
    sessionNumber: typeof payload.sessionNumber === "number" ? payload.sessionNumber : undefined,
  });
  if (!session) {
    throw new Error("No matching session was found.");
  }
  return session;
}

function terminalTextForCliKey(key: unknown): string | undefined {
  switch (String(key)) {
    case "ctrl-c":
    case "Control+C":
      return "\u0003";
    case "escape":
    case "Escape":
      return "\u001b";
    case "tab":
    case "Tab":
      return "\t";
    case "arrow-up":
    case "ArrowUp":
      return "\u001b[A";
    case "arrow-down":
    case "ArrowDown":
      return "\u001b[B";
    case "arrow-right":
    case "ArrowRight":
      return "\u001b[C";
    case "arrow-left":
    case "ArrowLeft":
      return "\u001b[D";
    default:
      return undefined;
  }
}

function summarizeCliState() {
  const sidebarMessage = buildSidebarMessage();
  return {
    activeProjectId,
    projects: summarizeCliStateProjects(sidebarMessage),
    revision,
    sidebar: {
      groups: sidebarMessage.groups,
      hud: sidebarMessage.hud,
      /*
      CDXC:GxserverPresentationSearch 2026-06-02-18:58:
      `gx state` reports the rendered sidebar contract, not native's transient previous-session request cache. Use the hydrate payload so gxserver-owned history does not leak back into CLI state as a revived macOS-owned storage surface after a modal/search request.
      */
      previousSessions: sidebarMessage.previousSessions,
    },
    terminalStates: Object.fromEntries(
      [...terminalStateById.entries()].map(([sessionId, state]) => [
        sessionId,
        {
          ...state,
          nativeSessionId: nativeSessionIdForSidebarSession(sessionId),
        },
      ]),
    ),
  };
}

function summarizeCliStateProjects(
  sidebarMessage: SidebarHydrateMessage,
): Array<{
  activeGroupId?: string;
  groupCount: number;
  isActive: boolean;
  name: string;
  path: string;
  projectId: string;
}> {
  if (gxserverStartupSnapshot?.presentation) {
    /*
    CDXC:CliSessions 2026-06-02-18:34:
    `gx state` is a debug view of the rendered sidebar. Once gxserver presentation is active, summarize projects from hydrate groups instead of the old native project tree so stale local rows do not look canonical in automation output.
    */
    return sidebarMessage.groups.flatMap((group) => {
      const projectContext = group.projectContext;
      if (!projectContext) {
        return [];
      }
      return [
        {
          activeGroupId: group.groupId,
          groupCount: 1,
          isActive: group.isActive,
          name: group.title,
          path: projectContext.path,
          projectId: projectContext.editor.projectId,
        },
      ];
    });
  }
  return projects.map((project) => ({
    activeGroupId: project.workspace.activeGroupId,
    groupCount: project.workspace.groups.length,
    isActive: project.projectId === activeProjectId,
    name: project.name,
    path: project.path,
    projectId: project.projectId,
  }));
}

function assertCliSidebarCard(payload: Record<string, unknown>) {
  const session = requireCliSession(payload);
  const sessionReference = resolveSidebarSessionReference(session.sessionId);
  const terminalState = terminalStateById.get(sessionReference.sessionId);
  const failures: string[] = [];
  const expectedAgentIcon = typeof payload.agentIcon === "string" ? payload.agentIcon : undefined;
  const expectedAgentName = typeof payload.agentName === "string" ? payload.agentName : undefined;
  const expectedVisible = typeof payload.visible === "boolean" ? payload.visible : undefined;
  if (expectedAgentIcon !== undefined && session.agentIcon !== expectedAgentIcon) {
    failures.push(
      `agentIcon expected ${expectedAgentIcon}, received ${session.agentIcon ?? "<empty>"}`,
    );
  }
  if (expectedAgentName !== undefined && terminalState?.agentName !== expectedAgentName) {
    failures.push(
      `agentName expected ${expectedAgentName}, received ${terminalState?.agentName ?? "<empty>"}`,
    );
  }
  if (expectedVisible !== undefined && session.isVisible !== expectedVisible) {
    failures.push(`visible expected ${expectedVisible}, received ${session.isVisible}`);
  }
  return {
    failures,
    ok: failures.length === 0,
    session,
    terminalState,
  };
}

async function waitForCliSidebarCard(payload: Record<string, unknown>) {
  const timeoutMs = typeof payload.timeoutMs === "number" ? payload.timeoutMs : 5_000;
  const intervalMs = typeof payload.intervalMs === "number" ? payload.intervalMs : 200;
  const startedAt = Date.now();
  let result = assertCliSidebarCard(payload);
  while (!result.ok && Date.now() - startedAt < timeoutMs) {
    await new Promise((resolve) => window.setTimeout(resolve, intervalMs));
    result = assertCliSidebarCard(payload);
  }
  return {
    ...result,
    elapsedMs: Date.now() - startedAt,
  };
}

async function runCliAgent(agentId: string, groupId?: string): Promise<SessionRecord | undefined> {
  const agent = agents.find((candidate) => candidate.agentId === agentId);
  if (!agent?.command) {
    throw new Error(`Unknown or unconfigured agent: ${agentId}`);
  }
  if (agent.agentId === "t3") {
    return createNativeT3Session(groupId);
  }
  return launchAgentTerminal(agent, groupId);
}

/**
 * CDXC:PreviousSessions 2026-04-28-05:12
 * Native ghostex must mirror the reference Prompt to Search workflow:
 * receive the modal's remembered-topic query, launch a terminal agent session,
 * rename that helper session, then stage the local-session search prompt.
 *
 * CDXC:PromptAgents 2026-05-28-07:15:
 * Prompt to Search should use the same Settings-selected default prompt
 * agent as Git helper prompts and project-board Start Work instead of
 * hardcoding Codex.
 */
async function promptFindPreviousSession(queryInput?: string): Promise<void> {
  const query = queryInput?.trim();
  appendAgentDetectionDebugLog("nativeSidebar.promptFindPreviousSession.received", {
    hasQuery: Boolean(query),
    queryLength: query?.length ?? 0,
  });
  if (!query) {
    showNativeMessage("info", "Type what you remember in the Previous Sessions search field.");
    return;
  }

  const agent = resolveFindPreviousSessionAgent();
  if (!agent) {
    appendAgentDetectionDebugLog("nativeSidebar.promptFindPreviousSession.missingAgent", {
      requestedAgentId: settings.defaultPromptAgentId,
    });
    showNativeMessage(
      "info",
      "Ghostex could not find a configured default prompt agent for Find a session.",
    );
    return;
  }

  const projectId = activeProjectId;
  const session = await launchAgentTerminal(agent);
  if (!session) {
    appendAgentDetectionDebugLog("nativeSidebar.promptFindPreviousSession.createSessionFailed", {
      agentId: agent.agentId,
      queryLength: query.length,
    });
    return;
  }

  const prompt = renderFindPreviousSessionPrompt(
    DEFAULT_FIND_PREVIOUS_SESSION_PROMPT_TEMPLATE,
    query,
  );
  /**
   * CDXC:PreviousSessions 2026-05-07-16:02
   * The Find Session button crosses React, the modal-host WebKit bridge, and
   * native sidebar command dispatch before terminal input is written. Keep
   * debug breadcrumbs at session creation and prompt staging so Computer Use
   * repros can identify the exact boundary that stopped the action.
   */
  appendAgentDetectionDebugLog("nativeSidebar.promptFindPreviousSession.stagingPrompt", {
    agentId: agent.agentId,
    nativeSessionId: nativeSessionIdForProjectSidebarSession(projectId, session.sessionId),
    queryLength: query.length,
    sessionId: session.sessionId,
  });
  await stageNativeAgentPrompt({
    agent,
    projectId,
    prompt,
    renameTitle: `Search: ${query}`,
    session,
  });
}

function resolveFindPreviousSessionAgent(): SidebarAgentButton | undefined {
  return resolveDefaultPromptAgent();
}

async function searchPreviousSessionsByText(): Promise<void> {
  /*
   * CDXC:PreviousSessions 2026-05-29-12:36:
   * The Previous Sessions modal's Search by Text button should open a fresh
   * terminal running `gx f`, which is the bundled zehn prompt-history search
   * path. Do not route this through the agent prompt flow; users asked for a
   * direct terminal search button next to Prompt to Find Session.
   *
   * CDXC:PreviousSessions 2026-05-29-20:32:
   * Search by Text belongs in the currently active project, not in a generated
   * Quick terminal area. Use the normal project terminal creation path and add
   * it as a tab beside the currently focused project pane.
   *
   * CDXC:PreviousSessions 2026-05-31-15:00:
   * Search by Text is a temporary terminal label for the `gx f` shell, not a
   * final session name. Mark it as a placeholder so cards render `∗ Search by
   * Text`, resume logic ignores it, and the next real terminal title can
   * replace it.
   */
  appendAgentDetectionDebugLog("nativeSidebar.searchPreviousSessionsByText.received");
  const session = createTerminal("Search by Text", withAtuinIgnoredShellHistoryPrefix("gx f\r"), undefined, undefined, {
    titleSource: "placeholder",
    visiblePlacement: createFocusedTabGroupPlacement(),
  });
  if (!session) {
    appendAgentDetectionDebugLog("nativeSidebar.searchPreviousSessionsByText.createSessionFailed");
  }
}

function runCliCommandButton(commandId: string): TerminalSessionRecord | undefined {
  const command = commands.find((candidate) => candidate.commandId === commandId);
  if (!command) {
    throw new Error(`Unknown command button: ${commandId}`);
  }
  if (command.actionType === "browser" && command.url) {
    openNativeBrowserWindow(command.url);
    return undefined;
  }
  if (!command.command) {
    throw new Error(`Command button is not configured: ${commandId}`);
  }
  return runNativeSidebarCommand(command);
}

function getNativeSidebarCommandSessionTitle(command: SidebarCommandButton): string {
  const normalizedActionName = command.name.trim();
  return normalizedActionName.length > 0
    ? normalizedActionName
    : (command.command ?? "").trim().slice(0, 20);
}

function normalizeNativeSidebarCommandTitle(value: string | undefined): string | undefined {
  const normalized = value?.trim().replace(/\s+/g, " ");
  return normalized ? normalized : undefined;
}

function getNativeSidebarCommandTitleKey(value: string | undefined): string {
  return normalizeNativeSidebarCommandTitle(value)?.toLocaleLowerCase() ?? "";
}

function getNativeSidebarActionTitle(
  command: Pick<SidebarCommandButton, "command" | "name" | "url">,
): string {
  const normalizedActionName = normalizeNativeSidebarCommandTitle(command.name);
  if (normalizedActionName) {
    return normalizedActionName;
  }
  const target = normalizeNativeSidebarCommandTitle(command.command ?? command.url);
  return target?.slice(0, 20) ?? "";
}

function getNativeSidebarCommandExecutionText(
  command: string,
  closeOnExit: boolean,
  runId: string,
  options: { continueWithInteractiveShell?: boolean } = {},
): string {
  /**
   * CDXC:CommandPanes 2026-05-16-07:29:
   * Command-pane tabs need activity based on the submitted action lifecycle,
   * not agent title parsing. Wrap sidebar action text in a shell function and
   * stamp the session-state file after the function returns so persistent
   * command panes can clear the yellow native tab dot without closing.
   *
   * CDXC:CommandPanes 2026-05-20-22:52:
   * Command-pane actions now run through the native terminal process command
   * instead of being pasted into the interactive shell. Keep the status wrapper
   * available for lifecycle tracking, but it must stay off the visible terminal
   * input path so users see only their action output.
   */
  return withAtuinIgnoredShellHistoryPrefix([
    "__ghostex_command_pane_action() {",
    command,
    "}",
    getNativeSidebarCommandStatusStampText("working", runId, "0"),
    "__ghostex_command_pane_action",
    "__ghostex_exit=$?",
    "unset -f __ghostex_command_pane_action",
    getNativeSidebarCommandStatusStampText("idle", runId, "$__ghostex_exit"),
    !closeOnExit && options.continueWithInteractiveShell ? "exec /bin/zsh -l" : "",
    closeOnExit ? 'exit "$__ghostex_exit"' : "",
  ].filter(Boolean).join("\n"));
}

function getNativeSidebarCommandProcessCommand(executionText: string): string {
  return `/bin/zsh -lic ${quoteNativeShellArg(executionText)}`;
}

function getNativeSidebarCommandStatusStampText(
  status: "idle" | "working",
  runId: string,
  exitCode: string,
): string {
  return [
    "__ghostex_session_state_file=\"${GHOSTEX_SESSION_STATE_FILE:-${VSMUX_SESSION_STATE_FILE:-$ghostex_SESSION_STATE_FILE}}\"",
    'if [ -n "$__ghostex_session_state_file" ]; then',
    `  /usr/bin/python3 - "$__ghostex_session_state_file" ${quoteNativeShellArg(status)} ${quoteNativeShellArg(runId)} ${exitCode} <<'GHOSTEX_COMMAND_PANE_STATUS'`,
    "import datetime",
    "import os",
    "import pathlib",
    "import sys",
    "",
    "state_path = pathlib.Path(sys.argv[1])",
    "status = sys.argv[2]",
    "run_id = sys.argv[3]",
    "exit_code = sys.argv[4]",
    "state = {}",
    "order = []",
    "try:",
    "    for line in state_path.read_text(encoding='utf-8').splitlines():",
    "        key, separator, value = line.partition('=')",
    "        if separator:",
    "            state[key] = value",
    "            if key not in order:",
    "                order.append(key)",
    "except FileNotFoundError:",
    "    pass",
    "",
    "state['status'] = status",
    "state['statusUpdatedAt'] = datetime.datetime.now(datetime.timezone.utc).isoformat().replace('+00:00', 'Z')",
    "state['commandRunId'] = run_id",
    "state['commandExitCode'] = exit_code",
    "state['lastActivityAt'] = state['statusUpdatedAt']",
    "for key in ['status', 'statusUpdatedAt', 'commandRunId', 'commandExitCode', 'lastActivityAt']:",
    "    if key not in order:",
    "        order.append(key)",
    "state_path.parent.mkdir(parents=True, exist_ok=True)",
    "# CDXC:CommandsPanel 2026-06-08-13:19:",
    "# Command-pane completion sound depends on the idle status stamp being read by macOS. Use a per-process temp file so concurrent hook/status writers cannot clobber the replace source before the final state reaches disk.",
    "temp_path = state_path.with_name(f'{state_path.name}.{os.getpid()}.command.tmp')",
    "temp_path.write_text(''.join(f'{key}={state.get(key, \"\")}\\n' for key in order), encoding='utf-8')",
    "temp_path.replace(state_path)",
    "GHOSTEX_COMMAND_PANE_STATUS",
    "fi",
  ].join("\n");
}

function createNativeSidebarCommandRunId(commandId: string): string {
  return `${commandId}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
}

function postNativeSidebarCommandRunState(
  commandId: string,
  runId: string,
  state: "error" | "running" | "success",
): void {
  sidebarBus.post({
    commandId,
    runId,
    state,
    type: "sidebarCommandRunStateChanged",
  });
}

function clearNativeSidebarCommandRunState(commandId: string): void {
  sidebarBus.post({
    commandId,
    type: "sidebarCommandRunStateCleared",
  });
}

function playNativeSidebarActionCompletionSound(sessionId?: string): void {
  /**
   * CDXC:NativeActions 2026-04-29-16:30
   * Terminal action completion sounds are per-command feedback and use the
   * action completion sound, independent of the global session completion
   * bell toggle.
   */
  appendAgentDetectionDebugLog("nativeSidebar.completionSound.action", {
    sessionId,
    sound: settings.actionCompletionSound,
  });
  playNativeSound(settings.actionCompletionSound);
}

function setNativeSidebarCommandSession(
  command: SidebarCommandButton,
  sessionId: string,
  closeOnExit: boolean,
  runId?: string,
): void {
  const projectId = activeProjectId;
  const sessionKey = createProjectCommandSessionKey(projectId, command.commandId);
  const existingSession = getNativeSidebarCommandSession(projectId, command.commandId);
  const commandTitle = getNativeSidebarCommandSessionTitle(command);
  appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.sessionMappingStart", {
    closeOnExit,
    commandId: command.commandId,
    commandTitle,
    existingSessionId: existingSession?.sessionId,
    nextSessionId: sessionId,
    previousCommandIdForSession: sidebarCommandCommandIdBySessionId.get(sessionId),
    runId,
  });
  if (existingSession?.sessionId && existingSession.sessionId !== sessionId) {
    sidebarCommandCommandIdBySessionId.delete(existingSession.sessionId);
  }
  const previousCommandIdForSession = sidebarCommandCommandIdBySessionId.get(sessionId);
  if (previousCommandIdForSession && previousCommandIdForSession !== command.commandId) {
    const previousSession = getNativeSidebarCommandSession(projectId, previousCommandIdForSession);
    if (previousSession?.sessionId === sessionId) {
      sidebarCommandSessionByCommandId.delete(
        createProjectCommandSessionKey(projectId, previousCommandIdForSession),
      );
    }
  }

  sidebarCommandSessionByCommandId.set(sessionKey, {
    closeOnExit,
    commandId: command.commandId,
    commandTitle,
    playCompletionSound: command.playCompletionSound,
    runId,
    sessionId,
  });
  sidebarCommandCommandIdBySessionId.set(sessionId, command.commandId);
  appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.sessionMappingDone", {
    closeOnExit,
    commandId: command.commandId,
    commandTitle,
    runId,
    sessionId,
  });
}

function clearNativeSidebarCommandSessionBySessionId(sessionId: string): void {
  clearNativeSidebarCommandSessionByProjectSessionId(activeProjectId, sessionId);
}

function clearNativeSidebarCommandSessionByProjectSessionId(
  projectId: string,
  sessionId: string,
): void {
  const commandId = sidebarCommandCommandIdBySessionId.get(sessionId);
  if (!commandId) {
    return;
  }

  sidebarCommandCommandIdBySessionId.delete(sessionId);
  const storedSession = getNativeSidebarCommandSession(projectId, commandId);
  if (storedSession?.sessionId === sessionId) {
    sidebarCommandSessionByCommandId.delete(
      createProjectCommandSessionKey(projectId, commandId),
    );
  }
}

function closeNativeSidebarCommandSession(sessionId: string): void {
  clearNativeSidebarCommandSessionBySessionId(sessionId);
  closeTerminal(sessionId);
}

function markNativeSidebarCommandPaneRunStarted(sessionId: string): void {
  const terminalState = terminalStateById.get(sessionId);
  if (!terminalState) {
    return;
  }
  terminalState.activity = "working";
  persistTerminalSessionRestoreActivity(sessionId, "working");
}

function setNativeSidebarCommandPaneTitle(sessionId: string, title: string): void {
  /**
   * CDXC:CommandPanes 2026-05-16-08:25:
   * Command-pane tabs should display the action title, not a stale shell or
   * previously mapped command title. Refresh the stored command-panel session
   * title before every run so reused tabs and native tab chrome stay aligned
   * with the current action label.
   *
   * CDXC:CommandPanes 2026-05-16-15:08:
   * The action title is the current-window command-pane owner key. Rewriting
   * commandTitle with the visible tab title keeps title-based reuse stable
   * during this window while gxserver remains the durable command-session
   * metadata owner.
   *
   * CDXC:ProjectSidebarOwnership 2026-06-02-21:05:
   * The command panel owns immediate tab chrome, but gxserver owns canonical
   * command-session title/provenance. Apply the local title first for
   * local-first feedback, then mirror canonical P/G command sessions through
   * `/api/requestSessionRename` so action rename/reuse cannot leave a native-only
   * shared title behind.
   */
  const reference = resolveSidebarSessionReference(sessionId);
  updateActiveProjectCommandsPanel((panel) => ({
    ...panel,
    sessions: panel.sessions.map((session) =>
      session.sessionId === sessionId
        ? {
            ...session,
            commandTitle: title,
            title,
            titleSource: "user",
          }
        : session,
    ),
  }));
  const terminalState = terminalStateById.get(sessionId);
  if (terminalState) {
    terminalState.terminalTitle = title;
  }
  if (isCanonicalGxserverProjectSession(reference.project.projectId, reference.sessionId)) {
    void gxserverClient
      .rpc<GxserverSessionRenameRequestResult>("/api/requestSessionRename", {
        projectId: reference.project.projectId,
        sessionId: reference.sessionId,
        title,
        titleSource: "user",
      })
      .then((result) => {
        applyGxserverSessionRenameRequestResult(
          reference.project.projectId,
          reference.sessionId,
          result,
        );
      })
      .catch((error) => {
        appendSidebarRefreshDebugLog("nativeSidebar.gxserver.commandPaneTitle.persistFailed", {
          errorType: error instanceof Error ? error.name : typeof error,
          projectIdIsCanonical: GXSERVER_CANONICAL_PROJECT_ID_PATTERN.test(reference.project.projectId),
          sessionIdIsCanonical: GXSERVER_CANONICAL_SESSION_ID_PATTERN.test(reference.sessionId),
        });
      });
  }
}

function findReusableNativeSidebarCommandPane(
  command: SidebarCommandButton,
): TerminalSessionRecord | undefined {
  const existingSession = getNativeSidebarCommandSession(activeProjectId, command.commandId);
  const commandTitle = getNativeSidebarCommandSessionTitle(command);
  const commandTitleKey = getNativeSidebarCommandTitleKey(commandTitle);
  const existingCommandSession =
    existingSession &&
    getNativeSidebarCommandTitleKey(existingSession.commandTitle) === commandTitleKey &&
    isReusableNativeSidebarCommandPane(existingSession.sessionId)
      ? findTerminalSession(existingSession.sessionId)
      : undefined;
  if (existingCommandSession) {
    appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.reuseExistingCommandSession", {
      commandId: command.commandId,
      commandTitle,
      sessionId: existingCommandSession.sessionId,
      terminalActivity: terminalStateById.get(existingCommandSession.sessionId)?.activity,
      terminalLifecycle: terminalStateById.get(existingCommandSession.sessionId)?.lifecycleState,
    });
    return existingCommandSession;
  }

  const titleOwnedSession = findNativeSidebarCommandPaneByTitle(commandTitleKey);
  const reusableTitleOwnedSession =
    titleOwnedSession && isReusableNativeSidebarCommandPane(titleOwnedSession.sessionId)
      ? titleOwnedSession
      : undefined;
  /**
   * CDXC:CommandPanes 2026-05-16-15:08:
   * Sidebar terminal actions own one command-pane tab per action title. The
   * title key lets Ghostex reuse a pane after restart even when the in-memory
   * command-id map has not been rebuilt. Duplicate action titles are rejected
   * per project so this title ownership stays unambiguous.
   */
  appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.reuseLookup", {
    commandId: command.commandId,
    commandTitle,
    commandPanelSessionCount: activeProject().commandsPanel.sessions.length,
    existingSessionId: existingSession?.sessionId,
    reusableSessionId: reusableTitleOwnedSession?.sessionId,
    titleOwnedSessionId: titleOwnedSession?.sessionId,
  });
  return reusableTitleOwnedSession;
}

function findNativeSidebarCommandPaneByTitle(
  commandTitleKey: string,
): TerminalSessionRecord | undefined {
  if (!commandTitleKey) {
    return undefined;
  }
  return activeProject().commandsPanel.sessions.find(
    (session) =>
      getNativeSidebarCommandTitleKey(session.commandTitle ?? session.title) === commandTitleKey,
  );
}

function isReusableNativeSidebarCommandPane(sessionId: string): boolean {
  if (!activeCommandPanelContainsSession(sessionId)) {
    return false;
  }
  const terminalState = terminalStateById.get(sessionId);
  return terminalState?.lifecycleState === "running" && terminalState.activity === "idle";
}

function cleanupExitedNativeCommandPaneSession(
  sessionId: string,
  exitCode: number | undefined,
  reason: string,
): boolean {
  const reference = resolveSidebarSessionReference(sessionId);
  if (!commandPanelContainsSession(reference.project, reference.sessionId)) {
    return false;
  }

  const commandId = sidebarCommandCommandIdBySessionId.get(reference.sessionId);
  const sessionRecord = findSessionRecordInProject(reference.project, reference.sessionId);
  const commandTransitionOrigin = createCommandPaneTransitionOrigin(
    reference.project,
    reference.sessionId,
  );
  const commandTransitionResult = applyGxserverSessionTransition(
    reference,
    sessionRecord,
    "close",
    commandTransitionOrigin,
  );
  const sessionsBefore = reference.project.commandsPanel.sessions.map((session) => session.sessionId);
  const nativeSessionId = forgetNativeSessionMappingForProject(
    reference.project.projectId,
    reference.sessionId,
  );
  clearNativeSidebarCommandSessionByProjectSessionId(reference.project.projectId, reference.sessionId);
  updateProjectCommandsPanel(reference.project.projectId, (panel) => {
    const sessions = panel.sessions.filter((session) => session.sessionId !== reference.sessionId);
    const paneLayout = removeCommandSessionFromPaneLayout(panel.paneLayout, reference.sessionId);
    const activeSessionId =
      panel.activeSessionId === reference.sessionId
        ? sessions[0]?.sessionId
        : panel.activeSessionId && sessions.some((session) => session.sessionId === panel.activeSessionId)
          ? panel.activeSessionId
          : sessions[0]?.sessionId;
    return {
      ...panel,
      activeSessionId,
      isVisible: sessions.length > 0 ? panel.isVisible : false,
      paneLayout,
      sessions,
    };
  });
  terminalStateById.delete(reference.sessionId);
  pendingNativeTerminalStartupTextBySessionId.delete(reference.sessionId);
  nativeActivitySuppressedUntilBySessionId.delete(reference.sessionId);
  nativeWorkingStartedAtBySessionId.delete(reference.sessionId);
  clearNativeSessionAttentionTracking(reference.sessionId);
  nativeAttentionNotificationLastSentAtBySessionId.delete(reference.sessionId);
  clearDelayedSendTimer(reference.sessionId, reference.project.projectId);
  /*
   * CDXC:ProjectSidebarOwnership 2026-06-02-17:06:
   * A command-pane terminal exit removes the macOS tab surface, but the backing
   * P/G command session lifecycle remains gxserver-owned. Route exit cleanup
   * through the same close transition as tab-close before pruning local command
   * panel placement so a stale shared command row cannot survive only because
   * native removed its tab.
   *
   * CDXC:CommandsPanel 2026-05-19-16:55:
   * Native terminal exit means the command-pane Ghostty surface is gone. The
   * command-panel model must prune that tab immediately so the next native
   * layout sync does not reserve a bottom command area for a session id Swift
   * can no longer render.
   */
  appendTerminalFocusDebugLog("nativeFocusTrace.commandPaneExitCleanup.applied", {
    activeProjectId,
    commandId,
    exitCode,
    nativeSessionId,
    reason,
    resolvedProjectId: reference.project.projectId,
    resolvedSessionId: reference.sessionId,
    transitionHandled: commandTransitionResult.handled,
    sessionsBefore,
    sessionsAfter: findProject(reference.project.projectId)?.commandsPanel.sessions.map(
      (session) => session.sessionId,
    ),
  });
  publish();
  focusGxserverSessionTransitionTarget(commandTransitionResult.focusTarget, commandTransitionOrigin.kind);
  return true;
}

function handleNativeSidebarCommandSessionExit(
  sessionId: string,
  exitCode: number | undefined,
): boolean {
  const commandId = sidebarCommandCommandIdBySessionId.get(sessionId);
  if (!commandId) {
    return cleanupExitedNativeCommandPaneSession(sessionId, exitCode, "terminalExited.unmappedCommandPane");
  }

  const storedSession = getNativeSidebarCommandSession(activeProjectId, commandId);
  if (!storedSession || storedSession.sessionId !== sessionId) {
    return cleanupExitedNativeCommandPaneSession(sessionId, exitCode, "terminalExited.staleCommandMapping");
  }

  const didFail = (exitCode ?? 0) !== 0;
  const runId = storedSession.runId ?? createNativeSidebarCommandRunId(commandId);
  postNativeSidebarCommandRunState(commandId, runId, didFail ? "error" : "success");

  if (didFail || storedSession.playCompletionSound) {
    playNativeSidebarActionCompletionSound(sessionId);
  }

  return cleanupExitedNativeCommandPaneSession(sessionId, exitCode, "terminalExited.mappedCommandPane");
}

/**
 * CDXC:Actions 2026-04-28-02:54
 * Native sidebar terminal actions must match the reference sidebar flow:
 * default runs open managed background terminals with button spinner/status
 * feedback, while Debug Action creates a normal visible session for inspection.
 */
function runNativeSidebarCommand(
  command: SidebarCommandButton,
  runMode: SidebarCommandRunMode = "default",
): TerminalSessionRecord | undefined {
  appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.runStart", {
    actionType: command.actionType,
    closeTerminalOnExit: command.closeTerminalOnExit,
    commandId: command.commandId,
    commandPanelSessionCount: activeProject().commandsPanel.sessions.length,
    hasCommand: Boolean(command.command?.trim()),
    hasUrl: Boolean(command.url?.trim()),
    projectId: activeProject().projectId,
    projectPath: activeProject().path,
    runMode,
  });
  if (command.actionType === "browser") {
    const browserUrl = command.url?.trim();
    if (!browserUrl) {
      openNativeSidebarCommandEditor(command);
      return undefined;
    }
    appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.browserAction", {
      commandId: command.commandId,
      url: browserUrl,
    });
    openNativeBrowserWindow(browserUrl);
    return undefined;
  }
  const commandText = command.command?.trim();
  if (!commandText) {
    appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.emptyCommand", {
      actionType: command.actionType,
      commandId: command.commandId,
    });
    openNativeSidebarCommandEditor(command);
    return undefined;
  }

  const sessionTitle = getNativeSidebarCommandSessionTitle(command);
  if (runMode === "debug") {
    appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.debugRun", {
      commandId: command.commandId,
      sessionTitle,
    });
    return createTerminal(`Debug: ${sessionTitle}`, withAtuinIgnoredShellHistoryPrefix(`${commandText}\r`));
  }

  /*
  CDXC:CommandPanes 2026-05-31-21:10:
  Command-pane actions are reusable gxserver/zmx sessions. Even if an older action definition requested close-on-exit, keep the pane shell alive so the session remains in the Commands panel and can be reused instead of exiting, losing its command-surface classification, and reappearing as a workspace sidebar row.
  */
  const closeOnExit = false;
  const runId = createNativeSidebarCommandRunId(command.commandId);
  const existingSession = getNativeSidebarCommandSession(activeProjectId, command.commandId);

  const reusableSession = findReusableNativeSidebarCommandPane(command);
  if (reusableSession) {
    /**
     * CDXC:CommandPanes 2026-05-31-02:20:
     * Re-running an action must reuse the idle command-pane tab whose title
     * matches the action title. Do not close and recreate that pane; gxserver
     * keeps the zmx runtime attached, while the sidebar sends the action script
     * into the existing terminal so the bottom Commands panel does not flicker.
     */
    const reuseExecutionText = getNativeSidebarCommandExecutionText(commandText, closeOnExit, runId);
    const nativeSessionId = nativeSessionIdForProjectSidebarSession(
      activeProjectId,
      reusableSession.sessionId,
    );
    updateActiveProjectCommandsPanel((panel) => ({
      ...panel,
      ...createCommandsPanelOpenStatePatch(panel, {
        defaultHeightPx: settings.commandsPanelDefaultHeightPx,
      }),
      activeSessionId: reusableSession.sessionId,
    }));
    setNativeSidebarCommandPaneTitle(reusableSession.sessionId, sessionTitle);
    setNativeSidebarCommandSession(command, reusableSession.sessionId, closeOnExit, runId);
    markNativeSidebarCommandPaneRunStarted(reusableSession.sessionId);
    postNativeSidebarCommandRunState(command.commandId, runId, "running");
    postNative({ sessionId: nativeSessionId, text: reuseExecutionText, type: "writeTerminalScript" });
    publish();
    appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.sessionSelected", {
      closeOnExit,
      commandId: command.commandId,
      createdSession: false,
      reusableSessionId: reusableSession.sessionId,
      runId,
      sessionId: reusableSession.sessionId,
      sessionTitle,
    });
    return reusableSession;
  }
  const existingTerminalState = existingSession ? terminalStateById.get(existingSession.sessionId) : undefined;
  if (
    existingSession &&
    !reusableSession &&
    !closeOnExit &&
    existingTerminalState?.lifecycleState !== "running"
  ) {
    appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.closeStaleCommandSession", {
      commandId: command.commandId,
      existingSessionId: existingSession.sessionId,
      terminalActivity: existingTerminalState?.activity,
      terminalLifecycle: existingTerminalState?.lifecycleState,
    });
    closeNativeSidebarCommandSession(existingSession.sessionId);
  }

  const executionText = getNativeSidebarCommandExecutionText(commandText, closeOnExit, runId, {
    continueWithInteractiveShell: !closeOnExit,
  });
  const shellCommand = getNativeSidebarCommandProcessCommand(executionText);
  /**
   * CDXC:TitlebarActions 2026-05-15-16:58:
   * Titlebar terminal actions must execute inside the Commands panel. Reuse a
   * running command-pane terminal only when it is idle; otherwise create a
   * command-pane tab and pass the command as startup input so new actions
   * do not depend on a second immediate write before the native surface is
   * ready.
   */
  const session = createCommandTerminal(sessionTitle, `${executionText}\r`, {
    commandId: command.commandId,
    commandTitle: sessionTitle,
    focusAfterCreate: false,
    shellCommand,
  });
  if (!session) {
    appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.createCommandPaneFailed", {
      commandId: command.commandId,
      commandPanelSessionCount: activeProject().commandsPanel.sessions.length,
      sessionTitle,
    });
    return undefined;
  }

  appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.sessionSelected", {
    closeOnExit,
    commandId: command.commandId,
    createdSession: true,
    reusableSessionId: undefined,
    runId,
    sessionId: session.sessionId,
    sessionTitle,
  });
  setNativeSidebarCommandPaneTitle(session.sessionId, sessionTitle);
  setNativeSidebarCommandSession(command, session.sessionId, closeOnExit, runId);
  markNativeSidebarCommandPaneRunStarted(session.sessionId);
  postNativeSidebarCommandRunState(command.commandId, runId, "running");
  publish();
  appendActionCrashTraceDebugLog("nativeSidebar.actionCrashTrace.runDone", {
    closeOnExit,
    commandId: command.commandId,
    sessionId: session.sessionId,
  });
  return session;
}

async function handleNativeCliCommand(action: string, payload: Record<string, unknown>) {
  /**
   * CDXC:DebugCli 2026-04-27-07:18
   * CLI actions are intentionally routed through the native sidebar runtime so
   * automated repros can create sessions, press sidebar buttons, send terminal
   * input, and inspect projected card state without bypassing app behavior.
   */
  try {
    switch (action) {
      case "state":
      case "dumpState":
        return { ok: true, state: summarizeCliState() };
      case "listSessions":
        return { ok: true, revision, sessions: listNativeCliSessions() };
      case "openPaths":
        return openNativePathTargetsFromCli(payload);
      case "createQuickTerminal": {
        const session = await createNativeQuickTerminal({
          command: typeof payload.command === "string" ? payload.command : undefined,
          cwd: typeof payload.cwd === "string" ? payload.cwd : undefined,
          title: typeof payload.title === "string" ? payload.title : undefined,
        });
        return {
          ok: true,
          revision,
          session: summarizeCreatedCliSession(session),
          state: summarizeCliState(),
        };
      }
      case "createSession": {
        const groupId = typeof payload.groupId === "string" ? payload.groupId : undefined;
        const projectId = typeof payload.projectId === "string" ? payload.projectId : undefined;
        if (projectId && findProject(projectId) && activeProjectId !== projectId) {
          focusProject(projectId);
        }
        if (groupId === COMBINED_CHATS_GROUP_ID || (!groupId && quickKindForProject(activeProject()) === "terminal")) {
          await createNativeChat(typeof payload.title === "string" ? payload.title : undefined);
          return { kind: "chat", ok: true, revision };
        }
        /**
         * CDXC:AndroidRemoteSessions 2026-05-18-02:31:
         * Android's project-header plus button reaches this path through the
         * Mac-hosted Ghostex CLI. Focus the requested project first, then use
         * createTerminal so current Settings, including zmx persistence, remain
         * the source of truth for the new session.
         *
         * CDXC:AndroidRemoteSessions 2026-05-18-03:01:
         * Android only needs to know whether create-session succeeded before it
         * refreshes the inventory. Return a compact created-session summary so
         * the mobile path does not serialize the full sidebar state immediately
         * after native terminal creation.
         */
        const session = createTerminal(
          typeof payload.title === "string" ? payload.title : DEFAULT_TERMINAL_SESSION_TITLE,
          typeof payload.input === "string" ? payload.input : "",
          groupId,
        );
        return { ok: true, revision, session: summarizeCreatedCliSession(session) };
      }
      case "createChat":
        await createNativeChat(typeof payload.title === "string" ? payload.title : undefined);
        return { ok: true, state: summarizeCliState() };
      case "createAgentSession":
      case "runAgent": {
        const agentId = typeof payload.agentId === "string" ? payload.agentId : "";
        const session = await runCliAgent(
          agentId,
          typeof payload.groupId === "string" ? payload.groupId : undefined,
        );
        return { ok: true, session, state: summarizeCliState() };
      }
      case "runCommand": {
        const session = runCliCommandButton(String(payload.commandId ?? ""));
        return { ok: true, session, state: summarizeCliState() };
      }
      case "clickButton": {
        const kind = String(payload.kind ?? "");
        const id = String(payload.id ?? "");
        if (kind === "agent") {
          return { ok: true, session: await runCliAgent(id), state: summarizeCliState() };
        }
        if (kind === "command") {
          return { ok: true, session: runCliCommandButton(id), state: summarizeCliState() };
        }
        if (kind === "projectEditor") {
          /**
           * CDXC:DebugCli 2026-05-08-13:13
           * Crash repros need to open the same project-owned VS Code surface
           * as the sidebar button before Computer Use drags the native sidebar
           * divider. Route the CLI button action through the real group command
           * instead of constructing native editor commands by hand.
           */
          openProjectEditorForGroup(id);
          return { ok: true, state: summarizeCliState() };
        }
        throw new Error(`Unsupported button kind: ${kind}`);
      }
      case "focusSession": {
        const session = requireCliSession(payload);
        focusSidebarSession(session.sessionId);
        return { ok: true, session, state: summarizeCliState() };
      }
      case "acknowledgeSessionAttention": {
        const session = requireCliSession(payload);
        const reference = resolveSidebarSessionReference(session.sessionId);
        const acknowledged = acknowledgeNativeTerminalAttention(reference.sessionId, "tui-attach");
        const terminalState = terminalStateById.get(reference.sessionId);
        if (!acknowledged && terminalState?.sessionStateFilePath) {
          await persistNativeSessionAttentionAcknowledged(
            terminalState.sessionStateFilePath,
            new Date().toISOString(),
            reference.sessionId,
            "tui-attach",
          );
        }
        publish();
        return { acknowledged, ok: true, session, state: summarizeCliState() };
      }
      case "focusGroup": {
        const groupReference = resolveSidebarGroupReference(String(payload.groupId));
        const groupId = groupReference.groupId;
        if (!groupId) {
          focusProject(groupReference.project.projectId);
          return { ok: true, state: summarizeCliState() };
        }
        updateProjectWorkspace(
          groupReference.project.projectId,
          (workspace) => focusGroupInSimpleWorkspace(workspace, groupId).snapshot,
        );
        publish();
        return { ok: true, state: summarizeCliState() };
      }
      case "switchProject": {
        const project = projects.find(
          (candidate) =>
            candidate.projectId === payload.projectId ||
            candidate.path === payload.path ||
            candidate.name === payload.name,
        );
        if (!project) {
          throw new Error("No matching project was found.");
        }
        focusProject(project.projectId);
        return { ok: true, state: summarizeCliState() };
      }
      case "moveProject": {
        /**
         * CDXC:AndroidSidebar 2026-05-18-16:13:
         * Android project overflow menus move projects through this CLI bridge so
         * desktop persistence owns ordering. The sessions inventory already emits
         * projects in desktop sidebar order, so mobile refreshes converge on the
         * same placement instead of keeping a phone-only sort.
         */
        const projectId = typeof payload.projectId === "string" ? payload.projectId : "";
        const direction = payload.direction === "up" || payload.direction === "down"
          ? payload.direction
          : undefined;
        const orderedProjectIds = orderNativeProjectsForSidebar(projects)
          .filter((project) => project.isRecentProject !== true)
          .map((project) => project.projectId);
        const sourceIndex = orderedProjectIds.indexOf(projectId);
        if (sourceIndex < 0) {
          return { error: "No matching project was found.", ok: false };
        }
        if (!direction) {
          return { error: "Project move direction must be up or down.", ok: false };
        }
        const targetIndex = sourceIndex + (direction === "up" ? -1 : 1);
        if (targetIndex < 0 || targetIndex >= orderedProjectIds.length) {
          return { ok: true, projectId, revision, unchanged: true };
        }
        const nextProjectIds = [...orderedProjectIds];
        const [movedProjectId] = nextProjectIds.splice(sourceIndex, 1);
        nextProjectIds.splice(targetIndex, 0, movedProjectId);
        reorderProjects(nextProjectIds);
        return { ok: true, projectId, revision, state: summarizeCliState() };
      }
      case "addProject":
        await addProject(
          String(payload.path),
          typeof payload.name === "string" ? payload.name : undefined,
        );
        return { ok: true, state: summarizeCliState() };
      case "closeSession": {
        const session = requireCliSession(payload);
        closeTerminal(session.sessionId);
        return { ok: true, state: summarizeCliState() };
      }
      case "restartSession": {
        const session = requireCliSession(payload);
        restartNativeSession(session.sessionId);
        return { ok: true, state: summarizeCliState() };
      }
      case "forkSession": {
        const session = requireCliSession(payload);
        void forkNativeSession(session.sessionId);
        return { ok: true, state: summarizeCliState() };
      }
      case "fullReloadSession": {
        const session = requireCliSession(payload);
        restartNativeSession(session.sessionId);
        return { ok: true, state: summarizeCliState() };
      }
      case "renameSession": {
        const session = requireCliSession(payload);
        await renameNativeSidebarTerminalSession(
          session.sessionId,
          String(payload.title ?? ""),
          "native-cli-rename-session",
        );
        return { ok: true, state: summarizeCliState() };
      }
      case "sleepSession": {
        const session = requireCliSession(payload);
        setNativeSessionSleeping(session.sessionId, payload.sleeping !== false);
        return { ok: true, state: summarizeCliState() };
      }
      case "favoriteSession": {
        const session = requireCliSession(payload);
        setNativeSessionFavoriteLocalFirst(
          session.sessionId,
          payload.favorite !== false,
          "native-cli-favorite-session",
        );
        return { ok: true, state: summarizeCliState() };
      }
      case "pinSession": {
        const session = requireCliSession(payload);
        setNativeSessionPinnedLocalFirst(
          session.sessionId,
          payload.pinned !== false,
          "native-cli-pin-session",
        );
        return { ok: true, state: summarizeCliState() };
      }
      case "sendText": {
        const session = requireCliSession(payload);
        postNative({
          sessionId: nativeSessionIdForSidebarSession(session.sessionId),
          text: String(payload.text ?? ""),
          type: "writeTerminalText",
        });
        return { ok: true, session };
      }
      case "sendMessage": {
        const text = String(payload.text ?? "");
        const submit = payload.submit !== false;
        const hasSessionSelector =
          typeof payload.sessionId === "string" ||
          typeof payload.selectorTitle === "string" ||
          typeof payload.index === "number" ||
          typeof payload.sessionNumber === "number";
        if (hasSessionSelector) {
          const session = requireCliSession(payload);
          const nativeSessionId = nativeSessionIdForSidebarSession(session.sessionId);
          postNative({ sessionId: nativeSessionId, text, type: "writeTerminalText" });
          if (submit) {
            postNative({ sessionId: nativeSessionId, type: "sendTerminalEnter" });
          }
          return { created: false, ghostexId: session.sessionId, ok: true, session };
        }
        const agentId = String(payload.agentId ?? "").trim();
        if (!agentId) {
          throw new Error("send-message requires a session selector or an agent id.");
        }
        /**
         * CDXC:CliAgentMessaging 2026-05-23-13:18:
         * When no target session is supplied, `ghostex send-message <agent>`
         * must create a normal visible sidebar agent session and return its
         * Ghostex id. Hidden background agent sessions are not allowed because
         * the creator agent needs to inspect and follow up through the sidebar.
         */
        const createdSession = await runCliAgent(
          agentId,
          typeof payload.groupId === "string" ? payload.groupId : undefined,
        );
        if (!createdSession) {
          throw new Error(`Could not create agent session for ${agentId}.`);
        }
        const createdAgent = resolveSidebarAgentButtonById(agentId);
        if (createdSession.kind === "terminal" && createdAgent) {
          await stageNativeAgentPrompt({
            agent: createdAgent,
            projectId: activeProjectId,
            prompt: text,
            session: createdSession,
            submitPrompt: submit,
          });
        } else {
          const nativeSessionId = nativeSessionIdForSidebarSession(createdSession.sessionId);
          await new Promise((resolve) =>
            window.setTimeout(resolve, Number(payload.sendDelayMs ?? 750)),
          );
          postNative({ sessionId: nativeSessionId, text, type: "writeTerminalText" });
          if (submit) {
            postNative({ sessionId: nativeSessionId, type: "sendTerminalEnter" });
          }
        }
        return {
          created: true,
          ghostexId: createCombinedProjectSessionId(activeProjectId, createdSession.sessionId),
          ok: true,
          session: summarizeCliSessionRecord(createdSession),
        };
      }
      case "readSessionText": {
        const session = requireCliSession(payload);
        const nativeSessionId = nativeSessionIdForSidebarSession(session.sessionId);
        const result = await readNativeTerminalText(nativeSessionId, {
          source: payload.source === "visible" ? "visible" : "screen",
          timeoutMs: Number(payload.timeoutMs ?? 5_000),
        });
        return {
          error: result.error,
          ok: result.ok,
          session,
          text: result.text ?? "",
        };
      }
      case "sendEnter": {
        const session = requireCliSession(payload);
        postNative({
          sessionId: nativeSessionIdForSidebarSession(session.sessionId),
          type: "sendTerminalEnter",
        });
        return { ok: true, session };
      }
      case "sendKey": {
        const session = requireCliSession(payload);
        const text = terminalTextForCliKey(payload.key);
        if (!text) {
          throw new Error(`Unsupported key: ${String(payload.key)}`);
        }
        postNative({
          sessionId: nativeSessionIdForSidebarSession(session.sessionId),
          text,
          type: "writeTerminalText",
        });
        return { ok: true, session };
      }
      case "renameCommand": {
        const session = requireCliSession(payload);
        postNative({
          sessionId: nativeSessionIdForSidebarSession(session.sessionId),
          text: `/rename ${String(payload.title ?? "")}`,
          type: "writeTerminalText",
        });
        await new Promise((resolve) => window.setTimeout(resolve, 1_000));
        postNative({
          sessionId: nativeSessionIdForSidebarSession(session.sessionId),
          type: "sendTerminalEnter",
        });
        return { ok: true, session };
      }
      case "setVisibleCount":
        updateActiveProjectWorkspace((workspace) =>
          setVisibleCountInSimpleWorkspace(
            workspace,
            clampVisibleSessionCount(Number(payload.count)),
          ),
        );
        publish();
        return { ok: true, state: summarizeCliState() };
      case "setViewMode":
        updateActiveProjectWorkspace((workspace) =>
          setViewModeInSimpleWorkspace(
            workspace,
            String(payload.mode) as "grid" | "horizontal" | "vertical",
          ),
        );
        publish();
        return { ok: true, state: summarizeCliState() };
      case "openBrowser":
        return { ok: true, ...openNativeBrowserPaneFromCli(payload) };
      case "openBrowserPane":
        /**
         * CDXC:ChromiumBrowserPanes 2026-05-04-17:04
         * CEF pane testing needs a non-UI path that exercises the same
         * in-workspace browser creation as the sidebar button when macOS
         * accessibility automation is unavailable in local agent sessions.
         *
         * CDXC:BrowserAgentControl 2026-05-27-06:43:
         * CLI browser pane creation should honor project/worktree flags and
         * same-origin reuse so agents do not create panes in the wrong active
         * project or repeatedly open duplicates of the same app.
         */
        return { ok: true, ...openNativeBrowserPaneFromCli(payload) };
      case "moveSidebar":
        moveSidebarToOtherSide();
        return { ok: true, state: summarizeCliState() };
      case "assertSidebarCard":
        return assertCliSidebarCard(payload);
      case "waitFor":
        return waitForCliSidebarCard(payload);
      default:
        throw new Error(`Unsupported CLI action: ${action}`);
    }
  } catch (error) {
    return {
      error: error instanceof Error ? error.message : String(error),
      ok: false,
    };
  }
}

async function copyResumeCommand(sessionId: string): Promise<void> {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  if (!session) {
    return;
  }
  const resumeCommand = (await fetchGxserverAgentResumePlanForSession(
    reference.project,
    reference.sessionId,
  ))?.copyCommand;
  if (!resumeCommand) {
    showNativeMessage("info", "No resume command is available for this session.");
    return;
  }
  /*
   * CDXC:SessionRestore 2026-06-07-10:01:
   * Copy Resume should put only gxserver's agent-specific exact-id resume command
   * on the clipboard. Do not prepend the project cwd; wake/attach flows own cwd
   * staging separately and clipboard users asked for the direct provider command.
   */
  void navigator.clipboard?.writeText(resumeCommand).catch(() => undefined);
}

async function copyRemoteResumeCommand(remoteSessionId: string): Promise<boolean> {
  const target = parseRemotePresentationSessionId(remoteSessionId);
  if (!target) {
    return false;
  }
  const remoteMachine = settings.remoteMachines.find((machine) => machine.id === target.machineId);
  const presentation = remotePresentationSnapshotsByMachineId.get(target.machineId);
  const projectPath = presentation?.projects.find((project) => project.projectId === target.projectId)?.path?.trim();
  if (!remoteMachine) {
    showAppToast("info", "Remote command unavailable", "Open Settings > Remote and add the machine again.");
    return true;
  }
  try {
    /*
     * CDXC:RemoteResume 2026-06-03-00:24:
     * Remote resume commands must come from the owning gxserver, not from
     * macOS-local agent parsing. Wrap the gxserver copyCommand in SSH so the
     * pasted command executes in the remote project directory without exposing
     * the native tunnel token or rebuilding provider-specific resume syntax.
     */
    const response = await requestRemoteGxserver<{ plan: GxserverAgentResumePlan; session: GxserverSessionDomainState }>(
      target.machineId,
      "/api/readAgentResumePlan",
      {
        params: {
          projectId: target.projectId,
          sessionId: target.sessionId,
        },
      },
    ) as { result: { plan: GxserverAgentResumePlan; session: GxserverSessionDomainState } };
    const resumeCommand = response.result.plan.copyCommand?.trim();
    if (!resumeCommand) {
      showAppToast("info", "Remote command unavailable", "No resume command is available for this remote session.");
      return true;
    }
    const remoteCommand = projectPath
      ? `cd ${quoteNativeShellArg(projectPath)} && ${resumeCommand}`
      : resumeCommand;
    const sshCommand = buildRemoteSshShellCommand(remoteMachine, remoteCommand);
    void navigator.clipboard?.writeText(sshCommand).catch(() => undefined);
    showAppToast("info", "Remote resume command copied", `SSH command copied for ${remoteMachine.name}.`);
  } catch (error) {
    showAppToast("error", "Remote command failed", error instanceof Error ? error.message : String(error));
  }
  return true;
}

async function copyAttachCommand(sessionId: string): Promise<void> {
  const reference = resolveSidebarSessionReference(sessionId);
  const session = findTerminalSessionInProject(reference.project, reference.sessionId);
  if (!session) {
    return;
  }
  if (session.isSleeping === true) {
    /**
     * CDXC:SessionSleep 2026-05-17-01:33:
     * Sleeping stops the provider runtime, so a copied external command should
     * resume the agent conversation instead of reattaching to a killed zmx/tmux
     * provider session and creating an empty shell.
     */
    const resumeCommand = (await fetchGxserverAgentResumePlanForSession(
      reference.project,
      reference.sessionId,
    ))?.copyCommand;
    if (!resumeCommand) {
      showNativeMessage("info", "No resume command is available for this sleeping session.");
      return;
    }
    void navigator.clipboard?.writeText(resumeCommand).catch(() => undefined);
    return;
  }
  const terminalState = terminalStateById.get(reference.sessionId);
  const provider =
    terminalState?.sessionPersistenceProvider ??
    (terminalState ? undefined : resolveTerminalAttachProvider(session));
  const sessionPersistenceName =
    terminalState?.sessionPersistenceName ??
    (terminalState
      ? undefined
      : session.sessionPersistenceName ?? session.tmuxSessionName);
  if (!provider || !sessionPersistenceName) {
    showNativeMessage("info", "No persistence attach command is available for this session.");
    return;
  }
  /**
   * CDXC:SessionPersistence 2026-05-07-20:32
   * Provider-backed session cards expose a copyable attach command that uses
   * the stored provider/name pair, not the current Settings provider. This lets
   * users attach from an external terminal to the exact tmux/zmx/zellij session
   * backing the sidebar card.
   */
  const quotedName = quoteNativeShellArg(sessionPersistenceName);
  const attachCommand =
    provider === "tmux"
      ? `tmux attach-session -t ${quotedName}`
      : provider === "zmx"
        ? `zmx attach ${quotedName}`
        : `zellij attach ${quotedName}`;
  void navigator.clipboard?.writeText(attachCommand).catch(() => undefined);
}

type RemoteAttachTarget = { machineId: string; projectId: string; sessionId: string };

type RemoteAttachCommandPlan = {
  remoteMachine: ghostexSettings["remoteMachines"][number];
  session: GxserverPresentationSession;
  sshCommand: string;
};

function copyRemoteAttachCommand(remoteSessionId: string): boolean {
  const target = parseRemotePresentationSessionId(remoteSessionId);
  if (!target) {
    return false;
  }
  void copyRemoteAttachCommandForTarget(target);
  return true;
}

function openRemoteAttachTerminal(remoteSessionId: string): boolean {
  const target = parseRemotePresentationSessionId(remoteSessionId);
  if (!target) {
    return false;
  }
  void openRemoteAttachTerminalForTarget(target);
  return true;
}

function copyRemoteGroupAttachCommand(groupId: string): boolean {
  const target = parseRemotePresentationGroupId(groupId);
  if (!target) {
    return false;
  }
  const attachTarget = selectRemoteGroupAttachTarget(target);
  if (!attachTarget) {
    return true;
  }
  void copyRemoteAttachCommandForTarget(attachTarget);
  return true;
}

function openRemoteGroupAttachTerminal(groupId: string): boolean {
  const target = parseRemotePresentationGroupId(groupId);
  if (!target) {
    return false;
  }
  const attachTarget = selectRemoteGroupAttachTarget(target);
  if (!attachTarget) {
    return true;
  }
  void openRemoteAttachTerminalForTarget(attachTarget);
  return true;
}

function selectRemoteGroupAttachTarget(
  target: { machineId: string; projectId: string },
): RemoteAttachTarget | undefined {
  const presentation = remotePresentationSnapshotsByMachineId.get(target.machineId);
  const sessions = (presentation?.sessions ?? [])
    .filter((session) =>
      session.projectId === target.projectId &&
      (session.kind === "terminal" || session.kind === "agent"),
    )
    .sort(compareRemoteAttachCandidateSessions);
  const session = sessions[0];
  if (!session) {
    showAppToast("info", "Remote attach unavailable", "This remote project has no attachable sessions.");
    return undefined;
  }
  /*
   * CDXC:RemoteFocus 2026-06-08-19:35:
   * Remote group focus/zoom should choose the best attachable session in that
   * remote project, preferring running/attention/working and recently active
   * sessions. The caller decides whether that target is opened in a local
   * terminal or copied by an explicit copy action.
   */
  return {
    machineId: target.machineId,
    projectId: target.projectId,
    sessionId: session.sessionId,
  };
}

function copyRemoteProjectOpenCommandForGroup(
  groupId: string,
  source: "folder" | "ide",
): boolean {
  const target = parseRemotePresentationGroupId(groupId);
  if (!target) {
    return false;
  }
  const remoteMachine = settings.remoteMachines.find((machine) => machine.id === target.machineId);
  const project = remotePresentationSnapshotsByMachineId
    .get(target.machineId)
    ?.projects.find((candidate) => candidate.projectId === target.projectId);
  const projectPath = project?.path?.trim();
  if (!remoteMachine || !projectPath) {
    showAppToast("info", "Remote open unavailable", "Reconnect the remote machine and try opening the project again.");
    return true;
  }
  /*
   * CDXC:RemoteOpen 2026-06-03-03:42:
   * Finder and local IDE open actions cannot dereference a remote filesystem
   * path on the Mac. The SSH-only v1 equivalent is a copied command that opens
   * an authenticated remote shell already cd'd into the project, using the
   * saved machine host/user/port/key settings and never exposing gxserver
   * bearer tokens.
   */
  const remoteCommand = `cd ${quoteNativeShellArg(projectPath)} && exec "\${SHELL:-/bin/zsh}" -l`;
  const sshCommand = buildRemoteSshShellCommand(remoteMachine, remoteCommand);
  void navigator.clipboard?.writeText(sshCommand).catch(() => undefined);
  showAppToast(
    "info",
    source === "ide" ? "Remote IDE command copied" : "Remote folder command copied",
    `SSH command copied for ${remoteMachine.name}.`,
  );
  return true;
}

function compareRemoteAttachCandidateSessions(
  left: GxserverPresentationSession,
  right: GxserverPresentationSession,
): number {
  const score = (session: GxserverPresentationSession): number => {
    let value = 0;
    if (session.lifecycleState === "running") {
      value += 100;
    }
    if (session.activity === "attention") {
      value += 40;
    } else if (session.activity === "working") {
      value += 30;
    }
    if (session.isPinned) {
      value += 10;
    }
    if (session.isFavorite) {
      value += 5;
    }
    return value;
  };
  const scoreDelta = score(right) - score(left);
  if (scoreDelta !== 0) {
    return scoreDelta;
  }
  const rightTime = Date.parse(right.lastActiveAt ?? right.updatedAt ?? right.createdAt);
  const leftTime = Date.parse(left.lastActiveAt ?? left.updatedAt ?? left.createdAt);
  return (Number.isFinite(rightTime) ? rightTime : 0) - (Number.isFinite(leftTime) ? leftTime : 0);
}

function createRemoteAttachCommandPlan(
  target: RemoteAttachTarget,
  action: "copy" | "open",
): RemoteAttachCommandPlan | undefined {
  const remoteMachine = settings.remoteMachines.find((machine) => machine.id === target.machineId);
  const presentation = remotePresentationSnapshotsByMachineId.get(target.machineId);
  const session = presentation?.sessions.find(
    (candidate) => candidate.projectId === target.projectId && candidate.sessionId === target.sessionId,
  );
  if (!remoteMachine || !session) {
    showAppToast(
      "info",
      "Remote command unavailable",
      action === "copy"
        ? "Reconnect the remote machine and try copying the attach command again."
        : "Reconnect the remote machine and try opening the remote session again.",
    );
    return undefined;
  }
  /*
   * CDXC:RemoteAttach 2026-06-08-19:53:
   * macOS remote session clicks must match Android/iOS attach semantics: open SSH with a forced PTY and run `ghostex attach --session-id --project-id` inside the remote user's login shell. Do not use raw gxserver attach metadata for the interactive remote pane because the mobile path relies on the stable Ghostex id contract and PTY allocation.
   */
  return { remoteMachine, session, sshCommand: buildRemoteGhostexAttachSshCommand(remoteMachine, target) };
}

async function copyRemoteAttachCommandForTarget(target: RemoteAttachTarget): Promise<void> {
  const plan = createRemoteAttachCommandPlan(target, "copy");
  if (!plan) {
    return;
  }
  void navigator.clipboard?.writeText(plan.sshCommand).catch(() => undefined);
  showAppToast("info", "Remote attach command copied", `SSH command copied for ${plan.remoteMachine.name}.`);
}

async function openRemoteAttachTerminalForTarget(target: RemoteAttachTarget): Promise<void> {
  if (focusExistingRemoteAttachTerminal(target)) {
    return;
  }
  const plan = createRemoteAttachCommandPlan(target, "open");
  if (!plan) {
    return;
  }
  /*
   * CDXC:RemoteAttach 2026-06-08-19:35:
   * Clicking a remote session is a navigation action, not a clipboard action.
   * Start a local Ghostty terminal with a hidden zsh process command that runs
   * the Android-compatible SSH attach command; this preserves explicit Copy
   * Attach Command while making sidebar click behavior open a usable terminal
   * pane.
   */
  const carrier = await createNativeRemoteAttachCarrierTerminal(target, plan);
  if (!carrier) {
    showAppToast("error", "Remote attach failed", "Ghostex could not create a local terminal for the remote session.");
    return;
  }
  /*
   * CDXC:RemoteAttach 2026-06-08-20:50:
   * The native renderer still needs a local Ghostty carrier for the SSH process, but the user's sidebar ownership model is remote-first. Hide the carrier's gxserver project/session rows and keep a focus map so the remote machine row remains the visible identity.
   */
  hideGxserverPresentationProjectLocally(carrier.projectId, "remote-attach-carrier");
  hideGxserverPresentationSessionLocally(carrier.projectId, carrier.session.sessionId, "remote-attach-carrier");
  rememberRemoteAttachLocalSession(target, createCombinedProjectSessionId(carrier.projectId, carrier.session.sessionId));
  publish();
}

async function createNativeRemoteAttachCarrierTerminal(
  target: RemoteAttachTarget,
  plan: RemoteAttachCommandPlan,
): Promise<{ projectId: string; session: TerminalSessionRecord } | undefined> {
  const title = createRemoteAttachTerminalTitle(plan.remoteMachine, plan.session);
  const carrierProject = await ensureNativeRemoteAttachCarrierProject();
  if (!carrierProject) {
    return undefined;
  }
  activeProjectId = carrierProject.projectId;
  /*
   * CDXC:RemoteAttach 2026-06-08-20:50:
   * Remote attach panes need a native Ghostty owner, but creating that owner in the active local project makes the remote session appear under the wrong sidebar section. Use a dedicated hidden carrier project for the AppKit surface and project the focused identity back to the remote machine row.
   */
  const session = createTerminal(title, "", undefined, undefined, {
    forceSessionPersistenceOff: true,
    shellCommand: buildRemoteAttachTerminalProcessCommand(plan.sshCommand),
  });
  if (!session) {
    return undefined;
  }
  const projectId = activeProjectId;
  markNativeRemoteAttachCarrierProject(projectId);
  appendTerminalLaunchDebugLog("nativeSidebar.remoteAttach.carrierCreated", {
    hasSession: true,
    machineId: target.machineId,
    projectId,
    remoteProjectIdLength: target.projectId.length,
    remoteSessionIdLength: target.sessionId.length,
    sessionId: session.sessionId,
  });
  return { projectId, session };
}

async function ensureNativeRemoteAttachCarrierProject(): Promise<NativeProject | undefined> {
  const carrierPath = `${nativeGhostexHomeDirectory().replace(/\/+$/u, "")}/remote-attach-carriers`;
  const existingProject = projects.find((project) =>
    isRemoteAttachCarrierProject(project) &&
    normalizeNativePathForProjectComparison(project.path) === normalizeNativePathForProjectComparison(carrierPath),
  );
  if (existingProject) {
    return existingProject;
  }
  const mkdirResult = await runNativeProcess("/bin/mkdir", ["-p", carrierPath], {
    timeoutMs: 5_000,
  });
  if (mkdirResult.exitCode !== 0) {
    appendTerminalLaunchDebugLog("nativeSidebar.remoteAttach.carrierDirectoryFailed", {
      exitCode: mkdirResult.exitCode,
      hasStderr: mkdirResult.stderr.trim().length > 0,
      hasStdout: mkdirResult.stdout.trim().length > 0,
    });
    return undefined;
  }
  const project: NativeProject = {
    commandsPanel: createProjectCommandsPanelState(),
    isRecentProject: true,
    isRemoteAttachCarrier: true,
    name: "Remote Attach",
    path: carrierPath,
    projectId: createProjectId("remote-attach-carrier"),
    theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
    workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
  };
  projects = orderNativeProjectsForSidebar([...projects, project]);
  return project;
}

function markNativeRemoteAttachCarrierProject(projectId: string): void {
  projects = projects.map((project) =>
    project.projectId === projectId
      ? {
          ...project,
          isRecentProject: true,
          isRemoteAttachCarrier: true,
        }
      : project,
  );
}

function buildRemoteSshShellCommand(
  remoteMachine: ghostexSettings["remoteMachines"][number],
  remoteCommand: string,
): string {
  return buildRemoteSshCommand(remoteMachine, [remoteCommand]);
}

function buildRemoteGhostexAttachSshCommand(
  remoteMachine: ghostexSettings["remoteMachines"][number],
  target: RemoteAttachTarget,
): string {
  const remoteCommand = buildRemoteLoginShellCommand(buildRemoteGhostexAttachCommand(target));
  return buildRemoteSshCommand(remoteMachine, [remoteCommand], { forceTty: true });
}

function buildRemoteGhostexAttachCommand(target: RemoteAttachTarget): string {
  const parts = [
    "ghostex",
    "attach",
    "--session-id",
    quoteNativeShellArg(target.sessionId),
  ];
  if (target.projectId.trim()) {
    parts.push("--project-id", quoteNativeShellArg(target.projectId));
  }
  return parts.join(" ");
}

function buildRemoteLoginShellCommand(remoteCommand: string): string {
  /*
   * CDXC:RemoteAttach 2026-06-08-20:50:
   * Android allocates a PTY and starts a shell before writing the attach command, so user-managed Node paths from zsh startup files are present. The macOS OpenSSH path must invoke zsh as login+interactive too; otherwise Homebrew/mise `ghostex` shims can fail with `env: node: No such file or directory`.
   */
  const quotedCommand = quoteNativeShellArg(remoteCommand);
  return `if [ -x /bin/zsh ]; then exec /bin/zsh -lic ${quotedCommand}; elif command -v zsh >/dev/null 2>&1; then exec zsh -lic ${quotedCommand}; else exec /bin/sh -lc ${quotedCommand}; fi`;
}

function buildRemoteSshCommand(
  remoteMachine: ghostexSettings["remoteMachines"][number],
  remoteArgs: readonly string[],
  options: { forceTty?: boolean } = {},
): string {
  const args = ["ssh"];
  if (options.forceTty === true) {
    args.push("-tt");
  }
  const identityFile = remoteMachine.sshIdentityFile?.trim();
  if (identityFile) {
    /*
     * CDXC:RemoteAttach 2026-06-08-19:35:
     * Saved Remote machine key paths may use `~`. Expand before shell quoting
     * so the local SSH process launched by a remote attach terminal resolves
     * the same identity file that native SSH connection checks use.
     */
    args.push("-i", normalizeNativeOpenPath(identityFile));
  }
  if (remoteMachine.sshPort) {
    args.push("-p", String(remoteMachine.sshPort));
  }
  const sshHost = remoteMachine.sshHost.trim();
  const sshUser = remoteMachine.sshUser?.trim();
  args.push(sshUser ? `${sshUser}@${sshHost}` : sshHost, ...remoteArgs);
  return args.map(quoteRemoteSshCommandArg).join(" ");
}

function quoteRemoteSshCommandArg(value: string): string {
  return /^[A-Za-z0-9_/:=@%+.,-]+$/u.test(value) ? value : quoteNativeShellArg(value);
}

function buildRemoteAttachTerminalProcessCommand(sshCommand: string): string {
  return `/bin/zsh -lic ${quoteNativeShellArg([
    sshCommand,
    "__ghostex_remote_attach_exit=$?",
    'printf "\\nRemote attach ended with exit code %s.\\n" "$__ghostex_remote_attach_exit"',
    "exec /bin/zsh -l",
  ].join("\n"))}`;
}

function createRemoteAttachTerminalTitle(
  remoteMachine: ghostexSettings["remoteMachines"][number],
  session: GxserverPresentationSession,
): string {
  const sessionTitle =
    session.displayTitle?.trim() ||
    session.primaryTitle?.trim() ||
    session.title?.trim() ||
    DEFAULT_TERMINAL_SESSION_TITLE;
  return `${remoteMachine.name}: ${sessionTitle}`;
}

function remoteAttachSessionKey(target: RemoteAttachTarget): string {
  return createRemotePresentationSessionId(target.machineId, target.projectId, target.sessionId);
}

function isRemoteAttachCarrierFocused(remoteSessionId: string): boolean {
  /*
   * CDXC:RemoteAttach 2026-06-08-19:53:
   * A focused remote attach pane is implemented as a local hidden carrier, but the sidebar focus ring should stay on the remote session row so the session still appears owned by its remote machine instead of by Quick.
   */
  const localSessionId = remoteAttachLocalSessionIdByRemoteSessionId.get(remoteSessionId);
  const localReference = localSessionId ? parseCombinedProjectSessionId(localSessionId) : undefined;
  if (!localReference || localReference.projectId !== activeProjectId) {
    return false;
  }
  const terminalState = terminalStateById.get(localReference.sessionId);
  return (
    activeSnapshot().focusedSessionId === localReference.sessionId &&
    terminalState?.lifecycleState === "running"
  );
}

function rememberRemoteAttachLocalSession(target: RemoteAttachTarget, localSessionId: string): void {
  remoteAttachLocalSessionIdByRemoteSessionId.set(remoteAttachSessionKey(target), localSessionId);
}

function forgetRemoteAttachLocalSessionForSidebarSession(sessionId: string): void {
  const combinedReference = parseCombinedProjectSessionId(sessionId);
  for (const [remoteSessionId, localSessionId] of remoteAttachLocalSessionIdByRemoteSessionId) {
    if (localSessionId === sessionId) {
      remoteAttachLocalSessionIdByRemoteSessionId.delete(remoteSessionId);
      continue;
    }
    const localReference = parseCombinedProjectSessionId(localSessionId);
    if (
      combinedReference &&
      localReference?.projectId === combinedReference.projectId &&
      localReference.sessionId === combinedReference.sessionId
    ) {
      remoteAttachLocalSessionIdByRemoteSessionId.delete(remoteSessionId);
      continue;
    }
    if (!combinedReference && localReference?.sessionId === sessionId) {
      remoteAttachLocalSessionIdByRemoteSessionId.delete(remoteSessionId);
    }
  }
}

function focusExistingRemoteAttachTerminal(target: RemoteAttachTarget): boolean {
  const remoteSessionId = remoteAttachSessionKey(target);
  const localSessionId = remoteAttachLocalSessionIdByRemoteSessionId.get(remoteSessionId);
  if (!localSessionId) {
    return false;
  }
  const localReference = parseCombinedProjectSessionId(localSessionId);
  const localProject = localReference ? findProject(localReference.projectId) : undefined;
  const localSession = localProject && localReference
    ? findTerminalSessionInProject(localProject, localReference.sessionId)
    : undefined;
  const terminalState = localReference ? terminalStateById.get(localReference.sessionId) : undefined;
  if (!localProject || !localSession || terminalState?.lifecycleState !== "running") {
    remoteAttachLocalSessionIdByRemoteSessionId.delete(remoteSessionId);
    return false;
  }
  focusSidebarSession(localSessionId);
  return true;
}

function resolveNativeBrowserAccessT3Session(preferredSessionId?: string): T3SessionRecord | undefined {
  const preferredReference = preferredSessionId
    ? resolveSidebarSessionReference(preferredSessionId)
    : undefined;
  const project = preferredReference?.project ?? activeProject();
  const candidateSessionIds = new Set<string>();
  if (preferredReference) {
    candidateSessionIds.add(preferredReference.sessionId);
  }

  for (const group of project.workspace.groups) {
    if (group.snapshot.focusedSessionId) {
      candidateSessionIds.add(group.snapshot.focusedSessionId);
    }
  }

  for (const sessionId of candidateSessionIds) {
    const sessionRecord = findSessionRecordInProject(project, sessionId);
    if (sessionRecord?.kind === "t3") {
      return sessionRecord;
    }
  }

  for (const group of project.workspace.groups) {
    const sessionRecord = group.snapshot.sessions.find(
      (candidate): candidate is T3SessionRecord => candidate.kind === "t3",
    );
    if (sessionRecord) {
      return sessionRecord;
    }
  }

  return undefined;
}

function resolveOrCreateNativeBrowserAccessT3Session(
  preferredSessionId?: string,
): T3SessionRecord | undefined {
  const existingSession = resolveNativeBrowserAccessT3Session(preferredSessionId);
  if (existingSession) {
    return existingSession;
  }

  const preferredReference = preferredSessionId
    ? resolveSidebarSessionReference(preferredSessionId)
    : undefined;
  if (preferredReference && activeProjectId !== preferredReference.project.projectId) {
    focusProject(preferredReference.project.projectId);
  }
  return createNativeT3Session();
}

async function requestNativeT3SessionBrowserAccess(preferredSessionId?: string): Promise<void> {
  /**
   * CDXC:T3RemoteAccess 2026-05-02-01:18
   * Native ghostex cannot delegate Remote Access to the extension controller. It
   * must reuse the managed desktop T3 runtime, issue a one-time pairing link,
   * and send the QR payload through the shared sidebar modal contract.
   */
  const sessionRecord = resolveOrCreateNativeBrowserAccessT3Session(preferredSessionId);
  if (!sessionRecord) {
    showNativeMessage("error", "Could not start T3 Code for remote access.");
    return;
  }

  postNative({ cwd: sessionRecord.t3.workspaceRoot, type: "startT3CodeRuntime" });

  try {
    const ownerBearerToken = await waitForNativeT3OwnerBearerToken();
    const credential = await issueNativeT3PairingCredential(ownerBearerToken);
    const localPairingUrl = buildT3PairingUrl(NATIVE_T3_REMOTE_ACCESS_ORIGIN, credential);
    const accessLink = await resolveNativeT3BrowserAccessLink(localPairingUrl);
    sidebarBus.post({
      endpointUrl: accessLink.endpointUrl,
      localUrl: accessLink.localUrl,
      mode: accessLink.mode,
      note: accessLink.note,
      sessionId: sessionRecord.sessionId,
      sessionTitle: sessionRecord.title,
      tailscaleEnabled: accessLink.tailscaleEnabled,
      type: "showT3BrowserAccess",
    });
  } catch (error) {
    appendAgentDetectionDebugLog("nativeSidebar.t3BrowserAccess.failed", {
      error: error instanceof Error ? error.message : String(error),
      sessionId: sessionRecord.sessionId,
    });
    showNativeMessage(
      "error",
      error instanceof Error ? error.message : "Could not create the T3 remote access link.",
    );
  }
}

async function waitForNativeT3OwnerBearerToken(): Promise<string> {
  for (let attempt = 0; attempt < NATIVE_T3_REMOTE_ACCESS_AUTH_ATTEMPTS; attempt += 1) {
    const token = await readNativeT3OwnerBearerToken();
    if (token) {
      return token;
    }
    await delay(NATIVE_T3_REMOTE_ACCESS_AUTH_RETRY_MS);
  }

  throw new Error("T3 Code is still starting. Try Remote Access again in a moment.");
}

async function readNativeT3OwnerBearerToken(): Promise<string | undefined> {
  const ghostexHomeDir = window.__ghostex_NATIVE_HOST__?.ghostexHomeDir;
  if (!ghostexHomeDir) {
    return undefined;
  }

  const authStatePath = `${ghostexHomeDir.replace(/\/+$/, "")}/t3-runtime/auth-state.json`;
  const result = await runNativeProcess("/bin/cat", [authStatePath]);
  if (result.exitCode !== 0) {
    return undefined;
  }

  try {
    const parsed = JSON.parse(result.stdout) as { ownerBearerToken?: unknown; provider?: unknown };
    return parsed.provider === "t3code" && typeof parsed.ownerBearerToken === "string"
      ? parsed.ownerBearerToken.trim() || undefined
      : undefined;
  } catch {
    return undefined;
  }
}

async function issueNativeT3PairingCredential(ownerBearerToken: string): Promise<string> {
  const requestBody = JSON.stringify({ label: "Ghostex Remote Access" });
  const result = await runNativeProcess(
    "/bin/sh",
    [
      "-lc",
      [
        "/usr/bin/curl",
        "--fail",
        "--silent",
        "--show-error",
        "--max-time",
        "5",
        "-X",
        "POST",
        `${NATIVE_T3_REMOTE_ACCESS_ORIGIN}/api/auth/pairing-token`,
        "-H",
        '"authorization: Bearer $T3_OWNER_BEARER"',
        "-H",
        '"content-type: application/json"',
        "--data",
        '"$T3_PAIRING_BODY"',
      ].join(" "),
    ],
    {
      env: {
        T3_OWNER_BEARER: ownerBearerToken,
        T3_PAIRING_BODY: requestBody,
      },
    },
  );
  if (result.exitCode !== 0) {
    throw new Error(`Could not create the T3 pairing link: ${result.stderr || result.stdout}`);
  }

  const parsed = JSON.parse(result.stdout) as { credential?: unknown };
  if (typeof parsed.credential !== "string" || !parsed.credential.trim()) {
    throw new Error("T3 pairing link response did not include a credential.");
  }
  return parsed.credential.trim();
}

async function resolveNativeT3BrowserAccessLink(localUrl: string): Promise<{
  endpointUrl: string;
  localUrl: string;
  mode: "external" | "local-network" | "local-only" | "tailscale";
  note: string;
  tailscaleEnabled: boolean;
}> {
  const parsedLocalUrl = new URL(localUrl);
  const [tailscaleHost, localNetworkHost] = await Promise.all([
    detectNativeTailscaleIpv4(),
    detectNativeLocalNetworkIpv4(),
  ]);
  const localNetworkUrl = localNetworkHost
    ? replaceT3AccessUrlHost(parsedLocalUrl, localNetworkHost)
    : undefined;

  if (tailscaleHost) {
    return {
      endpointUrl: replaceT3AccessUrlHost(parsedLocalUrl, tailscaleHost),
      localUrl: localNetworkUrl ?? localUrl,
      mode: "tailscale",
      note: localNetworkUrl
        ? "QR code and Copy link use your machine's Tailscale address. Open link uses your machine's local network address."
        : "QR code and Copy link use your machine's Tailscale address. No local network address was detected, so Open link falls back to this machine only.",
      tailscaleEnabled: true,
    };
  }

  if (localNetworkHost) {
    const resolvedLocalNetworkUrl = replaceT3AccessUrlHost(parsedLocalUrl, localNetworkHost);
    return {
      endpointUrl: resolvedLocalNetworkUrl,
      localUrl: resolvedLocalNetworkUrl,
      mode: "local-network",
      note: "Tailscale is not connected, so QR code, Copy link, and Open link all use your machine's local network address.",
      tailscaleEnabled: false,
    };
  }

  return {
    endpointUrl: localUrl,
    localUrl,
    mode: "local-only",
    note: "No Tailscale or local network address was detected, so QR code, Copy link, and Open link only work on this machine for now.",
    tailscaleEnabled: false,
  };
}

async function detectNativeTailscaleIpv4(): Promise<string | undefined> {
  const result = await runNativeProcess("/usr/bin/env", ["tailscale", "ip", "-4"]);
  if (result.exitCode !== 0) {
    return undefined;
  }
  return result.stdout
    .split(/\r?\n/u)
    .map((line) => line.trim())
    .find(isIpv4Host);
}

async function detectNativeLocalNetworkIpv4(): Promise<string | undefined> {
  const result = await runNativeProcess("/bin/sh", [
    "-lc",
    [
      'iface="$(/sbin/route get default 2>/dev/null | /usr/bin/awk \'/interface:/{print $2; exit}\')"',
      'if [ -n "$iface" ]; then /usr/sbin/ipconfig getifaddr "$iface" 2>/dev/null && exit 0; fi',
      "for fallback in en0 en1; do /usr/sbin/ipconfig getifaddr \"$fallback\" 2>/dev/null && exit 0; done",
      "exit 1",
    ].join("; "),
  ]);
  if (result.exitCode !== 0) {
    return undefined;
  }
  return result.stdout
    .split(/\r?\n/u)
    .map((line) => line.trim())
    .find(isIpv4Host);
}

function buildT3PairingUrl(origin: string, credential: string): string {
  const url = new URL("/pair", origin);
  url.hash = `token=${encodeURIComponent(credential)}`;
  return url.toString();
}

function replaceT3AccessUrlHost(url: URL, host: string): string {
  const nextUrl = new URL(url.toString());
  nextUrl.hostname = host;
  return nextUrl.toString();
}

function isIpv4Host(value: string): boolean {
  const parts = value.split(".");
  if (parts.length !== 4) {
    return false;
  }
  return parts.every((part) => {
    if (!/^\d{1,3}$/u.test(part)) {
      return false;
    }
    const value = Number(part);
    return Number.isInteger(value) && value >= 0 && value <= 255;
  });
}

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => {
    window.setTimeout(resolve, ms);
  });
}

function refreshDaemonSessionsState(): void {
  const now = new Date().toISOString();
  /*
  CDXC:RunningSessionsModal 2026-06-02-20:10:
  The Running Ghostex Sessions modal is a user-visible inventory. Once gxserver presentation is active, terminal rows must come from the same hydrate groups as the sidebar so stale native project/session storage cannot appear as another canonical session list. T3 panes remain macOS-hosted local surfaces and are still collected from native pane storage.
  */
  const sidebarMessage = gxserverStartupSnapshot?.presentation ? buildSidebarMessage() : undefined;
  const sessions = sidebarMessage
    ? createDaemonTerminalSessionsFromSidebarMessage(sidebarMessage, now)
    : createDaemonTerminalSessionsFromNativeProjects(now);
  const t3Sessions = createDaemonT3SessionsFromNativeProjects(now);
  const message: SidebarDaemonSessionsStateMessage = {
    daemon: {
      pid: 0,
      port: 0,
      protocolVersion: 1,
      startedAt: now,
    },
    sessions,
    t3Server:
      t3Sessions.length > 0
        ? {
            pid: 0,
            port: 3774,
            startedAt: now,
          }
        : undefined,
    t3Sessions,
    type: "daemonSessionsState",
  };
  sidebarBus.post(message);
  postAppModalHost({ message, type: "sidebarState" });
}

function createDaemonTerminalSessionsFromSidebarMessage(
  sidebarMessage: SidebarHydrateMessage,
  now: string,
): SidebarDaemonSessionItem[] {
  const sessions: SidebarDaemonSessionItem[] = [];
  for (const group of sidebarMessage.groups) {
    const projectContext = group.projectContext;
    for (const sidebarSession of group.sessions) {
      if (sidebarSession.sessionKind !== "terminal") {
        continue;
      }
      const combinedReference = parseCombinedProjectSessionId(sidebarSession.sessionId);
      const localReference = findLocalTerminalSessionReferenceForSidebarSession(sidebarSession.sessionId);
      const projectId =
        projectContext?.editor.projectId ??
        combinedReference?.projectId ??
        localReference?.project.projectId ??
        group.groupId;
      const terminalState = combinedReference
        ? terminalStateById.get(combinedReference.sessionId)
        : terminalStateById.get(localReference?.session.sessionId ?? sidebarSession.sessionId);
      const ownership = resolveNativeSessionInventoryOwnership({
        hasGxserverProjectContext: Boolean(projectContext),
        hasGxserverSessionReference: Boolean(combinedReference),
      });
      sessions.push({
        agentName: sidebarSession.agentIcon,
        agentStatus: sidebarSession.activity,
        cols: 80,
        cwd: projectContext?.path ?? localReference?.project.path ?? "",
        isCurrentWorkspace: projectId === activeProjectId,
        isLocalOnly: ownership.isLocalOnly,
        ownership: ownership.ownership,
        restoreState: "live",
        rows: 24,
        sessionId: sidebarSession.sessionId,
        shell:
          sidebarSession.displayTitle ??
          sidebarSession.terminalTitle ??
          sidebarSession.primaryTitle ??
          sidebarSession.alias ??
          localReference?.session.title ??
          "Native Ghostty",
        startedAt: sidebarSession.lastInteractionAt ?? now,
        status: getDaemonSessionStatusFromSidebarSession(sidebarSession, terminalState),
        title:
          sidebarSession.displayTitle ??
          sidebarSession.primaryTitle ??
          sidebarSession.terminalTitle ??
          sidebarSession.alias,
        workspaceId: projectId,
      });
    }
  }
  return sessions;
}

function getDaemonSessionStatusFromSidebarSession(
  session: SidebarSessionItem,
  terminalState:
    | {
        lifecycleState: "done" | "error" | "running" | "sleeping";
      }
    | undefined,
): SidebarDaemonSessionItem["status"] {
  const lifecycleState = session.lifecycleState ?? terminalState?.lifecycleState;
  switch (lifecycleState) {
    case "error":
      return "error";
    case "done":
      return "exited";
    case "sleeping":
      return "disconnected";
    case "running":
    default:
      return "running";
  }
}

function createDaemonTerminalSessionsFromNativeProjects(now: string): SidebarDaemonSessionItem[] {
  const sessions: SidebarDaemonSessionItem[] = [];
  for (const project of projects) {
    for (const group of project.workspace.groups) {
      for (const session of group.snapshot.sessions) {
        if (session.kind !== "terminal") {
          continue;
        }
        const state = terminalStateById.get(session.sessionId);
        sessions.push({
          agentStatus: state?.activity ?? "idle",
          cols: 80,
          cwd: project.path,
          isCurrentWorkspace: project.projectId === activeProjectId,
          isLocalOnly: true,
          ownership: "local",
          restoreState: "live",
          rows: 24,
          sessionId: session.sessionId,
          shell: session.title || "Native Ghostty",
          startedAt: now,
          status:
            state?.lifecycleState === "error"
              ? "error"
              : state?.lifecycleState === "done"
                ? "exited"
                : "running",
          title: state?.terminalTitle ?? session.title,
          workspaceId: project.projectId,
        });
      }
    }
  }
  return sessions;
}

function createDaemonT3SessionsFromNativeProjects(now: string): SidebarT3SessionItem[] {
  const t3Sessions: SidebarT3SessionItem[] = [];
  for (const project of projects) {
    for (const group of project.workspace.groups) {
      for (const session of group.snapshot.sessions) {
        if (session.kind !== "t3") {
          continue;
        }
        const isSleeping = session.isSleeping === true;
        t3Sessions.push({
          activity: "idle",
          detail: session.t3?.serverOrigin ?? "Native T3 Code pane",
          isCurrentWorkspace: project.projectId === activeProjectId,
          isFocused: group.snapshot.focusedSessionId === session.sessionId,
          isLocalOnly: true,
          isRunning: !isSleeping,
          isSleeping,
          lastInteractionAt: now,
          ownership: "local",
          sessionId: session.sessionId,
          threadId: session.t3?.threadId,
          title: session.title,
          workspaceId: project.projectId,
          workspaceRoot: session.t3?.workspaceRoot ?? project.path,
        });
      }
    }
  }
  return t3Sessions;
}

function closeAllNativeSessions(): void {
  if (gxserverStartupSnapshot?.presentation) {
    /*
    CDXC:RunningSessionsModal 2026-06-02-20:20:
    The legacy Kill Daemon action must not clear native project workspaces or previous-session storage after gxserver owns shared session inventory. Treat it as a local-first request to stop visible terminal runtimes by routing each gxserver-presented terminal through the shared sleep path, leaving canonical project/session rows to gxserver.
    */
    const sidebarMessage = buildSidebarMessage();
    const sessionIds = sidebarMessage.groups.flatMap((group) =>
      group.sessions
        .filter(
          (session) =>
            session.sessionKind === "terminal" &&
            session.isSleeping !== true &&
            session.lifecycleState !== "sleeping",
        )
        .map((session) => session.sessionId),
    );
    for (const sessionId of Array.from(new Set(sessionIds))) {
      setNativeSessionSleeping(sessionId, true);
    }
    sidebarCommandSessionByCommandId.clear();
    sidebarCommandCommandIdBySessionId.clear();
    publish();
    return;
  }
  const sessionIds = projects.flatMap((project) =>
    project.workspace.groups.flatMap((group) =>
      group.snapshot.sessions
        .filter((session) => session.kind === "terminal")
        .map((session) => session.sessionId),
    ),
  );
  for (const sessionId of sessionIds) {
    const nativeSessionId = forgetNativeSessionMapping(sessionId);
    postNative({ sessionId: nativeSessionId, type: "closeTerminal" });
    forgetRemoteAttachLocalSessionForSidebarSession(sessionId);
    terminalStateById.delete(sessionId);
    pendingNativeTerminalStartupTextBySessionId.delete(sessionId);
    clearNativeSessionAttentionTracking(sessionId);
  }
  sidebarCommandSessionByCommandId.clear();
  sidebarCommandCommandIdBySessionId.clear();
  projects = projects.map((project) => ({
    ...project,
    commandsPanel: createProjectCommandsPanelState(),
    workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
  }));
  previousSessions = [];
  writeStoredProjects("closeAllNativeSessions");
  publish();
}

async function addProject(
  path: string,
  name = projectNameFromPath(path),
  options: { gxserverProject?: GxserverProjectDomainState } = {},
): Promise<void> {
  const normalizedPath = path.replace(/\/+$/, "") || path;
  let gxserverProject: GxserverProjectDomainState | undefined = options.gxserverProject;
  try {
    gxserverProject ??= await gxserverClient.addProjectPath({
      name: name.trim() || projectNameFromPath(normalizedPath),
      path: normalizedPath,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    appendSidebarRefreshDebugLog("nativeSidebar.gxserverProject.addFailed", {
      errorType: error instanceof Error ? error.name : typeof error,
      hasMessage: message.length > 0,
      projectPathDepth: normalizedPath.split("/").filter(Boolean).length,
    });
    showNativeMessage("error", message);
    return;
  }
  if (!gxserverProject) {
    return;
  }
  applyGxserverProjectDomainStateToPresentationCache(gxserverProject, "addProject");
  const projectId = gxserverProject.projectId;
  showGxserverPresentationProjectLocally(projectId);
  const gxserverWorktreeOpenMetadata = resolveGxserverWorktreeProjectOpenMetadata(
    gxserverProject,
    name,
  );
  const worktreeOpenMetadata = gxserverWorktreeOpenMetadata;
  const existingProject = projects.find(
    (project) => project.projectId === projectId || project.path.replace(/\/+$/, "") === normalizedPath,
  );
  if (existingProject?.isRecentProject === true && !worktreeOpenMetadata) {
    const restoredProject = reconcileNativeProjectWithGxserverProject(
      existingProject,
      gxserverProject,
      "restoreRecentProject",
    );
    restoreRecentProject(restoredProject.projectId);
    return;
  }

  if (worktreeOpenMetadata) {
    const projectName = name.trim() || projectNameFromPath(normalizedPath);
    const nextProject: NativeProject = existingProject
      ? {
          ...existingProject,
          isRecentProject: false,
          name: gxserverProject.name || existingProject.name?.trim() || projectName,
          projectId,
          recentClosedAt: undefined,
          worktree: worktreeOpenMetadata.worktree,
          workspace:
            existingProject.isRecentProject === true
              ? wakeVisibleProjectSessions(existingProject.workspace)
              : existingProject.workspace,
        }
      : {
          commandsPanel: createProjectCommandsPanelState(),
          name: gxserverProject.name || projectName,
          path: normalizedPath,
          projectId,
          theme:
            worktreeOpenMetadata.parentProject.theme ??
            resolveSidebarTheme(settings.sidebarTheme, "dark"),
          themeColor: worktreeOpenMetadata.parentProject.themeColor,
          worktree: worktreeOpenMetadata.worktree,
          workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
        };
    projects = insertWorktreeProjectBelowSourceProject(
      ensureNativeProjectPresent(projects, worktreeOpenMetadata.parentProject),
      nextProject,
      worktreeOpenMetadata.parentProject.projectId,
    );
    ensureProjectCommandsState(resolveNativeProjectCommandsOwnerId(projectId));
    writeProjectCommandsStore();
    writeStoredProjects("addProjectWorktree");
  } else if (existingProject) {
    reconcileNativeProjectWithGxserverProject(existingProject, gxserverProject, "addProjectExistingPath");
  } else {
    /*
    CDXC:ProjectSidebarOwnership 2026-06-02-08:24:
    Add Project visibility comes from the gxserver-shaped presentation cache and later gxserver deltas. Keep this local project shell only for macOS-owned order, focus, command-cache, and pane-layout state so terminal creation can stay local-first without making native the canonical project source.
    */
    projects = orderNativeProjectsForSidebar([
      {
        commandsPanel: createProjectCommandsPanelState(),
        name: gxserverProject.name || name.trim() || projectNameFromPath(normalizedPath),
        path: normalizedPath,
        projectId,
        theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
        workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
      },
      ...projects,
    ]);
    ensureProjectCommandsState(resolveNativeProjectCommandsOwnerId(projectId));
    writeProjectCommandsStore();
    writeStoredProjects("addProject");
  }

  focusProject(projectId);
  /*
  CDXC:ProjectSidebarOwnership 2026-06-06-23:16:
  Upgrading from 3.6 to 4.0 and adding projects after startup both require the project shell to render as soon as gxserver returns the canonical project. Publish the empty project group before first-terminal creation so a blocked or delayed zmx attach cannot make the sidebar look empty while the project already exists in gxserver.
  */
  publish();
  if (activeSnapshot().sessions.length === 0) {
    createTerminal(DEFAULT_TERMINAL_SESSION_TITLE);
    return;
  }
}

async function cloneRepositoryFromModal(
  message: Extract<SidebarToExtensionMessage, { type: "cloneRepository" }>,
): Promise<void> {
  const requestId = message.requestId.trim();
  if (!requestId) {
    return;
  }
  let job: GxserverRepositoryCloneJobStatus;
  /*
   * CDXC:AddRepository 2026-06-01-10:33:
   * Repository clones can take long enough that the dialog should close at
   * submit time. Keep progress in a persistent toast with a Cancel action wired
   * to this clone request, and update the same toast id on success, failure, or
   * cancellation instead of reopening the modal.
   *
   * CDXC:RepositoryClone 2026-06-01-11:18:
   * macOS is only the UI layer for clone progress. It asks gxserver to start a
   * repository-clone job, polls that job for terminal state, and sends cancel
   * requests back to gxserver without constructing Git commands locally.
   */
  try {
    const result = await repositoryCloneRpc<{ job: GxserverRepositoryCloneJobStatus }>(
      message.remoteMachineId,
      "/api/startRepositoryClone",
      {
        branchName: message.branchName,
        cloneMainOnly: message.cloneMainOnly === true,
        folderPath: message.folderPath,
        newFolderName: message.newFolderName,
        repositoryInput: message.repositoryInput,
        shallowClone: message.shallowClone === true,
      },
    );
    job = result.job;
  } catch (error) {
    const messageText = error instanceof Error ? error.message : String(error);
    showAppToast(
      "error",
      "Repository clone failed",
      messageText,
    );
    postRepositoryCloneResult(requestId, {
      error: messageText,
      ok: false,
    });
    return;
  }

  const destinationName = job.preview.destinationFolderName;
  const toastId = showRunningAppToast("Cloning repository", destinationName, {
    action: {
      label: "Cancel",
      sidebarMessage: { requestId, type: "cancelRepositoryClone" },
    },
  });
  const pollTimer = window.setInterval(() => {
    void pollRepositoryCloneJob(requestId);
  }, 700);
    activeRepositoryCloneRequests.set(requestId, {
      destinationName,
      jobId: job.jobId,
      pollTimer,
      remoteMachineId: message.remoteMachineId,
      toastId,
    });
  await handleRepositoryCloneJobStatus(requestId, job);
}

async function previewRepositoryCloneFromModal(
  message: Extract<SidebarToExtensionMessage, { type: "previewRepositoryClone" }>,
): Promise<void> {
  try {
    const result = await repositoryCloneRpc<{ preview: GxserverRepositoryClonePreviewResult }>(
      message.remoteMachineId,
      "/api/previewRepositoryClone",
      {
        folderPath: message.folderPath,
        newFolderName: message.newFolderName,
        repositoryInput: message.repositoryInput,
      },
    );
    postRepositoryClonePreviewResult(message.requestId, { ok: true, preview: result.preview });
  } catch (error) {
    postRepositoryClonePreviewResult(message.requestId, {
      error: error instanceof Error ? error.message : String(error),
      ok: false,
    });
  }
}

async function pollRepositoryCloneJob(requestId: string): Promise<void> {
  const activeClone = activeRepositoryCloneRequests.get(requestId);
  if (!activeClone) {
    return;
  }
  try {
    const result = await repositoryCloneRpc<{ job: GxserverRepositoryCloneJobStatus }>(
      activeClone.remoteMachineId,
      "/api/readRepositoryCloneJob",
      { jobId: activeClone.jobId },
    );
    await handleRepositoryCloneJobStatus(requestId, result.job);
  } catch (error) {
    clearRepositoryClonePoll(requestId);
    finishRunningAppToast(
      activeClone.toastId,
      "error",
      "Repository clone failed",
      error instanceof Error ? error.message : String(error),
    );
    postRepositoryCloneResult(requestId, {
      error: error instanceof Error ? error.message : String(error),
      ok: false,
    });
  }
}

async function handleRepositoryCloneJobStatus(
  requestId: string,
  job: GxserverRepositoryCloneJobStatus,
): Promise<void> {
  const activeClone = activeRepositoryCloneRequests.get(requestId);
  if (!activeClone) {
    return;
  }
  if (job.state === "running") {
    return;
  }
  clearRepositoryClonePoll(requestId);
  if (job.state === "completed") {
    const projectPath = job.projectPath ?? job.preview.destinationPath;
    if (activeClone.remoteMachineId) {
      await refreshRemoteGxserverPresentationSnapshot(activeClone.remoteMachineId, "clone-completed");
    } else {
      await addProject(projectPath, job.preview.destinationFolderName, { gxserverProject: job.project });
    }
    finishRunningAppToast(activeClone.toastId, "success", "Repository cloned", job.preview.destinationFolderName);
    postRepositoryCloneResult(requestId, { ok: true, projectPath });
    return;
  }
  if (job.state === "canceled") {
    finishRunningAppToast(
      activeClone.toastId,
      "warning",
      "Repository clone canceled",
      "The partial destination folder may still exist.",
    );
    postRepositoryCloneResult(requestId, {
      error: "Repository clone canceled.",
      ok: false,
    });
    return;
  }
  finishRunningAppToast(
    activeClone.toastId,
    "error",
    "Repository clone failed",
    job.error ?? job.stderr ?? job.message,
  );
  postRepositoryCloneResult(requestId, {
    error: job.error ?? job.stderr ?? job.message,
    ok: false,
  });
}

function clearRepositoryClonePoll(requestId: string): void {
  const activeClone = activeRepositoryCloneRequests.get(requestId);
  if (!activeClone) {
    return;
  }
  window.clearInterval(activeClone.pollTimer);
  activeRepositoryCloneRequests.delete(requestId);
}

function cancelRepositoryClone(requestId: string): void {
  const activeClone = activeRepositoryCloneRequests.get(requestId);
  if (!activeClone) {
    showAppToast("info", "Repository clone already finished");
    return;
  }
  void repositoryCloneRpc<{ job: GxserverRepositoryCloneJobStatus }>(
    activeClone.remoteMachineId,
    "/api/cancelRepositoryCloneJob",
    {
      jobId: activeClone.jobId,
    },
  )
    .then((result) => handleRepositoryCloneJobStatus(requestId, result.job))
    .catch((error) => {
      finishRunningAppToast(
        activeClone.toastId,
        "error",
        "Repository clone cancel failed",
        error instanceof Error ? error.message : String(error),
      );
    });
}

async function repositoryCloneRpc<TResult extends Record<string, unknown>>(
  remoteMachineId: string | undefined,
  path:
    | "/api/previewRepositoryClone"
    | "/api/startRepositoryClone"
    | "/api/readRepositoryCloneJob"
    | "/api/cancelRepositoryCloneJob",
  params: Record<string, unknown>,
): Promise<TResult> {
  /*
   * CDXC:RemoteClone 2026-06-02-23:46:
   * Remote Clone Repository uses the same gxserver typed clone endpoints as
   * local clone, but requests are machine-scoped through the native SSH tunnel.
   * Keep local and remote clone on one RPC helper so preview/start/poll/cancel
   * cannot accidentally split across different gxservers.
   */
  if (remoteMachineId) {
    const response = await requestRemoteGxserver<Record<string, unknown>>(
      remoteMachineId,
      path,
      { params, timeoutMs: path === "/api/startRepositoryClone" ? 60_000 : 15_000 },
    ) as { result: TResult };
    return response.result;
  }
  return gxserverClient.rpc<TResult>(path, params);
}

function postRepositoryCloneResult(
  requestId: string,
  result: { error?: string; ok: boolean; projectPath?: string },
): void {
  postAppModalHostMessage(
    {
      error: result.error,
      ok: result.ok,
      projectPath: result.projectPath,
      requestId,
      type: "repositoryCloneResult",
    },
    "AppModals:addRepository.cloneResult",
  );
}

function postRepositoryClonePreviewResult(
  requestId: string,
  result: { error?: string; ok: boolean; preview?: GxserverRepositoryClonePreviewResult },
): void {
  postAppModalHostMessage(
    {
      error: result.error,
      ok: result.ok,
      preview: result.preview,
      requestId,
      type: "repositoryClonePreviewResult",
    },
    "AppModals:addRepository.clonePreviewResult",
  );
}

function resolveGxserverWorktreeProjectOpenMetadata(
  gxserverProject: GxserverProjectDomainState,
  projectName: string,
):
  | {
      parentProject: NativeProject;
      worktree: NativeProjectWorktreeMetadata;
    }
  | undefined {
  const worktree = resolveNativeProjectWorktreeParentMetadata(
    normalizeNativeProjectWorktreeMetadata(gxserverProject.worktree),
  );
  if (!worktree) {
    return undefined;
  }

  /*
   * CDXC:WorktreeProjectRegistration 2026-06-01-20:59:
   * Add Project now receives canonical gxserver worktree metadata. Prefer that
   * parent P-id over sidebar-local path-derived IDs so an imported existing
   * worktree is grouped under the already registered main project.
   */
  const parentProject =
    projects.find(
      (project) =>
        project.projectId === worktree.parentProjectId ||
        normalizeNativePathForProjectComparison(project.path) ===
          normalizeNativePathForProjectComparison(worktree.parentProjectPath),
    ) ?? {
      commandsPanel: createProjectCommandsPanelState(),
      name: worktree.parentProjectName,
      path: worktree.parentProjectPath,
      projectId: worktree.parentProjectId,
      theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
      workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
    };

  return {
    parentProject: { ...parentProject, isRecentProject: false, recentClosedAt: undefined },
    worktree: {
      ...worktree,
      name: worktree.name || projectName,
    },
  };
}

function insertWorktreeProjectBelowSourceProject(
  currentProjects: readonly NativeProject[],
  worktreeProject: NativeProject,
  sourceProjectId: string,
): NativeProject[] {
  const projectsWithoutWorktree = currentProjects.filter(
    (project) => project.projectId !== worktreeProject.projectId,
  );
  const sourceIndex = projectsWithoutWorktree.findIndex(
    (project) => project.projectId === sourceProjectId,
  );
  const insertIndex = sourceIndex >= 0 ? sourceIndex + 1 : 0;
  const nextProjects = [...projectsWithoutWorktree];
  nextProjects.splice(insertIndex, 0, worktreeProject);
  return orderNativeProjectsForSidebar(nextProjects);
}

function resolveNativeWorktreeFamilyParentProject(sourceProject: NativeProject): NativeProject {
  if (!sourceProject.worktree?.parentProjectId) {
    return sourceProject;
  }

  const parentProject = projects.find(
    (candidate) => candidate.projectId === sourceProject.worktree?.parentProjectId,
  );
  return parentProject
    ? { ...parentProject, isRecentProject: false, recentClosedAt: undefined }
    : createNativeProjectFromWorktreeParent(sourceProject.worktree, sourceProject);
}

function ensureNativeProjectPresent(
  currentProjects: readonly NativeProject[],
  projectToEnsure: NativeProject,
): NativeProject[] {
  const existingProject = currentProjects.find(
    (project) => project.projectId === projectToEnsure.projectId,
  );
  if (!existingProject) {
    return [...currentProjects, projectToEnsure];
  }

  return currentProjects.map((project) =>
    project.projectId === projectToEnsure.projectId
      ? { ...project, isRecentProject: false, recentClosedAt: undefined }
      : project,
  );
}

function gxserverProjectOperationScopeForNativeProject(
  project: NativeProject,
): { projectId?: never; projectPath: string } {
  return {
    projectId: GXSERVER_CANONICAL_PROJECT_ID_PATTERN.test(project.projectId)
      ? project.projectId as never
      : undefined,
    projectPath: project.path,
  };
}

async function runGxserverWorktreeActionForNativeProject(
  project: NativeProject,
  params: Omit<Parameters<typeof gxserverClient.runWorktreeAction>[0], "projectId" | "projectPath">,
): Promise<Awaited<ReturnType<typeof gxserverClient.runWorktreeAction>>> {
  return gxserverClient.runWorktreeAction({
    ...gxserverProjectOperationScopeForNativeProject(project),
    ...params,
  });
}

async function runGxserverGitActionForNativeProject(
  project: NativeProject,
  params: Omit<Parameters<typeof gxserverClient.runGitAction>[0], "projectId" | "projectPath">,
): Promise<Awaited<ReturnType<typeof gxserverClient.runGitAction>>> {
  /*
  CDXC:WorktreeDelete 2026-06-02-11:55:
  Worktree delete inspection reads shared Git state before a shared worktree mutation. Route branch/status checks through gxserver typed Git operations so native owns the confirmation modal while gxserver owns repository command execution.

  CDXC:ProjectDiffStats 2026-06-02-12:21:
  Native owns project-header diff loading, parsing, and rendering, but gxserver owns the Git inspections that feed those stats. This keeps local-first sidebar UI separate from backend repository command execution.
  */
  return gxserverClient.runGitAction({
    ...gxserverProjectOperationScopeForNativeProject(project),
    ...params,
  });
}

async function runGxserverGitHubActionForNativeProject(
  project: NativeProject,
  params: Omit<Parameters<typeof gxserverClient.runGitHubAction>[0], "projectId" | "projectPath">,
): Promise<Awaited<ReturnType<typeof gxserverClient.runGitHubAction>>> {
  /*
  CDXC:GitHubOperations 2026-06-02-13:18:
  Native owns PR review UI, browser opening, and local Git button state. gxserver owns the allowlisted GitHub CLI execution so PR view/create does not remain a macOS-owned backend shellout after the ownership split.
  */
  return gxserverClient.runGitHubAction({
    ...gxserverProjectOperationScopeForNativeProject(project),
    ...params,
  });
}

async function runGxserverBeadsActionForNativeProject(
  project: NativeProject,
  params: Omit<Parameters<typeof gxserverClient.runBeadsAction>[0], "projectId" | "projectPath">,
): Promise<Awaited<ReturnType<typeof gxserverClient.runBeadsAction>>> {
  return gxserverClient.runBeadsAction({
    ...gxserverProjectOperationScopeForNativeProject(project),
    ...params,
  });
}

function gxserverTypedOperationFailureMessage(
  result: Awaited<ReturnType<typeof gxserverClient.runWorktreeAction>>,
  fallback: string,
): string {
  return result.error?.message || result.stderr.trim() || result.stdout.trim() || fallback;
}

function gxserverGitTypedOperationFailureMessage(
  result: Awaited<ReturnType<typeof gxserverClient.runGitAction>>,
  fallback: string,
): string {
  return result.error?.message || result.stderr.trim() || result.stdout.trim() || fallback;
}

function hasGxserverShortStatusChanges(stdout: string): boolean {
  return stdout
    .split("\n")
    .some((line) => {
      const trimmed = line.trim();
      return trimmed.length > 0 && !trimmed.startsWith("##");
    });
}

async function pruneGxserverWorktreesForNativeProject(project: NativeProject, reason: string): Promise<void> {
  try {
    const result = await runGxserverWorktreeActionForNativeProject(project, { action: "prune" });
    if (result.exitCode !== 0) {
      appendSidebarRefreshDebugLog("nativeSidebar.gxserver.worktreePruneFailed", {
        commandBuilt: result.command !== undefined,
        errorCode: result.error?.code,
        exitCode: result.exitCode,
        reason,
      });
    }
  } catch (error) {
    appendSidebarRefreshDebugLog("nativeSidebar.gxserver.worktreePruneFailed", {
      errorType: error instanceof Error ? error.name : typeof error,
      hasMessage: (error instanceof Error ? error.message : String(error)).length > 0,
      reason,
    });
  }
}

async function requestProjectWorktrees(
  message: Extract<SidebarToExtensionMessage, { type: "requestProjectWorktrees" }>,
): Promise<void> {
  const requestId = message.requestId.trim();
  if (!requestId) {
    return;
  }
  const remoteReference = resolveRemoteWorktreeProjectReference(message);
  if (remoteReference) {
    try {
      postProjectWorktreesResult(requestId, {
        ok: true,
        worktrees: await listRemoteExistingProjectWorktrees(remoteReference),
      });
    } catch (error) {
      postProjectWorktreesResult(requestId, {
        error: error instanceof Error ? error.message : String(error),
        ok: false,
      });
    }
    return;
  }
  const sourceProject = resolveWorktreeSourceProject(message) ?? activeProject();
  try {
    postProjectWorktreesResult(requestId, {
      ok: true,
      worktrees: await listNativeExistingProjectWorktrees(sourceProject),
    });
  } catch (error) {
    postProjectWorktreesResult(requestId, {
      error: error instanceof Error ? error.message : String(error),
      ok: false,
    });
  }
}

function resolveRemoteWorktreeProjectReference(scope: {
  projectId?: string;
  projectPath?: string;
  remoteMachineId?: string;
}): { machineId: string; projectId: string; projectPath?: string } | undefined {
  const parsedProjectId = scope.projectId ? parseRemotePresentationProjectId(scope.projectId) : undefined;
  const machineId = scope.remoteMachineId?.trim() || parsedProjectId?.machineId;
  const projectId = parsedProjectId?.projectId ?? (machineId && scope.projectId ? scope.projectId : undefined);
  if (!machineId || !projectId) {
    return undefined;
  }
  return {
    machineId,
    projectId,
    ...(scope.projectPath?.trim() ? { projectPath: scope.projectPath.trim() } : {}),
  };
}

function resolveWorktreeSourceProject(scope: {
  projectId?: string;
  projectPath?: string;
}): NativeProject | undefined {
  if (scope.projectId) {
    const project = projects.find((candidate) => candidate.projectId === scope.projectId);
    if (project) {
      return project;
    }
  }

  const normalizedProjectPath = scope.projectPath?.trim()
    ? normalizeNativePathForProjectComparison(scope.projectPath)
    : "";
  if (!normalizedProjectPath) {
    return undefined;
  }
  const projectByPath = projects.find(
    (candidate) =>
      normalizeNativePathForProjectComparison(candidate.path) === normalizedProjectPath,
  );
  if (projectByPath) {
    return projectByPath;
  }

  /*
   * CDXC:WorktreeProjectRegistration 2026-06-01-20:59:
   * Add Worktree can open from gxserver presentation rows before the project is
   * materialized into the local sidebar project cache. Resolve by projectPath
   * and create an in-memory source so existing-worktree listing still works.
   */
  return {
    commandsPanel: createProjectCommandsPanelState(),
    name: projectNameFromPath(normalizedProjectPath),
    path: normalizedProjectPath,
    projectId: scope.projectId ?? createProjectId(normalizedProjectPath),
    theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
    workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
  };
}

async function listNativeExistingProjectWorktrees(
  sourceProject: NativeProject,
): Promise<NativeExistingWorktreeOption[]> {
  if (sourceProject.isChat === true || sourceProject.isRecentProject === true) {
    return [];
  }
  const parentProject = resolveNativeWorktreeFamilyParentProject(sourceProject);
  /*
  CDXC:WorktreeProjectRegistration 2026-06-02-13:01:
  Existing-worktree discovery and Git porcelain parsing are gxserver-owned after the ownership split. Native consumes the typed operation's structured `worktrees` result and owns only picker filtering, selection state, and local-first focus.
  */
  const result = await runGxserverWorktreeActionForNativeProject(parentProject, { action: "list" });
  if (result.exitCode !== 0) {
    throw new Error(gxserverTypedOperationFailureMessage(result, "Could not list worktrees."));
  }

  const entries = result.worktrees ?? [];
  const mainEntry = entries.find((entry) => !entry.bare);
  const mainPath = normalizeNativePathForProjectComparison(mainEntry?.path ?? parentProject.path);
  const sourcePath = normalizeNativePathForProjectComparison(sourceProject.path);
  const registeredPaths = new Set(
    projects.map((project) => normalizeNativePathForProjectComparison(project.path)),
  );

  /*
   * CDXC:WorktreeProjectRegistration 2026-06-01-20:59:
   * The Add Worktree modal lists existing linked worktrees for the selected
   * project family. Exclude the main checkout but keep already registered
   * worktrees selectable so Open Existing can focus that worktree project
   * without creating another checkout.
   */
  return entries
    .filter((entry) => !entry.bare)
    .map((entry) => ({
      ...entry,
      normalizedPath: normalizeNativePathForProjectComparison(entry.path),
    }))
    .filter((entry) => entry.normalizedPath && entry.normalizedPath !== mainPath)
    .map((entry) => ({
      branch: entry.branch,
      isCurrentProject: entry.normalizedPath === sourcePath,
      isRegistered: registeredPaths.has(entry.normalizedPath),
      name: projectNameFromPath(entry.normalizedPath),
      path: entry.normalizedPath,
    }));
}

async function listRemoteExistingProjectWorktrees(
  remoteReference: { machineId: string; projectId: string; projectPath?: string },
): Promise<NativeExistingWorktreeOption[]> {
  /*
   * CDXC:RemoteWorktrees 2026-06-03-00:29:
   * Existing remote worktree discovery should use the same gxserver typed
   * worktree operation as local rows, but scoped to the owning machine. The
   * modal receives only normalized paths/labels; command execution and Git
   * porcelain parsing stay inside the remote gxserver.
   */
  const result = await runRemoteGxserverWorktreeAction(remoteReference, { action: "list" });
  if (result.exitCode !== 0) {
    throw new Error(gxserverTypedOperationFailureMessage(result, "Could not list remote worktrees."));
  }
  const presentation = remotePresentationSnapshotsByMachineId.get(remoteReference.machineId);
  const sourceProject = presentation?.projects.find((project) => project.projectId === remoteReference.projectId);
  const entries = result.worktrees ?? [];
  const mainEntry = entries.find((entry) => !entry.bare);
  const mainPath = normalizeNativePathForProjectComparison(mainEntry?.path ?? sourceProject?.path ?? remoteReference.projectPath ?? "");
  const sourcePath = normalizeNativePathForProjectComparison(sourceProject?.path ?? remoteReference.projectPath ?? "");
  const registeredPaths = new Set(
    (presentation?.projects ?? [])
      .map((project) => normalizeNativePathForProjectComparison(project.path ?? ""))
      .filter(Boolean),
  );
  return entries
    .filter((entry) => !entry.bare)
    .map((entry) => ({
      ...entry,
      normalizedPath: normalizeNativePathForProjectComparison(entry.path),
    }))
    .filter((entry) => entry.normalizedPath && entry.normalizedPath !== mainPath)
    .map((entry) => ({
      branch: entry.branch,
      isCurrentProject: entry.normalizedPath === sourcePath,
      isRegistered: registeredPaths.has(entry.normalizedPath),
      name: projectNameFromPath(entry.normalizedPath),
      path: entry.normalizedPath,
    }));
}

function postProjectWorktreesResult(
  requestId: string,
  result: { error?: string; ok: boolean; worktrees?: NativeExistingWorktreeOption[] },
): void {
  postAppModalHostMessage(
    {
      error: result.error,
      ok: result.ok,
      requestId,
      type: "projectWorktreesResult",
      worktrees: result.worktrees,
    },
    "AppModals:worktree.projectWorktreesResult",
  );
}

function normalizeNativePathForProjectComparison(path: string): string {
  return path.trim().replace(/\/+$/u, "") || path.trim();
}

async function createNativeWorktreeForAgentPrompt(input: {
  agent: SidebarAgentButton;
  focusAfterCreate?: boolean;
  logEvent?: (event: string, details?: Record<string, unknown>) => void;
  prompt: string;
  sourceProject: NativeProject;
  submitPrompt?: boolean;
  successToastTitle?: string;
}): Promise<{ project: NativeProject; session: TerminalSessionRecord }> {
  const { agent, logEvent, prompt, sourceProject } = input;
  if (!prompt.trim()) {
    throw new Error("Worktree prompt is empty.");
  }
  if (!agent.command?.trim()) {
    throw new Error("Choose an agent with a configured command.");
  }
  if (sourceProject.isChat === true || sourceProject.isRecentProject === true) {
    throw new Error("Worktrees need an active code project.");
  }

  /**
   * CDXC:Worktrees 2026-05-18-23:07:
   * Creating a worktree should create a named branch, add a sibling worktree directory, focus that new project, optionally run the parent setup command, then launch the selected agent with the user's first prompt.
   *
   * CDXC:WorktreeProjectOrder 2026-05-25-12:38:
   * The new worktree project belongs directly below the project that created
   * it, while its metadata points at the main project so every worktree in
   * the family remains grouped under that main project during later reorders.
   *
   * CDXC:ProjectBoard 2026-05-28-12:32:
   * Project-board Create & Start can reuse the same worktree creation machinery,
   * but it supplies the bead work prompt and stores the conversation link on the
   * board project. Return the created terminal and worktree project so the
   * caller can link the bead to the actual execution environment.
   */
  showAppToast("info", "Generating worktree name");
  logEvent?.("projectBoard.worktree.repoCheck.start", {
    hasSourceProjectId: sourceProject.projectId.length > 0,
    hasSourceProjectPath: sourceProject.path.length > 0,
  });
  const repoCheck = await runGxserverGitActionForNativeProject(sourceProject, { action: "isInsideWorkTree" });
  if (repoCheck.exitCode !== 0 || repoCheck.stdout.trim() !== "true") {
    throw new Error(`${sourceProject.name} is not inside a Git work tree.`);
  }

  const baseSlug = await generateNativeWorktreeNameFromPrompt(sourceProject.path, prompt);
  const target = await resolveUniqueNativeWorktreeTarget(sourceProject, baseSlug);
  let parentProject = resolveNativeWorktreeFamilyParentProject(sourceProject);
  const gxserverParentProject = await gxserverClient.addProjectPath({
    name: parentProject.name,
    path: parentProject.path,
  });
  applyGxserverProjectDomainStateToPresentationCache(gxserverParentProject, "createProjectWorktree:parent");
  let gxserverSetupCommandProject = gxserverParentProject;
  parentProject = {
    ...parentProject,
    name: gxserverParentProject.name || parentProject.name,
    projectId: gxserverParentProject.projectId,
  };
  let worktreeOperationProject = sourceProject;
  if (
    normalizeNativePathForProjectComparison(sourceProject.path) ===
    normalizeNativePathForProjectComparison(parentProject.path)
  ) {
    worktreeOperationProject = parentProject;
  } else {
    const gxserverSourceProject = await gxserverClient.addProjectPath({
      name: sourceProject.name,
      path: sourceProject.path,
    });
    applyGxserverProjectDomainStateToPresentationCache(gxserverSourceProject, "createProjectWorktree:source");
    gxserverSetupCommandProject = gxserverSourceProject;
    worktreeOperationProject = {
      ...sourceProject,
      name: gxserverSourceProject.name || sourceProject.name,
      projectId: gxserverSourceProject.projectId,
    };
  }
  logEvent?.("projectBoard.worktree.targetResolved", {
    branchLength: target.branch.length,
    hasSourceProjectId: sourceProject.projectId.length > 0,
    targetPathDepth: target.path.split("/").filter(Boolean).length,
  });
  showAppToast("info", "Creating worktree", target.path);
  const createResult = await runGxserverWorktreeActionForNativeProject(worktreeOperationProject, {
    action: "create",
    baseRef: "HEAD",
    branch: target.branch,
    worktreePath: target.path,
  });
  if (createResult.exitCode !== 0) {
    throw new Error(gxserverTypedOperationFailureMessage(createResult, "git worktree add failed."));
  }

  const projectName = `${parentProject.name}-${target.name}`;
  const gxserverWorktreeProject = await gxserverClient.addProjectPath({
    name: projectName,
    path: target.path,
  });
  applyGxserverProjectDomainStateToPresentationCache(gxserverWorktreeProject, "createProjectWorktree:worktree");
  const gxserverWorktree = normalizeNativeProjectWorktreeMetadata(gxserverWorktreeProject.worktree);
  if (!gxserverWorktree) {
    throw new Error("gxserver did not register the new checkout as a worktree project.");
  }
  const projectId = gxserverWorktreeProject.projectId;
  const existingProject = projects.find((project) => project.projectId === projectId);
  const worktree: NativeProjectWorktreeMetadata = {
    ...gxserverWorktree,
    name: target.name,
  };

  const nextWorktreeProject: NativeProject = existingProject
    ? {
        ...existingProject,
        isRecentProject: false,
        name: projectName,
        recentClosedAt: undefined,
        worktree,
      }
    : {
        commandsPanel: createProjectCommandsPanelState(),
        name: projectName,
        path: target.path,
        projectId,
        theme: sourceProject.theme ?? resolveSidebarTheme(settings.sidebarTheme, "dark"),
        themeColor: sourceProject.themeColor,
        worktree,
        workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
      };
  projects = insertWorktreeProjectBelowSourceProject(
    ensureNativeProjectPresent(projects, parentProject),
    nextWorktreeProject,
    parentProject.projectId,
  );
  activeProjectId = projectId;
  collapseSidebarProjectSessionList(parentProject.projectId);
  ensureProjectCommandsState(resolveNativeProjectCommandsOwnerId(projectId));
  writeProjectCommandsStore();
  loadActiveProjectCommands();
  writeStoredProjects("createProjectWorktree");
  await refreshGitState();
  publish();
  logEvent?.("projectBoard.worktree.projectCreated", {
    projectId,
    projectName,
    sourceProjectId: sourceProject.projectId,
  });

  /*
  CDXC:WorktreeProjectRegistration 2026-06-02-15:31:
  The post-create worktree setup command is gxserver-owned Git/project metadata after the cutoff. Read it from the gxserver project row registered for this creation flow, not from the native project cache, so stale WK storage cannot run an old setup command after gxserver has reconciled the project.
  */
  const setupCommand = textValue(gxserverSetupCommandProject.gitConfig.worktreeCommand);
  if (setupCommand) {
    showAppToast("info", "Running worktree command");
    logEvent?.("projectBoard.worktree.setup.start", { projectId });
    const setupResult = await runNativeProcess("/bin/zsh", ["-lc", setupCommand], {
      cwd: target.path,
      timeoutMs: 120_000,
    });
    if (setupResult.exitCode === 0) {
      showAppToast("success", "Worktree command finished");
      logEvent?.("projectBoard.worktree.setup.completed", { projectId });
    } else {
      const setupError =
        setupResult.stderr.trim() || setupResult.stdout.trim() || "Command exited with an error.";
      showAppToast("error", "Worktree command failed", setupError.slice(0, 500));
      logEvent?.("projectBoard.worktree.setup.failed", {
        exitCode: setupResult.exitCode,
        projectId,
        stderrLength: setupResult.stderr.length,
        stdoutLength: setupResult.stdout.length,
      });
    }
  }

  showAppToast("info", "Opening agent", agent.name);
  const session = await launchAgentTerminal(agent, undefined, {
    focusAfterCreate: input.focusAfterCreate,
  });
  if (!session || session.kind !== "terminal") {
    throw new Error("Could not create an agent session in the worktree.");
  }
  await stageNativeAgentPrompt({
    agent,
    projectId,
    prompt,
    session,
    submitPrompt: input.submitPrompt,
  });
  showAppToast("success", input.successToastTitle ?? "Worktree ready", projectName);
  logEvent?.("projectBoard.worktree.agentStarted", {
    agentId: agent.agentId,
    projectId,
    sessionId: session.sessionId,
  });
  return {
    project: findProject(projectId) ?? nextWorktreeProject,
    session,
  };
}

async function createProjectWorktreeFromPrompt(
  message: Extract<SidebarToExtensionMessage, { type: "createProjectWorktree" }>,
): Promise<void> {
  const remoteReference = resolveRemoteWorktreeProjectReference(message);
  if (remoteReference) {
    try {
      if (message.mode === "openExisting" || message.existingWorktreePath?.trim()) {
        await openExistingRemoteWorktreeProject({
          remoteReference,
          worktreePath: message.existingWorktreePath,
        });
        return;
      }
      const prompt = message.prompt?.trim() ?? "";
      const agent = agents.find((candidate) => candidate.agentId === message.agentId);
      if (!prompt) {
        showAppToast("warning", "Worktree prompt is empty");
        return;
      }
      if (!agent?.command?.trim()) {
        showAppToast("error", "Agent is unavailable", "Choose an agent with a configured command.");
        return;
      }
      await createRemoteWorktreeForAgentPrompt({
        agent,
        prompt,
        remoteReference,
      });
    } catch (error) {
      showAppToast(
        "error",
        message.mode === "openExisting" ? "Could not open remote worktree" : "Could not create remote worktree",
        error instanceof Error ? error.message : String(error),
      );
    }
    return;
  }
  const sourceProject = resolveWorktreeSourceProject(message) ?? activeProject();
  try {
    if (message.mode === "openExisting" || message.existingWorktreePath?.trim()) {
      await openExistingNativeWorktreeProject({
        sourceProject,
        worktreePath: message.existingWorktreePath,
      });
      return;
    }

    const prompt = message.prompt?.trim() ?? "";
    const agent = agents.find((candidate) => candidate.agentId === message.agentId);
    if (!prompt) {
      showAppToast("warning", "Worktree prompt is empty");
      return;
    }
    if (!agent?.command?.trim()) {
      showAppToast("error", "Agent is unavailable", "Choose an agent with a configured command.");
      return;
    } else {
      await createNativeWorktreeForAgentPrompt({ agent, prompt, sourceProject });
    }
  } catch (error) {
    showAppToast(
      "error",
      message.mode === "openExisting" ? "Could not open worktree" : "Could not create worktree",
      error instanceof Error ? error.message : String(error),
    );
  }
}

async function openExistingRemoteWorktreeProject(input: {
  remoteReference: { machineId: string; projectId: string };
  worktreePath?: string;
}): Promise<void> {
  const normalizedPath = input.worktreePath?.trim().replace(/\/+$/u, "") ?? "";
  if (!normalizedPath) {
    throw new Error("Choose an existing worktree.");
  }
  const projectName = projectNameFromPath(normalizedPath);
  const response = await requestRemoteGxserver<{ project: GxserverProjectDomainState }>(
    input.remoteReference.machineId,
    "/api/addProjectPath",
    {
      params: {
        name: projectName,
        path: normalizedPath,
      },
    },
  ) as { result: { project: GxserverProjectDomainState } };
  const worktree = normalizeNativeProjectWorktreeMetadata(response.result.project.worktree);
  if (!worktree) {
    throw new Error(`${normalizedPath} is not a registered remote worktree.`);
  }
  void refreshRemoteGxserverPresentationSnapshot(input.remoteReference.machineId, "open-existing-remote-worktree");
  showAppToast("success", "Remote worktree ready", response.result.project.name || projectName);
}

async function createRemoteWorktreeForAgentPrompt(input: {
  agent: SidebarAgentButton;
  logEvent?: (event: string, details?: Record<string, unknown>) => void;
  prompt: string;
  remoteReference: { machineId: string; projectId: string; projectPath?: string };
  sourceProject?: GxserverProjectDomainState;
  successToastTitle?: string;
}): Promise<{ project: GxserverProjectDomainState; session: GxserverSessionDomainState }> {
  const { agent, logEvent, prompt, remoteReference } = input;
  if (!prompt.trim()) {
    throw new Error("Worktree prompt is empty.");
  }
  if (!agent.command?.trim()) {
    throw new Error("Choose an agent with a configured command.");
  }

  /*
   * CDXC:RemoteWorktrees 2026-06-03-02:44:
   * Fresh remote worktree creation should reuse the same gxserver-owned typed
   * boundaries as local worktrees, but scope every repository mutation and
   * agent launch to the owning machine. Native keeps naming and modal feedback;
   * remote gxserver owns Git ref checks, path availability, `git worktree add`,
   * project registration, zmx provider start, and prompt delivery.
   */
  const sourceProject = input.sourceProject ?? await readRemoteWorktreeSourceProject(remoteReference);
  showAppToast("info", "Generating remote worktree name");
  logEvent?.("remoteWorktree.create.repoCheck.start", {
    machineKnown: settings.remoteMachines.some((machine) => machine.id === remoteReference.machineId),
    sourceProjectId: sourceProject.projectId,
  });
  const repoCheck = await runRemoteGxserverGitAction(
    { machineId: remoteReference.machineId, projectId: sourceProject.projectId },
    { action: "isInsideWorkTree" },
  );
  if (repoCheck.exitCode !== 0 || repoCheck.stdout.trim() !== "true") {
    throw new Error(`${sourceProject.name} is not inside a Git work tree.`);
  }

  const baseSlug = await generateRemoteWorktreeNameFromPrompt(prompt);
  const target = await resolveUniqueRemoteWorktreeTarget(
    { machineId: remoteReference.machineId, projectId: sourceProject.projectId },
    sourceProject,
    baseSlug,
  );
  logEvent?.("remoteWorktree.create.targetResolved", {
    branchLength: target.branch.length,
    sourceProjectId: sourceProject.projectId,
    targetPathDepth: target.path.split("/").filter(Boolean).length,
  });
  showAppToast("info", "Creating remote worktree", target.path);
  const createResult = await runRemoteGxserverWorktreeAction(
    { machineId: remoteReference.machineId, projectId: sourceProject.projectId },
    {
      action: "create",
      baseRef: "HEAD",
      branch: target.branch,
      worktreePath: target.path,
    },
  );
  if (createResult.exitCode !== 0) {
    throw new Error(gxserverTypedOperationFailureMessage(createResult, "Remote git worktree add failed."));
  }

  const parentProject = await resolveRemoteWorktreeFamilyParentProject(remoteReference.machineId, sourceProject);
  const projectName = `${parentProject.name}-${target.name}`;
  const worktreeProject = await addRemoteGxserverProjectPath(
    remoteReference.machineId,
    target.path,
    projectName,
  );
  const worktree = normalizeNativeProjectWorktreeMetadata(worktreeProject.worktree);
  if (!worktree) {
    throw new Error("gxserver did not register the new remote checkout as a worktree project.");
  }

  /*
   * CDXC:RemoteWorktrees 2026-06-03-04:08:
   * Remote worktree creation must honor the same gxserver-owned post-create
   * setup command as local worktrees. Execute it through the owning gxserver's
   * narrow project setup endpoint after the target project is registered and
   * before the agent prompt starts, so the command runs in the remote checkout
   * cwd without exposing a generic process bridge.
   */
  const setupCommand = textValue(sourceProject.gitConfig.worktreeCommand);
  if (setupCommand) {
    showAppToast("info", "Running remote worktree command");
    logEvent?.("remoteWorktree.create.setup.start", {
      projectId: worktreeProject.projectId,
      setupProjectId: sourceProject.projectId,
    });
    const setupResult = await runRemoteGxserverProjectSetupCommand({
      machineId: remoteReference.machineId,
      setupCommandProjectId: sourceProject.projectId,
      targetProjectId: worktreeProject.projectId,
    });
    if (setupResult.exitCode === 0) {
      showAppToast("success", "Remote worktree command finished");
      logEvent?.("remoteWorktree.create.setup.completed", { projectId: worktreeProject.projectId });
    } else {
      const setupError =
        setupResult.stderr.trim() || setupResult.stdout.trim() || "Command exited with an error.";
      showAppToast("error", "Remote worktree command failed", setupError.slice(0, 500));
      logEvent?.("remoteWorktree.create.setup.failed", {
        exitCode: setupResult.exitCode,
        projectId: worktreeProject.projectId,
        stderrLength: setupResult.stderr.length,
        stdoutLength: setupResult.stdout.length,
      });
    }
  }

  showAppToast("info", "Opening remote agent", agent.name);
  const createSessionResponse = await requestRemoteGxserver<{ session: GxserverSessionDomainState }>(
    remoteReference.machineId,
    "/api/createAgentSession",
    {
      params: {
        agentId: agent.agentId,
        launchSettings: {
          agentCommand: agent.command,
          icon: agent.icon,
        },
        projectId: worktreeProject.projectId,
        runtimeSettings: {
          firstUserMessage: prompt,
        },
        surface: "workspace",
        title: createAgentSessionDefaultTitle(agent.name),
      },
      timeoutMs: 15_000,
    },
  ) as { result: { session: GxserverSessionDomainState } };
  const session = createSessionResponse.result.session;
  await requestRemoteGxserver(
    remoteReference.machineId,
    "/api/startSessionProvider",
    {
      params: {
        projectId: worktreeProject.projectId,
        sessionId: session.sessionId,
      },
      timeoutMs: 15_000,
    },
  );
  await delayNativeAgentPromptStep(AGENT_PROMPT_READY_DELAY_MS);
  await requestRemoteGxserver(
    remoteReference.machineId,
    "/api/sendSessionMessage",
    {
      params: {
        projectId: worktreeProject.projectId,
        sessionId: session.sessionId,
        submit: true,
        text: prompt,
      },
      timeoutMs: 15_000,
    },
  );
  void refreshRemoteGxserverPresentationSnapshot(remoteReference.machineId, "create-remote-worktree");
  showAppToast("success", input.successToastTitle ?? "Remote worktree ready", worktreeProject.name || projectName);
  logEvent?.("remoteWorktree.create.agentStarted", {
    agentId: agent.agentId,
    projectId: worktreeProject.projectId,
    sessionId: session.sessionId,
  });
  return { project: worktreeProject, session };
}

async function readRemoteGxserverProjects(machineId: string): Promise<readonly GxserverProjectDomainState[]> {
  const response = await requestRemoteGxserver<{ projects: readonly GxserverProjectDomainState[] }>(
    machineId,
    "/api/listProjects",
    { timeoutMs: 15_000 },
  ) as { result: { projects: readonly GxserverProjectDomainState[] } };
  return response.result.projects;
}

async function readRemoteWorktreeSourceProject(
  remoteReference: { machineId: string; projectId: string; projectPath?: string },
): Promise<GxserverProjectDomainState> {
  const projects = await readRemoteGxserverProjects(remoteReference.machineId);
  const normalizedProjectPath = normalizeNativePathForProjectComparison(remoteReference.projectPath ?? "");
  const project = projects.find((candidate) =>
    candidate.projectId === remoteReference.projectId ||
    (normalizedProjectPath &&
      candidate.path !== undefined &&
      normalizeNativePathForProjectComparison(candidate.path) === normalizedProjectPath),
  );
  if (project) {
    return project;
  }
  if (normalizedProjectPath) {
    return addRemoteGxserverProjectPath(
      remoteReference.machineId,
      normalizedProjectPath,
      projectNameFromPath(normalizedProjectPath),
    );
  }
  throw new Error("Remote source project was not found.");
}

async function addRemoteGxserverProjectPath(
  machineId: string,
  path: string,
  name = projectNameFromPath(path),
): Promise<GxserverProjectDomainState> {
  const response = await requestRemoteGxserver<{ project: GxserverProjectDomainState }>(
    machineId,
    "/api/addProjectPath",
    {
      params: {
        name,
        path,
      },
      timeoutMs: 15_000,
    },
  ) as { result: { project: GxserverProjectDomainState } };
  return response.result.project;
}

async function resolveRemoteWorktreeFamilyParentProject(
  machineId: string,
  sourceProject: GxserverProjectDomainState,
): Promise<GxserverProjectDomainState> {
  const worktree = normalizeNativeProjectWorktreeMetadata(sourceProject.worktree);
  if (!worktree?.parentProjectId) {
    return sourceProject;
  }
  const projects = await readRemoteGxserverProjects(machineId);
  const parentProject = projects.find((candidate) => candidate.projectId === worktree.parentProjectId);
  if (parentProject) {
    return parentProject;
  }
  return addRemoteGxserverProjectPath(machineId, worktree.parentProjectPath, worktree.parentProjectName);
}

async function generateRemoteWorktreeNameFromPrompt(prompt: string): Promise<string> {
  try {
    return normalizeNativeWorktreeSlug(await generateNativeSessionTitleFromPrompt(nativeHomeDirectory(), prompt));
  } catch (error) {
    appendSessionTitleGenerationErrorLog("nativeSidebar.remoteWorktree.generateName.failed", {
      error: error instanceof Error ? error.message : String(error),
      promptLength: prompt.length,
    });
    return normalizeNativeWorktreeSlug(prompt);
  }
}

async function resolveUniqueRemoteWorktreeTarget(
  remoteReference: { machineId: string; projectId: string },
  sourceProject: GxserverProjectDomainState,
  baseSlug: string,
): Promise<{ branch: string; name: string; path: string }> {
  const sourceProjectPath = sourceProject.path?.trim();
  if (!sourceProjectPath) {
    throw new Error("Remote source project path is missing.");
  }
  const parentDirectory = dirnameNativePath(sourceProjectPath.replace(/\/+$/, ""));
  const projectFolderName = projectNameFromPath(sourceProjectPath);
  const presentation = remotePresentationSnapshotsByMachineId.get(remoteReference.machineId);
  const registeredPaths = new Set(
    (presentation?.projects ?? [])
      .map((project) => normalizeNativePathForProjectComparison(project.path ?? ""))
      .filter(Boolean),
  );
  for (let index = 0; index < 50; index += 1) {
    const name = index === 0 ? baseSlug : `${baseSlug}-${index + 1}`;
    const branch = name;
    const path = `${parentDirectory}/${projectFolderName}-${name}`;
    const branchCheck = await runRemoteGxserverGitAction(remoteReference, {
      action: "verifyRef",
      ref: `refs/heads/${branch}`,
    });
    const pathCheck = await runRemoteGxserverWorktreeAction(remoteReference, {
      action: "pathExists",
      worktreePath: path,
    });
    if (branchCheck.exitCode !== 0 && pathCheck.exitCode !== 0 && !registeredPaths.has(path)) {
      return { branch, name, path };
    }
  }
  throw new Error(`Could not find an unused remote worktree name for ${baseSlug}.`);
}

async function openExistingNativeWorktreeProject(input: {
  sourceProject: NativeProject;
  worktreePath?: string;
}): Promise<NativeProject> {
  const normalizedPath = input.worktreePath?.trim().replace(/\/+$/u, "") ?? "";
  if (!normalizedPath) {
    throw new Error("Choose an existing worktree.");
  }

  const projectName = projectNameFromPath(normalizedPath);
  const gxserverProject = await gxserverClient.addProjectPath({
    name: projectName,
    path: normalizedPath,
  });
  applyGxserverProjectDomainStateToPresentationCache(gxserverProject, "openExistingProjectWorktree");
  const worktreeOpenMetadata = resolveGxserverWorktreeProjectOpenMetadata(
    gxserverProject,
    projectName,
  );
  if (!worktreeOpenMetadata) {
    throw new Error(`${normalizedPath} is not a registered worktree for ${input.sourceProject.name}.`);
  }

  /*
   * CDXC:WorktreeProjectRegistration 2026-06-01-20:59:
   * Opening an existing worktree from the Add Worktree modal must register the
   * selected checkout through gxserver, focus the canonical worktree project,
   * and create a starter terminal when the project has no visible sessions,
   * without creating another checkout.
   *
   * CDXC:WorktreeProjectRegistration 2026-06-01-21:33:
   * Open Existing is intentionally not an agent prompt flow. It only opens the
   * selected checkout as a worktree project under the canonical parent.
   */
  const projectId = gxserverProject.projectId;
  const existingProject = projects.find(
    (project) =>
      project.projectId === projectId ||
      normalizeNativePathForProjectComparison(project.path) === normalizedPath,
  );
  const nextProject: NativeProject = existingProject
    ? {
        ...existingProject,
        isRecentProject: false,
        name: gxserverProject.name || existingProject.name || projectName,
        projectId,
        recentClosedAt: undefined,
        worktree: worktreeOpenMetadata.worktree,
        workspace:
          existingProject.isRecentProject === true
            ? wakeVisibleProjectSessions(existingProject.workspace)
            : existingProject.workspace,
      }
    : {
        commandsPanel: createProjectCommandsPanelState(),
        name: gxserverProject.name || projectName,
        path: normalizedPath,
        projectId,
        theme:
          worktreeOpenMetadata.parentProject.theme ??
          resolveSidebarTheme(settings.sidebarTheme, "dark"),
        themeColor: worktreeOpenMetadata.parentProject.themeColor,
        worktree: worktreeOpenMetadata.worktree,
        workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
      };

  projects = insertWorktreeProjectBelowSourceProject(
    ensureNativeProjectPresent(projects, worktreeOpenMetadata.parentProject),
    nextProject,
    worktreeOpenMetadata.parentProject.projectId,
  );
  activeProjectId = projectId;
  collapseSidebarProjectSessionList(worktreeOpenMetadata.parentProject.projectId);
  ensureProjectCommandsState(resolveNativeProjectCommandsOwnerId(projectId));
  writeProjectCommandsStore();
  loadActiveProjectCommands();
  writeStoredProjects("openExistingProjectWorktree");
  await refreshGitState();
  if (activeSnapshot().sessions.length === 0) {
    createTerminal(DEFAULT_TERMINAL_SESSION_TITLE);
  } else {
    publish();
  }
  showAppToast("success", "Worktree ready", nextProject.name);
  return findProject(projectId) ?? nextProject;
}

async function resolveUniqueNativeWorktreeTarget(
  project: NativeProject,
  baseSlug: string,
): Promise<{ branch: string; name: string; path: string }> {
  const parentDirectory = dirnameNativePath(project.path.replace(/\/+$/, ""));
  const projectFolderName = projectNameFromPath(project.path);
  for (let index = 0; index < 50; index += 1) {
    const name = index === 0 ? baseSlug : `${baseSlug}-${index + 1}`;
    const branch = name;
    const path = `${parentDirectory}/${projectFolderName}-${name}`;
    const branchCheck = await runGxserverGitActionForNativeProject(project, {
      action: "verifyRef",
      ref: `refs/heads/${branch}`,
    });
    /*
    CDXC:WorktreeProjectRegistration 2026-06-02-13:16:
    Candidate worktree path availability belongs to the same gxserver-owned worktree mutation boundary as branch/ref checks and `git worktree add`. Native keeps the naming loop for local-first UI, but asks gxserver whether the target path already exists instead of shelling out directly.
    */
    const pathCheck = await runGxserverWorktreeActionForNativeProject(project, {
      action: "pathExists",
      worktreePath: path,
    });
    const projectExists = projects.some((candidate) => candidate.path.replace(/\/+$/, "") === path);
    if (branchCheck.exitCode !== 0 && pathCheck.exitCode !== 0 && !projectExists) {
      return { branch, name, path };
    }
  }
  throw new Error(`Could not find an unused worktree name for ${baseSlug}.`);
}

async function createNativeChat(title = "chat"): Promise<void> {
  /**
   * CDXC:Chats 2026-05-04-09:30
   * A chat is not tied to an existing code project. Starting one must create a
   * real folder under ~/ghostex/chats/<date>-title and then launch a normal empty
   * terminal in that directory so the user can choose any agent from the shell.
   */
  const createdAt = new Date();
  const chatTitle = title.trim() || "chat";
  const chatPath = createNativeChatDirectoryPath(chatTitle, createdAt);
  const result = await runNativeProcess("/bin/mkdir", ["-p", chatPath]);
  if (result.exitCode !== 0) {
    showNativeMessage(
      "error",
      result.stderr.trim() || result.stdout.trim() || `Unable to create chat folder: ${chatPath}`,
    );
    return;
  }

  const projectId = createProjectId(chatPath);
  if (!projects.some((project) => project.projectId === projectId)) {
    projects = orderNativeProjectsForSidebar([
      ...projects,
      {
        commandsPanel: createProjectCommandsPanelState(),
        isChat: true,
        isQuick: true,
        name: nativeChatTitleFromDate(createdAt),
        path: chatPath,
        projectId,
        quickKind: "terminal",
        theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
        workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
      },
    ]);
    writeStoredProjects("createChat");
  }
  focusProject(projectId);
  if (activeSnapshot().sessions.length === 0) {
    createTerminal(DEFAULT_TERMINAL_SESSION_TITLE);
    return;
  }
  publish();
}

async function createNativeAgentChat(agent: SidebarAgentButton): Promise<void> {
  /**
   * CDXC:QuickAgents 2026-06-08-18:25:
   * Quick's section-header agent picker is projectless even though it reuses the project-header picker UI. Create and focus a new Quick chat workspace first, then launch the selected provider through the existing T3 or terminal-backed agent path so the agent never lands in the active code project.
   */
  const createdAt = new Date();
  const chatTitle = agent.name.trim() || "agent";
  const chatPath = createNativeChatDirectoryPath(chatTitle, createdAt);
  const result = await runNativeProcess("/bin/mkdir", ["-p", chatPath]);
  if (result.exitCode !== 0) {
    showNativeMessage(
      "error",
      result.stderr.trim() || result.stdout.trim() || `Unable to create agent chat folder: ${chatPath}`,
    );
    return;
  }

  const projectId = createProjectId(chatPath);
  if (!projects.some((project) => project.projectId === projectId)) {
    projects = orderNativeProjectsForSidebar([
      ...projects,
      {
        commandsPanel: createProjectCommandsPanelState(),
        isChat: true,
        isQuick: true,
        name: nativeChatTitleFromDate(createdAt),
        path: chatPath,
        projectId,
        quickKind: "terminal",
        theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
        workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
      },
    ]);
    writeStoredProjects("createNativeAgentChat");
  }
  focusProject(projectId);
  if (agent.agentId === "t3") {
    createNativeT3Session();
    return;
  }
  if (agent.command) {
    await launchAgentTerminal(agent);
    return;
  }
  publish();
}

async function createNativeQuickTerminal(options: {
  command?: string;
  cwd?: string;
  forceSessionPersistenceOff?: boolean;
  shellCommand?: string;
  title?: string;
} = {}): Promise<TerminalSessionRecord | undefined> {
  /*
   * CDXC:OSIntegration 2026-05-27-18:06:
   * `ghostex terminal` is the explicit default-terminal integration surface.
   * Create a projectless Quick terminal rooted at the requested cwd instead of
   * mutating the active code project or relying on broad macOS terminal defaults.
   */
  const requestedCwd = options.cwd?.trim() || nativeHomeDirectory();
  const cwd = await resolveExistingDirectoryForOpenRequest(requestedCwd);
  const createdAt = new Date();
  const title = options.title?.trim() || projectNameFromPath(cwd) || DEFAULT_TERMINAL_SESSION_TITLE;
  const projectId = createProjectId(`quick-terminal:${createdAt.toISOString()}:${cwd}`);
  projects = orderNativeProjectsForSidebar([
    ...projects,
    {
      commandsPanel: createProjectCommandsPanelState(),
      isQuick: true,
      name: title,
      path: cwd,
      projectId,
      quickKind: "terminal",
      theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
      workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
    },
  ]);
  writeStoredProjects("createQuickTerminal");
  focusProject(projectId);
  const commandText = options.command?.trim();
  const session = createTerminal(title, commandText ? `${commandText}\r` : "", undefined, undefined, {
    forceSessionPersistenceOff: options.forceSessionPersistenceOff,
    shellCommand: options.shellCommand,
  });
  if (!session) {
    publish();
  }
  return session;
}

type NativeOpenPathTarget = {
  column?: number;
  line?: number;
  path: string;
  raw?: string;
  waitToken?: string;
};

type NativeCodeServerFileOpenTarget = Pick<NativeOpenPathTarget, "column" | "line" | "path">;
type NativeProjectFileWaitTarget = Required<Pick<NativeOpenPathTarget, "path" | "waitToken">> &
  Pick<NativeOpenPathTarget, "column" | "line">;

const QUICK_FILE_EDITOR_PROJECT_ID_PREFIX = "quick-file:";
const QUICK_FILE_SHARED_EDITOR_PROJECT_ID = "quick-files";
const QUICK_FILE_EDITOR_SIDEBAR_SESSION_ID = "__quick-file-editor__";
const QUICK_FILE_MISSING_POLL_MS = 5_000;
const CODE_SERVER_PROJECT_FILE_WAIT_SESSION_RETRY_MS = 500;
const CODE_SERVER_PROJECT_FILE_WAIT_SESSION_TIMEOUT_MS = 30_000;
let quickFileMissingPollInFlight = false;
const quickFileWaitResolvers = new Map<string, (value: { ok: true; path: string }) => void>();

async function resolveExistingDirectoryForOpenRequest(path: string): Promise<string> {
  const normalizedPath = normalizeNativeOpenPath(path);
  const directoryCheck = await runNativeProcess("/bin/test", ["-d", normalizedPath], {
    timeoutMs: 5_000,
  });
  return directoryCheck.exitCode === 0 ? normalizedPath : nativeHomeDirectory();
}

function normalizeNativeOpenPath(path: string): string {
  const trimmed = path.trim();
  if (trimmed === "~") {
    return nativeHomeDirectory();
  }
  if (trimmed.startsWith("~/")) {
    return `${nativeHomeDirectory()}${trimmed.slice(1)}`;
  }
  return trimmed.replace(/\/+$/, "") || trimmed;
}

async function getNativeOpenPathKind(path: string): Promise<"directory" | "file" | undefined> {
  const normalizedPath = normalizeNativeOpenPath(path);
  const directoryCheck = await runNativeProcess("/bin/test", ["-d", normalizedPath], {
    timeoutMs: 5_000,
  });
  if (directoryCheck.exitCode === 0) {
    return "directory";
  }
  const fileCheck = await runNativeProcess("/bin/test", ["-f", normalizedPath], { timeoutMs: 5_000 });
  return fileCheck.exitCode === 0 ? "file" : undefined;
}

async function resolveGitRootForNativeOpenPath(path: string): Promise<string | undefined> {
  /*
   * CDXC:OSIntegration 2026-06-02-12:14:
   * Native owns CLI open-file/open-folder routing and pane focus. gxserver owns
   * the Git-root inspection needed before an arbitrary path is registered as a
   * project, so native should not shell out to `git rev-parse` here.
   */
  return (await gxserverClient.resolveGitRootForPath({ path })).gitRoot;
}

function isDeniedBroadFileParent(path: string): boolean {
  const home = nativeHomeDirectory().replace(/\/+$/, "");
  const normalizedPath = normalizeNativeOpenPath(path);
  return new Set([
    "/",
    "/Users",
    home,
    `${home}/Desktop`,
    `${home}/Downloads`,
    `${home}/Documents`,
  ]).has(normalizedPath);
}

async function isLargeNativeOpenParent(path: string): Promise<boolean> {
  const script = [
    "set -e",
    `count=$(/usr/bin/find ${quoteNativeShellArg(path)} \\( -name .git -o -name node_modules -o -name dist -o -name build -o -name .next -o -name coverage \\) -prune -o -type f -print | /usr/bin/head -n 10001 | /usr/bin/wc -l)`,
    'test "${count//[[:space:]]/}" -gt 10000',
  ].join("\n");
  const result = await runNativeProcess("/bin/zsh", ["-lc", script], { timeoutMs: 30_000 });
  return result.exitCode === 0;
}

async function shouldRouteFileParentToQuick(path: string): Promise<boolean> {
  if (isDeniedBroadFileParent(path)) {
    return true;
  }
  return isLargeNativeOpenParent(path);
}

function createQuickFileProjectId(originalPath: string): string {
  return createProjectId(`${QUICK_FILE_EDITOR_PROJECT_ID_PREFIX}${originalPath}`);
}

function quickFileSharedNativeEditorId(): string {
  return createNativeProjectEditorId(QUICK_FILE_SHARED_EDITOR_PROJECT_ID, "code");
}

function quickFileOriginalPath(project: NativeProject): string {
  return project.quickOriginalPath?.trim() || project.path;
}

function quickFileDisplayName(project: NativeProject): string {
  return projectNameFromPath(quickFileOriginalPath(project)) || project.name || "File";
}

function workspaceHasOpenSessions(workspace: GroupedSessionWorkspaceSnapshot): boolean {
  return workspace.groups.some((group) => group.snapshot.sessions.length > 0);
}

function createQuickFileSidebarSession(project: NativeProject, index = 0): SidebarSessionItem {
  const originalPath = quickFileOriginalPath(project);
  const missing = project.quickOriginalMissing === true;
  /*
   * CDXC:OSIntegration 2026-05-27-11:26:
   * Loose Quick files are not real terminal sessions, but every opened file
   * needs its own closeable/focusable Quick sidebar row while sharing one
   * embedded Code surface. Model the row as a synthetic session so the existing
   * sidebar interactions can stay project-scoped without creating one webview
   * per loose file.
   */
  return {
    activity: missing ? "attention" : "idle",
    activityLabel: missing ? "Missing" : undefined,
    alias: quickFileDisplayName(project),
    column: 0,
    detail: missing ? `Missing - ${originalPath}` : originalPath,
    isFocused: project.projectId === activeProjectId,
    isRunning: false,
    isVisible: project.projectId === activeProjectId,
    kind: "workspace",
    lifecycleState: missing ? "error" : "done",
    primaryTitle: quickFileDisplayName(project),
    row: index + 1,
    sessionId: createCombinedProjectSessionId(
      project.projectId,
      QUICK_FILE_EDITOR_SIDEBAR_SESSION_ID,
    ),
    shortcutLabel: "",
  };
}

function isQuickFileEditorSidebarReference(reference: {
  project: NativeProject;
  sessionId: string;
}): boolean {
  return (
    reference.sessionId === QUICK_FILE_EDITOR_SIDEBAR_SESSION_ID &&
    quickKindForProject(reference.project) === "editor"
  );
}

function focusQuickFileEditorProject(project: NativeProject): void {
  const surfaceState = projectEditorSurfaceByProjectId.get(project.projectId);
  const targetPath = project.quickSymlinkPath ?? project.quickOriginalPath;
  focusProject(project.projectId);
	  projectEditorSurfaceByProjectId.set(project.projectId, {
	    errorMessage: undefined,
	    isOpen: true,
	    isSleeping: false,
	    lastAccessedAt: new Date().toISOString(),
	    mode: "code",
    nativeEditorId: nativeProjectEditorIdForProject(project, "code"),
    status: surfaceState?.status === "running" ? "running" : "opening",
    title: "Quick Files",
    url: targetPath
      ? createCodeServerProjectEditorUrl(project.path, { path: targetPath })
      : surfaceState?.url ?? createCodeServerProjectEditorUrl(project.path),
  });
  wakeProjectEditorSurface(project, "code");
  postNative({
    projectId: nativeProjectEditorIdForProject(project, "code"),
    type: "focusProjectEditorPane",
  });
  publish();
}

function nativeProjectEditorIdForProject(
  project: Pick<NativeProject, "isChat" | "isQuick" | "projectId" | "quickKind">,
  mode: ProjectEditorSurfaceMode,
): string {
  /*
   * CDXC:OSIntegration 2026-05-27-18:06:
   * Loose Quick file rows are separate sidebar items, but they must share one
   * embedded VS Code webview rooted at ~/.ghostex/quick-files. Keep the shared
   * native editor id centralized so wake/focus/close paths do not accidentally
   * create one Chromium surface per loose file.
   */
  if (mode === "code" && quickKindForProject(project) === "editor") {
    return quickFileSharedNativeEditorId();
  }
  return createNativeProjectEditorId(project.projectId, mode);
}

async function removeQuickFileSymlink(project: NativeProject): Promise<void> {
  const symlinkPath = project.quickSymlinkPath?.trim();
  if (!symlinkPath) {
    return;
  }
  /*
   * CDXC:OSIntegration 2026-05-27-18:06:
   * Loose Quick file rows own only their mirrored symlink under
   * ~/.ghostex/quick-files. Closing that row must remove the symlink without
   * touching the original file, so a later Quick open cannot reuse stale state.
   */
  await runNativeProcess("/bin/rm", ["-f", symlinkPath], { timeoutMs: 5_000 });
}

function resolveQuickFileWait(project: NativeProject): void {
  const waitToken = project.quickWaitToken?.trim();
  if (!waitToken) {
    return;
  }
  const resolver = quickFileWaitResolvers.get(waitToken);
  if (!resolver) {
    return;
  }
  quickFileWaitResolvers.delete(waitToken);
  resolver({ ok: true, path: project.quickOriginalPath ?? project.path });
}

async function openNativeProjectEditorForFile(
  projectPath: string,
  target?: NativeOpenPathTarget,
): Promise<void> {
  await addProject(projectPath);
  const normalizedProjectPath = normalizeNativePathForProjectComparison(projectPath);
  const project = projects.find(
    (candidate) =>
      normalizeNativePathForProjectComparison(candidate.path) === normalizedProjectPath,
  );
  if (!project) {
    return;
  }
  if (activeProjectId !== project.projectId) {
    focusProject(project.projectId);
  }
  /*
   * CDXC:OSIntegration 2026-05-27-18:06:
   * Opening a file that belongs to a project should route through the existing
   * project Code surface and let VS Code own its normal file tabs. Re-wake the
   * surface with a file-specific URL even when the project editor is already
   * running, because OS open/edit commands are explicit navigation requests.
   *
   * CDXC:OSIntegration 2026-06-07-14:39:
   * Finder/Open With/default-editor requests must open the requested file, not
   * merely reveal the Source tab. If the embedded VS Code workbench already
   * owns the same URL, native will only focus it, so schedule an explicit
   * code-server IPC file-open after wake/focus for non-wait file requests.
   */
	  projectEditorSurfaceByProjectId.set(project.projectId, {
	    errorMessage: undefined,
	    isOpen: true,
	    isSleeping: false,
	    lastAccessedAt: new Date().toISOString(),
	    mode: "code",
    nativeEditorId: nativeProjectEditorIdForProject(project, "code"),
    status: "opening",
    title: projectEditorTitle(project),
    url: createCodeServerProjectEditorUrl(project.path, target),
  });
  setProjectEditorPersistedOpen(project.projectId, true, "openProjectEditorFile");
  wakeProjectEditorSurface(project, "code");
  postNative({
    projectId: nativeProjectEditorIdForProject(project, "code"),
    type: "focusProjectEditorPane",
  });
  if (target?.path && !target.waitToken) {
    scheduleCodeServerFileOpen(
      {
        column: target.column,
        line: target.line,
        path: target.path,
      },
      "openNativeProjectEditorForFile",
    );
  }
  void refreshProjectDiffStats(project.projectId);
  publish();
}

async function openLooseQuickFile(target: NativeOpenPathTarget): Promise<NativeProject | undefined> {
  const quickRoot = `${nativeGhostexHomeDirectory().replace(/\/+$/, "")}/quick-files`;
  const originalPath = normalizeNativeOpenPath(target.path);
  const symlinkPath = `${quickRoot}${originalPath}`;
  const symlinkDirectory = dirnameNativePath(symlinkPath);
  const linkCommand = [
    `mkdir -p ${quoteNativeShellArg(symlinkDirectory)}`,
    `if [ -L ${quoteNativeShellArg(symlinkPath)} ]; then target=$(/bin/readlink ${quoteNativeShellArg(symlinkPath)}); if [ "$target" != ${quoteNativeShellArg(originalPath)} ]; then rm -f ${quoteNativeShellArg(symlinkPath)}; fi; elif [ -e ${quoteNativeShellArg(symlinkPath)} ]; then rm -f ${quoteNativeShellArg(symlinkPath)}; fi`,
    `if [ ! -L ${quoteNativeShellArg(symlinkPath)} ]; then ln -s ${quoteNativeShellArg(originalPath)} ${quoteNativeShellArg(symlinkPath)}; fi`,
  ].join("\n");
  const result = await runNativeProcess("/bin/zsh", ["-lc", linkCommand], { timeoutMs: 10_000 });
  if (result.exitCode !== 0) {
    throw new Error(result.stderr.trim() || result.stdout.trim() || "Could not prepare Quick file.");
  }
  /*
   * CDXC:OSIntegration 2026-05-27-18:06:
   * Loose file opens must not auto-add broad folders such as ~/Downloads as
   * Projects. Root the shared Quick Code surface at ~/.ghostex/quick-files and
   * mirror the real file through a symlink so edits still affect the original.
   */
  const projectId = createQuickFileProjectId(originalPath);
  let project = findProject(projectId);
  if (!project) {
    projects = orderNativeProjectsForSidebar([
      ...projects,
      {
        commandsPanel: createProjectCommandsPanelState(),
        isQuick: true,
        name: projectNameFromPath(originalPath),
        path: quickRoot,
        projectId,
        quickKind: "editor",
        quickOriginalMissing: false,
        quickOriginalPath: originalPath,
        quickSymlinkPath: symlinkPath,
        quickWaitToken: target.waitToken,
        theme: resolveSidebarTheme(settings.sidebarTheme, "dark"),
        workspace: createDefaultGroupedSessionWorkspaceSnapshot(),
      },
    ]);
    project = findProject(projectId);
  }
  if (!project) {
    return undefined;
  }
  focusProject(projectId);
  project.isQuick = true;
  project.quickKind = "editor";
  project.quickOriginalMissing = false;
  project.quickOriginalPath = originalPath;
  project.quickSymlinkPath = symlinkPath;
  project.quickWaitToken = target.waitToken;
  writeStoredProjects("openLooseQuickFile");
	  projectEditorSurfaceByProjectId.set(project.projectId, {
	    errorMessage: undefined,
	    isOpen: true,
	    isSleeping: false,
	    lastAccessedAt: new Date().toISOString(),
	    mode: "code",
    nativeEditorId: quickFileSharedNativeEditorId(),
    status: "opening",
    title: "Quick Files",
    url: createCodeServerProjectEditorUrl(quickRoot, {
      column: target.column,
      line: target.line,
      path: symlinkPath,
    }),
  });
  wakeProjectEditorSurface(project);
  postNative({ projectId: quickFileSharedNativeEditorId(), type: "focusProjectEditorPane" });
  /*
   * CDXC:OSIntegration 2026-06-07-14:39:
   * Quick loose-file rows share one VS Code workbench. Opening another loose
   * file, or reopening a closed loose-file tab, must send an explicit file-open
   * command to that shared workbench instead of relying on the project-editor
   * URL changing or the pane merely becoming focused.
   */
  scheduleCodeServerFileOpen(
    {
      column: target.column,
      line: target.line,
      path: symlinkPath,
    },
    "openLooseQuickFile",
  );
  publish();
  return project;
}

async function refreshQuickFileMissingStates(reason: string): Promise<void> {
  if (quickFileMissingPollInFlight) {
    return;
  }
  const quickFileProjects = projects.filter(
    (project) => quickKindForProject(project) === "editor" && project.quickOriginalPath?.trim(),
  );
  if (quickFileProjects.length === 0) {
    return;
  }
  quickFileMissingPollInFlight = true;
  try {
    const statuses = await Promise.all(
      quickFileProjects.map(async (project) => {
        const originalPath = quickFileOriginalPath(project);
        const result = await runNativeProcess("/bin/test", ["-e", originalPath], {
          timeoutMs: 5_000,
        });
        return {
          missing: result.exitCode !== 0,
          projectId: project.projectId,
        };
      }),
    );
    let changed = false;
    for (const status of statuses) {
      const project = findProject(status.projectId);
      if (!project || quickKindForProject(project) !== "editor") {
        continue;
      }
      if (project.quickOriginalMissing !== status.missing) {
        project.quickOriginalMissing = status.missing;
        changed = true;
      }
    }
    if (changed) {
      /*
       * CDXC:OSIntegration 2026-05-27-11:26:
       * Quick loose-file rows must remain visible after the original file moves
       * or is deleted so the user can close the row deliberately. Poll the
       * original path and mark the synthetic row missing instead of silently
       * removing sidebar state or recreating a stale symlink target.
       */
      writeStoredProjects(`refreshQuickFileMissingStates:${reason}`);
      publish();
    }
  } finally {
    quickFileMissingPollInFlight = false;
  }
}

function startQuickFileMissingMonitor(): void {
  void refreshQuickFileMissingStates("startup");
  window.setInterval(() => {
    void refreshQuickFileMissingStates("poll");
  }, QUICK_FILE_MISSING_POLL_MS);
}

function codeServerSessionSocketPath(): string {
  return `${nativeGhostexHomeDirectory().replace(/\/+$/, "")}/code-server-runtime/user-data/code-server-ipc.sock`;
}

function codeServerWaitMarkerPath(waitToken: string): string {
  return `${nativeGhostexHomeDirectory().replace(/\/+$/, "")}/edit-waits/${waitToken}.wait`;
}

function codeServerIpcOpenArg(target: NativeCodeServerFileOpenTarget): string {
  if (!target.line) {
    return target.path;
  }
  return `${target.path}:${target.line}${target.column ? `:${target.column}` : ""}`;
}

function codeServerIpcOpenScript(): string {
  return String.raw`
const http = require("http");

const [sessionSocket, filePath, openArg] = process.argv.slice(1);

function request(socketPath, requestPath, method, body) {
  return new Promise((resolve, reject) => {
    const req = http.request(
      {
        headers: body ? { "content-type": "application/json" } : undefined,
        method,
        path: requestPath,
        socketPath,
      },
      (res) => {
        let raw = "";
        res.setEncoding("utf8");
        res.on("data", (chunk) => {
          raw += chunk;
        });
        res.on("end", () => {
          if (res.statusCode >= 200 && res.statusCode < 300) {
            resolve(raw);
            return;
          }
          reject(new Error(method + " " + requestPath + " failed with " + res.statusCode + ": " + raw));
        });
      },
    );
    req.on("error", reject);
    if (body) {
      req.write(body);
    }
    req.end();
  });
}

(async () => {
  const rawSession = await request(
    sessionSocket,
    "/session?filePath=" + encodeURIComponent(filePath),
    "GET",
  );
  const session = JSON.parse(rawSession);
  if (!session.socketPath) {
    throw new Error("No code-server editor session is registered for " + filePath);
  }
  await request(
    session.socketPath,
    "/",
    "POST",
    JSON.stringify({
      type: "open",
      folderURIs: [],
      fileURIs: [openArg],
      gotoLineMode: true,
      forceReuseWindow: true,
    }),
  );
  process.stdout.write(JSON.stringify({ ok: true, socketPath: session.socketPath }));
})().catch((error) => {
  process.stderr.write(error?.stack || error?.message || String(error));
  process.exit(1);
});
`;
}

function codeServerIpcWaitScript(): string {
  return String.raw`
const fs = require("fs");
const http = require("http");
const path = require("path");

const [sessionSocket, filePath, openArg, waitMarkerFilePath] = process.argv.slice(1);

function request(socketPath, requestPath, method, body) {
  return new Promise((resolve, reject) => {
    const req = http.request(
      {
        headers: body ? { "content-type": "application/json" } : undefined,
        method,
        path: requestPath,
        socketPath,
      },
      (res) => {
        let raw = "";
        res.setEncoding("utf8");
        res.on("data", (chunk) => {
          raw += chunk;
        });
        res.on("end", () => {
          if (res.statusCode >= 200 && res.statusCode < 300) {
            resolve(raw);
            return;
          }
          reject(new Error(method + " " + requestPath + " failed with " + res.statusCode + ": " + raw));
        });
      },
    );
    req.on("error", reject);
    if (body) {
      req.write(body);
    }
    req.end();
  });
}

(async () => {
  const rawSession = await request(
    sessionSocket,
    "/session?filePath=" + encodeURIComponent(filePath),
    "GET",
  );
  const session = JSON.parse(rawSession);
  if (!session.socketPath) {
    throw new Error("No code-server editor session is registered for " + filePath);
  }
  fs.mkdirSync(path.dirname(waitMarkerFilePath), { recursive: true });
  fs.writeFileSync(waitMarkerFilePath, "");
  await request(
    session.socketPath,
    "/",
    "POST",
    JSON.stringify({
      type: "open",
      folderURIs: [],
      fileURIs: [openArg],
      gotoLineMode: true,
      forceReuseWindow: true,
      waitMarkerFilePath,
    }),
  );
  process.stdout.write(JSON.stringify({ ok: true, socketPath: session.socketPath, waitMarkerFilePath }));
})().catch((error) => {
  try {
    if (typeof waitMarkerFilePath === "string" && fs.existsSync(waitMarkerFilePath)) {
      fs.unlinkSync(waitMarkerFilePath);
    }
  } catch {}
  process.stderr.write(error?.stack || error?.message || String(error));
  process.exit(1);
});
`;
}

